INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 8, 8, 'Será tragado Israel: presto serán entre las gentes como vaso en que no hay contentamiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 8, 9, 'Porque ellos subieron á Assur, asno montés para sí solo: Ephraim con salario alquiló amantes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 8, 10, 'Aunque alquilen á las gentes, ahora las juntaré; y serán un poco afligidos por la carga del rey y de los príncipes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 8, 11, 'Porque multiplicó Ephraim altares para pecar, tuvo altares para pecar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 8, 12, 'Escribíle las grandezas de mi ley, y fueron tenidas por cosas ajenas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 8, 13, 'En los sacrificios de mis dones sacrificaron carne, y comieron: no los quiso Jehová: ahora se acordará de su iniquidad, y visitará su pecado; ellos se tornarán á Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 8, 14, 'Olvidó pues Israel á su Hacedor, y edificó templos, y Judá multiplicó ciudades fuertes: mas yo meteré fuego en sus ciudades, el cual devorará sus palacios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 9, 1, 'No te alegres, oh Israel, hasta saltar de gozo como los pueblos, pues has fornicado apartándote de tu Dios: amaste salario por todas las eras de trigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 9, 2, 'La era y el lagar no los mantedrán; les fallará el mosto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 9, 3, 'No quedarán en la tierra de Jehová, sino que volverá Ephraim á Egipto, y á Asiria, donde comerán vianda inmunda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 9, 4, 'No derramarán vino á Jehová, ni él tomará contento en sus sacrificios; como pan de enlutados le serán á ellos: todos los que comieren de él, serán inmundos. Será pues el pan de ellos para si mismos; no entrará en la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 9, 5, '¿Qué haréis el día de la solemnidad, y el día de la fiesta de Jehová?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 9, 6, 'Porque, he aquí se fueron ellos á causa de la destrucción: Egipto los recogerá, Memphis los enterrará: espino poseerá por heredad lo deseable de su plata, ortiga crecerá en sus moradas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 9, 7, 'Vinieron los días de la visitación, vinieron los días de la paga; conocerálo Israel: necio el profeta. insensato el varón de espíritu, á causa de la multitud de tu maldad, y grande odio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 9, 8, 'Atalaya es Ephraim para con mi Dios: el profeta es lazo de cazador en todos sus caminos, odio en la casa de su Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 9, 9, 'Llegaron al profundo, corrompiéronse, como en los días de Gabaa: ahora se acordará de su iniquidad; visitará su pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 9, 10, 'Como uvas en el desierto hallé á Israel: como la fruta temprana de la higuera en su principio vi á vuestros padres. Ellos entraron á Baal-peor, y se apartaron para vergüenza, é hiciéronse abominables como aquello que amaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 9, 11, 'Ephraim, cual ave volará su gloria desde el nacimiento, aun desde el vientre y desde la concepción.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 9, 12, 'Y si llegaren á grandes sus hijos, quitarélos de entre los hombre, porque ¡ay de ellos también, cuando de ellos me apartare!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 9, 13, 'Ephraim, según veo, es semejante á Tiro, asentada en lugar delicioso: mas Ephraim sacará sus hijos al matador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 9, 14, 'Dales, oh Jehová, lo que les has de dar: dales matriz expeliente, y enjutos pechos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 9, 15, 'Toda la maldad de ellos fué en Gilgal; allí, pues, les tomé aversión: por la malicia de sus obras echarélos de mi casa; no los amaré más; todos sus príncipes son desleales.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 9, 16, 'Ephraim fué herido, secóse su cepa, no hará más fruto: aunque engendren, yo mataré lo deseable de su vientre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 9, 17, 'Mi Dios los desechará, porque ellos no le oyeron; y andarán errantes entre las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 10, 1, 'ES Israel una frondosa viña, haciendo fruto para sí: conforme á la multiplicación de su fruto multiplicó altares, conforme á la bondad de su tierra aumentaron sus estatuas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 10, 2, 'Dividióse su corazón. Ahora serán hallados culpables: él quebrantará sus altares, asolará sus estatuas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 10, 3, 'Porque dirán ahora: No tenemos rey, porque no temimos á Jehová: ¿y qué haría el rey por nosotros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 10, 4, 'Han hablado palabras jurando en vano al hacer alianza: por tanto, el juicio florecerá como ajenjo en los surcos del campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 10, 5, 'Por las becerras de Beth-aven serán atemorizados los moradores de Samaria: porque su pueblo lamentará á causa del becerro, y sus sacerdotes que en él se regocijaban por su gloria, la cual será disipada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 10, 6, 'Y aun será él llevado á Asiria en presente al rey Jareb: Ephraim será avergonzado, é Israel será confuso de su consejo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 10, 7, 'De Samaria fué cortado su rey como la espuma sobre la superficie de las aguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 10, 8, 'Y los altares de Avén serán destruídos, el pecado de Israel; crecerá sobre sus altares espino y cardo. Y dirán á los montes: Cubridnos; y á los collados: Caed sobre nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 10, 9, 'Desde los días de Gabaa has pecado, oh Israel: allí estuvieron: no los tomó la batalla en Gabaa contra los inicuos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 10, 10, 'Y los castigaré como deseo: y pueblos se juntarán sobre ellos cuando serán atados en sus dos surcos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 10, 11, 'Ephraim es becerra domada, amadora del trillar; mas yo pasaré sobre su lozana cerviz: yo haré llevar yugo á Ephraim; arará Judá, quebrará sus terrones Jacob.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 10, 12, 'Sembrad para vosotros en justicia, segad para vosotros en misericordia; arad para vosotros barbecho: porque es el tiempo de buscar á Jehová, hasta que venga y os enseñe justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 10, 13, 'Habéis arado impiedad, segasteis iniquidad: comeréis fruto de mentira: porque confiaste en tu camino, en la multitud de tus fuertes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 10, 14, 'Por tanto, en tus pueblos se levantará alboroto, y todas tus fortalezas serán destruídas, como destruyó Salmán á Beth-arbel el día de la batalla: la madre fué arrojada sobre los hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 10, 15, 'Así hará á vosotros Beth-el por la maldad de vuestra maldad: en la mañana será del todo cortado el rey de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 11, 1, 'CUANDO Israel era muchacho, yo lo amé, y de Egipto llamé á mi hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 11, 2, 'Como los llamaban, así ellos se iban de su presencia; á los Baales sacrificaban, y á las esculturas ofrecían sahumerios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 11, 3, 'Yo con todo eso guiaba en pies al mismo Ephraim, tomándolos de sus brazos; y no conocieron que yo los cuidaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 11, 4, 'Con cuerdas humanas los traje, con cuerdas de amor: y fuí para ellos como los que alzan el yugo de sobre sus mejillas, y llegué hacia él la comida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 11, 5, 'No tornará á tierra de Egipto, antes el mismo Assur será su rey, porque no se quisieron convertir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 11, 6, 'Y caerá espada sobre sus ciudades, y consumirá sus aldeas; consumirálas á causa de sus consejos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 11, 7, 'Entre tanto, está mi pueblo adherido á la rebelión contra mí: aunque lo llaman al Altísimo, ninguno absolutamente quiere ensalzar le.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 11, 8, '¿Cómo tengo de dejarte, oh Ehpraim? ¿he de entregarte yo, Israel? ¿cómo podré yo hacerte como Adma, ni ponerte como á Zeboim? Mi corazón se revuelve dentro de mí, inflámanse todas mis conmiseraciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 11, 9, 'No ejecutaré el furor de mi ira, no volveré para destruir á Ephraim: porque Dios soy, y no hombre; el Santo en medio de ti: y no entraré en la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 11, 10, 'En pos de Jehová caminarán: él bramará como león: cual león rugirá él de cierto, y los hijos se moverán azorados del occidente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 11, 11, 'Como ave se moverán velozmente de Egipto, y de la tierra de Asiria como paloma; y pondrélos en sus casas, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 11, 12, '(12-1) CERCOME Ephraim con mentira, y la casa de Israel con engaño: mas Judá aún domina con Dios, y es fiel con los santos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 12, 1, '(12-2) Ephraim se apacienta del viento, y sigue al solano: mentira y destrucción aumenta continuamente; porque hicieron alianza con los Asirios, y aceite se lleva á Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 12, 2, '(12-3) Pleito tiene Jehová con Judá para visitar á Jacob conforme á sus caminos: pagarále conforme á sus obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 12, 3, '(12-4) En el vientre tomó por el calcañar á su hermano, y con su fortaleza venció al ángel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 12, 4, '(12-5) Venció al ángel, y prevaleció; lloró, y rogóle: en Beth-el le halló, y allí habló con nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 12, 5, '(12-6) Mas Jehová es Dios de los ejércitos: Jehová es su memorial.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 12, 6, '(12-7) Tú pues, conviértete á tu Dios: guarda misericordia y juicio, y en tu Dios espera siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 12, 7, '(12-8) Es mercader que tiene en su mano peso falso, amador de opresión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 12, 8, '(12-9) Y dijo Ephraim: Ciertamente yo he enriquecido, hallado he riquezas para mí: nadie hallará en mí iniquidad, ni pecado en todos mis trabajos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 12, 9, '(12-10) Empero yo soy Jehová tu Dios desde la tierra de Egipto: aun te haré morar en tiendas, como en los días de la fiesta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 12, 10, '(12-11) Y hablado he á los profetas, y yo aumenté la profecía, y por mano de los profetas puse semejanzas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 12, 11, '(12-12) ¿Es Galaad iniquidad? Ciertamente vanidad han sido; en Gilgal sacrificaron bueyes: y aún son sus altares como montones en los surcos del campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 12, 12, '(12-13) Mas Jacob huyó á tierra de Aram, y sirvió Israel por mujer, y por mujer fué pastor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 12, 13, '(12-14) Y por profeta hizo subir Jehová á Israel de Egipto, y por profeta fué guardado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 12, 14, '(12-15) Enojado ha Ephraim á Dios con amarguras; por tanto, sus sangres se derramarán sobre él, y su Señor le pagará su oprobio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 13, 1, 'CUANDO Ephraim hablaba, hubo temor; fué ensalzado en Israel; mas pecó en Baal, y murió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 13, 2, 'Y ahora añadieron á su pecado, y de su plata se han hecho según su entendimiento, estatuas de fundición, ídolos, toda obra de artífices; acerca de los cuales dicen á los hombres que sacrifican, que besen los becerros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 13, 3, 'Por tanto serán como la niebla de la mañana, y como el rocío de la madrugada que se pasa; como el tamo que la tempestad arroja de la era, y como el humo que de la chimenea sale.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 13, 4, 'Mas yo soy Jehová tu Dios desde la tierra de Egipto: no conocerás pues Dios fuera de mí, ni otro Salvador sino á mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 13, 5, 'Yo te conocí en el desierto, en tierra seca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 13, 6, 'En sus pastos se hartaron, hartáronse, y ensoberbecióse su corazón: por esta causa se olvidaron de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 13, 7, 'Por tanto, yo seré para ellos como león; como un leopardo en el camino los espiaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 13, 8, 'Como oso que ha perdido los hijos los encontraré, y romperé las telas de su corazón, y allí los devoraré como león: bestia del campo los despedazará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 13, 9, 'Te perdiste, oh Israel, mas en mí está tu ayuda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 13, 10, '¿Dónde está tu rey, para que te guarde con todas tus ciudades? ¿y tus jueces, de los cuales dijiste: Dame rey y príncipes?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 13, 11, 'Díte rey en mi furor, y quitélo en mi ira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 13, 12, 'Atada está la maldad de Ephraim; su pecado está guardado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 13, 13, 'Dolores de mujer de parto le vendrán: es un hijo ignorante, que de otra manera no estuviera tanto tiempo en el rompimiento de los hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 13, 14, 'De la mano del sepulcro los redimiré, librarélos de la muerte. Oh muerte, yo seré tu muerte; y seré tu destrucción, oh sepulcro; arrepentimiento será escondido de mis ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 13, 15, 'Aunque él fructificará entre los hermanos, vendrá el solano, viento de Jehová, subiendo de la parte del desierto, y secarse ha su vena, y secaráse su manadero: él saqueará el tesoro de todas las preciosas alhajas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 13, 16, 'Samaria será asolada, porque se rebeló contra su Dios: caerán á cuchillo: sus niños serán estrellados, y su preñadas serán abiertas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 14, 1, 'CONVIÉRTETE, oh Israel, á Jehová tu Dios: porque por tu pecado has caído.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 14, 2, 'Tomad con vosotros palabras, y convertíos á Jehová, y decidle: Quita toda iniquidad, y acepta el bien, y daremos becerros de nuestros labios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 14, 3, 'No nos librará Assur; no subiremos sobre caballos, ni nunca más diremos á la obra de nuestras manos: Dioses nuestros: porque en ti el huérfano alcanzará misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 14, 4, 'Yo medicinaré su rebelión, amarélos de voluntad: porque mi furor se apartó de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 14, 5, 'Yo seré á Israel como rocío; él florecerá como lirio, y extenderá sus raíces como el Líbano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 14, 6, 'Extenderse han sus ramos, y será su gloria como la de la oliva, y olerá como el Líbano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 14, 7, 'Volverán, y se sentarán bajo de su sombra: serán vivificados como trigo, y florecerán como la vid: su olor, como de vino del Líbano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 14, 8, 'Ephraim dirá: ¿Qué más tendré ya con los ídolos? Yo lo oiré, y miraré; yo seré á él como la haya verde: de mí será hallado tu fruto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 14, 9, '¿Quién es sabio para que entienda esto, y prudente para que los sepa? Porque los caminos del Jehová son derechos, y los justos andarán por ellos: mas los rebeldes en ellos caerán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 1, 1, 'PALABRA de Jehová que fué á Miqueas de Morasti en días de Jotham, Achâz, y Ezechîas, reyes de Judá: lo que vió sobre Samaria y Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 1, 2, 'Oid, pueblos todos: está atenta, tierra, y todo lo que en ella hay: y el Señor Jehová, el Señor desde su santo templo sea testigo contra vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 1, 3, 'Porque he aquí, Jehová sale de su lugar, y descenderá, y hollará sobre las alturas de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 1, 4, 'Y debajo de él se derretirán los montes, y los valles se hendirán como la cera delante del fuego, como las aguas que corren por un precipicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 1, 5, 'Todo esto por la rebelión de Jacob, y por los pecados de la casa de Israel. ¿Cuál es la rebelión de Jacob? ¿no es Samaria? ¿Y cuáles son los excelsos de Judá? ¿no es Jerusalem?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 1, 6, 'Pondré pues á Samaria en majanos de heredad, en tierra de viñas; y derramaré sus piedras por el valle, y descubriré sus fundamentos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 1, 7, 'Y todas sus estatuas serán despedazadas, y todos sus dones serán quemados en fuego, y asolaré todos sus ídolos; porque de dones de rameras los juntó, y á dones de rameras volverán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 1, 8, 'Por tanto lamentaré y aullaré, y andaré despojado y desnudo; haré gemido como de chacales, y lamento como de avestruces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 1, 9, 'Porque su llaga es dolorosa, que llegó hasta Judá; llegó hasta la puerta de mi pueblo, hasta Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 1, 10, 'No lo digáis en Gath, ni lloréis mucho: revuélcate en el polvo de Beth-le-aphrah.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 1, 11, 'Pásate desnuda con vergüenza, oh moradora de Saphir: la moradora de Saanán no salió al llanto de Beth-esel: tomará de vosotros su tardanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 1, 12, 'Porque la moradora de Maroth tuvo dolor por el bien; por cuanto el mal descendió de Jehová hasta la puerta de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 1, 13, 'Unce al carro dromedarios, oh moradora de Lachîs, que fuiste principio de pecado á la hija de Sión; porque en ti se inventaron las rebeliones de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 1, 14, 'Por tanto, tú darás dones á Moreseth-gath: las casas de Achzib serán en mentira á los reyes de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 1, 15, 'Aun te traeré heredero, oh moradora de Maresah: la gloria de Israel vendrá hasta Adullam.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 1, 16, 'Mésate y trasquílate por los hijos de tus delicias: ensancha tu calva como águila; porque fueron trasportados de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 2, 1, '¡AY de los que piensan iniquidad, y de los que fabrican el mal en sus camas! Cuando viene la mañana lo ponen en obra, porque tienen en su mano el poder.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 2, 2, 'Y codiciaron las heredades, y robáronlas: y casas, y las tomaron: oprimieron al hombre y á su casa, al hombre y á su heredad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 2, 3, 'Por tanto, así ha dicho Jehová: He aquí, yo pienso sobre esta familia un mal, del cual no sacaréis vuestros cuellos, ni andaréis erguidos; porque el tiempo será malo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 2, 4, 'En aquel tiempo se levantará sobre vosotros refrán, y se endechará endecha de lametación, diciendo: Del todo fuimos destruídos; ha cambiado la parte de mi pueblo. ¡Cómo nos quitó nuestros campos! dió, repartiólos á otros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 2, 5, 'Por tanto, no tendrás quien eche cordel para suerte en la congregación de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 2, 6, 'No profeticéis, dicen á los que profetizan; no les profeticen que los ha de comprender vergüenza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 2, 7, 'La que te dices casa de Jacob, ¿hase acortado el espíritu de Jehová? ¿son éstas sus obras? ¿Mis palabras no hacen bien al que camina derechamente?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 2, 8, 'El que ayer era mi pueblo, se ha levantado como enemigo: tras las vestiduras quitasteis las capas atrevidamente á los que pasaban, como los que vuelven de la guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 2, 9, 'A las mujeres de mi pueblo echasteis fuera de las casas de sus delicias: á sus niños quitasteis mi perpetua alabanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 2, 10, 'Levantaos, y andad, que no es ésta la holganza; porque está contaminada, corrompióse, y de grande corrupción.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 2, 11, 'Si hubiere alguno que ande con el viento, y finja mentiras diciendo: Yo te profetizaré de vino y de sidra; este tal será profeta á este pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 2, 12, 'De cierto te reuniré todo, oh Jacob: recogeré ciertamente el resto de Israel: pondrélo junto como ovejas de Bosra, como rebaño en mitad de su majada: harán estruendo por la multitud de los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 2, 13, 'Subirá rompedor delante de ellos; romperán y pasarán la puerta, y saldrán por ella: y su rey pasará delante de ellos, y á la cabeza de ellos Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 3, 1, 'Y DIJE: Oid ahora, príncipes de Jacob, y cabezas de la casa de Israel: ¿No pertenecía á vosotros saber el derecho?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 3, 2, 'Que aborrecen lo bueno y aman lo malo, que les quitan su piel y su carne de sobre los huesos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 3, 3, 'Que comen asimismo la carne de mi pueblo, y les desuellan su piel de sobre ellos, y les quebrantan sus huesos y los rompen, como para el caldero, y como carnes en olla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 3, 4, 'Entonces clamarán á Jehová y no les responderá; antes esconderá de ellos su rostro en aquel tiempo, por cuanto hicieron malvadas obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 3, 5, 'Así ha dicho Jehová acerca de los profetas que hacen errar á mi pueblo, que muerden con sus dientes, y claman, Paz, y al que no les diere que coman, aplazan contra él batalla:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 3, 6, 'Por tanto, de la profecía se os hará noche, y oscuridad del adivinar; y sobre los profetas se pondrá el sol, y el día se entenebrecerá sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 3, 7, 'Y serán avergonzados los profetas, y confundiránse los adivinos; y ellos todos cubrirán su labio, porque no hay respuesta de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 3, 8, 'Yo empero estoy lleno de fuerza del espíritu de Jehová, y de juicio, y de fortaleza, para denunciar á Jacob su rebelión, y á Israel su pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 3, 9, 'Oid ahora esto, cabezas de la casa de Jacob, y capitanes de la casa de Israel, que abomináis el juicio, y pervertís todo el derecho;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 3, 10, 'Que edificáis á Sión con sangre, y á Jerusalem con injusticia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 3, 11, 'Sus cabezas juzgan por cohecho, y sus sacerdotes enseñan por precio, y sus profetas adivinan por dinero; y apóyanse en Jehová diciendo: ¿no está Jehová entre nosotros? No vendrá mal sobre nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 3, 12, 'Por tanto, á causa de vosotros será Sión arada como campo, y Jerusalem será majanos, y el monte de la casa como cumbres de breñal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 4, 1, 'Y ACONTECERA en los postreros tiempos, que el monte de la casa de Jehová será constituído por cabecera de montes, y más alto que los collados, y correrán á él pueblos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 4, 2, 'Y vendrán muchas gentes, y dirán: Venid, y subamos al monte de Jehová, y á la casa del Dios de Jacob; y enseñarános en sus caminos, y andaremos por sus veredas: porque de Sión saldrá la ley, y de Jerusalem la palabra de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 4, 3, 'Y juzgará entre muchos pueblos, y corregirá fuertes gentes hasta muy lejos: y martillarán sus espadas para azadones, y sus lanzas para hoces: no alzará espada gente contra gente, ni más se ensayarán para la guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 4, 4, 'Y cada uno se sentará debajo de su vid y debajo de su higuera, y no habrá quien amedrente: porque la boca de Jehová de los ejércitos lo ha hablado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 4, 5, 'Bien que todos los pueblos anduvieren cada uno en el nombre de sus dioses, nosotros con todo andaremos en el nombre de Jehová nuestro Dios para siempre y eternalmente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 4, 6, 'En aquel día, dice Jehová, juntaré la coja, y recogeré la amontada, y á la que afligí:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 4, 7, 'Y pondré á la coja para sucesión, y á la descarriada para nación robusta: y Jehová reinará sobre ellos en el monte de Sión desde ahora para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 4, 8, 'Y tú, oh torre del rebaño, la fortaleza de la hija de Sión vendrá hasta ti: y el señorío primero, el reino vendrá á la hija de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 4, 9, 'Ahora ¿por qué gritas tanto? ¿No hay rey en ti? ¿Pereció tu consejero, que te ha tomado dolor como de mujer de parto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 4, 10, 'Duélete y gime, hija de Sión como mujer de parto; porque ahora saldrás de la ciudad, y morarás en el campo, y llegarás hasta Babilonia: allí serás librada, allí te redimirá Jehová de la mano de tus enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 4, 11, 'Ahora empero se han juntado muchas gentes contra ti, y dicen: Sea profanada, y vean nuestros ojos su deseo sobre Sión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 4, 12, 'Mas ellos no conocieron los pensamientos de Jehová, ni entendieron su consejo: por lo cual los juntó como gavillas en la era.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 4, 13, 'Levántate y trilla, hija de Sión, porque tu cuerno tornaré de hierro, y tus uñas de metal, y desmenuzarás muchos pueblos; y consagrarás á Jehová sus robos, y sus riquezas al Señor de toda la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 5, 1, 'REUNETE ahora en bandas, oh hija de bandas: nos han sitiado: con vara herirán sobre la quijada al juez de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 5, 2, 'Mas tú, Beth-lehem Ephrata, pequeña para ser en los millares de Judá, de ti me saldrá el que será Señor en Israel; y sus salidas son desde el principio, desde los días del siglo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 5, 3, 'Empero los dejará hasta el tiempo que para la que ha de parir; y el resto de sus hermanos se tornará con los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 5, 4, 'Y estará, y apacentará con fortaleza de Jehová, con grandeza del nombre de Jehová su Dios: y asentarán; porque ahora será engrandecido hasta los fines de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 5, 5, 'Y éste será nuestra paz. Cuando Assur viniere á nuestra tierra, y cuando pisare nuestros palacios, entonces levantaremos contra él siete pastores, y ocho hombres principales;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 5, 6, 'Y comerán la tierra de Assur á cuchillo, y la tierra de Nimrod con sus espadas: y nos librará del Asirio, cuando viniere contra nuestra tierra y hollare nuestros términos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 5, 7, 'Y será el residuo de Jacob en medio de muchos pueblos, como el rocío de Jehová, como las lluvias sobre la hierba, las cuales no esperan varón, ni aguardan á hijos de hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 5, 8, 'Asimismo será el resto de Jacob entre las gentes, en medio de muchos pueblos, como el león entre las bestias de la montaña, como el cachorro del león entre las manadas de las ovejas, el cual si pasare, y hollare, y arrebatare, no hay quien escape.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 5, 9, 'Tu mano se alzará sobre tus enemigos, y todos tus adversarios serán talados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 5, 10, 'Y acontecerá en aquel día, dice Jehová, que haré matar tus caballos de en medio de ti, y haré destruir tus carros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 5, 11, 'Haré también destruir las ciudades de tu tierra, y arruinaré todas tus fortalezas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 5, 12, 'Asimismo destruiré de tu mano las hechicerías, y no se hallarán en ti agoreros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 5, 13, 'Y haré destruir tus esculturas y tus imágenes de en medio de ti, y nunca más te inclinarás á la obra de tus manos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 5, 14, 'Y arrancaré tus bosques de en medio de ti, y destruiré tus ciudades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 5, 15, 'Y con ira y con furor haré venganza en las gentes que no escucharon.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 6, 1, 'OID ahora lo que dice Jehová: Levántate, pleitea con los montes, y oigan los collados tu voz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 6, 2, 'Oid, montes, y fuertes fundamentos de la tierra, el pleito de Jehová: porque tiene Jehová pleito con su pueblo, y altercará con Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 6, 3, 'Pueblo mío, ¿qué te he hecho, ó en qué te he molestado? Responde contra mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 6, 4, 'Porque yo te hice subir de la tierra de Egipto, y de la casa de siervos te redimí; y envié delante de ti á Moisés, y á Aarón, y á María.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 6, 5, 'Pueblo mío, acuérdate ahora qué aconsejó Balac rey de Moab, y qué le respondió Balaam, hijo de Beor, desde Sittim hasta Gilgal, para que conozcas las justicias de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 6, 6, '¿Con qué prevendré á Jehová, y adoraré al alto Dios? ¿vendré ante él con holocaustos, con becerros de un año?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 6, 7, '¿Agradaráse Jehová de millares de carneros, ó de diez mil arroyos de aceite? ¿daré mi primogénito por mi rebelión, el fruto de mi vientre por el pecado de mi alma?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 6, 8, 'Oh hombre, él te ha declarado qué sea lo bueno, y qué pida de ti Jehová: solamente hacer juicio, y amar misericordia, y humillarte para andar con tu Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 6, 9, 'La voz de Jehová clama á la ciudad, y el sabio mirará á tu nombre. Oid la vara, y á quien la establece.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 6, 10, '¿Hay aún en casa del impío tesoros de impiedad, y medida escasa que es detestable?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 6, 11, '¿Seré limpio con peso falso, y con bolsa de engañosas pesas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 6, 12, 'Con lo cual sus ricos se hinchieron de rapiña, y sus moradores hablaron mentira, y su lengua engañosa en su boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 6, 13, 'Por eso yo también te enflaqueceré hiriéndote, asolándote por tus pecados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 6, 14, 'Tú comerás, y no te hartarás; y tu abatimiento será en medio de ti: tú cogerás, mas no salvarás; y lo que salvares, lo entregaré yo á la espada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 6, 15, 'Tú sembrarás, mas no segarás: pisarás aceitunas, mas no te ungirás con el aceite; y mosto, mas no beberás el vino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 6, 16, 'Porque los mandamientos de Omri se han guardado, y toda obra de la casa de Achâb; y en los consejos de ellos anduvisteis, para que yo te diese en asolamiento, y tus moradores para ser silbados. Llevaréis por tanto el oprobio de mi pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 7, 1, '¡AY de mí! que he venido á ser como cuando han cogido los frutos del verano, como cuando han rebuscado después de la vendimia, que no queda racimo para comer; mi alma deseó primeros frutos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 7, 2, 'Faltó el misericordioso de la tierra, y ninguno hay recto entre los hombres: todos acechan á la sangre; cada cual arma red á su hermano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 7, 3, 'Para completar la maldad con sus manos, el príncipe demanda, y el juez juzga por recompensa; y el grande habla el antojo de su alma, y lo confirman.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 7, 4, 'El mejor de ellos es como el cambrón; el más recto, como zarzal: el día de tus atalayas, tu visitación, viene; ahora será su confusión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 7, 5, 'No creáis en amigo, ni confiéis en príncipe: de la que duerme á tu lado, guarda, no abras tu boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 7, 6, 'Porque el hijo deshonra al padre, la hija se levanta contra la madre, la nuera contra su suegra: y los enemigos del hombre son los de su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 7, 7, 'Yo empero á Jehová esperaré, esperaré al Dios de mi salud: el Dios mío me oirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 7, 8, 'Tú, enemiga mía, no te huelgues de mí: porque aunque caí, he de levantarme; aunque more en tinieblas, Jehová será mi luz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 7, 9, 'La ira de Jehová soportaré, porque pequé contra él, hasta que juzgue mi causa y haga mi juicio él me sacará á luz; veré su justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 7, 10, 'Y mi enemiga verá, y la cubrirá vergüenza: la que me decía: ¿Dónde está Jehová tu Dios? Mis ojos la verán; ahora será hollada como lodo de las calles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 7, 11, 'El día en que se edificarán tus muros, aquel día será alejado el mandamiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 7, 12, 'En ese día vendrán hasta ti desde Asiria y las ciudades fuertes, y desde las ciudades fuertes hasta el Río, y de mar á mar, y de monte á monte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 7, 13, 'Y la tierra con sus moradores será asolada por el fruto de sus obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 7, 14, 'Apacienta tu pueblo con tu cayado, el rebaño de tu heredad, que mora solo en la montaña, en medio del Carmelo: pazcan en Basán y Galaad, como en el tiempo pasado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 7, 15, 'Yo les mostraré maravillas como el día que saliste de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 7, 16, 'Las gentes verán, y se avergonzarán de todas sus valentías; pondrán la mano sobre su boca, ensordecerán sus oídos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 7, 17, 'Lamerán el polvo como la culebra; como las serpientes de la tierra, temblarán en sus encierros: despavorirse han de Jehová nuestro Dios, y temerán de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 7, 18, '¿Qué Dios como tú, que perdonas la maldad, y olvidas el pecado del resto de su heredad? No retuvo para siempre su enojo, porque es amador de misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 7, 19, 'El tornará, él tendrá misericordia de nosotros; él sujetará nuestras iniquidades, y echará en los profundos de la mar todos nuestros pecados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MIC', 'Miqueas', 7, 20, 'Otorgarás á Jacob la verdad, y á Abraham la misericordia, que tú juraste á nuestros padres desde tiempos antiguos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 1, 1, 'LA carga que vió Habacuc profeta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 1, 2, '¿Hasta cuándo, oh Jehová, clamaré, y no oirás; y daré voces á ti á causa de la violencia, y no salvarás?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 1, 3, '¿Por qué me haces ver iniquidad, y haces que mire molestia, y saco y violencia delante de mí, habiendo además quien levante pleito y contienda?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 1, 4, 'Por lo cual la ley es debilitada, y el juicio no sale verdadero: por cuanto el impío asedia al justo, por eso sale torcido el juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 1, 5, 'Mirad en las gentes, y ved, y maravillaos pasmosamente; porque obra será hecha en vuestros días, que aun cuando se os contare, no la creeréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 1, 6, 'Porque he aquí, yo levanto los Caldeos, gente amarga y presurosa, que camina por la anchura de la tierra para poseer las habitaciones ajenas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 1, 7, 'Espantosa es y terrible: de ella misma saldrá su derecho y su grandeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 1, 8, 'Y serán sus caballos más ligeros que tigres, y más agudos que lobos de tarde; y sus jinetes se multiplicarán: vendrán de lejos sus caballeros, y volarán como águilas que se apresuran á la comida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 1, 9, 'Toda ella vendrá á la presa: delante su sus caras viento solano; y juntará cautivos como arena.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 1, 10, 'Y escarnecerá de los reyes, y de los príncipes hará burla: reiráse de toda fortaleza, y amontonará polvo, y la tomará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 1, 11, 'Luego mudará espíritu, y pasará adelante, y ofenderá atribuyendo esta su potencia á su dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 1, 12, '¿No eres tú desde el principio, oh Jehová, Dios mío, Santo mío? No moriremos. Oh Jehová, para juicio lo pusiste; y tú, oh Roca, lo fundaste para castigar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 1, 13, 'Muy limpio eres de ojos para ver el mal, ni puedes ver el agravio: ¿por qué ves los menospreciadores, y callas cuando destruye el impío al más justo que él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 1, 14, 'Y haces que sean los hombres como los peces de la mar, como reptiles que no tienen señor?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 1, 15, 'Sacará á todos con anzuelo, cogerálos con su red, y juntarálos en su aljerife: por lo cual se holgará y hará alegrías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 1, 16, 'Por esto hará sacrificios á su red, y ofrecerá sahumerios á su aljerife: porque con ellos engordó su porción, y engrasó su comida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 1, 17, '¿Vaciará por eso su red, ó tendrá piedad de matar gentes continuamente?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 2, 1, 'SOBRE mi guarda estaré, y sobre la fortaleza afirmaré el pie, y atalayaré para ver qué hablará en mí, y qué tengo de responder á mi pregunta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 2, 2, 'Y Jehová me respondió, y dijo: Escribe la visión, y declárala en tablas, para que corra el que leyere en ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 2, 3, 'Aunque la visión tardará aún por tiempo, mas al fin hablará, y no mentirá: aunque se tardare, espéralo, que sin duda vendrá; no tardará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 2, 4, 'He aquí se enorgullece aquel cuya alma no es derecha en él: mas el justo en su fe vivirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 2, 5, 'Y también, por cuanto peca por el vino, es un hombre soberbio, y no permanecerá: que ensanchó como el infierno su alma, y es como la muerte, que no se hartará: antes reunió á sí todas las gentes, y amontonó á sí todos los pueblos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 2, 6, '¿No han de levantar todos estos sobre él parábola, y sarcasmos contra él? Y dirán: ¡Ay del que multiplicó lo que no era suyo! ¿Y hasta cuándo había de amontonar sobre sí espeso lodo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 2, 7, '¿No se levantarán de repente los que te han de morder, y se despertarán los que te han de quitar de tu lugar, y serás á ellos por rapiña?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 2, 8, 'Porque tú has despojado muchas gentes, todos los otros pueblos te despojarán; á causa de las sangres humanas, y robos de la tierra, de las ciudades y de todos los que moraban en ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 2, 9, '¡Ay del que codicia maligna codicia para su casa, por poner en alto su nido, por escaparse del poder del mal!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 2, 10, 'Tomaste consejo vergonzoso para tu casa, asolaste muchos pueblos, y has pecado contra tu vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 2, 11, 'Porque la piedra clamará desde el muro, y la tabla del enmaderado le responderá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 2, 12, '¡Ay del que edifica la ciudad con sangres, y del que funda la villa con iniquidad!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 2, 13, '¿No es esto de Jehová de los ejércitos? Los pueblos pues trabajarán para el fuego, y las gentes se fatigarán en vano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 2, 14, 'Porque la tierra será llena de conocimiento de la gloria de Jehová, como las aguas cubren la mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 2, 15, '¡Ay del que da de beber á sus compañeros, que les acercas tu hiel y embriagas, para mirar sus desnudeces!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 2, 16, 'Haste llenado de deshonra más que de honra: bebe tú también, y serás descubierto; el cáliz de la mano derecha de Jehová volverá sobre ti, y vómito de afrenta sobre tu gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 2, 17, 'Porque la rapiña del Líbano caerá sobre ti, y la destrucción de las fieras lo quebrantará; á causa de las sangres humanas, y del robo de la tierra, de las ciudades, y de todos los que en ellas moraban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 2, 18, '¿De qué sirve la escultura que esculpió el que la hizo? ¿la estatua de fundición, que enseña mentira, para que haciendo imágenes mudas confíe el hacedor en su obra?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 2, 19, '¡Ay del que dice al palo; Despiértate; y á la piedra muda: Levántate! ¿Podrá él enseñar? He aquí él está cubierto de oro y plata, y no hay dentro de él espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 2, 20, 'Mas Jehová está en su santo templo: calle delante de él toda la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 3, 1, 'ORACION de Habacuc profeta, sobre Sigionoth.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 3, 2, 'Oh Jehová, oído he tu palabra, y temí: Oh Jehová, aviva tu obra en medio de los tiempos, En medio de los tiempos hazla conocer; En la ira acuérdate de la misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 3, 3, 'Dios vendrá de Temán, Y el Santo del monte de Parán, (Selah.) Su gloria cubrió los cielos, Y la tierra se llenó de su alabanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 3, 4, 'Y el resplandor fué como la luz; Rayos brillantes salían de su mano; Y allí estaba escondida su fortaleza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 3, 5, 'Delante de su rostro iba mortandad, Y á sus pies salían carbones encendidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 3, 6, 'Paróse, y midió la tierra: Miró, é hizo temblar las gentes; Y los montes antiguos fueron desmenuzados, Los collados antiguos se humillaron á él. Sus caminos son eternos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 3, 7, 'He visto las tiendas de Cushán en aflicción; Las tiendas de la tierra de Madián temblaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 3, 8, '¿Airóse Jehová contra los ríos? ¿Contra los ríos fué tu enojo? ¿Tu ira contra la mar, Cuando subiste sobre tus caballos, Y sobre tus carros de salud?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 3, 9, 'Descubrióse enteramente tu arco, Los juramentos á las tribus, palabra segura. (Selah.) Hendiste la tierra con ríos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 3, 10, 'Viéronte, y tuvieron temor los montes: Pasó la inundación de las aguas: El abismo dió su voz, La hondura alzó sus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 3, 11, 'El sol y la luna se pararon en su estancia: A la luz de tus saetas anduvieron, Y al resplandor de tu fulgente lanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 3, 12, 'Con ira hollaste la tierra, Con furor trillaste las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 3, 13, 'Saliste para salvar tu pueblo, Para salvar con tu ungido. Traspasaste la cabeza de la casa del impío, Desnudando el cimiento hasta el cuello. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 3, 14, 'Horadaste con sus báculos las cabezas de sus villas, Que como tempestad acometieron para derramarme: Su orgullo era como para devorar al pobre encubiertamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 3, 15, 'Hiciste camino en la mar á tu caballos, Por montón de grandes aguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 3, 16, 'Oí, y tembló mi vientre; A la voz se batieron mis labios; Pudrición se entró en mis huesos, y en mi asiento me estremecí; Si bien estaré quieto en el día de la angustia, Cuando suba al pueblo el que lo invadirá con sus tropas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 3, 17, 'Aunque la higuera no florecerá, Ni en las vides habrá frutos; Mentirá la obra de la oliva, Y los labrados no darán mantenimiento. Y las ovejas serán quitadas de la majada, Y no habrá vacas en los corrales;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 3, 18, 'Con todo yo me alegraré en Jehová, Y me gozaré en el Dios de mi salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAB', 'Habacuc', 3, 19, 'Jehová el Señor es mi fortaleza, El cual pondrá mis pies como de ciervas, Y me hará andar sobre mis alturas');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 1, 1, 'PALABRA de Jehová que fué á Sofonías hijo de Cushi, hijo de Gedalías, hijo de Amarías, hijo de Ezechîas, en días de Josías hijo de Amón, rey de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 1, 2, 'Destruiré del todo todas las cosas de sobre la haz de la tierra, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 1, 3, 'Destruiré los hombres y las bestias; destruiré las aves del cielo, y los peces de la mar, y las piedras de tropiezo con los impíos; y talaré los hombres de sobre la haz de la tierra, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 1, 4, 'Y extenderé mi mano sobre Judá, y sobre todos los moradores de Jerusalem, y exterminaré de este lugar el remanente de Baal, y el nombre de los Chemarim con los sacerdotes;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 1, 5, 'Y á los que se inclinan sobre los terrados al ejército del cielo; y á los que se inclinan jurando por Jehová y jurando por su rey;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 1, 6, 'Y á los que tornan atrás de en pos de Jehová; y á los que no buscaron á Jehová, ni preguntaron por él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 1, 7, 'Calla en la presencia del Señor Jehová, porque el día de Jehová está cercano; porque Jehová ha aparejado sacrificio, prevenido á sus convidados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 1, 8, 'Y será que en el día del sacrificio de Jehová, haré visitación sobre los príncipes, y sobre los hijos del rey, y sobre todos los que visten vestido extranjero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 1, 9, 'Asimismo haré visitación en aquel día sobre todos los que saltan la puerta, los que hinchen de robo y de engaño las casas de sus señores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 1, 10, 'Y habrá en aquel día, dice Jehová, voz de clamor desde la puerta del pescado, y aullido desde la segunda, y grande quebrantamiento desde los collados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 1, 11, 'Aullad, moradores de Mactes, porque todo el pueblo mercader es destruido; talado son todos los que traían dinero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 1, 12, 'Y será en aquel tiempo, que yo escudriñaré á Jerusalem con candiles, y haré visitación sobre los hombres que están sentados sobre sus heces, los cuales dicen en su corazón: Jehová ni hará bien ni mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 1, 13, 'Será por tanto saqueada su hacienda, y sus casas asoladas: y edificarán casas, mas no las habitarán; y plantarán viñas, mas no beberán el vino de ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 1, 14, 'Cercano está el día grande de Jehová, cercano y muy presuroso; voz amarga del Día de Jehová; gritará allí el valiente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 1, 15, 'Día de ira aquel día, día de angustia y de aprieto, día de alboroto y de asolamiento, día de tiniebla y de oscuridad, día de nublado y de entenebrecimiento,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 1, 16, 'Día de trompeta y de algazara, sobre las ciudades fuertes, y sobre las altas torres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 1, 17, 'Y atribularé los hombres, y andarán como ciegos, porque pecaron contra Jehová: y la sangre de ellos será derramada como polvo, y su carne como estiércol.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 1, 18, 'Ni su plata ni su oro podrá librarlos en el día de la ira de Jehová; pues toda la tierra será consumida con el fuego de su celo: porque ciertamente consumación apresurada hará con todos los moradores de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 2, 1, 'CONGREGAOS y meditad, gente no amable,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 2, 2, 'Antes que pára el decreto, y el día se pase como el tamo; antes que venga sobre vosotros el furor de la ira de Jehová, antes que el día de la ira de Jehová venga sobre vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 2, 3, 'Buscad á Jehová todos los humildes de la tierra, que pusisteis en obra su juicio; buscad justicia, buscad mansedumbre: quizás seréis guardados en el día del enojo de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 2, 4, 'Porque Gaza será desamparada, y Ascalón asolada: saquearán á Asdod en el medio día, y Ecrón será desarraigada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 2, 5, '¡Ay de los que moran á la parte de la mar, de la gente de Cheretim! La palabra de Jehová es contra vosotros, oh Canaán, tierra de Palestinos, que te haré destruir hasta no quedar morador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 2, 6, 'Y será la parte de la mar por moradas de cabañas de pastores, y corrales de ovejas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 2, 7, 'Y será aquella parte para el resto de la casa de Judá; allí apacentarán: en las casas de Ascalón dormirán á la noche; porque Jehová su Dios los visitará, y tornará sus cautivos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 2, 8, 'Yo he oído las afrentas de Moab, y los denuestos de los hijos de Ammón con que deshonraron á mi pueblo, y se engrandecieron sobre su término.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 2, 9, 'Por tanto, vivo yo, dice Jehová de los ejércitos, Dios de Israel, que Moab será como Sodoma, y los hijos de Ammon como Gomorra; campo de ortigas, y mina de sal, y asolamiento perpetuo: el resto de mi pueblo los saqueará, y el resto de mi gente los heredará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 2, 10, 'Esto les vendrá por su soberbia, porque afrentaron, y se engrandecieron contra el pueblo de Jehová de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 2, 11, 'Terrible será Jehová contra ellos, porque enervará á todos los dioses de la tierra; y cada uno desde su lugar se inclinará á él, todas las islas de las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 2, 12, 'Vosotros también los de Etiopía seréis muertos con mi espada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 2, 13, 'Y extenderá su mano sobre el aquilón, y destruirá al Assur, y pondrá á Nínive en asolamiento, y en secadal como un desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 2, 14, 'Y rebaños de ganado harán en ella majada, todas las bestias de las gentes; el onocrótalo también y el erizo dormirán en sus umbrales: su voz cantará en las ventanas; asolación será en las puertas, porque su enmaderamiento de cedro será descubierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 2, 15, 'Esta es la ciudad alegre que estaba confiada, la que decía en su corazón: Yo, y no más. ¡Cómo fué en asolamiento, en cama de bestias! Cualquiera que pasare junto á ella silbará, meneará su mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 3, 1, '¡AY de la ciudad ensuciada y contaminada y opresora!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 3, 2, 'No escuchó la voz, ni recibió la disciplina: no se confió en Jehová, no se acercó á su Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 3, 3, 'Sus príncipes en medio de ella son leones bramadores: sus jueces, lobos de tarde que no dejan hueso para la mañana:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 3, 4, 'Sus profetas, livianos, hombres prevaricadores: sus sacerdotes contaminaron el santuario, falsearon la ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 3, 5, 'Jehová justo en medio de ella, no hará iniquidad: de mañana sacará á luz su juicio, nunca falta: mas el perverso no tiene vergüenza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 3, 6, 'Hice talar gentes; sus castillos están asolados; hice desiertas sus calles, hasta no quedar quien pase: sus ciudades están asoladas hasta no quedar hombre, hasta no quedar morador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 3, 7, 'Dije: Ciertamente me temerás, recibirás corrección; y no será su habitación derruída por todo aquello sobre que los visité. Mas ellos se levantaron de mañana y corrompieron todas sus obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 3, 8, 'Por tanto, esperadme, dice Jehová, al día que me levantaré al despojo: porque mi determinación es reunir las gentes, juntar los reinos, para derramar sobre ellos mi enojo, todo el furor de mi ira; porque del fuego de mi celo será consumida toda la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 3, 9, 'Por entonces volveré yo á los pueblos el labio limpio, para que todos invoquen el nombre de Jehová, para que de un consentimiento le sirvan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 3, 10, 'De esa parte de los ríos de Etiopía, mis suplicantes, la hija de mis esparcidos, me traerán ofrenda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 3, 11, 'En aquel día no serás avergonzada por ninguna de tus obras con que te rebelaste contra mí; porque entonces quitaré de en medio de ti los que se alegran en tu soberbia, y nunca más te ensoberbecerás del monte de mi santidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 3, 12, 'Y dejaré en medio de ti un pueblo humilde y pobre, los cuales esperarán en el nombre de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 3, 13, 'El resto de Israel no hará iniquidad, ni dirá mentira, ni en boca de ellos se hallará lengua engañosa: porque ellos serán apacentados y dormirán, y no habrá quien los espante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 3, 14, 'Canta, oh hija de Sión: da voces de júbilo, oh Israel; gózate y regocíjate de todo corazón, hija de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 3, 15, 'Jehová ha apartado tus juicios, ha echado fuera tus enemigos: Jehová es Rey de Israel en medio de ti; nunca más verás mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 3, 16, 'En aquel tiempo se dirá á Jerusalem: No temas: Sión, no se debiliten tus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 3, 17, 'Jehová en medio de ti, poderoso, él salvará; gozaráse sobre ti con alegría, callará de amor, se regocijará sobre ti con cantar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 3, 18, 'Reuniré á los fastidiados por causa del largo tiempo; tuyos fueron; para quienes el oprobio de ella era una carga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 3, 19, 'He aquí, en aquel tiempo yo apremiaré á todos tus opresores; y salvaré la coja, y recogeré la descarriada; y pondrélos por alabanza y por renombre en todo país de confusión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEP', 'Sofonías', 3, 20, 'En aquel tiempo yo os traeré, en aquel tiempo os reuniré yo; pues os daré por renombre y por alabanza entre todos los pueblos de la tierra, cuando tornaré vuestros cautivos delante de vuestros ojos, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 1, 1, 'EN el año segundo del rey Darío en el mes sexto, en el primer día del mes, fué palabra de Jehová, por mano del profeta Haggeo, á Zorobabel hijo de Sealtiel, gobernador de Judá, y á Josué hijo de Josadac, gran sacerdote, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 1, 2, 'Jehová de los ejércitos habla así, diciendo: Este pueblo dice: No es aún venido el tiempo, el tiempo de que la casa de Jehová sea reedificada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 1, 3, 'Fué pues palabra de Jehová por mano del profeta Haggeo, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 1, 4, '¿Es para vosotros tiempo, para vosotros, de morar en vuestras casas enmaderadas, y esta casa está desierta?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 1, 5, 'Pues así ha dicho Jehová de los ejércitos: Pensad bien sobre vuestros caminos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 1, 6, 'Sembráis mucho, y encerráis poco; coméis, y no os hartáis; bebéis, y no os saciáis; os vestís, y no os calentáis; y el que anda á jornal recibe su jornal en trapo horadado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 1, 7, 'Así ha dicho Jehová de los ejércitos: Meditad sobre vuestros caminos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 1, 8, 'Subid al monte, y traed madera, y reedificad la casa; y pondré en ella, mi voluntad, y seré honrado, ha dicho Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 1, 9, 'Buscáis mucho, y halláis poco; y encerráis en casa, y soplo en ello. ¿Por qué? dice Jehová de los ejércitos. Por cuanto mi casa está desierta, y cada uno de vosotros corre á su propia casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 1, 10, 'Por eso se detuvo de los cielos sobre vosotros la lluvia, y la tierra detuvo sus frutos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 1, 11, 'Y llamé la sequedad sobre esta tierra, y sobre los montes, y sobre el trigo, y sobre el vino, y sobre el aceite, y sobre todo lo que la tierra produce, y sobre los hombres sobre y las bestias, y sobre todo trabajo de manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 1, 12, 'Y oyó Zorobabel hijo de Sealtiel, y Josué hijo de Josadac, gran sacerdote, y todo el demás pueblo, la voz de Jehová su Dios, y las palabras del porfeta Haggeo, como lo había enviado Jehová el Dios de ellos; y temió el pueblo delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 1, 13, 'Entonces Haggeo, enviado de Jehová, habló por mandado de Jehová, al pueblo, diciendo: Yo soy con vosotros, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 1, 14, 'Y despertó Jehová el espíritu de Zorobabel hijo de Sealtiel, gobernador de Judá, y el espíritu de Josué hijo de Josadac, gran sacerdote, y el espíritu de todo el resto del pueblo; y vinieron é hicieron obra en la casa de Jehová de los ejércitos, su Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 1, 15, 'En el día veinte y cuatro del mes sexto, en el segundo año del rey Darío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 2, 1, 'EN el mes séptimo, á los veinte y uno del mes, fué palabra de Jehová por mano del profeta Haggeo, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 2, 2, 'Habla ahora á Zorobabel hijo de Sealtiel, gobernador de Judá, y á Josué hijo de Josadac, gran sacerdote, y al resto del pueblo, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 2, 3, '¿Quién ha quedado entre vosotros que haya visto esta casa en su primera gloria, y cual ahora la veis? ¿No es ella como nada delante de vuestros ojos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 2, 4, 'Pues ahora, Zorobabel, esfuérzate, dice Jehová; esfuérzate también Josué, hijo de Josadac, gran sacerdote; y cobra ánimo, pueblo todo de la tierra, dice Jehová, y obrad: porque yo soy con vosotros, dice Jehová de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 2, 5, 'Según el pacto que concerté con vosotros a vuestra salida de Egipto, así mi espíritu estará en medio de vosotros: no temáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 2, 6, 'Porque así dice Jehová de los ejércitos: De aquí á poco aun haré yo temblar los cielos y la tierra, y la mar y la seca:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 2, 7, 'Y haré temblar á todas las gentes, y vendrá el Deseado de todas las gentes; y henchiré esta casa de gloria, ha dicho Jehová de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 2, 8, 'Mía es la plata, y mío el oro, dice Jehová de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 2, 9, 'La gloria de aquesta casa postrera será mayor que la de la primera, ha dicho Jehová de los ejércitos; y daré paz en este lugar, dice Jehová de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 2, 10, 'A veinticuatro del noveno mes, en el segundo año de Darío, fué palabra de Jehová por mano del profeta Haggeo, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 2, 11, 'Así ha dicho Jehová de los ejércitos: Pregunta ahora á los sacerdotes acerca de la ley, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 2, 12, 'Si llevare alguno las carnes sagradas en la falda de su ropa, y con el vuelo de ella tocare el pan, ó la vianda, ó el vino, ó el aceite, ú otra cualquier comida, ¿será santificado? Y respondieron los sacerdotes, y dijeron: No.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 2, 13, 'Y dijo Haggeo: Si un inmundo á causa de cuerpo muerto tocare alguna cosa de éstas, ¿será inmunda? Y respondieron los sacerdotes, y dijeron: Inmunda será.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 2, 14, 'Y respondió Haggeo y dijo: Así es este pueblo, y esta gente, delante de mí, dice Jehová; y asimismo toda obra de sus manos; y todo lo que aquí ofrecen es inmundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 2, 15, 'Ahora pues, poned vuestro corazón desde este día en adelante, antes que pusiesen piedra sobre piedra en el templo de Jehová,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 2, 16, 'Antes que fuesen estas cosas, venían al montón de veinte hanegas, y había diez; venían al lagar para sacar cincuenta cántaros del lagar, y había veinte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 2, 17, 'Os herí con viento solano, y con tizoncillo, y con granizo en toda obra de vuestras manos; mas no os convertisteis á mí, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 2, 18, 'Pues poned ahora vuestro corazón desde este día en adelante, desde el día veinticuatro del noveno mes, desde el día que se echó el cimiento al templo de Jehová; poned vuestro corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 2, 19, '¿Aun no está la simiente en el granero? ni la vid, ni la higuera, ni el granado, ni el árbol de la oliva ha todavía florecido: mas desde aqueste día daré bendición.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 2, 20, 'Y fué segunda vez palabra de Jehová á Haggeo, á los veinticuatro del mismo mes, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 2, 21, 'Habla á Zorobabel, gobernador de Judá, diciendo: Yo haré temblar los cielos y la tierra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 2, 22, 'Y trastornaré el trono de los reinos, y destruiré la fuerza del reino de las gentes; y trastornaré el carro, y los que en él suben; y vendrán abajo los caballos, y los que en ellos montan, cada cual por la espada de su hermano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HAG', 'Hageo', 2, 23, 'En aquel día, dice Jehová de los ejércitos, te tomaré, oh Zorobabel, hijo de Sealtiel, siervo mío, dice Jehová, y ponerte he como anillo de sellar: porque yo te escogí, dice Jehová de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 1, 'PRINCIPIO del evangelio de Jesucristo, Hijo de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 2, 'Como está escrito en Isaías el profeta: He aquí yo envío á mi mensajero delante de tu faz, Que apareje tu camino delante de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 3, 'Voz del que clama en el desierto: Aparejad el camino del Señor; Enderezad sus veredas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 4, 'Bautizaba Juan en el desierto, y predicaba el bautismo del arrepentimiento para remisión de pecados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 5, 'Y salía á él toda la provincia de Judea, y los de Jerusalem; y eran todos, bautizados por él en el río de Jordán, confesando sus pecados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 6, 'Y Juan andaba vestido de pelos de camello, y con un cinto de cuero alrededor de sus lomos; y comía langostas y miel silvestre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 7, 'Y predicaba, diciendo: Viene tras mí el que es más poderoso que yo, al cual no soy digno de desatar encorvado la correa de sus zapatos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 8, 'Yo á la verdad os he bautizado con agua; mas él os bautizará con Espíritu Santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 9, 'Y aconteció en aquellos días, que Jesús vino de Nazaret de Galilea, y fué bautizado por Juan en el Jordán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 10, 'Y luego, subiendo del agua, vió abrirse los cielos, y al Espíritu como paloma, que descendía sobre él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 11, 'Y hubo una voz de los cielos que decía: Tú eres mi Hijo amado; en ti tomo contentamiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 12, 'Y luego el Espíritu le impele al desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 13, 'Y estuvo allí en el desierto cuarenta días, y era tentado de Satanás; y estaba con las fieras; y los ángeles le servían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 14, 'Mas después que Juan fué encarcelado, Jesús vino á Galilea predicando el evangelio del reino de Dios,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 15, 'Y diciendo: El tiempo es cumplido, y el reino de Dios está cerca: arrepentíos, y creed al evangelio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 16, 'Y pasando junto á la mar de Galilea, vió á Simón, y á Andrés su hermano, que echaban la red en la mar; porque eran pescadores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 17, 'Y les dijo Jesús: Venid en pos de mí, y haré que seáis pescadores de hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 18, 'Y luego, dejadas sus redes, le siguieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 19, 'Y pasando de allí un poco más adelante, vió á Jacobo, hijo de Zebedeo, y á Juan su hermano, también ellos en el navío, que aderezaban las redes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 20, 'Y luego los llamó: y dejando á su padre Zebedeo en el barco con los jornaleros, fueron en pos de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 21, 'Y entraron en Capernaum; y luego los sábados, entrando en la sinagoga, enseñaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 22, 'Y se admiraban de su doctrina; porque les enseñaba como quien tiene potestad, y no como los escribas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 23, 'Y había en la sinagoga de ellos un hombre con espíritu inmundo, el cual dió voces,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 24, 'Diciendo: ¡Ah! ¿qué tienes con nosotros, Jesús Nazareno? ¿Has venido á destruirnos? Sé quién eres, el Santo de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 25, 'Y Jesús le riñó, diciendo: Enmudece, y sal de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 26, 'Y el espíritu inmundo, haciéndole pedazos, y clamando á gran voz, salió de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 27, 'Y todos se maravillaron, de tal manera que inquirían entre sí, diciendo: ¿Qué es esto? ¿Qué nueva doctrina es ésta, que con potestad aun á los espíritus inmundos manda, y le obedecen?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 28, 'Y vino luego su fama por toda la provincia alrededor de Galilea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 29, 'Y luego saliendo de la sinagoga, vinieron á casa de Simón y de Andrés, con Jacobo y Juan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 30, 'Y la suegra de Simón estaba acostada con calentura; y le hablaron luego de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 31, 'Entonces llegando él, la tomó de su mano y la levantó; y luego la dejó la calentura, y les servía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 32, 'Y cuando fué la tarde, luego que el sol se puso, traían á él todos los que tenían mal, y endemoniados;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 33, 'Y toda la ciudad se juntó á la puerta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 34, 'Y sanó á muchos que estaban enfermos de diversas enfermedades, y echó fuera muchos demonios; y no dejaba decir á los demonios que le conocían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 35, 'Y levantándose muy de mañana, aun muy de noche, salió y se fué á un lugar desierto, y allí oraba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 36, 'Y le siguió Simón, y los que estaban con él;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 37, 'Y hallándole, le dicen: Todos te buscan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 38, 'Y les dice: Vamos á los lugares vecinos, para que predique también allí; porque para esto he venido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 39, 'Y predicaba en las sinagogas de ellos en toda Galilea, y echaba fuera los demonios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 40, 'Y un leproso vino á él, rogándole; é hincada la rodilla, le dice: Si quieres, puedes limpiarme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 41, 'Y Jesús, teniendo misericordia de él, extendió su mano, y le tocó, y le dice: Quiero, sé limpio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 42, 'Y así que hubo él hablado, la lepra se fué luego de aquél, y fué limpio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 43, 'Entonces le apercibió, y despidióle luego,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 44, 'Y le dice: Mira, no digas á nadie nada; sino ve, muéstrate al sacerdote, y ofrece por tu limpieza lo que Moisés mandó, para testimonio á ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 1, 45, 'Mas él salido, comenzó á publicarlo mucho, y á divulgar el hecho, de manera que ya Jesús no podía entrar manifiestamente en la ciudad, sino que estaba fuera en los lugares desiertos; y venían á él de todas partes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 2, 1, 'Y ENTRO otra vez en Capernaum después de algunos días, y se oyó que estaba en casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 2, 2, 'Y luego se juntaron á él muchos, que ya no cabían ni aun á la puerta; y les predicaba la palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 2, 3, 'Entonces vinieron á él unos trayendo un paralítico, que era traído por cuatro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 2, 4, 'Y como no podían llegar á él á causa del gentío, descubrieron el techo de donde estaba, y haciendo abertura, bajaron el lecho en que yacía el paralítico.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 2, 5, 'Y viendo Jesús la fe de ellos, dice al paralítico: Hijo, tus pecados te son perdonados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 2, 6, 'Y estaban allí sentados algunos de los escribas, los cuales pensando en sus corazones,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 2, 7, 'Decían: ¿Por qué habla éste así? Blasfemias dice. ¿Quién puede perdonar pecados, sino solo Dios?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 2, 8, 'Y conociendo luego Jesús en su espíritu que pensaban así dentro de sí mismos, les dijo: ¿Por qué pensáis estas cosas en vuestros corazones?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 2, 9, '¿Qué es más fácil, decir al paralítico: Tus pecados te son perdonados, ó decirle: Levántate, y toma tu lecho y anda?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 2, 10, 'Pues para que sepáis que el Hijo del hombre tiene potestad en la tierra de perdonar los pecados, (dice al paralítico):');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 2, 11, 'A ti te digo: Levántate, y toma tu lecho, y vete á tu casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 2, 12, 'Entonces él se levantó luego, y tomando su lecho, se salió delante de todos, de manera que todos se asombraron, y glorificaron á Dios, diciendo: Nunca tal hemos visto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 2, 13, 'Y volvió á salir á la mar, y toda la gente venía á él, y los enseñaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 2, 14, 'Y pasando, vió á Leví, hijo de Alfeo, sentado al banco de los públicos tributos, y le dice: Sígueme. Y levantándose le siguió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 2, 15, 'Y aconteció que estando Jesús á la mesa en casa de él, muchos publicanos y pecadores estaban también á la mesa juntamente con Jesús y con sus discípulos: porque había muchos, y le habían seguido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 2, 16, 'Y los escribas y los Fariseos, viéndole comer con los publicanos y con los pecadores, dijeron á sus discípulos: ¿Qué es esto, que él come y bebe con los publicanos y con los pecadores?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 2, 17, 'Y oyéndolo Jesús, les dice: Los sanos no tienen necesidad de médico, mas los que tienen mal. No he venido á llamar á los justos, sino á los pecadores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 2, 18, 'Y los discípulos de Juan, y de los Fariseos ayunaban; y vienen, y le dicen: ¿Por qué los discípulos de Juan y los de los Fariseos ayunan, y tus discípulos no ayunan?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 2, 19, 'Y Jesús les dice: ¿Pueden ayunar los que están de bodas, cuando el esposo está con ellos? Entre tanto que tienen consigo al esposo no pueden ayunar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 2, 20, 'Mas vendrán días, cuando el esposo les será quitado, y entonces en aquellos días ayunarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 2, 21, 'Nadie echa remiendo de paño recio en vestido viejo; de otra manera el mismo remiendo nuevo tira del viejo, y la rotura se hace peor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 2, 22, 'Ni nadie echa vino nuevo en odres viejos; de otra manera, el vino nuevo rompe los odres, y se derrama el vino, y los odres se pierden; mas el vino nuevo en odres nuevos se ha de echar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 2, 23, 'Y aconteció que pasando él por los sembrados en sábado, sus discípulos andando comenzaron á arrancar espigas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 2, 24, 'Entonces los Fariseos le dijeron: He aquí, ¿por qué hacen en sábado lo que no es lícito?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 2, 25, 'Y él les dijo: ¿Nunca leísteis qué hizo David cuando tuvo necesidad, y tuvo hambre, él y los que con él estaban:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 2, 26, 'Cómo entró en la casa de Dios, siendo Abiathar sumo pontífice, y comió los panes de la proposición, de los cuales no es lícito comer sino á los sacerdotes, y aun dió á los que con él estaban?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 2, 27, 'También les dijo: El sábado por causa del hombre es hecho; no el hombre por causa del sábado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 2, 28, 'Así que el Hijo del hombre es Señor aun del sábado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 1, 'Y OTRA vez entró en la sinagoga; y había allí un hombre que tenía una mano seca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 2, 'Y le acechaban si en sábado le sanaría, para acusarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 3, 'Entonces dijo al hombre que tenía la mano seca: Levántate en medio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 4, 'Y les dice: ¿Es lícito hacer bien en sábado, ó hacer mal? ¿salvar la vida, ó quitarla? Mas ellos callaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 5, 'Y mirándolos alrededor con enojo, condoleciéndose de la ceguedad de su corazón, dice al hombre: Extiende tu mano. Y la extendió, y su mano fué restituída sana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 6, 'Entonces saliendo los Fariseos, tomaron consejo con los Herodianos contra él, para matarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 7, 'Mas Jesús se apartó á la mar con sus discípulos: y le siguió gran multitud de Galilea, y de Judea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 8, 'Y de Jerusalem, y de Idumea, y de la otra parte del Jordán. Y los de alrededor de Tiro y de Sidón, grande multitud, oyendo cuán grandes cosas hacía, vinieron á él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 9, 'Y dijo á sus discípulos que le estuviese siempre apercibida la barquilla, por causa del gentío, para que no le oprimiesen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 10, 'Porque había sanado á muchos; de manera que caían sobre él cuantos tenían plagas, por tocarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 11, 'Y los espíritus inmundos, al verle, se postraban delante de él, y daban voces, diciendo: Tú eres el Hijo de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 12, 'Mas él les reñía mucho que no le manifestasen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 13, 'Y subió al monte, y llamó á sí á los que él quiso; y vinieron á él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 14, 'Y estableció doce, para que estuviesen con él, y para enviarlos á predicar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 15, 'Y que tuviesen potestad de sanar enfermedades, y de echar fuera demonios:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 16, 'A Simón, al cual puso por nombre Pedro;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 17, 'Y á Jacobo, hijo de Zebedeo, y á Juan hermano de Jacobo; y les apellidó Boanerges, que es, Hijos del trueno;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 18, 'Y á Andrés, y á Felipe, y á Bartolomé, y á Mateo, y á Tomas, y á Jacobo hijo de Alfeo, y á Tadeo, y á Simón el Cananita,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 19, 'Y á Judas Iscariote, el que le entregó. Y vinieron á casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 20, 'Y agolpóse de nuevo la gente, de modo que ellos ni aun podían comer pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 21, 'Y como lo oyeron los suyos, vinieron para prenderle: porque decían: Está fuera de sí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 22, 'Y los escribas que habían venido de Jerusalem, decían que tenía á Beelzebub, y que por el príncipe de los demonios echaba fuera los demonios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 23, 'Y habiéndolos llamado, les decía en parábolas: ¿Cómo puede Satanás echar fuera á Satanás?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 24, 'Y si algún reino contra sí mismo fuere dividido, no puede permanecer el tal reino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 25, 'Y si alguna casa fuere dividida contra sí misma, no puede permanecer la tal casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 26, 'Y si Satanás se levantare contra sí mismo, y fuere dividido, no puede permanecer; antes tiene fin.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 27, 'Nadie puede saquear las alhajas del valiente entrando en su casa, si antes no atare al valiente y entonces saqueará su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 28, 'De cierto os digo que todos los pecados serán perdonados á los hijos de los hombres, y las blasfemias cualesquiera con que blasfemaren;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 29, 'Mas cualquiera que blasfemare contra el Espíritu Santo, no tiene jamás perdón, mas está expuesto á eterno juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 30, 'Porque decían: Tiene espíritu inmundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 31, 'Vienen después sus hermanos y su madre, y estando fuera, enviaron á él llamándole.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 32, 'Y la gente estaba sentada alrededor de él, y le dijeron: He aquí, tu madre y tus hermanos te buscan fuera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 33, 'Y él les respondió, diciendo: ¿Quién es mi madre y mis hermanos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 34, 'Y mirando á los que estaban sentados alrededor de él, dijo: He aquí mi madre y hermanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 3, 35, 'Porque cualquiera que hiciere la voluntad de Dios, éste es mi hermano, y mi hermana, y mi madre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 1, 'Y OTRA vez comenzó á enseñar junto á la mar, y se juntó á él mucha gente; tanto, que entrándose él en un barco, se sentó en la mar: y toda la gente estaba en tierra junto á la mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 2, 'Y les enseñaba por parábolas muchas cosas, y les decía en su doctrina:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 3, 'Oid: He aquí, el sembrador salió á sembrar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 4, 'Y aconteció sembrando, que una parte cayó junto al camino; y vinieron las aves del cielo, y la tragaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 5, 'Y otra parte cayó en pedregales, donde no tenía mucha tierra; y luego salió, porque no tenía la tierra profunda:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 6, 'Mas salido el sol, se quemó; y por cuanto no tenía raíz, se secó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 7, 'Y otra parte cayó en espinas; y subieron las espinas, y la ahogaron, y no dió fruto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 8, 'Y otra parte cayó en buena tierra, y dió fruto, que subió y creció: y llevó uno á treinta, y otro á sesenta, y otro á ciento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 9, 'Entonces les dijo: El que tiene oídos para oir, oiga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 10, 'Y cuando estuvo solo, le preguntaron los que estaban cerca de él con los doce, sobre la parábola.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 11, 'Y les dijo: A vosotros es dado saber el misterio del reino de Dios; mas á los que están fuera, por parábolas todas las cosas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 12, 'Para que viendo, vean y no echen de ver; y oyendo, oigan y no entiendan: porque no se conviertan, y les sean perdonados los pecados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 13, 'Y les dijo: ¿No sabéis esta parábola? ¿Cómo, pues, entenderéis todas las parábolas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 14, 'El que siembra es el que siembra la palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 15, 'Y éstos son los de junto al camino: en los que la palabra es sembrada: mas después que la oyeron, luego viene Satanás, y quita la palabra que fué sembrada en sus corazones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 16, 'Y asimismo éstos son los que son sembrados en pedregales: los que cuando han oído la palabra, luego la toman con gozo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 17, 'Mas no tienen raíz en sí, antes son temporales, que en levantándose la tribulación ó la persecución por causa de la palabra, luego se escandalizan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 18, 'Y éstos son los que son sembrados entre espinas: los que oyen la palabra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 19, 'Mas los cuidados de este siglo, y el engaño de las riquezas, y las codicias que hay en las otras cosas, entrando, ahogan la palabra, y se hace infructuosa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 20, 'Y éstos son los que fueron sembrados en buena tierra: los que oyen la palabra, y la reciben, y hacen fruto, uno á treinta, otro á sesenta, y otro á ciento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 21, 'También les dijo: ¿Tráese la antorcha para ser puesta debajo del almud, ó debajo de la cama? ¿No es para ser puesta en el candelero?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 22, 'Porque no hay nada oculto que no haya de ser manifestado, ni secreto que no haya de descubrirse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 23, 'Si alguno tiene oídos para oir, oiga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 24, 'Les dijo también: Mirad lo que oís: con la medida que medís, os medirán otros, y será añadido á vosotros los que oís.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 25, 'Porque al que tiene, le será dado; y al que no tiene, aun lo que tiene le será quitado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 26, 'Decía más: Así es el reino de Dios, como si un hombre echa simiente en la tierra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 27, 'Y duerme, y se levanta de noche y de día, y la simiente brota y crece como él no sabe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 28, 'Porque de suyo fructifica la tierra, primero hierba, luego espiga, después grano lleno en la espiga;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 29, 'Y cuando el fruto fuere producido, luego se mete la hoz, porque la siega es llegada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 30, 'Y decía: ¿A qué haremos semejante el reino de Dios? ¿ó con qué parábola le compararemos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 31, 'Es como el grano de mostaza, que, cuando se siembra en tierra, es la más pequeña de todas las simientes que hay en la tierra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 32, 'Mas después de sembrado, sube, y se hace la mayor de todas las legumbres, y echa grandes ramas, de tal manera que las aves del cielo puedan morar bajo su sombra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 33, 'Y con muchas tales parábolas les hablaba la palabra, conforme á lo que podían oir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 34, 'Y sin parábola no les hablaba; mas á sus discípulos en particular declaraba todo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 35, 'Y les dijo aquel día cuando fué tarde: Pasemos de la otra parte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 36, 'Y despachando la multitud, le tomaron como estaba, en el barco; y había también con él otros barquitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 37, 'Y se levantó una grande tempestad de viento, y echaba las olas en el barco, de tal manera que ya se henchía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 38, 'Y él estaba en la popa, durmiendo sobre un cabezal, y le despertaron, y le dicen: ¿Maestro, no tienes cuidado que perecemos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 39, 'Y levantándose, increpó al viento, y dijo á la mar: Calla, enmudece. Y cesó el viento, y fué hecha grande bonanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 40, 'Y á ellos dijo: ¿Por qué estáis así amedrentados? ¿Cómo no tenéis fe?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 4, 41, 'Y temieron con gran temor, y decían el uno al otro. ¿Quién es éste, que aun el viento y la mar le obedecen?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 1, 'Y VINIERON de la otra parte de la mar á la provincia de los Gadarenos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 2, 'Y salido él del barco, luego le salió al encuentro, de los sepulcros, un hombre con un espíritu inmundo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 3, 'Que tenía domicilio en los sepulcros, y ni aun con cadenas le podía alguien atar;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 4, 'Porque muchas veces había sido atado con grillos y cadenas, mas las cadenas habían sido hechas pedazos por él, y los grillos desmenuzados; y nadie le podía domar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 5, 'Y siempre, de día y de noche, andaba dando voces en los montes y en los sepulcros, é hiriéndose con las piedras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 6, 'Y como vió á Jesús de lejos, corrió, y le adoró.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 7, 'Y clamando á gran voz, dijo: ¿Qué tienes conmigo, Jesús, Hijo del Dios Altísimo? Te conjuro por Dios que no me atormentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 8, 'Porque le decía: Sal de este hombre, espíritu inmundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 9, 'Y le preguntó: ¿Cómo te llamas? Y respondió diciendo: Legión me llamo; porque somos muchos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 10, 'Y le rogaba mucho que no le enviase fuera de aquella provincia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 11, 'Y estaba allí cerca del monte una grande manada de puercos paciendo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 12, 'Y le rogaron todos los demonios, diciendo: Envíanos á los puercos para que entremos en ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 13, 'Y luego Jesús se lo permitió. Y saliendo aquellos espíritus inmundos, entraron en los puercos, y la manada cayó por un despeñadero en la mar; los cuales eran como dos mil; y en la mar se ahogaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 14, 'Y los que apacentaban los puercos huyeron, y dieron aviso en la ciudad y en los campos. Y salieron para ver qué era aquello que había acontecido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 15, 'Y vienen á Jesús, y ven al que había sido atormentado del demonio, y que había tenido la legión, sentado y vestido, y en su juicio cabal; y tuvieron miedo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 16, 'Y les contaron los que lo habían visto, cómo había acontecido al que había tenido el demonio, y lo de los puercos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 17, 'Y comenzaron á rogarle que se fuese de los términos de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 18, 'Y entrando él en el barco, le rogaba el que había sido fatigado del demonio, para estar con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 19, 'Mas Jesús no le permitió, sino le dijo: Vete á tu casa, á los tuyos, y cuéntales cuán grandes cosas el Señor ha hecho contigo, y cómo ha tenido misericordia de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 20, 'Y se fué, y comenzó á publicar en Decápolis cuan grandes cosas Jesús había hecho con él: y todos se maravillaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 21, 'Y pasando otra vez Jesús en un barco á la otra parte, se juntó á él gran compañía; y estaba junto á la mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 22, 'Y vino uno de los príncipes de la sinagoga, llamado Jairo; y luego que le vió, se postró á sus pies,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 23, 'Y le rogaba mucho, diciendo: Mi hija está á la muerte: ven y pondrás las manos sobre ella para que sea salva, y vivirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 24, 'Y fué con él, y le seguía gran compañía, y le apretaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 25, 'Y una mujer que estaba con flujo de sangre doce años hacía,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 26, 'Y había sufrido mucho de muchos médicos, y había gastado todo lo que tenía, y nada había aprovechado, antes le iba peor,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 27, 'Como oyó hablar de Jesús, llegó por detrás entre la compañía, y tocó su vestido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 28, 'Porque decía: Si tocare tan solamente su vestido, seré salva.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 29, 'Y luego la fuente de su sangre se secó; y sintió en el cuerpo que estaba sana de aquel azote.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 30, 'Y luego Jesús, conociendo en sí mismo la virtud que había salido de él, volviéndose á la compañía, dijo: ¿Quién ha tocado mis vestidos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 31, 'Y le dijeron sus discípulos: Ves que la multitud te aprieta, y dices: ¿Quién me ha tocado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 32, 'Y él miraba alrededor para ver á la que había hecho esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 33, 'Entonces la mujer, temiendo y temblando, sabiendo lo que en sí había sido hecho, vino y se postró delante de él, y le dijo toda la verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 34, 'Y él le dijo: Hija, tu fe te ha hecho salva: ve en paz, y queda sana de tu azote.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 35, 'Hablando aún él, vinieron de casa del príncipe de la sinagoga, diciendo: Tu hija es muerta; ¿para qué fatigas más al Maestro?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 36, 'Mas luego Jesús, oyendo esta razón que se decía, dijo al príncipe de la sinagoga: No temas, cree solamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 37, 'Y no permitió que alguno viniese tras él sino Pedro, y Jacobo, y Juan hermano de Jacobo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 38, 'Y vino á casa del príncipe de la sinagoga, y vió el alboroto, los que lloraban y gemían mucho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 39, 'Y entrando, les dice: ¿Por qué alborotáis y lloráis? La muchacha no es muerta, mas duerme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 40, 'Y hacían burla de él: mas él, echados fuera todos, toma al padre y á la madre de la muchacha, y á los que estaban con él, y entra donde la muchacha estaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 41, 'Y tomando la mano de la muchacha, le dice: Talitha cumi; que es, si lo interpretares: Muchacha, á ti digo, levántate.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 42, 'Y luego la muchacha se levantó, y andaba; porque tenía doce años. Y se espantaron de grande espanto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 5, 43, 'Mas él les mandó mucho que nadie lo supiese, y dijo que le diesen de comer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 1, 'Y SALIO de allí, y vino á su tierra, y le siguieron sus discípulos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 2, 'Y llegado el sábado, comenzó á enseñar en la sinagoga; y muchos oyéndole, estaban atónitos, diciendo: ¿De dónde tiene éste estas cosas? ¿Y qué sabiduría es ésta que le es dada, y tales maravillas que por sus manos son hechas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 3, '¿No es éste el carpintero, hijo de María, hermano de Jacobo, y de José, y de Judas, y de Simón? ¿No están también aquí con nosotros, sus hermanas? Y se escandalizaban en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 4, 'Mas Jesús les decía: No hay profeta deshonrado sino en su tierra, y entre sus parientes, y en su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 5, 'Y no pudo hacer allí alguna maravilla; solamente sanó unos pocos enfermos, poniendo sobre ellos las manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 6, 'Y estaba maravillado de la incredulidad de ellos. Y rodeaba las aldeas de alrededor, enseñando.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 7, 'Y llamó á los doce, y comenzó á enviarlos de dos en dos: y les dió potestad sobre los espíritus inmundos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 8, 'Y les mandó que no llevasen nada para el camino, sino solamente báculo; no alforja, ni pan, ni dinero en la bolsa;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 9, 'Mas que calzasen sandalias, y no vistiesen dos túnicas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 10, 'Y les decía: Donde quiera que entréis en una casa, posad en ella hasta que salgáis de allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 11, 'Y todos aquellos que no os recibieren ni os oyeren, saliendo de allí, sacudid el polvo que está debajo de vuestros pies, en testimonio á ellos. De cierto os digo que más tolerable será el castigo de los de Sodoma y Gomorra el día del juicio, que el de aquella ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 12, 'Y saliendo, predicaban que los hombres se arrepintiesen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 13, 'Y echaban fuera muchos demonios, y ungían con aceite á muchos enfermos, y sanaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 14, 'Y oyó el rey Herodes la fama de Jesús, porque su nombre se había hecho notorio; y dijo: Juan el que bautizaba, ha resucitado de los muertos, y por tanto, virtudes obran en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 15, 'Otros decían: Elías es. Y otros decían: Profeta es, ó alguno de los profetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 16, 'Y oyéndo lo Herodes, dijo: Este es Juan el que yo degollé: él ha resucitado de los muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 17, 'Porque el mismo Herodes había enviado, y prendido á Juan, y le había aprisionado en la cárcel á causa de Herodías, mujer de Felipe su hermano; pues la había tomado por mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 18, 'Porque Juan decía á Herodes: No te es lícito tener la mujer de tu hermano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 19, 'Mas Herodías le acechaba, y deseaba matarle, y no podía:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 20, 'Porque Herodes temía á Juan, sabiendo que era varón justo y santo, y le tenía respeto: y oyéndole, hacía muchas cosas; y le oía de buena gana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 21, 'Y venido un día oportuno, en que Herodes, en la fiesta de su nacimiento, daba una cena á sus príncipes y tribunos, y á los principales de Galilea;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 22, 'Y entrando la hija de Herodías, y danzando, y agradando á Herodes y á los que estaban con él á la mesa, el rey dijo á la muchacha: Pídeme lo que quisieres, que yo te lo daré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 23, 'Y le juró: Todo lo que me pidieres te daré, hasta la mitad de mi reino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 24, 'Y saliendo ella, dijo á su madre: ¿Qué pediré? Y ella dijo: La cabeza de Juan Bautista.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 25, 'Entonces ella entró prestamente al rey, y pidió, diciendo: Quiero que ahora mismo me des en un plato la cabeza de Juan Bautista.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 26, 'Y el rey se entristeció mucho; mas á causa del juramento, y de los que estaban con él á la mesa, no quiso desecharla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 27, 'Y luego el rey, enviando uno de la guardia, mandó que fuese traída su cabeza;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 28, 'El cual fué, y le degolló en la cárcel, y trajó su cabeza en un plato, y la dió á la muchacha, y la muchacha la dió á su madre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 29, 'Y oyéndo lo sus discípulos, vinieron y tomaron su cuerpo, y le pusieron en un sepulcro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 30, 'Y los apóstoles se juntaron con Jesús, y le contaron todo lo que habían hecho, y lo que habían enseñado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 31, 'Y él les dijo: Venid vosotros aparte al lugar desierto, y reposad un poco. Porque eran muchos los que iban y venían, que ni aun tenían lugar de comer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 32, 'Y se fueron en un barco al lugar desierto aparte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 33, 'Y los vieron ir muchos, y le conocieron; y concurrieron allá muchos á pie de las ciudades, y llegaron antes que ellos, y se juntaron á él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 34, 'Y saliendo Jesús vió grande multitud, y tuvo compasión de ellos, porque eran como ovejas que no tenían pastor; y les comenzó á enseñar muchas cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 35, 'Y como ya fuese el día muy entrado, sus discípulos llegaron á él, diciendo: El lugar es desierto, y el día ya muy entrado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 36, 'Envíalos para que vayan á los cortijos y aldeas de alrededor, y compren para sí pan; porque no tienen qué comer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 37, 'Y respondiendo él, les dijo: Dadles de comer vosotros. Y le dijeron: ¿Que vayamos y compremos pan por doscientos denarios, y les demos de comer?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 38, 'Y él les dice: ¿Cuántos panes tenéis? Id, y vedlo. Y sabiéndolo, dijeron: Cinco, y dos peces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 39, 'Y les mandó que hiciesen recostar á todos por partidas sobre la hierba verde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 40, 'Y se recostaron por partidas, de ciento en ciento, y de cincuenta en cincuenta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 41, 'Y tomados los cinco panes y los dos peces, mirando al cielo, bendijo, y partió los panes, y dió á sus discípulos para que los pusiesen delante: y repartió á todos los dos peces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 42, 'Y comieron todos, y se hartaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 43, 'Y alzaron de los pedazos doce cofines llenos, y de los peces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 44, 'Y los que comieron eran cinco mil hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 45, 'Y luego dió priesa á sus discípulos á subir en el barco, é ir delante de él á Bethsaida de la otra parte, entre tanto que él despedía la multitud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 46, 'Y después que los hubo despedido, se fué al monte á orar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 47, 'Y como fué la tarde, el barco estaba en medio de la mar, y él solo en tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 48, 'Y los vió fatigados bogando, porque el viento les era contrario: y cerca de la cuarta vigilia de la noche, vino á ellos andando sobre la mar, y quería precederlos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 49, 'Y viéndole ellos, que andaba sobre la mar, pensaron que era fantasma, y dieron voces;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 50, 'Porque todos le veían, y se turbaron. Mas luego habló con ellos, y les dijo: Alentaos; yo soy, no temáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 51, 'Y subió á ellos en el barco, y calmó el viento: y ellos en gran manera estaban fuera de sí, y se maravillaban:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 52, 'Porque aun no habían considerado lo de los panes, por cuanto estaban ofuscados sus corazones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 53, 'Y cuando estuvieron de la otra parte, vinieron á tierra de Genezaret, y tomaron puerto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 54, 'Y saliendo ellos del barco, luego le conocieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 55, 'Y recorriendo toda la tierra de alrededor, comenzaron á traer de todas partes enfermos en lechos, á donde oían que estaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 6, 56, 'Y donde quiera que entraba, en aldeas, ó ciudades, ó heredades, ponían en las calles á los que estaban enfermos, y le rogaban que tocasen siquiera el borde de su vestido; y todos los que le tocaban quedaban sanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 1, 'Y SE juntaron á él los Fariseos, y algunos de los escribas, que habían venido de Jerusalem;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 2, 'Los cuales, viendo á algunos de sus discípulos comer pan con manos comunes, es á saber, no lavadas, los condenaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 3, '(Porque los Fariseos y todos los Judíos, teniendo la tradición de los ancianos, si muchas veces no se lavan las manos, no comen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 4, 'Y volviendo de la plaza, si no se lavaren, no comen. Y otras muchas cosas hay, que tomaron para guardar, como las lavaduras de los vasos de beber, y de los jarros, y de los vasos de metal, y de los lechos.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 5, 'Y le preguntaron los Fariseos y los escribas: ¿Por qué tus discípulos no andan conforme á la tradición de los ancianos, sino que comen pan con manos comunes?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 6, 'Y respondiendo él, les dijo: Hipócritas, bien profetizó de vosotros Isaías, como está escrito: Este pueblo con los labios me honra, Mas su corazón lejos está de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 7, 'Y en vano me honra, Enseñando como doctrinas mandamientos de hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 8, 'Porque dejando el mandamiento de Dios, tenéis la tradición de los hombres; las lavaduras de los jarros y de los vasos de beber: y hacéis otras muchas cosas semejantes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 9, 'Les decía también: Bien invalidáis el mandamiento de Dios para guardar vuestra tradición.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 10, 'Porque Moisés dijo: Honra á tu padre y á tu madre, y: El que maldijera al padre ó á la madre, morirá de muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 11, 'Y vosotros decís: Basta si dijere un hombre al padre ó á la madre: Es Corbán (quiere decir, don mío á Dios) todo aquello con que pudiera valerte;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 12, 'Y no le dejáis hacer más por su padre ó por su madre,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 13, 'Invalidando la palabra de Dios con vuestra tradición que disteis: y muchas cosas hacéis semejantes á éstas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 14, 'Y llamando á toda la multitud, les dijo: Oidme todos, y entended:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 15, 'Nada hay fuera del hombre que entre en él, que le pueda contaminar: mas lo que sale de él, aquello es lo que contamina al hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 16, 'Si alguno tiene oídos para oir, oiga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 17, 'Y apartado de la multitud, habiendo entrado en casa, le preguntaron sus discípulos sobra la parábola.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 18, 'Y díjoles: ¿También vosotros estáis así sin entendimiento? ¿No entendéis que todo lo de fuera que entra en el hombre, no le puede contaminar;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 19, 'Porque no entra en su corazón, sino en el vientre, y sale á la secreta? Esto decía, haciendo limpias todas las viandas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 20, 'Mas decía, que lo que del hombre sale, aquello contamina al hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 21, 'Porque de dentro, del corazón de los hombres, salen los malos pensamientos, los adulterios, las fornicaciones, los homicidios,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 22, 'Los hurtos, las avaricias, las maldades, el engaño, las desvergüenzas, el ojo maligno, las injurias, la soberbia, la insensatez.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 23, 'Todas estas maldades de dentro salen, y contaminan al hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 24, 'Y levantándose de allí, se fué á los términos de Tiro y de Sidón; y entrando en casa, quiso que nadie lo supiese; mas no pudo esconderse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 25, 'Porque una mujer, cuya hija tenía un espíritu inmundo, luego que oyó de él, vino y se echó á sus pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 26, 'Y la mujer era Griega, Sirofenisa de nación; y le rogaba que echase fuera de su hija al demonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 27, 'Más Jesús le dijo: Deja primero hartarse los hijos, porque no es bien tomar el pan de los hijos y echarlo á los perrillos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 28, 'Y respondió ella, y le dijo: Sí, Señor; pero aun los perrillos debajo de la mesa, comen de las migajas de los hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 29, 'Entonces le dice: Por esta palabra, ve; el demonio ha salido de tu hija.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 30, 'Y como fué á su casa, halló que el demonio había salido, y á la hija echada sobre la cama.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 31, 'Y volviendo á salir de los términos de Tiro, vino por Sidón á la mar de Galilea, por mitad de los términos de Decápolis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 32, 'Y le traen un sordo y tartamudo, y le ruegan que le ponga la mano encima.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 33, 'Y tomándole aparte de la gente, metió sus dedos en las orejas de él, y escupiendo, tocó su lengua;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 34, 'Y mirando al cielo, gimió, y le dijo: Ephphatha: que es decir: Sé abierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 35, 'Y luego fueron abiertos sus oídos, y fué desatada la ligadura de su lengua, y hablaba bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 36, 'Y les mandó que no lo dijesen á nadie; pero cuanto más les mandaba, tanto más y más lo divulgaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 7, 37, 'Y en gran manera se maravillaban, diciendo: Bien lo ha hecho todo: hace á los sordos oir, y á los mudos hablar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 1, 'EN aquellos días, como hubo gran gentío, y no tenían qué comer, Jesús llamó á sus discípulos, y les dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 2, 'Tengo compasión de la multitud, porque ya hace tres días que están conmigo, y no tienen qué comer:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 3, 'Y si los enviare en ayunas á sus casas, desmayarán en el camino; porque algunos de ellos han venido de lejos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 4, 'Y sus discípulos le respondieron: ¿De dónde podrá alguien hartar á estos de pan aquí en el desierto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 5, 'Y les pregunto: ¿Cuántos panes tenéis? Y ellos dijeron: Siete.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 6, 'Entonces mandó á la multitud que se recostase en tierra; y tomando los siete panes, habiendo dado gracias, partió, y dió á sus discípulos que los pusiesen delante: y los pusieron delante á la multitud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 7, 'Tenían también unos pocos pececillos: y los bendijo, y mandó que también los pusiesen delante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 8, 'Y comieron, y se hartaron: y levantaron de los pedazos que habían sobrado, siete espuertas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 9, 'Y eran los que comieron, como cuatro mil: y los despidió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 10, 'Y luego entrando en el barco con sus discípulos, vino á las partes de Dalmanutha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 11, 'Y vinieron los Fariseos, y comenzaron á altercar con él, pidiéndole señal del cielo, tentándole.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 12, 'Y gimiendo en su espíritu, dice: ¿Por qué pide señal esta generación? De cierto os digo que no se dará señal á esta generación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 13, 'Y dejándolos, volvió á entrar en el barco, y se fué de la otra parte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 14, 'Y se habían olvidado de tomar pan, y no tenían sino un pan consigo en el barco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 15, 'Y les mandó, diciendo: Mirad, guardaos de la levadura de los Fariseos, y de la levadura de Herodes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 16, 'Y altercaban los unos con los otros diciendo: Pan no tenemos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 17, 'Y como Jesús lo entendió, les dice: ¿Qué altercáis, porque no tenéis pan? ¿no consideráis ni entendéis? ¿aun tenéis endurecido vuestro corazón?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 18, '¿Teniendo ojos no veis, y teniendo oídos no oís? ¿y no os acordáis?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 19, 'Cuando partí los cinco panes entre cinco mil, ¿cuántas espuertas llenas de los pedazos alzasteis? Y ellos dijeron: Doce.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 20, 'Y cuando los siete panes entre cuatro mil, ¿cuántas espuertas llenas de los pedazos alzasteis? Y ellos dijeron: Siete.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 21, 'Y les dijo: ¿Cómo aún no entendéis?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 22, 'Y vino á Bethsaida; y le traen un ciego, y le ruegan que le tocase.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 23, 'Entonces, tomando la mano del ciego, le sacó fuera de la aldea; y escupiendo en sus ojos, y poniéndole las manos encima, le preguntó si veía algo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 24, 'Y él mirando, dijo: Veo los hombres, pues veo que andan como árboles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 25, 'Luego le puso otra vez las manos sobre sus ojos, y le hizo que mirase; y fué restablecido, y vió de lejos y claramente á todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 26, 'Y envióle á su casa, diciendo: No entres en la aldea, ni lo digas á nadie en la aldea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 27, 'Y salió Jesús y sus discípulos por las aldeas de Cesarea de Filipo. Y en el camino preguntó á sus discípulos, diciéndoles: ¿Quién dicen los hombres que soy yo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 28, 'Y ellos respondieron: Juan Bautista; y otros, Elías; y otros, Alguno de los profetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 29, 'Entonces él les dice: Y vosotros, ¿quién decís que soy yo? Y respondiendo Pedro, le dice: Tú eres el Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 30, 'Y les apercibió que no hablasen de él á ninguno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 31, 'Y comenzó á enseñarles, que convenía que el Hijo del hombre padeciese mucho, y ser reprobado de los ancianos, y de los príncipes de los sacerdotes, y de los escribas, y ser muerto, y resucitar después de tres días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 32, 'Y claramente decía esta palabra. Entonces Pedro le tomó, y le comenzó á reprender.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 33, 'Y él, volviéndose y mirando á sus discípulos, riñó á Pedro, diciendo: Apártate de mí, Satanás; porque no sabes las cosas que son de Dios, sino las que son de los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 34, 'Y llamando á la gente con sus discípulos, les dijo: Cualquiera que quisiere venir en pos de mí, niéguese á sí mismo, y tome su cruz, y sígame.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 35, 'Porque el que quisiere salvar su vida, la perderá; y el que perdiere su vida por causa de mí y del evangelio, la salvará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 36, 'Porque ¿qué aprovechará al hombre, si granjeare todo el mundo, y pierde su alma?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 37, '¿O qué recompensa dará el hombre por su alma?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 8, 38, 'Porque el que se avergonzare de mí y de mis palabras en esta generación adulterina y pecadora, el Hijo del hombre se avergonzará también de él, cuando vendrá en la gloria de su Padre con los santos ángeles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 1, 'TAMBIÉN les dijo: De cierto os digo que hay algunos de los que están aquí, que no gustarán la muerte hasta que hayan visto el reino de Dios que viene con potencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 2, 'Y seis días después tomó Jesús á Pedro, y á Jacobo, y á Juan, y los sacó aparte solos á un monte alto; y fué transfigurado delante de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 3, 'Y sus vestidos se volvieron resplandecientes, muy blancos, como la nieve; tanto que ningún lavador en la tierra los puede hacer tan blancos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 4, 'Y les apareció Elías con Moisés, que hablaban con Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 5, 'Entonces respondiendo Pedro, dice á Jesús: Maestro, bien será que nos quedemos aquí, y hagamos tres pabellones: para ti uno, y para Moisés otro, y para Elías otro;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 6, 'Porque no sabía lo que hablaba; que estaban espantados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 7, 'Y vino una nube que les hizo sombra, y una voz de la nube, que decía: Este es mi Hijo amado: á él oíd.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 8, 'Y luego, como miraron, no vieron más á nadie consigo, sino á Jesús solo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 9, 'Y descendiendo ellos del monte, les mandó que á nadie dijesen lo que habían visto, sino cuando el Hijo del hombre hubiese resucitado de los muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 10, 'Y retuvieron la palabra en sí, altercando qué sería aquéllo: Resucitar de los muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 11, 'Y le preguntaron, diciendo: ¿Qué es lo que los escribas dicen, que es necesario que Elías venga antes?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 12, 'Y respondiendo él, les dijo: Elías á la verdad, viniendo antes, restituirá todas las cosas: y como está escrito del Hijo del hombre, que padezca mucho y sea tenido en nada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 13, 'Empero os digo que Elías ya vino, y le hicieron todo lo que quisieron, como está escrito de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 14, 'Y como vino á los discípulos, vió grande compañía alrededor de ellos, y escribas que disputaban con ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 15, 'Y luego toda la gente, viéndole, se espantó, y corriendo á él, le saludaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 16, 'Y preguntóles: ¿Qué disputáis con ellos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 17, 'Y respondiendo uno de la compañía, dijo: Maestro, traje á ti mi hijo, que tiene un espíritu mudo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 18, 'El cual, donde quiera que le toma, le despedaza; y echa espumarajos, y cruje los dientes, y se va secando: y dije á tus discípulos que le echasen fuera, y no pudieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 19, 'Y respondiendo él, les dijo: ¡Oh generación infiel! ¿hasta cuándo estaré con vosotros? ¿hasta cuándo os tengo de sufrir? Traédmele.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 20, 'Y se le trajeron: y como le vió, luego el espíritu le desgarraba; y cayendo en tierra, se revolcaba, echando espumarajos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 21, 'Y Jesús preguntó á su padre: ¿Cuánto tiempo há que le aconteció esto? Y él dijo: Desde niño:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 22, 'Y muchas veces le echa en el fuego y en aguas, para matarle; mas, si puedes algo, ayúdanos, teniendo misericordia de nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 23, 'Y Jesús le dijo: Si puedes creer, al que cree todo es posible.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 24, 'Y luego el padre del muchacho dijo clamando: Creo, ayuda mi incredulidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 25, 'Y como Jesús vió que la multitud se agolpaba, reprendió al espíritu inmundo, diciéndole: Espíritu mudo y sordo, yo te mando, sal de él, y no entres más en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 26, 'Entonces el espíritu clamando y desgarrándole mucho, salió; y él quedó como muerto, de modo que muchos decían: Está muerto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 27, 'Mas Jesús tomándole de la mano, enderezóle; y se levantó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 28, 'Y como él entró en casa, sus discípulos le preguntaron aparte: ¿Por qué nosotros no pudimos echarle fuera?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 29, 'Y les dijo: Este género con nada puede salir, sino con oración y ayuno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 30, 'Y habiendo salido de allí, caminaron por Galilea; y no quería que nadie lo supiese.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 31, 'Porque enseñaba á sus discípulos, y les decía: El Hijo del hombre será entregado en manos de hombres, y le matarán; mas muerto él, resucitará al tercer día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 32, 'Pero ellos no entendían esta palabra, y tenían miedo de preguntarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 33, 'Y llegó á Capernaum; y así que estuvo en casa, les preguntó: ¿Qué disputabais entre vosotros en el camino?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 34, 'Mas ellos callaron; porque los unos con los otros habían disputado en el camino quién había de ser el mayor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 35, 'Entonces sentándose, llamó á los doce, y les dice: Si alguno quiere ser el primero, será el postrero de todos, y el servidor de todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 36, 'Y tomando un niño, púsolo en medio de ellos; y tomándole en sus brazos, les dice:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 37, 'El que recibiere en mi nombre uno de los tales niños, á mí recibe; y el que á mí recibe, no recibe á mí, mas al que me envió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 38, 'Y respondióle Juan, diciendo: Maestro, hemos visto á uno que en tu nombre echaba fuera los demonios, el cual no nos sigue; y se lo prohibimos, porque no nos sigue.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 39, 'Y Jesús dijo: No se lo prohibáis; porque ninguno hay que haga milagro en mi nombre que luego pueda decir mal de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 40, 'Porque el que no es contra nosotros, por nosotros es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 41, 'Y cualquiera que os diere un vaso de agua en mi nombre, porque sois de Cristo, de cierto os digo que no perderá su recompensa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 42, 'Y cualquiera que escandalizare á uno de estos pequeñitos que creen en mí, mejor le fuera si se le atase una piedra de molino al cuello, y fuera echado en la mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 43, 'Y si tu mano te escandalizare, córtala: mejor te es entrar á la vida manco, que teniendo dos manos ir á la Gehenna, al fuego que no puede ser apagado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 44, 'Donde su gusano no muere, y el fuego nunca se apaga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 45, 'Y si tu pie te fuere ocasión de caer, córtalo: mejor te es entrar á la vida cojo, que teniendo dos pies ser echado en la Gehenna, al fuego que no puede ser apagado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 46, 'Donde el gusano de ellos no muere, y el fuego nunca se apaga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 47, 'Y si tu ojo te fuere ocasión de caer, sácalo: mejor te es entrar al reino de Dios con un ojo, que teniendo dos ojos ser echado á la Gehenna;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 48, 'Donde el gusano de ellos no muere, y el fuego nunca se apaga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 49, 'Porque todos serán salados con fuego, y todo sacrificio será salado con sal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 9, 50, 'Buena es la sal; mas si la sal fuere desabrida, ¿con qué la adobaréis? Tened en vosotros mismos sal; y tened paz los unos con los otros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 1, 'Y PARTIENDOSE de allí, vino á los términos de Judea y tras el Jordán: y volvió el pueblo á juntarse á él; y de nuevo les enseñaba como solía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 2, 'Y llegándose los Fariseos, le preguntaron, para tentarle, si era lícito al marido repudiar á su mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 3, 'Mas él respondiendo, les dijo: ¿Qué os mandó Moisés?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 4, 'Y ellos dijeron: Moisés permitió escribir carta de divorcio, y repudiar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 5, 'Y respondiendo Jesús, les dijo: Por la dureza de vuestro corazón os escribió este mandamiento;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 6, 'Pero al principio de la creación, varón y hembra los hizo Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 7, 'Por esto dejará el hombre á su padre y á su madre, y se juntará á su mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 8, 'Y los que eran dos, serán hechos una carne: así que no son más dos, sino una carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 9, 'Pues lo que Dios juntó, no lo aparte el hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 10, 'Y en casa volvieron los discípulos á preguntarle de lo mismo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 11, 'Y les dice: Cualquiera que repudiare á su mujer, y se casare con otra, comete adulterio contra ella:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 12, 'Y si la mujer repudiare á su marido y se casare con otro, comete adulterio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 13, 'Y le presentaban niños para que los tocase; y los discípulos reñían á los que los presentaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 14, 'Y viéndolo Jesús, se enojó, y les dijo: Dejad los niños venir, y no se lo estorbéis; porque de los tales es el reino de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 15, 'De cierto os digo, que el que no recibiere el reino de Dios como un niño, no entrará en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 16, 'Y tomándolos en los brazos, poniendo las manos sobre ellos, los bendecía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 17, 'Y saliendo él para ir su camino, vino uno corriendo, é hincando la rodilla delante de él, le preguntó: Maestro bueno, ¿qué haré para poseer la vida eterna?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 18, 'Y Jesús le dijo: ¿Por qué me dices bueno? Ninguno hay bueno, sino sólo uno, Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 19, 'Los mandamientos sabes: No adulteres: No mates: No hurtes: No digas falso testimonio: No defraudes: Honra á tu padre y á tu madre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 20, 'El entonces respondiendo, le dijo: Maestro, todo esto he guardado desde mi mocedad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 21, 'Entonces Jesús mirándole, amóle, y díjole: Una cosa te falta: ve, vende todo lo que tienes, y da á los pobres, y tendrás tesoro en el cielo; y ven, sígueme, tomando tu cruz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 22, 'Mas él, entristecido por esta palabra, se fué triste, porque tenía muchas posesiones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 23, 'Entonces Jesús, mirando alrededor, dice á sus discípulos: ¡Cuán dificilmente entrarán en el reino de Dios los que tienen riquezas!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 24, 'Y los discípulos se espantaron de sus palabras; mas Jesús respondiendo, les volvió á decir: ¡Hijos, cuán dificil es entrar en el reino de Dios, los que confían en las riquezas!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 25, 'Más fácil es pasar un camello por el ojo de una aguja, que el rico entrar en el reino de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 26, 'Y ellos se espantaban más, diciendo dentro de sí: ¿Y quién podrá salvarse?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 27, 'Entonces Jesús mirándolos, dice: Para los hombres es imposible; mas para Dios, no; porque todas las cosas son posibles para Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 28, 'Entonces Pedro comenzó á decirle: He aquí, nosotros hemos dejado todas las cosas, y te hemos seguido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 29, 'Y respondiendo Jesús, dijo: De cierto os digo, que no hay ninguno que haya dejado casa, ó hermanos, ó hermanas, ó padre, ó madre, ó mujer, ó hijos, ó heredades, por causa de mí y del evangelio,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 30, 'Que no reciba cien tantos ahora en este tiempo, casas, y hermanos, y hermanas, y madres, é hijos, y heredades, con persecuciones; y en el siglo venidero la vida eterna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 31, 'Empero muchos primeros serán postreros, y postreros primeros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 32, 'Y estaban en el camino subiendo á Jerusalem; y Jesús iba delante de ellos, y se espantaban, y le seguían con miedo: entonces volviendo á tomar á los doce aparte, les comenzó á decir las cosas que le habían de acontecer:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 33, 'He aquí subimos á Jerusalem, y el Hijo del hombre será entregado á los principes de los sacerdotes, y á los escribas, y le condenarán á muerte, y le entregarán á los Gentiles:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 34, 'Y le escarnecerán, y le azotarán, y escupirán en él, y le matarán; mas al tercer día resucitará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 35, 'Entonces Jacobo y Juan, hijos de Zebedeo, se llegaron á él, diciendo: Maestro, querríamos que nos hagas lo que pidiéremos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 36, 'Y él les dijo: ¿Qué queréis que os haga?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 37, 'Y ellos le dijeron: Danos que en tu gloria nos sentemos el uno á tu diestra, y el otro á tu siniestra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 38, 'Entonces Jesús les dijo: No sabéis lo que pedís. ¿Podéis beber del vaso que yo bebo, ó ser bautizados del bautismo de que yo soy bautizado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 39, 'Y ellos dijeron: Podemos. Y Jesús les dijo: A la verdad, del vaso que yo bebo, beberéis; y del bautismo de que soy bautizado, seréis bautizados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 40, 'Mas que os sentéis á mi diestra y á mi siniestra, no es mío darlo, sino á quienes está aparejado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 41, 'Y como lo oyeron los diez, comenzaron á enojarse de Jacobo y de Juan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 42, 'Mas Jesús, llamándolos, les dice: Sabéis que los que se ven ser príncipes entre las gentes, se enseñorean de ellas, y los que entre ellas son grandes, tienen sobre ellas potestad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 43, 'Mas no será así entre vosotros: antes cualquiera que quisiere hacerse grande entre vosotros, será vuestro servidor;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 44, 'Y cualquiera de vosotros que quisiere hacerse el primero, será siervo de todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 45, 'Porque el Hijo del hombre tampoco vino para ser servido, mas para servir, y dar su vida en rescate por muchos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 46, 'Entonces vienen á Jericó: y saliendo él de Jericó y sus discípulos y una gran compañía, Bartimeo el ciego, hijo de Timeo, estaba sentado junto al camino mendigando.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 47, 'Y oyendo que era Jesús el Nazareno, comenzó á dar voces y decir: Jesús, Hijo de David, ten misericordia de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 48, 'Y muchos le reñían, que callase: mas él daba mayores voces: Hijo de David, ten misericordia de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 49, 'Entonces Jesús parándose, mandó llamarle: y llaman al ciego, diciéndole: Ten confianza: levántate, te llama.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 50, 'El entonces, echando su capa, se levantó, y vino á Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 51, 'Y respondiendo Jesús, le dice: ¿Qué quieres que te haga? Y el ciego le dice: Maestro, que cobre la vista.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 10, 52, 'Y Jesús le dijo: Ve, tu fe te ha salvado. Y luego cobró la vista, y seguía á Jesús en el camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 1, 'Y COMO fueron cerca de Jerusalem, de Bethphagé, y de Bethania, al monte de las Olivas, envía dos de sus discípulos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 2, 'Y les dice: Id al lugar que está delante de vosotros, y luego entrados en él, hallaréis un pollino atado, sobre el cual ningún hombre ha subido; desatadlo y traedlo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 3, 'Y si alguien os dijere: ¿Por qué hacéis eso? decid que el Señor lo ha menester: y luego lo enviará acá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 4, 'Y fueron, y hallaron el pollino atado á la puerta fuera, entre dos caminos; y le desataron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 5, 'Y unos de los que estaban allí, les dijeron: ¿Qué hacéis desatando el pollino?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 6, 'Ellos entonces les dijeron como Jesús había mandado: y los dejaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 7, 'Y trajeron el pollino á Jesús, y echaron sobre él sus vestidos, y se sentó sobre él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 8, 'Y muchos tendían sus vestidos por el camino, y otros cortaban hojas de los árboles, y las tendían por el camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 9, 'Y los que iban delante, y los que iban detrás, daban voces diciendo: ¡Hosanna! Bendito el que viene en el nombre del Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 10, 'Bendito el reino de nuestro padre David que viene: ¡Hosanna en las alturas!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 11, 'Y entró Jesús en Jerusalem, y en el templo: y habiendo mirado alrededor todas las cosas, y siendo ya tarde, salióse á Bethania con los doce.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 12, 'Y el día siguiente, como salieron de Bethania, tuvo hambre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 13, 'Y viendo de lejos una higuera que tenía hojas, se acercó, si quizá hallaría en ella algo: y como vino á ella, nada halló sino hojas; porque no era tiempo de higos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 14, 'Entonces Jesús respondiendo, dijo á la higuera: Nunca más coma nadie fruto de ti para siempre. Y lo oyeron sus discípulos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 15, 'Vienen, pues, á Jerusalem; y entrando Jesús en el templo, comenzó á echar fuera á los que vendían y compraban en el templo; y trastornó las mesas de los cambistas, y las sillas de los que vendían palomas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 16, 'Y no consentía que alguien llevase vaso por el templo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 17, 'Y les enseñaba diciendo: ¿No está escrito que mi casa, casa de oración será llamada por todas las gentes? Mas vosotros la habéis hecho cueva de ladrones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 18, 'Y lo oyeron los escribas y los príncipes de los sacerdotes, y procuraban cómo le matarían; porque le tenían miedo, por cuanto todo el pueblo estaba maravillado de su doctrina.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 19, 'Mas como fué tarde, Jesús salió de la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 20, 'Y pasando por la mañana, vieron que la higuera se había secado desde las raíces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 21, 'Entonces Pedro acordándose, le dice: Maestro, he aquí la higuera que maldijiste, se ha secado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 22, 'Y respondiendo Jesús, les dice: Tened fe en Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 23, 'Porque de cierto os digo que cualquiera que dijere á este monte: Quítate, y échate en la mar, y no dudare en su corazón, mas creyere que será hecho lo que dice, lo que dijere le será hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 24, 'Por tanto, os digo que todo lo que orando pidiereis, creed que lo recibiréis, y os vendrá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 25, 'Y cuando estuviereis orando, perdonad, si tenéis algo contra alguno, para que vuestro Padre que está en los cielos os perdone también á vosotros vuestras ofensas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 26, 'Porque si vosotros no perdonareis, tampoco vuestro Padre que está en los cielos os perdonará vuestras ofensas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 27, 'Y volvieron á Jerusalem; y andando él por el templo, vienen á él los príncipes de los sacerdotes, y los escribas, y los ancianos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 28, 'Y le dicen: ¿Con qué facultad haces estas cosas? ¿y quién te ha dado esta facultad para hacer estas cosas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 29, 'Y Jesús respondiendo entonces, les dice: Os preguntaré también yo una palabra; y respondedme, y os diré con qué facultad hago estas cosas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 30, 'El bautismo de Juan, ¿era del cielo, ó de los hombres? Respondedme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 31, 'Entonces ellos pensaron dentro de sí, diciendo: Si dijéremos, del cielo, dirá: ¿Por qué, pues, no le creísteis?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 32, 'Y si dijéremos, de los hombres, tememos al pueblo: porque todos juzgaban de Juan, que verdaderamente era profeta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 11, 33, 'Y respondiendo, dicen á Jesús: No sabemos. Entonces respondiendo Jesús, les dice: Tampoco yo os diré con qué facultad hago estas cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 1, 'Y COMENZO á hablarles por parábolas: Plantó un hombre una viña, y la cercó con seto, y cavó un lagar, y edificó una torre, y la arrendó á labradores, y se partió lejos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 2, 'Y envió un siervo á los labradores, al tiempo, para que tomase de los labradores del fruto de la viña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 3, 'Mas ellos, tomándole, le hirieron, y le enviaron vacío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 4, 'Y volvió á enviarles otro siervo; mas apedreándole, le hirieron en la cabeza, y volvieron á enviarle afrentado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 5, 'Y volvió á enviar otro, y á aquél mataron; y á otros muchos, hiriendo á unos y matando á otros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 6, 'Teniendo pues aún un hijo suyo amado, enviólo también á ellos el postrero, diciendo: Tendrán en reverencia á mi hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 7, 'Mas aquellos labradores dijeron entre sí: Este es el heredero; venid, matémosle, y la heredad será nuestra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 8, 'Y prendiéndole, le mataron, y echaron fuera de la viña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 9, '¿Qué, pues, hará el señor de la viña? Vendrá, y destruirá á estos labradores, y dará su viña á otros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 10, '¿Ni aun esta Escritura habéis leído: La piedra que desecharon los que edificaban, Esta es puesta por cabeza de esquina;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 11, 'Por el Señor es hecho esto, Y es cosa maravillosa en nuestros ojos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 12, 'Y procuraban prenderle, porque entendían que decía á ellos aquella parábola; mas temían á la multitud; y dejándole, se fueron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 13, 'Y envían á él algunos de los Fariseos y de los Herodianos, para que le sorprendiesen en alguna palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 14, 'Y viniendo ellos, le dicen: Maestro, sabemos que eres hombre de verdad, y que no te cuidas de nadie; porque no miras á la apariencia de hombres, antes con verdad enseñas el camino de Dios: ¿Es lícito dar tributo á César, ó no? ¿Daremos, ó no daremos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 15, 'Entonces él, como entendía la hipocresía de ellos, les dijo: ¿Por qué me tentáis? Traedme la moneda para que la vea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 16, 'Y ellos se la trajeron y les dice: ¿Cúya es esta imagen y esta inscripción? Y ellos le dijeron: De César.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 17, 'Y respondiendo Jesús, les dijo: Dad lo que es de César á César; y lo que es de Dios, á Dios. Y se maravillaron de ello.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 18, 'Entonces vienen á el los Saduceos, que dicen que no hay resurrección, y le preguntaron, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 19, 'Maestro, Moisés nos escribió, que si el hermano de alguno muriese, y dejase mujer, y no dejase hijos, que su hermano tome su mujer, y levante linaje á su hermano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 20, 'Fueron siete hermanos: y el primero tomó mujer, y muriendo, no dejó simiente;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 21, 'Y la tomó el segundo, y murió, y ni aquél tampoco dejó simiente; y el tercero, de la misma manera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 22, 'Y la tomaron los siete, y tampoco dejaron simiente: á la postre murió también la mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 23, 'En la resurrección, pues, cuando resucitaren, ¿de cuál de ellos será mujer? porque los siete la tuvieron por mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 24, 'Entonces respondiendo Jesús, les dice: ¿No erráis por eso, porque no sabéis las Escrituras, ni la potencia de Dios?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 25, 'Porque cuando resucitarán de los muertos, ni se casarán, ni serán dados en casamiento, mas son como los ángeles que están en los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 26, 'Y de que los muertos hayan de resucitar, ¿no habéis leído en el libro de Moisés cómo le habló Dios en la zarza, diciendo: Yo soy el Dios de Abraham, y el Dios de Isaac, y el Dios de Jacob?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 27, 'No es Dios de muertos, mas Dios de vivos; así que vosotros mucho erráis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 28, 'Y llegándose uno de los escribas, que los había oído disputar, y sabía que les había respondido bien, le preguntó: ¿Cuál es el primer mandamiento de todos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 29, 'Y Jesús le respondió: El primer mandamiento de todos es: Oye, Israel, el Señor nuestro Dios, el Señor uno es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 30, 'Amarás pues al Señor tu Dios de todo tu corazón, y de toda tu alma, y de toda tu mente, y de todas tus fuerzas; este es el principal mandamiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 31, 'Y el segundo es semejante á él: Amarás á tu prójimo como á ti mismo. No hay otro mandamiento mayor que éstos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 32, 'Entonces el escriba le dijo: Bien, Maestro, verdad has dicho, que uno es Dios, y no hay otro fuera de él;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 33, 'Y que amarle de todo corazón, y de todo entendimiento, y de toda el alma, y de todas las fuerzas, y amar al prójimo como á sí mismo, más es que todos los holocaustos y sacrificios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 34, 'Jesús entonces, viendo que había respondido sabiamente, le dice: No estás lejos del reino de Dios. Y ya ninguno osaba preguntarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 35, 'Y respondiendo Jesús decía, enseñando en el templo: ¿Cómo dicen los escribas que el Cristo es hijo de David?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 36, 'Porque el mismo David dijo por el Espíritu Santo: Dijo el Señor á mi Señor: Siéntate á mi diestra, Hasta que ponga tus enemigos por estrado de tus pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 37, 'Luego llamándole el mismo David Señor, ¿de dónde, pues, es su hijo? Y los que eran del común del pueblo le oían de buena gana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 38, 'Y les decía en su doctrina: Guardaos de los escribas, que quieren andar con ropas largas, y aman las salutaciones en las plazas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 39, 'Y las primeras sillas en las sinagogas, y los primeros asientos en las cenas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 40, 'Que devoran las casas de las viudas, y por pretexto hacen largas oraciones. Estos recibirán mayor juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 41, 'Y estando sentado Jesús delante del arca de la ofrenda, miraba cómo el pueblo echaba dinero en el arca: y muchos ricos echaban mucho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 42, 'Y como vino una viuda pobre, echó dos blancas, que son un maravedí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 43, 'Entonces llamando á sus discípulos, les dice: De cierto os digo que esta viuda pobre echó más que todos los que han echado en el arca:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 12, 44, 'Porque todos han echado de lo que les sobra; mas ésta, de su pobreza echó todo lo que tenía, todo su alimento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 1, 'Y SALIENDO del templo, le dice uno de sus discípulos: Maestro, mira qué piedras, y qué edificios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 2, 'Y Jesús respondiendo, le dijo: ¿Ves estos grandes edificios? no quedará piedra sobre piedra que no sea derribada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 3, 'Y sentándose en el monte de las Olivas delante del templo, le preguntaron aparte Pedro y Jacobo y Juan y Andrés:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 4, 'Dinos, ¿cuándo serán estas cosas? ¿y qué señal habrá cuando todas estas cosas han de cumplirse?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 5, 'Y Jesús respondiéndoles, comenzó á decir: Mirad, que nadie os engañe;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 6, 'Porque vendrán muchos en mi nombre, diciendo: Yo soy el Cristo; y engañaran á muchos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 7, 'Mas cuando oyereis de guerras y de rumores de guerras no os turbéis, porque conviene hacerse así; mas aun no será el fin.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 8, 'Porque se levantará nación contra nación, y reino contra reino; y habrá terremotos en muchos lugares, y habrá hambres y alborotos; principios de dolores serán estos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 9, 'Mas vosotros mirad por vosotros: porque os entregarán en los concilios, y en sinagogas seréis azotados: y delante de presidentes y de reyes seréis llamados por causa de mí, en testimonio á ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 10, 'Y á todas las gentes conviene que el evangelio sea predicado antes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 11, 'Y cuando os trajeren para entregaros, no premeditéis qué habéis de decir, ni lo penséis: mas lo que os fuere dado en aquella hora, eso hablad; porque no sois vosotros los que habláis, sino el Espíritu Santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 12, 'Y entregará á la muerte el hermano al hermano, y el padre al hijo: y se levantarán los hijos contra los padres, y los matarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 13, 'Y seréis aborrecidos de todos por mi nombre: mas el que perseverare hasta el fin, éste será salvo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 14, 'Empero cuando viereis la abominación de asolamiento, que fué dicha por el profeta Daniel, que estará donde no debe (el que lee, entienda), entonces los que estén en Judea huyan á los montes;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 15, 'Y el que esté sobre el terrado, no descienda á la casa, ni entre para tomar algo de su casa;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 16, 'Y el que estuviere en el campo, no vuelva atrás á tomar su capa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 17, 'Mas ¡ay de las preñadas, y de las que criaren en aquellos días!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 18, 'Orad pues, que no acontezca vuestra huída en invierno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 19, 'Porque aquellos días serán de aflicción, cual nunca fué desde el principio de la creación que crió Dios, hasta este tiempo, ni será.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 20, 'Y si el Señor no hubiese abreviado aquellos días, ninguna carne se salvaría; mas por causa de los escogidos que él escogió, abrevió aquellos días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 21, 'Y entonces si alguno os dijere: He aquí, aquí está el Cristo; ó, He aquí, allí está, no le creáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 22, 'Porque se levantarán falsos Cristos y falsos profetas, y darán señales y prodigios, para engañar, si se pudiese hacer, aun á los escogidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 23, 'Mas vosotros mirad; os lo he dicho antes todo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 24, 'Empero en aquellos días, después de aquella aflicción, el sol se obscurecerá, y la luna no dará su resplandor;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 25, 'Y las estrellas caerán del cielo, y las virtudes que están en los cielos serán conmovidas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 26, 'Y entonces verán al Hijo del hombre, que vendrá en las nubes con mucha potestad y gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 27, 'Y entonces enviará sus ángeles, y juntará sus escogidos de los cuatro vientos, desde el cabo de la tierra hasta el cabo del cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 28, 'De la higuera aprended la semejanza: Cuando su rama ya se enternece, y brota hojas, conocéis que el verano está cerca:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 29, 'Así también vosotros, cuando viereis hacerse estas cosas, conoced que está cerca, á las puertas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 30, 'De cierto os digo que no pasará esta generación, que todas estas cosas no sean hechas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 31, 'El cielo y la tierra pasarán, mas mis palabras no pasarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 32, 'Empero de aquel día y de la hora, nadie sabe; ni aun los ángeles que están en el cielo, ni el Hijo, sino el Padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 33, 'Mirad, velad y orad: porque no sabéis cuándo será el tiempo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 34, 'Como el hombre que partiéndose lejos, dejó su casa, y dió facultad á sus siervos, y á cada uno su obra, y al portero mandó que velase:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 35, 'Velad pues, porque no sabéis cuándo el señor de la casa vendrá; si á la tarde, ó á la media noche, ó al canto del gallo, ó á la mañana;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 36, 'Porque cuando viniere de repente, no os halle durmiendo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 13, 37, 'Y las cosas que á vosotros digo, á todos las dijo: Velad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 1, 'Y DOS días después era la Pascua y los días de los panes sin levadura: y procuraban los príncipes de los sacerdotes y los escribas cómo le prenderían por engaño, y le matarían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 2, 'Y decían: No en el día de la fiesta, porque no se haga alboroto del pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 3, 'Y estando él en Bethania en casa de Simón el leproso, y sentado á la mesa, vino una mujer teniendo un alabastro de ungüento de nardo espique de mucho precio; y quebrando el alabastro, derramóselo sobre su cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 4, 'Y hubo algunos que se enojaron dentro de sí, y dijeron: ¿Para qué se ha hecho este desperdicio de ungüento?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 5, 'Porque podía esto ser vendido por más de trescientos denarios, y darse á los pobres. Y murmuraban contra ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 6, 'Mas Jesús dijo: Dejadla; ¿por qué la fatigáis? Buena obra me ha hecho;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 7, 'Que siempre tendréis los pobres con vosotros, y cuando quisiereis les podréis hacer bien; mas á mí no siempre me tendréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 8, 'Esta ha hecho lo que podía; porque se ha anticipado á ungir mi cuerpo para la sepultura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 9, 'De cierto os digo que donde quiera que fuere predicado este evangelio en todo el mundo, también esto que ha hecho ésta, será dicho para memoria de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 10, 'Entonces Judas Iscariote, uno de los doce, vino á los príncipes de los sacerdotes, para entregársele.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 11, 'Y ellos oyéndolo se holgaron, y prometieron que le darían dineros. Y buscaba oportunidad cómo le entregaría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 12, 'Y el primer día de los panes sin levadura, cuando sacrificaban la pascua, sus discípulos le dicen: ¿Dónde quieres que vayamos á disponer para que comas la pascua?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 13, 'Y envía dos de sus discípulos, y les dice: Id á la ciudad, y os encontrará un hombre que lleva un cántaro de agua; seguidle;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 14, 'Y donde entrare, decid al señor de la casa: El Maestro dice: ¿Dónde está el aposento donde he de comer la pascua con mis discípulos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 15, 'Y él os mostrará un gran cenáculo ya preparado: aderezad para nosotros allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 16, 'Y fueron sus discípulos, y vinieron á la ciudad, y hallaron como les había dicho; y aderezaron la pascua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 17, 'Y llegada la tarde, fué con los doce.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 18, 'Y como se sentaron á la mesa y comiesen, dice Jesús: De cierto os digo que uno de vosotros, que come conmigo, me ha de entregar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 19, 'Entonces ellos comenzaron á entristecerse, y á decirle cada uno por sí: ¿Seré yo? Y el otro: ¿Seré yo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 20, 'Y él respondiendo les dijo: Es uno de los doce que moja conmigo en el plato.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 21, 'A la verdad el Hijo del hombre va, como está de él escrito; mas ¡ay de aquel hombre por quien el Hijo del hombre es entregado! bueno le fuera á aquel hombre si nunca hubiera nacido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 22, 'Y estando ellos comiendo, tomó Jesús pan, y bendiciendo, partió y les dió, y dijo: Tomad, esto es mi cuerpo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 23, 'Y tomando el vaso, habiendo hecho gracias, les dió: y bebieron de él todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 24, 'Y les dice: Esto es mi sangre del nuevo pacto, que por muchos es derramada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 25, 'De cierto os digo que no beberé más del fruto de la vid, hasta aquel día cundo lo beberé nuevo en el reino de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 26, 'Y como hubieron cantado el himno, se salieron al monte de las Olivas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 27, 'Jesús entonces les dice: Todos seréis escandalizados en mí esta noche; porque escrito está: Heriré al pastor, y serán derramadas las ovejas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 28, 'Mas después que haya resucitado, iré delante de vosotros á Galilea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 29, 'Entonces Pedro le dijo: Aunque todos sean escandalizados, mas no yo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 30, 'Y le dice Jesús: De cierto te digo que tú, hoy, en esta noche, antes que el gallo haya cantado dos veces, me negarás tres veces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 31, 'Mas él con mayor porfía decía: Si me fuere menester morir contigo, no te negaré. También todos decían lo mismo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 32, 'Y vienen al lugar que se llama Gethsemaní, y dice á sus discípulos: Sentaos aquí, entre tanto que yo oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 33, 'Y toma consigo á Pedro y á Jacobo y á Juan, y comenzó á atemorizarse, y á angustiarse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 34, 'Y les dice: Está muy triste mi alma, hasta la muerte: esperad aquí y velad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 35, 'Y yéndose un poco adelante, se postró en tierra, y oro que si fuese posible, pasase de él aquella hora,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 36, 'Y decía: Abba, Padre, todas las cosas son á ti posibles: traspasa de mí este vaso; empero no lo que yo quiero, sino lo que tú.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 37, 'Y vino y los halló durmiendo; y dice á Pedro: ¿Simón, duermes? ¿No has podido velar una hora?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 38, 'Velad y orad, para que no entréis en tentación: el espíritu á la verdad es presto, mas la carne enferma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 39, 'Y volviéndose á ir, oró, y dijo las mismas palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 40, 'Y vuelto, los halló otra vez durmiendo, porque los ojos de ellos estaban cargados; y no sabían qué responderle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 41, 'Y vino la tercera vez, y les dice: Dormid ya y descansad: basta, la hora es venida; he aquí, el Hijo del hombre es entregado en manos de los pecadores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 42, 'Levantaos, vamos: he aquí, el que me entrega está cerca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 43, 'Y luego, aun hablando él, vino Judas, que era uno de los doce, y con él una compañía con espadas y palos, de parte de los príncipes de los sacerdotes, y de los escribas y de los ancianos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 44, 'Y el que le entregaba les había dado señal común, diciendo: Al que yo besare, aquél es: prendedle, y llevadle con seguridad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 45, 'Y como vino, se acercó luego á él, y le dice: Maestro, Maestro. Y le besó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 46, 'Entonces ellos echaron en él sus manos, y le prendieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 47, 'Y uno de los que estaban allí, sacando la espada, hirió al siervo del sumo sacerdote, y le cortó la oreja.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 48, 'Y respondiendo Jesús, les dijo: ¿Como á ladrón habéis salido con espadas y con palos á tomarme?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 49, 'Cada día estaba con vosotros enseñando en el templo, y no me tomasteis; pero es así, para que se cumplan las Escrituras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 50, 'Entonces dejándole todos sus discípulos, huyeron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 51, 'Empero un mancebillo le seguía cubierto de una sábana sobre el cuerpo desnudo; y los mancebos le prendieron:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 52, 'Mas él, dejando la sábana, se huyó de ellos desnudo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 53, 'Y trajeron á Jesús al sumo sacerdote; y se juntaron á él todos los príncipes de los sacerdotes y los ancianos y los escribas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 54, 'Empero Pedro le siguió de lejos hasta dentro del patio del sumo sacerdote; y estaba sentado con los servidores, y calentándose al fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 55, 'Y los príncipes de los sacerdotes y todo el concilio buscaban testimonio contra Jesús, para entregarle á la muerte; mas no lo hallaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 56, 'Porque muchos decían falso testimonio contra él; mas sus testimonios no concertaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 57, 'Entonces levantandose unos, dieron falso testimonio contra él, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 58, 'Nosotros le hemos oído decir: Yo derribaré este templo que es hecho de mano, y en tres días edificaré otro echo sin mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 59, 'Mas ni aun así se concertaba el testimonio de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 60, 'Entonces el sumo sacerdote, levantándose en medio, preguntó á Jesús, diciendo: ¿No respondes algo? ¿Qué atestiguan estos contra ti?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 61, 'Mas él callaba, y nada respondía. El sumo sacerdote le volvió á preguntar, y le dice: ¿Eres tú el Cristo, el Hijo del Bendito?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 62, 'Y Jesús le dijo: Yo soy; y veréis al Hijo del hombre sentado á la diestra de la potencia de Dios, y viniendo en las nubes del cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 63, 'Entonces el sumo sacerdote, rasgando sus vestidos, dijo: ¿Qué más tenemos necesidad de testigos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 64, 'Oído habéis la blasfemia: ¿qué os parece? Y ellos todos le condenaron ser culpado de muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 65, 'Y algunos comenzaron á escupir en él, y cubrir su rostro, y á darle bofetadas, y decirle: Profetiza. Y los servidores le herían de bofetadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 66, 'Y estando Pedro abajo en el atrio, vino una de las criadas del sumo sacerdote;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 67, 'Y como vió á Pedro que se calentaba, mirándole, dice: Y tú con Jesús el Nazareno estabas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 68, 'Mas él negó, diciendo: No conozco, ni sé lo que dices. Y se salió fuera á la entrada; y cantó el gallo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 69, 'Y la criada viéndole otra vez, comenzó á decir á los que estaban allí: Este es de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 70, 'Mas él negó otra vez. Y poco después, los que estaban allí dijeron otra vez á Pedro: Verdaderamente tú eres de ellos; porque eres Galileo, y tu habla es semejante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 71, 'Y él comenzó á maldecir y á jurar: No conozco á este hombre de quien habláis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 14, 72, 'Y el gallo cantó la segunda vez: y Pedro se acordó de las palabras que Jesús le había dicho: Antes que el gallo cante dos veces, me negarás tres veces. Y pensando en esto, lloraba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 1, 'Y LUEGO por la mañana, habiendo tenido consejo los príncipes de los sacerdotes con los ancianos, y con los escribas, y con todo el concilio, llevaron á Jesús atado, y le entregaron á Pilato.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 2, 'Y Pilato le preguntó: ¿Eres tú el Rey de los Judíos? Y respondiendo él, le dijo: Tú lo dices.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 3, 'Y los príncipes de los sacerdotes le acusaban mucho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 4, 'Y le preguntó otra vez Pilato, diciendo: ¿No respondes algo? Mira de cuántas cosas te acusan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 5, 'Mas Jesús ni aun con eso respondió; de modo que Pilato se maravillaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 6, 'Empero en el día de la fiesta les soltaba un preso, cualquiera que pidiesen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 7, 'Y había uno, que se llamaba Barrabás, preso con sus compañeros de motín que habían hecho muerte en una revuelta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 8, 'Y viniendo la multitud, comenzó á pedir hiciese como siempre les había hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 9, 'Y Pilato les respondió, diciendo: ¿Queréis que os suelte al Rey de los Judíos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 10, 'Porque conocía que por envidia le habían entregado los príncipes de los sacerdotes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 11, 'Mas los príncipes de los sacerdotes incitaron á la multitud, que les soltase antes á Barrabás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 12, 'Y respondiendo Pilato, les dice otra vez: ¿Qué pues queréis que haga del que llamáis Rey de los Judíos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 13, 'Y ellos volvieron á dar voces: Crucifícale.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 14, 'Mas Pilato les decía: ¿Pues qué mal ha hecho? Y ellos daban más voces: Crucifícale.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 15, 'Y Pilato, queriendo satisfacer al pueblo, les soltó á Barrabás, y entregó á Jesús, después de azotarle, para que fuese crucificado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 16, 'Entonces los soldados le llevaron dentro de la sala, es á saber al Pretorio; y convocan toda la cohorte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 17, 'Y le visten de púrpura; y poniéndole una corona tejida de espinas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 18, 'Comenzaron luego á saludarle: ¡Salve, Rey de los Judíos!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 19, 'Y le herían en la cabeza con una caña, y escupían en él, y le adoraban hincadas las rodillas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 20, 'Y cuando le hubieron escarnecido, le desnudaron la púrpura, y le vistieron sus propios vestidos, y le sacaron para crucificarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 21, 'Y cargaron á uno que pasaba, Simón Cireneo, padre de Alejandro y de Rufo, que venía del campo, para que llevase su cruz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 22, 'Y le llevan al lugar de Gólgotha, que declarado quiere decir: Lugar de la Calavera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 23, 'Y le dieron á beber vino mezclado con mirra; mas él no lo tomó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 24, 'Y cuando le hubieron crucificado, repartieron sus vestidos, echando suertes sobre ellos, qué llevaría cada uno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 25, 'Y era la hora de las tres cuando le crucificaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 26, 'Y el título escrito de su causa era: EL REY DE LOS JUDIOS.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 27, 'Y crucificaron con él dos ladrones, uno á su derecha, y el otro á su izquierda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 28, 'Y se cumplió la Escritura, que dice: Y con los inicuos fué contado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 29, 'Y los que pasaban le denostaban, meneando sus cabezas, y diciendo: ¡Ah! tú que derribas el templo de Dios, y en tres días lo edificas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 30, 'Sálvate á ti mismo, y desciende de la cruz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 31, 'Y de esta manera también los príncipes de los sacerdotes escarneciendo, decían unos á otros, con los escribas: A otros salvó, á sí mismo no se puede salvar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 32, 'El Cristo, Rey de Israel, descienda ahora de la cruz, para que veamos y creamos. También los que estaban crucificados con él le denostaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 33, 'Y cuando vino la hora de sexta, fueron hechas tinieblas sobre toda la tierra hasta la hora de nona.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 34, 'Y á la hora de nona, exclamó Jesús á gran voz, diciendo: Eloi, Eloi, ¿lama sabachthani? que declarado, quiere decir: Dios mío, Díos mío, ¿por qué me has desamparado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 35, 'Y oyéndole unos de los que estaban allí, decían: He aquí, llama á Elías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 36, 'Y corrió uno, y empapando una esponja en vinagre, y poniéndola en una caña, le dió á beber, diciendo: Dejad, veamos si vendrá Elías á quitarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 37, 'Mas Jesús, dando una grande voz, espiró.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 38, 'Entonces el velo del templo se rasgó en dos, de alto á bajo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 39, 'Y el centurión que estaba delante de él, viendo que había espirado así clamando, dijo: Verdaderamente este hombre era el Hijo de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 40, 'Y también estaban algunas mujeres mirando de lejos; entre las cuales estaba María Magdalena, y María la madre de Jacobo el menor y de José, y Salomé;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 41, 'Las cuales, estando aún él en Galilea, le habían seguido, y le servían; y otras muchas que juntamente con él habían subido á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 42, 'Y cuando fué la tarde, porque era la preparación, es decir, la víspera del sábado,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 43, 'José de Arimatea, senador noble, que también esperaba el reino de Dios, vino, y osadamente entró á Pilato, y pidió el cuerpo de Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 44, 'Y Pilato se maravilló que ya fuese muerto; y haciendo venir al centurión, preguntóle si era ya muerto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 45, 'Y enterado del centurión, dió el cuerpo á José.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 46, 'El cual compró una sábana, y quitándole, le envolvió en la sábana, y le puso en un sepulcro que estaba cavado en una peña, y revolvió una piedra á la puerta del sepulcro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 15, 47, 'Y María Magdalena, y María madre de José, miraban donde era puesto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 16, 1, 'Y COMO pasó el sábado, María Magdalena, y María madre de Jacobo, y Salomé, compraron drogas aromáticas, para venir á ungirle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 16, 2, 'Y muy de mañana, el primer día de la semana, vienen al sepulcro, ya salido el sol.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 16, 3, 'Y decían entre sí: ¿Quién nos revolverá la piedra de la puerta del sepulcro?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 16, 4, 'Y como miraron, ven la piedra revuelta; que era muy grande.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 16, 5, 'Y entradas en el sepulcro, vieron un mancebo sentado al lado derecho, cubierto de una larga ropa blanca; y se espantaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 16, 6, 'Más él les dice: No os asustéis: buscáis á Jesús Nazareno, el que fué crucificado; resucitado há, no está aquí; he aquí el lugar en donde le pusieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 16, 7, 'Mas id, decid á sus discípulos y á Pedro, que él va antes que vosotros á Galilea: allí le veréis, como os dijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 16, 8, 'Y ellas se fueron huyendo del sepulcro; porque las había tomado temblor y espanto; ni decían nada á nadie, porque tenían miedo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 16, 9, 'Mas como Jesús resucitó por la mañana, el primer día de la semana, apareció primeramente á María Magdalena, de la cual había echado siete demonios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 16, 10, 'Yendo ella, lo hizo saber á los que habían estado con él, que estaban tristes y llorando.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 16, 11, 'Y ellos como oyeron que vivía, y que había sido visto de ella, no lo creyeron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 16, 12, 'Mas después apareció en otra forma á dos de ellos que iban caminando, yendo al campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 16, 13, 'Y ellos fueron, y lo hicieron saber á los otros; y ni aun á éllos creyeron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 16, 14, 'Finalmente se apareció á los once mismos, estando sentados á la mesa, y censuróles su incredulidad y dureza de corazón, que no hubiesen creído á los que le habían visto resucitado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 16, 15, 'Y les dijo: Id por todo el mundo; predicad el evangelio á toda criatura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 16, 16, 'El que creyere y fuere bautizado, será salvo; mas el que no creyere, será condenado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 16, 17, 'Y estas señales seguirán á los que creyeren: En mi nombre echarán fuera demonios; hablaran nuevas lenguas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 16, 18, 'Quitarán serpientes, y si bebieren cosa mortífera, no les dañará; sobre los enfermos pondrán sus manos, y sanarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 16, 19, 'Y el Señor, después que les habló, fué recibido arriba en el cielo, y sentóse á la diestra de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MRK', 'Marcos', 16, 20, 'Y ellos, saliendo, predicaron en todas partes, obrando con ellos el Señor, y confirmando la palabra con las señales que se seguían. Amen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 1, 'HABIENDO muchos tentado á poner en orden la historia de las cosas que entre nosotros han sido ciertísimas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 2, 'Como nos lo enseñaron los que desde el principio lo vieron por sus ojos, y fueron ministros de la palabra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 3, 'Me ha parecido también á mí, después de haber entendido todas las cosas desde el principio con diligencia, escribírtelas por orden, oh muy buen Teófilo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 4, 'Para que conozcas la verdad de las cosas en las cuales has sido enseñado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 5, 'HUBO en los días de Herodes, rey de Judea, un sacerdote llamado Zacarías, de la suerte de Abías; y su mujer, de las hijas de Aarón, llamada Elisabet.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 6, 'Y eran ambos justos delante de Dios, andando sin reprensión en todos los mandamientos y estatutos del Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 7, 'Y no tenían hijo, porque Elisabet era estéril, y ambos eran avanzados en días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 8, 'Y aconteció que ejerciendo Zacarías el sacerdocio delante de Dios por el orden de su vez,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 9, 'Conforme á la costumbre del sacerdocio, salió en suerte á poner el incienso, entrando en el templo del Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 10, 'Y toda la multitud del pueblo estaba fuera orando á la hora del incienso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 11, 'Y se le apareció el ángel del Señor puesto en pie á la derecha del altar del incienso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 12, 'Y se turbó Zacarías viéndo le, y cayó temor sobre él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 13, 'Mas el ángel le dijo: Zacarías, no temas; porque tu oración ha sido oída, y tu mujer Elisabet te parirá un hijo, y llamarás su nombre Juan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 14, 'Y tendrás gozo y alegría, y muchos se gozarán de su nacimiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 15, 'Porque será grande delante de Dios, y no beberá vino ni sidra; y será lleno del Espíritu Santo, aun desde el seno de su madre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 16, 'Y á muchos de los hijos de Israel convertirá al Señor Dios de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 17, 'Porque él irá delante de él con el espíritu y virtud de Elías, para convertir los corazones de los padres á los hijos, y los rebeldes á la prudencia de los justos, para aparejar al Señor un pueblo apercibido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 18, 'Y dijo Zacarías al ángel: ¿En qué conoceré esto? porque yo soy viejo, y mi mujer avanzada en días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 19, 'Y respondiendo el ángel le dijo: Yo soy Gabriel, que estoy delante de Dios; y soy enviado á hablarte, y á darte estas buenas nuevas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 20, 'Y he aquí estarás mudo y no podrás hablar, hasta el día que esto sea hecho, por cuanto no creíste á mis palabras, las cuales se cumplirán á su tiempo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 21, 'Y el pueblo estaba esperando á Zacarías, y se maravillaban de que él se detuviese en el templo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 22, 'Y saliendo, no les podía hablar: y entendieron que había visto visión en el templo: y él les hablaba por señas, y quedó mudo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 23, 'Y fué, que cumplidos los días de su oficio, se vino á su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 24, 'Y después de aquellos días concibió su mujer Elisabet, y se encubrió por cinco meses, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 25, 'Porque el Señor me ha hecho así en los días en que miró para quitar mi afrenta entre los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 26, 'Y al sexto mes, el ángel Gabriel fué enviado de Dios á una ciudad de Galilea, llamada Nazaret,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 27, 'A una virgen desposada con un varón que se llamaba José, de la casa de David: y el nombre de la virgen era María.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 28, 'Y entrando el ángel á donde estaba, dijo, ¡Salve, muy favorecida! el Señor es contigo: bendita tú entre las mujeres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 29, 'Mas ella, cuando le vió, se turbó de sus palabras, y pensaba qué salutación fuese ésta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 30, 'Entonces el ángel le dijo: María, no temas, porque has hallado gracia cerca de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 31, 'Y he aquí, concebirás en tu seno, y parirás un hijo, y llamarás su nombre JESUS.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 32, 'Este será grande, y será llamado Hijo del Altísimo: y le dará el Señor Dios el trono de David su padre:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 33, 'Y reinará en la casa de Jacob por siempre; y de su reino no habrá fin.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 34, 'Entonces María dijo al ángel: ¿Cómo será esto? porque no conozco varón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 35, 'Y respondiendo el ángel le dijo: El Espíritu Santo vendrá sobre ti, y la virtud del Altísimo te hará sombra; por lo cual también lo Santo que nacerá, será llamado Hijo de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 36, 'Y he aquí, Elisabet tu parienta, también ella ha concebido hijo en su vejez; y este es el sexto mes á ella que es llamada la estéril:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 37, 'Porque ninguna cosa es imposible para Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 38, 'Entonces María dijo: He aquí la sierva del Señor; hágase á mí conforme á tu palabra. Y el ángel partió de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 39, 'En aquellos días levantándose María, fué á la montaña con priesa, á una ciudad de Judá;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 40, 'Y entró en casa de Zacarías, y saludó á Elisabet.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 41, 'Y aconteció, que como oyó Elisabet la salutación de María, la criatura saltó en su vientre; y Elisabet fué llena del Espíritu Santo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 42, 'Y exclamó á gran voz, y dijo. Bendita tú entre las mujeres, y bendito el fruto de tu vientre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 43, '¿Y de dónde esto á mí, que la madre de mi Señor venga á mí?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 44, 'Porque he aquí, como llegó la voz de tu salutación á mis oídos, la criatura saltó de alegría en mi vientre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 45, 'Y bienaventurada la que creyó, porque se cumplirán las cosas que le fueron dichas de parte del Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 46, 'Entonces María dijo: engrandece mi alma al Señor;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 47, 'Y mi espíritu se alegró en Dios mi Salvador,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 48, 'Porque ha mirado á la bajeza de su criada; Porque he aquí, desde ahora me dirán bienaventurada todas las generaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 49, 'Porque me ha hecho grandes cosas el Poderoso; Y santo es su nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 50, 'Y su misericordia de generación á generación A los que le temen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 51, 'Hizo valentía con su brazo: Esparció los soberbios del pensamiento de su corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 52, 'Quitó los poderosos de los tronos, Y levantó á los humildes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 53, 'A los hambrientos hinchió de bienes; Y á los ricos envió vacíos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 54, 'Recibió á Israel su siervo, Acordandose de la misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 55, 'Como habló á nuestros padres A Abraham y á su simiente para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 56, 'Y se quedó María con ella como tres meses: después se volvió á su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 57, 'Y á Elisabet se le cumplió el tiempo de parir, y parió un hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 58, 'Y oyeron los vecinos y los parientes que Dios había hecho con ella grande misericordia, y se alegraron con ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 59, 'Y aconteció, que al octavo día vinieron para circuncidar al niño; y le llamaban del nombre de su padre, Zacarías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 60, 'Y respondiendo su madre, dijo: No; sino Juan será llamado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 61, 'Y le dijeron: ¿Por qué? nadie hay en tu parentela que se llame de este nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 62, 'Y hablaron por señas á su padre, cómo le quería llamar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 63, 'Y demandando la tablilla, escribió, diciendo: Juan es su nombre. Y todos se maravillaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 64, 'Y luego fué abierta su boca y su lengua, y habló bendiciendo á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 65, 'Y fué un temor sobre todos los vecinos de ellos; y en todas las montañas de Judea fueron divulgadas todas estas cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 66, 'Y todos los que las oían, las conservaban en su corazón, diciendo: ¿Quién será este niño? Y la mano del Señor estaba con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 67, 'Y Zacarías su padre fué lleno de Espíritu Santo, y profetizó, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 68, 'Bendito el Señor Dios de Israel, Que ha visitado y hecho redención á su pueblo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 69, 'Y nos alzó un cuerno de salvación En la casa de David su siervo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 70, 'Como habló por boca de sus santos profetas que fueron desde el principio:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 71, 'Salvación de nuestros enemigos, y de mano de todos los que nos aborrecieron;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 72, 'Para hacer misericordia con nuestros padres, Y acordándose de su santo pacto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 73, 'Del juramento que juró á Abraham nuestro padre, Que nos había de dar,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 74, 'Que sin temor librados de nuestros enemigos, Le serviríamos');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 75, 'En santidad y en justicia delante de él, todos los días nuestros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 76, 'Y tú, niño, profeta del Altísimo serás llamado; Porque irás ante la faz del Señor, para aparejar sus caminos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 77, 'Dando conocimiento de salud á su pueblo, Para remisión de sus pecados,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 78, 'Por las entrañas de misericordia de nuestro Dios, Con que nos visitó de lo alto el Oriente,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 79, 'Para dar luz á los que habitan en tinieblas y en sombra de muerte; Para encaminar nuestros pies por camino de paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 1, 80, 'Y el niño crecía, y se fortalecía en espíritu: y estuvo en los desiertos hasta el día que se mostró á Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 1, 'Y ACONTECIO en aquellos días que salió edicto de parte de Augusto César, que toda la tierra fuese empadronada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 2, 'Este empadronamiento primero fué hecho siendo Cirenio gobernador de la Siria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 3, 'E iban todos para ser empadronados, cada uno á su ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 4, 'Y subió José de Galilea, de la ciudad de Nazaret, á Judea, á la ciudad de David, que se llama Bethlehem, por cuanto era de la casa y familia de David;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 5, 'Para ser empadronado con María su mujer, desposada con él, la cual estaba encinta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 6, 'Y aconteció que estando ellos allí, se cumplieron los días en que ella había de parir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 7, 'Y parió á su hijo primogénito, y le envolvió en pañales, y acostóle en un pesebre, porque no había lugar para ellos en el mesón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 8, 'Y había pastores en la misma tierra, que velaban y guardaban las vigilias de la noche sobre su ganado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 9, 'Y he aquí el ángel del Señor vino sobre ellos, y la claridad de Dios los cercó de resplandor; y tuvieron gran temor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 10, 'Mas el ángel les dijo: No temáis; porque he aquí os doy nuevas de gran gozo, que será para todo el pueblo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 11, 'Que os ha nacido hoy, en la ciudad de David, un Salvador, que es CRISTO el Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 12, 'Y esto os será por señal: hallaréis al niño envuelto en pañales, echado en un pesebre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 13, 'Y repentinamente fué con el ángel una multitud de los ejércitos celestiales, que alababan á Dios, y decían:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 14, 'Gloria en las alturas á Dios, Y en la tierra paz, buena voluntad para con los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 15, 'Y aconteció que como los ángeles se fueron de ellos al cielo, los pastores dijeron los unos á los otros: Pasemos pues hasta Bethlehem, y veamos esto que ha sucedido, que el Señor nos ha manifestado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 16, 'Y vinieron apriesa, y hallaron á María, y á José, y al niño acostado en el pesebre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 17, 'Y viéndolo, hicieron notorio lo que les había sido dicho del niño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 18, 'Y todos los que oyeron, se maravillaron de lo que los pastores les decían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 19, 'Mas María guardaba todas estas cosas, confiriéndolas en su corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 20, 'Y se volvieron los pastores glorificando y alabando á Dios de todas las cosas que habían oído y visto, como les había sido dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 21, 'Y pasados los ocho días para circuncidar al niño, llamaron su nombre JESUS; el cual le fué puesto por el ángel antes que él fuese concebido en el vientre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 22, 'Y como se cumplieron los días de la purificación de ella, conforme á la ley de Moisés, le trajeron á Jerusalem para presentarle al Señor,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 23, '(Como está escrito en la ley del Señor: Todo varón que abriere la matriz, será llamado santo al Señor),');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 24, 'Y para dar la ofrenda, conforme á lo que está dicho en la ley del Señor: un par de tórtolas, ó dos palominos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 25, 'Y he aquí, había un hombre en Jerusalem, llamado Simeón, y este hombre, justo y pío, esperaba la consolación de Israel: y el Espíritu Santo era sobre él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 26, 'Y había recibido respuesta del Espíritu Santo, que no vería la muerte antes que viese al Cristo del Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 27, 'Y vino por Espíritu al templo. Y cuando metieron al niño Jesús sus padres en el templo, para hacer por él conforme á la costumbre de la ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 28, 'Entonces él le tomó en sus brazos, y bendijo á Dios, y dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 29, 'Ahora despides, Señor, á tu siervo, Conforme á tu palabra, en paz;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 30, 'Porque han visto mis ojos tu salvación,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 31, 'La cual has aparejado en presencia de todos los pueblos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 32, 'Luz para ser revelada á los Gentiles, Y la gloria de tu pueblo Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 33, 'Y José y su madre estaban maravillados de las cosas que se decían de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 34, 'Y los bendijo Simeón, y dijo á su madre María: He aquí, éste es puesto para caída y para levantamiento de muchos en Israel; y para señal á la que será contradicho;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 35, 'Y una espada traspasará tu alma de ti misma, para que sean manifestados los pensamientos de muchos corazones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 36, 'Estaba también allí Ana, profetisa, hija de Phanuel, de la tribu de Aser; la cual había venido en grande edad, y había vivido con su marido siete años desde su virginidad;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 37, 'Y era viuda de hasta ochenta y cuatro años, que no se apartaba del templo, sirviendo de noche y de día con ayunos y oraciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 38, 'Y ésta, sobreviniendo en la misma hora, juntamente confesaba al Señor, y hablaba de él á todos los que esperaban la redención en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 39, 'Mas como cumplieron todas las cosas según la ley del Señor, se volvieron á Galilea, á su ciudad de Nazaret.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 40, 'Y el niño crecía, y fortalecíase, y se henchía de sabiduría; y la gracia de Dios era sobre él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 41, 'E iban sus padres todos los años á Jerusalem en la fiesta de la Pascua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 42, 'Y cuando fué de doce años, subieron ellos á Jerusalem conforme á la costumbre del día de la fiesta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 43, 'Y acabados los días, volviendo ellos, se quedó el niño Jesús en Jerusalem, sin saberlo José y su madre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 44, 'Y pensando que estaba en la compañía, anduvieron camino de un día; y le buscaban entre los parientes y entre los conocidos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 45, 'Mas como no le hallasen, volvieron á Jerusalem buscándole.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 46, 'Y aconteció, que tres días después le hallaron en el templo, sentado en medio de los doctores, oyéndoles y preguntándoles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 47, 'Y todos los que le oían, se pasmaban de su entendimiento y de sus respuestas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 48, 'Y cuando le vieron, se maravillaron; y díjole su madre: Hijo, ¿por qué nos has hecho así? He aquí, tu padre y yo te hemos buscado con dolor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 49, 'Entonces él les dice: ¿Qué hay? ¿por qué me buscabais? ¿No sabíais que en los negocios de mi Padre me conviene estar?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 50, 'Mas ellos no entendieron las palabras que les habló.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 51, 'Y descendió con ellos, y vino á Nazaret, y estaba sujeto á ellos. Y su madre guardaba todas estas cosas en su corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 2, 52, 'Y Jesús crecía en sabiduría, y en edad, y en gracia para con Dios y los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 1, 'Y EN el año quince del imperio de Tiberio César, siendo gobernador de Judea Poncio Pilato, y Herodes tetrarca de Galilea, y su hermano Felipe tetrarca de Iturea y de la provincia de Traconite, y Lisanias tetrarca de Abilinia,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 2, 'Siendo sumos sacerdotes Anás y Caifás, vino palabra del Señor sobre Juan, hijo de Zacarías, en el desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 3, 'Y él vino por toda la tierra al rededor del Jordán predicando el bautismo del arrepentimiento para la remisión de pecados;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 4, 'Como está escrito en el libro de las palabras del profeta Isaías que dice: Voz del que clama en el desierto: Aparejad el camino del Señor, Haced derechas sus sendas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 5, 'Todo valle se henchirá, Y bajaráse todo monte y collado; Y los caminos torcidos serán enderezados, Y los caminos ásperos allanados;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 6, 'Y verá toda carne la salvación de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 7, 'Y decía á las gentes que salían para ser bautizadas de él: ¡Oh generación de víboras, quién os enseñó á huir de la ira que vendrá?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 8, 'Haced, pues, frutos dignos de arrepentimiento, y no comencéis á decir en vosotros mismos: Tenemos á Abraham por padre: porque os digo que puede Dios, aun de estas piedras, levantar hijos á Abraham.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 9, 'Y ya también el hacha está puesta á la raíz de los árboles: todo árbol pues que no hace buen fruto, es cortado, y echado en el fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 10, 'Y las gentes le preguntaban, diciendo: ¿Pues qué haremos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 11, 'Y respondiendo, les dijo: El que tiene dos túnicas, dé al que no tiene; y el que tiene qué comer, haga lo mismo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 12, 'Y vinieron también publicanos para ser bautizados, y le dijeron: Maestro, ¿qué haremos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 13, 'Y él les dijo: No exijáis más de lo que os está ordenado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 14, 'Y le preguntaron también los soldados, diciendo: Y nosotros, ¿qué haremos? Y les dice: No hagáis extorsión á nadie, ni calumniéis; y contentaos con vuestras pagas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 15, 'Y estando el pueblo esperando, y pensando todos de Juan en sus corazones, si él fuese el Cristo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 16, 'Respondió Juan, diciendo á todos: Yo, á la verdad, os bautizo en agua; mas viene quien es más poderoso que yo, de quien no soy digno de desatar la correa de sus zapatos: él os bautizará en Espíritu Santo y fuego;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 17, 'Cuyo bieldo está en su mano, y limpiará su era, y juntará el trigo en su alfolí, y la paja quemará en fuego que nunca se apagará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 18, 'Y amonestando, otras muchas cosas también anunciaba al pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 19, 'Entonces Herodes el tetrarca, siendo reprendido por él á causa de Herodías, mujer de Felipe su hermano, y de todas las maldades que había hecho Herodes,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 20, 'Añadió también esto sobre todo, que encerró á Juan en la cárcel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 21, 'Y aconteció que, como todo el pueblo se bautizaba, también Jesús fué bautizado; y orando, el cielo se abrió,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 22, 'Y descendió el Espíritu Santo sobre él en forma corporal, como paloma, y fué hecha una voz del cielo que decía: Tú eres mi Hijo amado, en ti me he complacido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 23, 'Y el mismo Jesús comenzaba á ser como de treinta años, hijo de José, como se creía; que fué hijo de Elí,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 24, 'Que fué de Mathat, que fué de Leví, que fué Melchî, que fué de Janna, que fué de José,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 25, 'Que fué de Mattathías, que fué de Amós, que fué de Nahum, que fué de Esli,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 26, 'Que fué de Naggai, que fué de Maat, que fué de Matthathías, que fué de Semei, que fué de José, que fué de Judá,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 27, 'Que fué de Joanna, que fué de Rhesa, que fué de Zorobabel, que fué de Salathiel,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 28, 'Que fué de Neri, que fué de Melchî, que fué de Abdi, que fué de Cosam, que fué de Elmodam, que fué de Er,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 29, 'Que fué de Josué, que fué de Eliezer, que fué de Joreim, que fué de Mathat,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 30, 'Que fué de Leví, que fué de Simeón, que fué de Judá, que fué de José, que fué de Jonán, que fué de Eliachîm,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 31, 'Que fué de Melea, que fué de Mainán, que fué de Mattatha, que fué de Nathán,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 32, 'Que fué de David, que fué de Jessé, que fué de Obed, que fué de Booz, que fué de Salmón, que fué de Naassón,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 33, 'Que fué de Aminadab, que fué de Aram, que fué de Esrom, que fué de Phares,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 34, 'Que fué de Judá, que fué de Jacob, que fué de Isaac, que fué de Abraham, que fué de Thara, que fué de Nachôr,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 35, 'Que fué de Saruch, que fué de Ragau, que fué de Phalec, que fué de Heber,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 36, 'Que fué de Sala, que fué de Cainán, Arphaxad, que fué de Sem, que fué de Noé, que fué de Lamech,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 37, 'Que fué de Mathusala, que fué de Enoch, que fué de Jared, que fué de Maleleel,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 3, 38, 'Que fué de Cainán, que fué de Enós, que fué de Seth, que fué de Adam, que fué de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 1, 'Y JESUS, lleno del Espíritu Santo, volvió del Jordán, y fué llevado por el Espíritu al desierto');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 2, 'Por cuarenta días, y era tentado del diablo. Y no comió cosa en aquellos días: los cuales pasados, tuvo hambre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 3, 'Entonces el diablo le dijo: Si eres Hijo de Dios, di á esta piedra que se haga pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 4, 'Y Jesús respondiéndole, dijo: Escrito está: Que no con pan solo vivirá el hombre, mas con toda palabra de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 5, 'Y le llevó el diablo á un alto monte, y le mostró en un momento de tiempo todos los reinos de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 6, 'Y le dijo el diablo: A ti te daré toda esta potestad, y la gloria de ellos; porque á mí es entregada, y á quien quiero la doy:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 7, 'Pues si tú adorares delante de mí, serán todos tuyos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 8, 'Y respondiendo Jesús, le dijo: Vete de mí, Satanás, porque escrito está: A tu Señor Dios adorarás, y á él solo servirás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 9, 'Y le llevó á Jerusalem, y púsole sobre las almenas del templo, y le dijo: Si eres Hijo de Dios, échate de aquí abajo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 10, 'Porque escrito está: Que á sus ángeles mandará de ti, que te guarden;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 11, 'Y En las manos te llevarán, Porque no dañes tu pie en piedra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 12, 'Y respondiendo Jesús, le dijo: Dicho está: No tentarás al Señor tu Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 13, 'Y acabada toda tentación, el diablo se fué de él por un tiempo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 14, 'Y Jesús volvió en virtud del Espíritu á Galilea, y salió la fama de él por toda la tierra de alrededor,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 15, 'Y enseñaba en las sinagogas de ellos, y era glorificado de todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 16, 'Y vino á Nazaret, donde había sido criado; y entró, conforme á su costumbre, el día del sábado en la sinagoga, y se levantó á leer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 17, 'Y fuéle dado el libro del profeta Isaías; y como abrió el libro, halló el lugar donde estaba escrito:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 18, 'El Espíritu del Señor es sobre mí, Por cuanto me ha ungido para dar buenas nuevas á los pobres: Me ha enviado para sanar á los quebrantados de corazón; Para pregonar á los cautivos libertad, Y á los ciegos vista; Para poner en libertad á los quebrantados:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 19, 'Para predicar el año agradable del Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 20, 'Y rollando el libro, lo dió al ministro, y sentóse: y los ojos de todos en la sinagoga estaban fijos en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 21, 'Y comenzó á decirles: Hoy se ha cumplido esta Escritura en vuestros oídos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 22, 'Y todos le daban testimonio, y estaban maravillados de las palabras de gracia que salían de su boca, y decían: ¿No es éste el hijo de José?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 23, 'Y les dijo: Sin duda me diréis este refrán: Médico, cúrate á ti mismo: de tantas cosas que hemos oído haber sido hechas en Capernaum, haz también aquí en tu tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 24, 'Y dijo: De cierto os digo, que ningún profeta es acepto en su tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 25, 'Mas en verdad os digo, que muchas viudas había en Israel en los días de Elías, cuando el cielo fué cerrado por tres años y seis meses, que hubo una grande hambre en toda la tierra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 26, 'Pero á ninguna de ellas fué enviado Elías, sino á Sarepta de Sidón, á una mujer viuda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 27, 'Y muchos leprosos había en Israel en tiempo del profeta Eliseo; mas ninguno de ellos fué limpio, sino Naamán el Siro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 28, 'Entonces todos en la sinagoga fueron llenos de ira, oyendo estas cosas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 29, 'Y levantándose, le echaron fuera de la ciudad, y le llevaron hasta la cumbre del monte sobre el cual la ciudad de ellos estaba edificada, para despeñarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 30, 'Mas él, pasando por medio de ellos, se fué.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 31, 'Y descendió á Capernaum, ciudad de Galilea. Y los enseñaba en los sábados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 32, 'Y se maravillaban de su doctrina, porque su palabra era con potestad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 33, 'Y estaba en la sinagoga un hombre que tenía un espíritu de un demonio inmundo, el cual exclamó á gran voz,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 34, 'Diciendo: Déjanos, ¿qué tenemos contigo Jesús Nazareno? ¿has venido á destruirnos? Yo te conozco quién eres, el Santo de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 35, 'Y Jesús le increpó, diciendo: Enmudece, y sal de él. Entonces el demonio, derribándole en medio, salió de él, y no le hizo daño alguno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 36, 'Y hubo espanto en todos, y hablaban unos á otros, diciendo: ¿Qué palabra es ésta, que con autoridad y potencia manda á los espíritus inmundos, y salen?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 37, 'Y la fama de él se divulgaba de todas partes por todos los lugares de la comarca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 38, 'Y levantándose Jesús de la sinagoga, entró en casa de Simón: y la suegra de Simón estaba con una grande fiebre; y le rogaron por ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 39, 'E inclinándose hacia ella, riñó á la fiebre; y la fiebre la dejó; y ella levantándose luego, les servía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 40, 'Y poniéndose el sol, todos los que tenían enfermos de diversas enfermedades, los traían á él; y él poniendo las manos sobre cada uno de ellos, los sanaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 41, 'Y salían también demonios de muchos, dando voces, y diciendo: Tú eres el Hijo de Dios. Mas riñéndolos no les dejaba hablar; porque sabían que él era el Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 42, 'Y siendo ya de día salió, y se fué á un lugar desierto: y las gentes le buscaban, y vinieron hasta él; y le detenían para que no se apartase de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 43, 'Mas él les dijo: Que también á otras ciudades es necesario que anuncie el evangelio del reino de Dios; porque para esto soy enviado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 4, 44, 'Y predicaba en las sinagogas de Galilea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 1, 'Y ACONTECIO, que estando él junto al lago de Genezaret, las gentes se agolpaban sobre él para oir la palabra de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 2, 'Y vió dos barcos que estaban cerca de la orilla del lago: y los pescadores, habiendo descendido de ellos, lavaban sus redes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 3, 'Y entrado en uno de estos barcos, el cual era de Simón, le rogó que lo desviase de tierra un poco; y sentándose, enseñaba desde el barco á las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 4, 'Y como cesó de hablar, dijo á Simón: Tira á alta mar, y echad vuestras redes para pescar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 5, 'Y respondiendo Simón, le dijo: Maestro, habiendo trabajado toda la noche, nada hemos tomado; mas en tu palabra echaré la red.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 6, 'Y habiéndolo hecho, encerraron gran multitud de pescado, que su red se rompía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 7, 'E hicieron señas á los compañeros que estaban en el otro barco, que viniesen á ayudarles; y vinieron, y llenaron ambos barcos, de tal manera que se anegaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 8, 'Lo cual viendo Simón Pedro, se derribó de rodillas á Jesús, diciendo: Apártate de mí, Señor, porque soy hombre pecador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 9, 'Porque temor le había rodeado, y á todos los que estaban con él, de la presa de los peces que habían tomado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 10, 'Y asimismo á Jacobo y á Juan, hijos de Zebedeo, que eran compañeros de Simón. Y Jesús dijo á Simón: No temas: desde ahora pescarás hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 11, 'Y como llegaron á tierra los barcos, dejándolo todo, le siguieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 12, 'Y aconteció que estando en una ciudad, he aquí un hombre lleno de lepra, el cual viendo á Jesús, postrándose sobre el rostro, le rogó, diciendo: Señor, si quieres, puedes limpiarme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 13, 'Entonces, extendiendo la mano, le tocó diciendo: Quiero: sé limpio. Y luego la lepra se fué de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 14, 'Y él le mandó que no lo dijese á nadie: Mas ve, díjole, muéstrate al sacerdote, y ofrece por tu limpieza, como mandó Moisés, para testimonio á ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 15, 'Empero tanto más se extendía su fama: y se juntaban muchas gentes á oir y ser sanadas de sus enfermedades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 16, 'Mas él se apartaba á los desiertos, y oraba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 17, 'Y aconteció un día, que él estaba enseñando, y los Fariseos y doctores de la ley estaban sentados, los cuales habían venido de todas las aldeas de Galilea, y de Judea y Jerusalem: y la virtud del Señor estaba allí para sanarlos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 18, 'Y he aquí unos hombres, que traían sobre un lecho un hombre que estaba paralítico; y buscaban meterle, y ponerle delante de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 19, 'Y no hallando por donde meterle á causa de la multitud, subieron encima de la casa, y por el tejado le bajaron con el lecho en medio, delante de Jesús;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 20, 'El cual, viendo la fe de ellos, le dice: Hombre, tus pecados te son perdonados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 21, 'Entonces los escribas y los Fariseos comenzaron á pensar, diciendo: ¿Quién es éste que habla blasfemias? ¿Quién puede perdonar pecados sino sólo Dios?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 22, 'Jesús entonces, conociendo los pensamientos de ellos, respondiendo les dijo: ¿Qué pensáis en vuestros corazones?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 23, '¿Qué es más fácil, decir: Tus pecados te son perdonados, ó decir: Levántate y anda?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 24, 'Pues para que sepáis que el Hijo del hombre tiene potestad en la tierra de perdonar pecados, (dice al paralítico): A ti digo, levántate, toma tu lecho, y vete á tu casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 25, 'Y luego, levantándose en presencia de ellos, y tomando aquel en que estaba echado, se fué á su casa, glorificando á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 26, 'Y tomó espanto á todos, y glorificaban á Dios; y fueron llenos del temor, diciendo: Hemos visto maravillas hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 27, 'Y después de estas cosas salió, y vió á un publicano llamado Leví, sentado al banco de los públicos tributos, y le dijo: Sígueme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 28, 'Y dejadas todas las cosas, levantándose, le siguió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 29, 'E hizo Leví gran banquete en su casa; y había mucha compañía de publicanos y de otros, los cuales estaban á la mesa con ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 30, 'Y los escribas y los Fariseos murmuraban contra sus discípulos, diciendo: ¿Por qué coméis y bebéis con los publicanos y pecadores?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 31, 'Y respondiendo Jesús, les dijo: Los que están sanos no necesitan médico, sino los que están enfermos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 32, 'No he venido á llamar justos, sino pecadores á arrepentimiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 33, 'Entonces ellos le dijeron: ¿Por qué los discípulos de Juan ayunan muchas veces y hacen oraciones, y asimismo los de los Fariseos, y tus discípulos comen y beben?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 34, 'Y él les dijo: ¿Podéis hacer que los que están de bodas ayunen, entre tanto que el esposo está con ellos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 35, 'Empero vendr��n días cuando el esposo les será quitado: entonces ayunarán en aquellos días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 36, 'Y les decía también una parábola: Nadie mete remiendo de paño nuevo en vestido viejo; de otra manera el nuevo rompe, y al viejo no conviene remiendo nuevo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 37, 'Y nadie echa vino nuevo en cueros viejos; de otra manera el vino nuevo romperá los cueros, y el vino se derramará, y los cueros se perderán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 38, 'Mas el vino nuevo en cueros nuevos se ha de echar; y lo uno y lo otro se conserva.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 5, 39, 'Y ninguno que bebiere del añejo, quiere luego el nuevo; porque dice: El añejo es mejor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 1, 'Y ACONTECIO que pasando él por los sembrados en un sábado segundo del primero, sus discípulos arrancaban espigas, y comían, restregándolas con las manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 2, 'Y algunos de los Fariseos les dijeron: ¿Por qué hacéis lo que no es lícito hacer en los sábados?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 3, 'Y respondiendo Jesús les dijo: ¿Ni aun esto habéis leído, qué hizo David cuando tuvo hambre, él, y los que con él estaban;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 4, 'Cómo entró en la casa de Dios, y tomó los panes de la proposición, y comió, y dió también á los que estaban con él, los cuales no era lícito comer, sino á solos los sacerdotes?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 5, 'Y les decía. El Hijo del hombre es Señor aun del sábado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 6, 'Y aconteció también en otro sábado, que él entró en la sinagoga y enseñaba; y estaba allí un hombre que tenía la mano derecha seca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 7, 'Y le acechaban los escribas y los Fariseos, si sanaría en sábado, por hallar de qué le acusasen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 8, 'Mas él sabía los pensamientos de ellos; y dijo al hombre que tenía la mano seca: Levántate, y ponte en medio. Y él levantándose, se puso en pie.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 9, 'Entonces Jesús les dice: Os preguntaré un cosa: ¿Es lícito en sábados hacer bien, ó hacer mal? ¿salvar la vida, ó quitarla?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 10, 'Y mirándolos á todos alrededor, dice al hombre: Extiende tu mano. Y él lo hizo así, y su mano fué restaurada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 11, 'Y ellos se llenaron de rabia; y hablaban los unos á los otros qué harían á Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 12, 'Y aconteció en aquellos días, que fué al monte á orar, y pasó la noche orando á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 13, 'Y como fué de día, llamó á sus discípulos, y escogió doce de ellos, á los cuales también llamó apóstoles:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 14, 'A Simón, al cual también llamó Pedro, y á Andrés su hermano, Jacobo y Juan, Felipe y Bartolomé,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 15, 'Mateo y Tomás, Jacobo hijo de Alfeo, y Simón el que se llama Celador,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 16, 'Judas hermano de Jacobo, y Judas Iscariote, que también fué el traidor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 17, 'Y descendió con ellos, y se paró en un lugar llano, y la compañía de sus discípulos, y una grande multitud de pueblo de toda Judea y de Jerusalem, y de la costa de Tiro y de Sidón, que habían venido á oirle, y para ser sanados de sus enfermedades;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 18, 'Y los que habían sido atormentados de espíritus inmundos: y estaban curados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 19, 'Y toda la gente procuraba tocarle; porque salía de él virtud, y sanaba á todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 20, 'Y alzando él los ojos á sus discípulos, decía: Bienaventurados vosotros los pobres; porque vuestro es el reino de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 21, 'Bienaventurados los que ahora tenéis hambre; porque seréis saciados. Bienaventurados los que ahora lloráis, porque reiréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 22, 'Bienaventurados seréis, cuando los hombres os aborrecieren, y cuando os apartaren de sí, y os denostaren, y desecharen vuestro nombre como malo, por el Hijo del hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 23, 'Gozaos en aquel día, y alegraos; porque he aquí vuestro galardón es grande en los cielos; porque así hacían sus padres á los profetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 24, 'Mas ¡ay de vosotros, ricos! porque tenéis vuestro consuelo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 25, '¡Ay de vosotros, los que estáis hartos! porque tendréis hambre. ¡Ay de vosotros, los que ahora reís! porque lamentaréis y lloraréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 26, '¡Ay de vosotros, cuando todos los hombres dijeren bien de vosotros! porque así hacían sus padres á los falsos profetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 27, 'Mas á vosotros los que oís, digo: Amad á vuestros enemigos, haced bien á los que os aborrecen;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 28, 'Bendecid á los que os maldicen, y orad por los que os calumnian.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 29, 'Y al que te hiriere en la mejilla, dale también la otra; y al que te quitare la capa, ni aun el sayo le defiendas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 30, 'Y á cualquiera que te pidiere, da; y al que tomare lo que es tuyo, no vuelvas á pedir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 31, 'Y como queréis que os hagan los hombres, así hacedles también vosotros:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 32, 'Porque si amáis á los que os aman, ¿qué gracias tendréis? porque también los pecadores aman á los que los aman.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 33, 'Y si hiciereis bien á los que os hacen bien, ¿qué gracias tendréis? porque también los pecadores hacen lo mismo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 34, 'Y si prestareis á aquellos de quienes esperáis recibir, ¿qué gracias tendréis? porque también los pecadores prestan á los pecadores, para recibir otro tanto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 35, 'Amad, pués, á vuestros enemigos, y haced bien, y prestad, no esperando de ello nada; y será vuestro galardón grande, y seréis hijos del Altísimo: porque él es benigno para con los ingratos y malos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 36, 'Sed pues misericordiosos, como también vuestro Padre es misericordioso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 37, 'No juzguéis, y no seréis juzgados: no condenéis, y no seréis condenados: perdonad, y seréis perdonados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 38, 'Dad, y se os dará; medida buena, apretada, remecida, y rebosando darán en vuestro seno: porque con la misma medida que midiereis, os será vuelto á medir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 39, 'Y les decía una parábola: ¿Puede el ciego guiar al ciego? ¿No caerán ambos en el hoyo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 40, 'El discípulo no es sobre su maestro; mas cualquiera que fuere como el maestro, será perfecto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 41, '¿Por qué miras la paja que está en el ojo de tu hermano, y la viga que está en tu propio ojo no consideras?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 42, '¿O cómo puedes decir á tu hermano: Hermano, deja, echaré fuera la paja que está en tu ojo, no mirando tú la viga, que está en tu ojo? Hipócrita, echa primero fuera de tu ojo la viga, y entonces verás bien para sacar la paja que está en el ojo de tu hermano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 43, 'Porque no es buen árbol el que da malos frutos; ni árbol malo el que da buen fruto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 44, 'Porque cada árbol por su fruto es conocido: que no cogen higos de los espinos, ni vendimian uvas de las zarzas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 45, 'El buen hombre del buen tesoro de su corazón saca bien; y el mal hombre del mal tesoro de su corazón saca mal; porque de la abundancia del corazón habla su boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 46, '¿Por qué me llamáis, Señor, Señor, y no hacéis lo que digo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 47, 'Todo aquel que viene á mí, y oye mis palabras, y las hace, os enseñaré á quién es semejante:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 48, 'Semejante es al hombre que edifica una casa, el cual cavó y ahondó, y puso el fundamento sobre la peña; y cuando vino una avenida, el río dió con ímpetu en aquella casa, mas no la pudo menear: porque estaba fundada sobre la peña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 6, 49, 'Mas el que oyó y no hizo, semejante es al hombre que edificó su casa sobre tierra, sin fundamento; en la cual el río dió con ímpetu, y luego cayó; y fué grande la ruina de aquella casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 1, 'Y COMO acabó todas sus palabras oyéndole el pueblo, entró en Capernaum.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 2, 'Y el siervo de un centurión, al cual tenía él en estima, estaba enfermo y á punto de morir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 3, 'Y como oyó hablar de Jesús, envió á él los ancianos de los Judíos, rogándole que viniese y librase á su siervo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 4, 'Y viniendo ellos á Jesús, rogáronle con diligencia, diciéndole: Porque es digno de concederle esto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 5, 'Que ama nuestra nación, y él nos edificó una sinagoga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 6, 'Y Jesús fué con ellos. Mas como ya no estuviesen lejos de su casa, envió el centurión amigos á él, diciéndole: Señor, no te incomodes, que no soy digno que entres debajo de mi tejado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 7, 'Por lo cual ni aun me tuve por digno de venir á ti; mas di la palabra, y mi siervo será sano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 8, 'Porque también yo soy hombre puesto en potestad, que tengo debajo de mí soldados; y digo á éste: Ve, y va; y al otro: Ven, y viene; y á mi siervo: Haz esto, y lo hace.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 9, 'Lo cual oyendo Jesús, se maravilló de él, y vuelto, dijo á las gentes que le seguían: Os digo que ni aun en Israel he hallado tanta fe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 10, 'Y vueltos á casa los que habían sido enviados, hallaron sano al siervo que había estado enfermo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 11, 'Y aconteció después, que él iba á la ciudad que se llama Naín, é iban con él muchos de sus discípulos, y gran compañía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 12, 'Y como llegó cerca de la puerta de la ciudad, he aquí que sacaban fuera á un difunto, unigénito de su madre, la cual también era viuda: y había con ella grande compañía de la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 13, 'Y como el Señor la vió, compadecióse de ella, y le dice: No llores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 14, 'Y acercándose, tocó el féretro: y los que lo llevaban, pararon. Y dice: Mancebo, á ti digo, levántate.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 15, 'Entonces se incorporó el que había muerto, y comenzó á hablar. Y dióle á su madre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 16, 'Y todos tuvieron miedo, y glorificaban á Dios, diciendo: Que un gran profeta se ha levantado entre nosotros; y que Dios ha visitado á su pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 17, 'Y salió esta fama de él por toda Judea, y por toda la tierra de alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 18, 'Y sus discípulos dieron á Juan las nuevas de todas estas cosas: y llamó Juan á dos de sus discípulos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 19, 'Y envió á Jesús, diciendo: ¿Eres tú aquél que había de venir, ó esperaremos á otro?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 20, 'Y como los hombres vinieron á él, dijeron: Juan el Bautista nos ha enviado á ti, diciendo: ¿Eres tú aquél que había de venir, ó esperaremos á otro?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 21, 'Y en la misma hora sanó á muchos de enfermedades y plagas, y de espíritus malos; y á muchos ciegos dió la vista.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 22, 'Y respondiendo Jesús, les dijo: Id, dad las nuevas á Juan de lo que habéis visto y oído: que los ciegos ven, los cojos andan, los leprosos son limpiados, los sordos oyen, los muertos resucitan, á los pobres es anunciado el evangelio:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 23, 'Y bienaventurado es el que no fuere escandalizado en mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 24, 'Y como se fueron los mensajeros de Juan, comenzó á hablar de Juan á las gentes: ¿Qué salisteis á ver al desierto? ¿una caña que es agitada por el viento?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 25, 'Mas ¿qué salisteis á ver? ¿un hombre cubierto de vestidos delicados? He aquí, los que están en vestido precioso, y viven en delicias, en los palacios de los reyes están.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 26, 'Mas ¿qué salisteis á ver? ¿un profeta? También os digo, y aun más que profeta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 27, 'Este es de quien está escrito: He aquí, envío mi mensajero delante de tu faz, El cual aparejará tu camino delante de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 28, 'Porque os digo que entre los nacidos de mujeres, no hay mayor profeta que Juan el Bautista: mas el más pequeño en el reino de los cielos es mayor que él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 29, 'Y todo el pueblo oyéndole, y los publicanos, justificaron á Dios, bautizándose con el bautismo de Juan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 30, 'Mas los Fariseos y los sabios de la ley, desecharon el consejo de Dios contra sí mismos, no siendo bautizados de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 31, 'Y dice el Señor: ¿A quién, pues, compararé los hombres de esta generación, y á qué son semejantes?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 32, 'Semejantes son á los muchachos sentados en la plaza, y que dan voces los unos á los otros, y dicen: Os tañimos con flautas, y no bailasteis: os endechamos, y no llorasteis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 33, 'Porque vino Juan el Bautista, que ni comía pan, ni bebía vino, y decís: Demonio tiene.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 34, 'Vino el Hijo del hombre, que come y bebe, y decís: He aquí un hombre comilón, y bebedor de vino, amigo de publicanos y de pecadores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 35, 'Mas la sabiduría es justificada de todos sus hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 36, 'Y le rogó uno de los Fariseos, que comiese con él. Y entrado en casa del Fariseo, sentóse á la mesa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 37, 'Y he aquí una mujer que había sido pecadora en la ciudad, como entendió que estaba á la mesa en casa de aquel Fariseo, trajo un alabastro de ungüento,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 38, 'Y estando detrás á sus pies, comenzó llorando á regar con lágrimas sus pies, y los limpiaba con los cabellos de su cabeza; y besaba sus pies, y los ungía con el ungüento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 39, 'Y como vió esto el Fariseo que le había convidado, habló entre sí, diciendo: Este, si fuera profeta, conocería quién y cuál es la mujer que le toca, que es pecadora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 40, 'Entonces respondiendo Jesús, le dijo: Simón, una cosa tengo que decirte. Y él dice: Di, Maestro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 41, 'Un acredor tenía dos deudores: el uno le debía quinientos denarios, y el otro cincuenta;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 42, 'Y no teniendo ellos de qué pagar, perdonó á ambos. Di, pues, ¿cuál de éstos le amará más?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 43, 'Y respondiendo Simón, dijo: Pienso que aquél al cual perdonó más. Y él le dijo: Rectamente has juzgado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 44, 'Y vuelto á la mujer, dijo á Simón: ¿Ves esta mujer? Entré en tu casa, no diste agua para mis pies; mas ésta ha regado mis pies con lágrimas, y los ha limpiado con los cabellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 45, 'No me diste beso, mas ésta, desde que entré, no ha cesado de besar mis pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 46, 'No ungiste mi cabeza con óleo; mas ésta ha ungido con ungüento mis pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 47, 'Por lo cual te digo que sus muchos pecados son perdonados, porque amó mucho; mas al que se perdona poco, poco ama.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 48, 'Y á ella dijo: Los pecados te son perdonados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 49, 'Y los que estaban juntamente sentados á la mesa, comenzaron á decir entre sí: ¿Quién es éste, que también perdona pecados?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 7, 50, 'Y dijo á la mujer: Tu fe te ha salvado, ve en paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 1, 'Y ACONTECIO después, que él caminaba por todas las ciudades y aldeas, predicando y anunciando el evangelio del reino de Dios, y los doce con él,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 2, 'Y algunas mujeres que habían sido curadas de malos espíritus y de enfermedades: María, que se llamaba Magdalena, de la cual habían salido siete demonios,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 3, 'Y Juana, mujer de Chuza, procurador de Herodes, y Susana, y otras muchas que le servían de sus haciendas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 4, 'Ycomo se juntó una grande compañía, y los que estaban en cada ciudad vinieron á él, dijo por una parábola:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 5, 'Uno que sembraba, salió á sembrar su simiente; y sembrando, una parte cayó junto al camino, y fué hollada; y las aves del cielo la comieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 6, 'Y otra parte cayó sobre la piedra; y nacida, se secó, porque no tenía humedad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 7, 'Y otra parte cayó entre las espinas; y naciendo las espinas juntamente, la ahogaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 8, 'Y otra parte cayó en buena tierra, y cuando fué nacida, llevó fruto á ciento por uno. Diciendo estas cosas clamaba: El que tiene oídos para oir, oiga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 9, 'Y sus discípulos le preguntaron, diciendo, qué era está parábola.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 10, 'Y él dijo: A vosotros es dado conocer los misterios del reino de Dios; mas á los otros por parábolas, para que viendo no vean, y oyendo no entiendan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 11, 'Es pues ésta la parábola: La simiente es la palabra de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 12, 'Y los de junto al camino, éstos son los que oyen; y luego viene el diablo, y quita la palabra de su corazón, porque no crean y se salven.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 13, 'Y los de sobre la piedra, son los que habiendo oído, reciben la palabra con gozo; mas éstos no tienen raíces; que á tiempo creen, y en el tiempo de la tentación se apartan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 14, 'Y la que cayó entre las espinas, éstos son los que oyeron; mas yéndose, son ahogados de los cuidados y de las riquezas y de los pasatiempos de la vida, y no llevan fruto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 15, 'Mas la que en buena tierra, éstos son los que con corazón bueno y recto retienen la palabra oída, y llevan fruto en paciencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 16, 'Ninguno que enciende la antorcha la cubre con vasija, ó la pone debajo de la cama; mas la pone en un candelero, para que los que entran vean la luz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 17, 'Porque no hay cosa oculta, que no haya de ser manifestada; ni cosa escondida, que no haya de ser entendida, y de venir á luz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 18, 'Mirad pues cómo oís; porque á cualquiera que tuviere, le será dado; y á cualquiera que no tuviere, aun lo que parece tener le será quitado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 19, 'Y vinieron á él su madre y hermanos; y no podían llegar á el por causa de la multitud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 20, 'Y le fué dado aviso, diciendo: Tu madre y tus hermanos están fuera, que quieren verte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 21, 'El entonces respondiendo, les dijo: Mi madre y mis hermanos son los que oyen la palabra de Dios, y la ejecutan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 22, 'Y aconteció un día que él entró en un barco con sus discípulos, y les dijo: Pasemos á la otra parte del lago. Y partieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 23, 'Pero mientras ellos navegaban, él se durmió. Y sobrevino una tempestad de viento en el lago; y henchían de agua, y peligraban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 24, 'Y llegándose á él, le despertaron, diciendo: ¡Maestro, Maestro, que perecemos! Y despertado él increpó al viento y á la tempestad del agua; y cesaron, y fué hecha bonanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 25, 'Y les dijo: ¿Qué es de vuestra fe? Y atemorizados, se maravillaban, diciendo los unos á los otros: ¿Quién es éste, que aun á los vientos y al agua manda, y le obedecen?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 26, 'Y navegaron á la tierra de los Gadarenos, que está delante de Galilea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 27, 'Y saliendo él á tierra, le vino al encuentro de la ciudad un hombre que tenía demonios ya de mucho tiempo; y no vestía vestido, ni estaba en casa, sino por los sepulcros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 28, 'El cual, como vió á Jesús, exclamó y se postró delante de él, y dijo á gran voz: ¿Qué tengo yo contigo, Jesús, Hijo del Dios Altísimo? Ruégote que no me atormentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 29, '(Porque mandaba al espíritu inmundo que saliese del hombre: porque ya de mucho tiempo le arrebataba; y le guardaban preso con cadenas y grillos; mas rompiendo las prisiones, era agitado del demonio por los desiertos.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 30, 'Y le preguntó Jesús, diciendo: ¿Qué nombre tienes? Y él dijo: Legión. Porque muchos demonios habían entrado en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 31, 'Y le rogaban que no les mandase ir al abismo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 32, 'Y había allí un hato de muchos puercos que pacían en el monte; y le rogaron que los dejase entrar en ellos; y los dejó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 33, 'Y salidos los demonios del hombre, entraron en los puercos; y el hato se arrojó de un despeñadero en el lago, y ahogóse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 34, 'Y los pastores, como vieron lo que había acontecido, huyeron, y yendo dieron aviso en la ciudad y por las heredades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 35, 'Y salieron á ver lo que había acontecido; y vinieron á Jesús, y hallaron sentado al hombre de quien habían salido los demonios, vestido, y en su juicio, á los pies de Jesús; y tuvieron miedo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 36, 'Y les contaron los que lo habían visto, cómo había sido salvado aquel endemoniado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 37, 'Entonces toda la multitud de la tierra de los Gadarenos alrededor, le rogaron que se fuese de ellos; porque tenían gran temor. Y él, subiendo en el barco, volvióse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 38, 'Y aquel hombre, de quien habían salido los demonios, le rogó para estar con él; mas Jesús le despidió, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 39, 'Vuélvete á tu casa, y cuenta cuán grandes cosas ha hecho Dios contigo. Y él se fué, publicando por toda la ciudad cuán grandes cosas habiá hecho Jesús con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 40, 'Y aconteció que volviendo Jesús, recibióle la gente; porque todos le esperaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 41, 'Y he aquí un varón, llamado Jairo, y que era príncipe de la sinagoga, vino, y cayendo á los pies de Jesús, le rogaba que entrase en su casa;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 42, 'Porque tenía una hija única, como de doce años, y ella se estaba muriendo. Y yendo, le apretaba la compañía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 43, 'Y una mujer, que tenía flujo de sangre hacía ya doce años, la cual había gastado en médicos toda su hacienda, y por ninguno había podido ser curada,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 44, 'Llegándose por las espaldas, tocó el borde de su vestido; y luego se estancó el flujo de su sangre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 45, 'Entonces Jesús dijo: ¿Quién es el que me ha tocado? Y negando todos, dijo Pedro y los que estaban con él: Maestro, la compañía te aprieta y oprime, y dices: ¿Quién es el que me ha tocado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 46, 'Y Jesús dijo: Me ha tocado alguien; porque yo he conocido que ha salido virtud de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 47, 'Entonces, como la mujer vió que no se había ocultado, vino temblando, y postrándose delante de él declaróle delante de todo el pueblo la causa por qué le había tocado, y cómo luego había sido sana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 48, 'Y él dijo: Hija, tu fe te ha salvado: ve en paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 49, 'Estando aún él hablando, vino uno del príncipe de la sinagoga á decirle: Tu hija es muerta, no des trabajo al Maestro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 50, 'Y oyéndolo Jesús, le respondió: No temas: cree solamente, y será salva.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 51, 'Y entrado en casa, no dejó entrar á nadie consigo, sino á Pedro, y á Jacobo, y á Juan, y al padre y á la madre de la moza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 52, 'Y lloraban todos, y la plañían. Y él dijo: No lloréis; no es muerta, sino que duerme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 53, 'Y hacían burla de él, sabiendo que estaba muerta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 54, 'Mas él, tomándola de la mano, clamó, diciendo: Muchacha, levántate.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 55, 'Entonces su espíritu volvió, y se levantó luego: y él mando que le diesen de comer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 8, 56, 'Y sus padres estaban atónitos; á los cuales él mandó, que á nadie dijesen lo que había sido hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 1, 'Y JUNTANDO á sus doce discípulos, les dió virtud y potestad sobre todos los demonios, y que sanasen enfermedades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 2, 'Y los envió á que predicasen el reino de Dios, y que sanasen á los enfermos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 3, 'Y les dice: No toméis nada para el camino, ni báculo, ni alforja, ni pan, ni dinero; ni tengáis dos vestidos cada uno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 4, 'Y en cualquiera casa en que entrareis, quedad allí, y de allí salid.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 5, 'Y todos los que no os recibieren, saliéndoos de aquella ciudad, aun el polvo sacudid de vuestros pies en testimonio contra ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 6, 'Y saliendo, rodeaban por todas las aldeas, anunciando el evangelio, y sanando por todas partes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 7, 'Y oyó Herodes el tetrarca todas las cosas que hacía; y estaba en duda, porque decían algunos: Juan ha resucitado de los muertos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 8, 'Y otros: Elías ha aparecido; y otros: Algún profeta de los antiguos ha resucitado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 9, 'Y dijo Herodes: A Juan yo degollé: ¿quién pues será éste, de quien yo oigo tales cosas? Y procuraba verle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 10, 'Y vueltos los apóstoles, le contaron todas las cosas que habían hecho. Y tomándolos, se retiró aparte á un lugar desierto de la ciudad que se llama Bethsaida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 11, 'Y como lo entendieron las gentes, le siguieron; y él las recibió, y les hablaba del reino de Dios, y sanaba á los que tenían necesidad de cura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 12, 'Y el día había comenzado á declinar; y llegándose los doce, le dijeron: Despide á las gentes, para que yendo á las aldeas y heredades de alrededor, procedan á alojarse y hallen viandas; porque aquí estamos en lugar desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 13, 'Y les dice: Dadles vosotros de comer. Y dijeron ellos: No tenemos más que cinco panes y dos pescados, si no vamos nosotros á comprar viandas para toda esta compañía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 14, 'Y eran como cinco mil hombres. Entonces dijo á sus discípulos: Hacedlos sentar en ranchos, de cincuenta en cincuenta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 15, 'Y así lo hicieron, haciéndolos sentar á todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 16, 'Y tomando los cinco panes y los dos pescados, mirando al cielo los bendijo, y partió, y dió á sus discípulos para que pusiesen delante de las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 17, 'Y comieron todos, y se hartaron; y alzaron lo que les sobró, doce cestos de pedazos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 18, 'Y aconteció que estando él solo orando, estaban con él los discípulos; y les preguntó diciendo: ¿Quién dicen las gentes que soy?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 19, 'Y ellos respondieron, y dijeron: Juan el Bautista; y otros, Elías; y otros, que algún profeta de los antiguos ha resucitado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 20, 'Y les dijo: ¿Y vosotros, quién decís que soy? Entonces respondiendo Simón Pedro, dijo: El Cristo de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 21, 'Mas él, conminándolos, mandó que á nadie dijesen esto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 22, 'Diciendo: Es necesario que el Hijo del hombre padezca muchas cosas, y sea desechado de los ancianos, y de los príncipes de los sacerdotes, y de los escribas, y que sea muerto, y resucite al tercer día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 23, 'Y decía á todos: Si alguno quiere venir en pos de mí, niéguese á sí mismo, y tome su cruz cada día, y sígame.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 24, 'Porque cualquiera que quisiere salvar su vida, la perderá; y cualquiera que perdiere su vida por causa de mí, éste la salvará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 25, 'Porque ¿qué aprovecha al hombre, si granjeare todo el mundo, y sé pierda él á sí mismo, ó corra peligro de sí?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 26, 'Porque el que se avergonzare de mí y de mis palabras, de este tal el Hijo del hombre se avergonzará cuando viniere en su gloria, y del Padre, y de los santos ángeles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 27, 'Y os digo en verdad, que hay algunos de los que están aquí, que no gustarán la muerte, hasta que vean el reino de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 28, 'Y aconteció como ocho días después de estas palabras, que tomó á Pedro y á Juan y á Jacobo, y subió al monte á orar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 29, 'Y entre tanto que oraba, la apariencia de su rostro se hizo otra, y su vestido blanco y resplandeciente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 30, 'Y he aquí dos varones que hablaban con él, los cuales eran Moisés y Elías;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 31, 'Que aparecieron en majestad, y hablaban de su salida, la cual había de cumplir en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 32, 'Y Pedro y los que estaban con él, estaban cargados de sueño: y como despertaron, vieron su majestad, y á aquellos dos varones que estaban con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 33, 'Y aconteció, que apartándose ellos de él, Pedro dice á Jesús: Maestro, bien es que nos quedemos aquí: y hagamos tres pabellones, uno para ti, y uno para Moisés, y uno para Elías; no sabiendo lo que se decía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 34, 'Y estando él hablando esto, vino una nube que los cubrió; y tuvieron temor entrando ellos en la nube.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 35, 'Y vino una voz de la nube, que decía: Este es mi Hijo amado; á él oid.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 36, 'Y pasada aquella voz, Jesús fué hallado solo: y ellos callaron; y por aquellos días no dijeron nada á nadie de lo que habían visto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 37, 'Y aconteció al día siguiente, que apartándose ellos del monte, gran compañía les salió al encuentro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 38, 'Y he aquí, un hombre de la compañía clamó, diciendo: Maestro, ruégote que veas á mi hijo; que es el único que tengo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 39, 'Y he aquí un espíritu le toma, y de repente da voces; y le despedaza y hace echar espuma, y apenas se aparta de él quebrantándole.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 40, 'Y rogué á tus discípulos que le echasen fuera, y no pudieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 41, 'Y respondiendo Jesús, dice: ¡Oh generación infiel y perversa! ¿hasta cuándo tengo de estar con vosotros, y os sufriré? Trae tu hijo acá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 42, 'Y como aun se acercaba, el demonio le derribó y despedazó: mas Jesús increpó al espíritu inmundo, y sanó al muchacho, y se lo volvió á su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 43, 'Y todos estaban atónitos de la grandeza de Dios. Y maravillándose todos de todas las cosas que hacía, dijo á sus discípulos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 44, 'Poned vosotros en vuestros oídos estas palabras; porque ha de acontecer que el Hijo del hombre será entregado en manos de hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 45, 'Mas ellos no entendían esta palabra, y les era encubierta para que no la entendiesen; y temían preguntarle de esta palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 46, 'Entonces entraron en disputa, cuál de ellos sería el mayor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 47, 'Mas Jesús, viendo los pensamientos del corazón de ellos, tomó un niño, y púsole junto á sí,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 48, 'Y les dice: Cualquiera que recibiere este niño en mí nombre, á mí recibe; y cualquiera que me recibiere á mí, recibe al que me envió; porque el que fuere el menor entre todos vosotros, éste será el grande.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 49, 'Entonces respondiendo Juan, dijo: Maestro, hemos visto á uno que echaba fuera demonios en tu nombre; y se lo prohibimos, porque no sigue con nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 50, 'Jesús le dijo: No se lo prohibáis; porque el que no es contra nosotros, por nosotros es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 51, 'Y aconteció que, como se cumplió el tiempo en que había de ser recibido arriba, él afirmó su rostro para ir á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 52, 'Y envió mensajeros delante de sí, los cuales fueron y entraron en una ciudad de los Samaritanos, para prevenirle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 53, 'Mas no le recibieron, porque era su traza de ir á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 54, 'Y viendo esto sus discípulos Jacobo y Juan, dijeron: Señor, ¿quieres que mandemos que descienda fuego del cielo, y los consuma, como hizo Elías?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 55, 'Entonces volviéndose él, los reprendió, diciendo: Vosotros no sabéis de qué espíritu sois;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 56, 'Porque el Hijo del hombre no ha venido para perder las almas de los hombres, sino para salvarlas. Y se fueron á otra aldea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 57, 'Y aconteció que yendo ellos, uno le dijo en el camino: Señor, te seguiré donde quiera que fueres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 58, 'Y le dijo Jesús: Las zorras tienen cuevas, y las aves de los cielos nidos; mas el Hijo del hombre no tiene donde recline la cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 59, 'Y dijo á otro: Sígueme. Y él dijo: Señor, déjame que primero vaya y entierre á mi padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 60, 'Y Jesús le dijo: Deja los muertos que entierren á sus muertos; y tú, ve, y anuncia el reino de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 61, 'Entonces también dijo otro: Te seguiré, Señor; mas déjame que me despida primero de los que están en mi casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 9, 62, 'Y Jesús le dijo: Ninguno que poniendo su mano al arado mira atrás, es apto para el reino de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 1, 'Y DESPUÉS de estas cosas, designó el Señor aun otros setenta, los cuales envió de dos en dos delante de sí, á toda ciudad y lugar á donde él había de venir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 2, 'Y les decía: La mies á la verdad es mucha, mas los obreros pocos; por tanto, rogad al Señor de la mies que envíe obreros á su mies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 3, 'Andad, he aquí yo os envío como corderos en medio de lobos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 4, 'No llevéis bolsa, ni alforja, ni calzado; y á nadie saludéis en el camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 5, 'En cualquiera casa donde entrareis, primeramente decid: Paz sea á esta casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 6, 'Y si hubiere allí algún hijo de paz, vuestra paz reposará sobre él; y si no, se volverá á vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 7, 'Y posad en aquella misma casa, comiendo y bebiendo lo que os dieren; porque el obrero digno es de su salario. No os paséis de casa en casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 8, 'Y en cualquiera ciudad donde entrareis, y os recibieren, comed lo que os pusieren delante;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 9, 'Y sanad los enfermos que en ella hubiere, y decidles: Se ha llegado á vosotros el reino de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 10, 'Mas en cualquier ciudad donde entrareis, y no os recibieren, saliendo por sus calles, decid:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 11, 'Aun el polvo que se nos ha pegado de vuestra ciudad á nuestros pies, sacudimos en vosotros: esto empero sabed, que el reino de los cielos se ha llegado á vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 12, 'Y os digo que los de Sodoma tendrán más remisión aquel día, que aquella ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 13, '¡Ay de ti, Corazín! ¡Ay de ti, Bethsaida! que si en Tiro y en Sidón hubieran sido hechas las maravillas que se han hecho en vosotras, ya días ha que, sentados en cilicio y ceniza, se habrían arrepentido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 14, 'Por tanto, Tiro y Sidón tendrán más remisión que vosotras en el juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 15, 'Y tú, Capernaum, que hasta los cielos estás levantada, hasta los infiernos serás abajada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 16, 'El que á vosotros oye, á mí oye; y el que á vosotros desecha, á mí desecha; y el que á mí desecha, desecha al que me envió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 17, 'Y volvieron los setenta con gozo, diciendo: Señor, aun los demonios se nos sujetan en tu nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 18, 'Y les dijo: Yo veía á Satanás, como un rayo, que caía del cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 19, 'He aquí os doy potestad de hollar sobre las serpientes y sobre los escorpiones, y sobre toda fuerza del enemigo, y nada os dañará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 20, 'Mas no os gocéis de esto, que los espíritus se os sujetan; antes gozaos de que vuestros nombres están escritos en los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 21, 'En aquella misma hora Jesús se alegró en espíritu, y dijo: Yo te alabo, oh Padre, Señor del cielo y de la tierra, que escondiste estas cosas á los sabios y entendidos, y las has revelado á los pequeños: así, Padre, porque así te agradó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 22, 'Todas las cosas me son entregadas de mi Padre: y nadie sabe quién sea el Hijo sino el Padre; ni quién sea el Padre, sino el Hijo, y á quien el Hijo lo quisiere revelar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 23, 'Y vuelto particularmente á los discípulos, dijo: Bienaventurados los ojos que ven lo que vosotros veis:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 24, 'Porque os digo que muchos profetas y reyes desearon ver lo que vosotros veis, y no lo vieron; y oir lo que oís, y no lo oyeron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 25, 'Y he aquí, un doctor de la ley se levantó, tentándole y diciendo: Maestro, ¿haciendo qué cosa poseeré la vida eterna?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 26, 'Y él dijo: ¿Qué está escrito de la ley? ¿cómo lees?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 27, 'Y él respondiendo, dijo: Amarás al Señor tu Dios de todo tu corazón, y de toda tu alma, y de todas tus fuerzas, y de todo tu entendimiento; y á tu prójimo como á ti mismo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 28, 'Y díjole: Bien has respondido: haz esto, y vivirás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 29, 'Mas él, queriéndose justificar á sí mismo, dijo á Jesús: ¿Y quién es mi prójimo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 30, 'Y respondiendo Jesús, dijo: Un hombre descendía de Jerusalem á Jericó, y cayó en manos de ladrones, los cuales le despojaron; é hiriéndole, se fueron, dejándole medio muerto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 31, 'Y aconteció, que descendió un sacerdote por aquel camino, y viéndole, se pasó de un lado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 32, 'Y asimismo un Levita, llegando cerca de aquel lugar, y viéndole, se pasó de un lado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 33, 'Mas un Samaritano que transitaba, viniendo cerca de él, y viéndole, fué movido á misericordia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 34, 'Y llegándose, vendó sus heridas, echándo les aceite y vino; y poniéndole sobre su cabalgadura, llevóle al mesón, y cuidó de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 35, 'Y otro día al partir, sacó dos denarios, y diólos al huésped, y le dijo: Cuídamele; y todo lo que de más gastares, yo cuando vuelva te lo pagaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 36, '¿Quién, pues, de estos tres te parece que fué el prójimo de aquél que cayó en manos de los ladrónes?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 37, 'Y él dijo: El que usó con él de misericordia. Entonces Jesús le dijo: Ve, y haz tú lo mismo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 38, 'Y aconteció que yendo, entró él en una aldea: y una mujer llamada Marta, le recibió en su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 39, 'Y ésta tenía una hermana que se llamaba María, la cual sentándose á los pies de Jesús, oía su palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 40, 'Empero Marta se distraía en muchos servicios; y sobreviniendo, dice: Señor, ¿no tienes cuidado que mi hermana me deja servir sola? Dile pues, que me ayude.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 41, 'Pero respondiendo Jesús, le dijo: Marta, Marta, cuidadosa estás, y con las muchas cosas estás turbada:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 10, 42, 'Empero una cosa es necesaria; y María escogió la buena parte, la cual no le será quitada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 1, 'Y ACONTECIO que estando él orando en un lugar, como acabó, uno de sus discípulos le dijo: Señor, enséñanos á orar, como también Juan enseñó á sus discípulos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 2, 'Y les dijo: Cuando orareis, decid: Padre nuestro que estás en los cielos; sea tu nombre santificado. Venga tu reino. Sea hecha tu voluntad, como en el cielo, así también en la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 3, 'El pan nuestro de cada día, dános lo hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 4, 'Y perdónanos nuestros pecados, porque también nosotros perdonamos á todos los que nos deben. Y no nos metas en tentación, mas líbranos del malo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 5, 'Díjoles también: ¿Quién de vosotros tendrá un amigo, é irá á él á media noche, y le dirá: Amigo, préstame tres panes,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 6, 'Porque un amigo mío ha venido á mí de camino, y no tengo que ponerle delante;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 7, 'Y el de dentro respondiendo, dijere: No me seas molesto; la puerta está ya cerrada, y mis niños están conmigo en cama; no puedo levantarme, y darte?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 8, 'Os digo, que aunque no se levante á darle por ser su amigo, cierto por su importunidad se levantará, y le dará todo lo que habrá menester.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 9, 'Y yo os digo: Pedid, y se os dará; buscad, y hallaréis; llamad, y os será abierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 10, 'Porque todo aquel que pide, recibe; y el que busca, halla; y al que llama, se abre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 11, '¿Y cuál padre de vosotros, si su hijo le pidiere pan, le dará una piedra?, ó, si pescado, ¿en lugar de pescado, le dará una serpiente?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 12, 'O, si le pidiere un huevo, ¿le dará un escorpión?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 13, 'Pues si vosotros, siendo malos, sabéis dar buenas dádivas á vuestros hijos, ¿cuánto más vuestro Padre celestial dará el Espíritu Santo á los que lo pidieren de él?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 14, 'Y estaba él lanzando un demonio, el cual era mudo: y aconteció que salido fuera el demonio, el mudo habló y las gentes se maravillaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 15, 'Mas algunos de ellos decían: En Beelzebub, príncipe de los demonios, echa fuera los demonios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 16, 'Y otros, tentando, pedían de él señal del cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 17, 'Mas él, conociendo los pensamientos de ellos, les dijo: Todo reino dividido contra sí mismo, es asolado; y una casa dividida contra sí misma, cae.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 18, 'Y si también Satanás está dividido contra sí mismo, ¿cómo estará en pie su reino? porque decís que en Beelzebub echo yo fuera los demonios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 19, 'Pues si yo echo fuera los demonios en Beelzebub, ¿vuestros hijos en quién los echan fuera? Por tanto, ellos serán vuestros jueces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 20, 'Mas si por el dedo de Dios echo yo fuera los demonios, cierto el reino de Dios ha llegado á vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 21, 'Cuando el fuerte armado guarda su atrio, en paz está lo que posee.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 22, 'Mas si sobreviniendo otro más fuerte que él, le venciere, le toma todas sus armas en que confiaba, y reparte sus despojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 23, 'El que no es conmigo, contra mí es; y el que conmigo no recoge, desparrama.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 24, 'Cuando el espíritu inmundo saliere del hombre, anda por lugares secos, buscando reposo; y no hallándolo, dice: Me volveré á mi casa de donde salí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 25, 'Y viniendo, la halla barrida y adornada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 26, 'Entonces va, y toma otros siete espíritus peores que él; y entrados, habitan allí: y lo postrero del tal hombre es peor que lo primero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 27, 'Y aconteció que diciendo estas cosas, una mujer de la compañía, levantando la voz, le dijo: Bienaventurado el vientre que te trajo, y los pechos que mamaste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 28, 'Y él dijo: Antes bienaventurados los que oyen la palabra de Dios, y la guardan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 29, 'Y juntándose las gentes á él, comenzó á decir: Esta generación mala es: señal busca, mas señal no le será dada, sino la señal de Jonás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 30, 'Porque como Jonás fué señal á los Ninivitas, así también será el Hijo del hombre á esta generación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 31, 'La reina del Austro se levantará en juicio con los hombres de esta generación, y los condenará; porque vino de los fines de la tierra á oir la sabiduría de Salomón; y he aquí más que Salomón en este lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 32, 'Los hombres de Nínive se levantarán en juicio con esta generación, y la condenarán; porque á la predicación de Jonás se arrepintieron; y he aquí más que Jonás en este lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 33, 'Nadie pone en oculto la antorcha encendida, ni debajo del almud, sino en el candelero, para que los que entran vean la luz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 34, 'La antorcha del cuerpo es el ojo: pues si tu ojo fuere simple, también todo tu cuerpo será resplandeciente; mas si fuere malo, también tu cuerpo será tenebroso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 35, 'Mira pues, si la lumbre que en ti hay, es tinieblas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 36, 'Así que, siendo todo tu cuerpo resplandeciente, no teniendo alguna parte de tinieblas, será todo luminoso, como cuando una antorcha de resplandor te alumbra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 37, 'Y luego que hubo hablado, rogóle un Fariseo que comiese con él: y entrado Jesús, se sentó á la mesa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 38, 'Y el Fariseo, como lo vió, maravillóse de que no se lavó antes de comer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 39, 'Y el Señor le dijo: Ahora vosotros los Fariseos lo de fuera del vaso y del plato limpiáis; mas lo interior de vosotros está lleno de rapiña y de maldad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 40, 'Necios, ¿el que hizo lo de fuera, no hizo también lo de dentro?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 41, 'Empero de lo que os resta, dad limosna; y he aquí todo os será limpio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 42, 'Mas ¡ay de vosotros, Fariseos! que diezmáis la menta, y la ruda, y toda hortliza; mas el juicio y la caridad de Dios pasáis de largo. Pues estas cosas era necesario hacer, y no dejar las otras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 43, '¡Ay de vosotros, Fariseos! que amáis las primeras sillas en las sinagogas, y las salutaciones en las plazas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 44, '¡Ay de vosotros, escribas y Fariseos, hipócritas! que sois como sepulcros que no se ven, y los hombres que andan encima no lo saben.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 45, 'Y respondiendo uno de los doctores de la ley, le dice: Maestro, cuando dices esto, también nos afrentas á nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 46, 'Y él dijo: ¡Ay de vosotros también, doctores de la ley! que cargáis á los hombres con cargas que no pueden llevar; mas vosotros ni aun con un dedo tocáis las cargas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 47, '¡Ay de vosotros! que edificáis los sepulcros de los profetas, y los mataron vuestros padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 48, 'De cierto dais testimonio que consentís en los hechos de vuestros padres; porque á la verdad ellos los mataron, mas vosotros edificáis sus sepulcros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 49, 'Por tanto, la sabiduría de Dios también dijo: Enviaré á ellos profetas y apóstoles; y de ellos á unos matarán y á otros perseguirán;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 50, 'Para que de esta generación sea demandada la sangre de todos los profetas, que ha sido derramada desde la fundación del mundo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 51, 'Desde la sangre de Abel, hasta la sangre de Zacarías, que murió entre el altar y el templo: así os digo, será demandada de esta generación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 52, '¡Ay de vosotros, doctores de la ley! que habéis quitado la llave de la ciencia; vosotros mismos no entrasteis, y á los que entraban impedisteis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 53, 'Y diciéndoles estas cosas, los escribas y los Fariseos comenzaron á apretar le en gran manera, y á provocarle á que hablase de muchas cosas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 11, 54, 'Acechándole, y procurando cazar algo de su boca para acusarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 1, 'EN esto, juntándose muchas gentes, tanto que unos á otros se hollaban, comenzó á decir á sus discípulos, primeramente: Guardaos de la levadura de los Fariseos, que es hipocresía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 2, 'Porque nada hay encubierto, que no haya de ser descubierto; ni oculto, que no haya de ser sabido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 3, 'Por tanto, las cosas que dijisteis en tinieblas, á la luz serán oídas; y lo que hablasteis al oído en las cámaras, será pregonado en los terrados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 4, 'Mas os digo, amigos míos: No temáis de los que matan el cuerpo, y después no tienen más que hacer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 5, 'Mas os enseñaré á quién temáis: temed á aquel que después de haber quitado la vida, tiene poder de echar en la Gehenna: así os digo: á éste temed.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 6, '¿No se venden cinco pajarillos por dos blancas? pues ni uno de ellos está olvidado delante de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 7, 'Y aun los cabellos de vuestra cabeza están todos contados. No temáis pues: de más estima sois que muchos pajarillos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 8, 'Y os digo que todo aquel que me confesare delante de los hombres, también el Hijo del hombre le confesará delante de los ángeles de Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 9, 'Mas el que me negare delante de los hombres, será negado delante de los ángeles de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 10, 'Y todo aquel que dice palabra contra el Hijo del hombre, le será perdonado; mas al que blasfemare contra el Espíritu Santo, no le será perdonado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 11, 'Y cuando os trajeren á las sinagogas, y á los magistrados y potestades, no estéis solícitos cómo ó qué hayáis de responder, ó qué hayáis de decir;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 12, 'Porque el Espíritu Santo os enseñará en la misma hora lo que será necesario decir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 13, 'Y díjole uno de la compañía: Maestro, di á mi hermano que parta conmigo la herencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 14, 'Mas él le dijo: Hombre, ¿quién me puso por juez ó partidor sobre vosotros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 15, 'Y díjoles: Mirad, y guardaos de toda avaricia; porque la vida del hombre no consiste en la abundancia de los bienes que posee.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 16, 'Y refirióles una parábola, diciendo: La heredad de un hombre rico había llevado mucho;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 17, 'Y él pensaba dentro de sí, diciendo: ¿qué haré, porque no tengo donde juntar mis frutos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 18, 'Y dijo: Esto haré: derribaré mis alfolíes, y los edificaré mayores, y allí juntaré todos mis frutos y mis bienes;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 19, 'Y diré á mi alma: Alma, muchos bienes tienes almacenados para muchos años; repósate, come, bebe, huélgate.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 20, 'Y díjole Dios: Necio, esta noche vuelven á pedir tu alma; y lo que has prevenido, ¿de quién será?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 21, 'Así es el que hace para sí tesoro, y no es rico en Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 22, 'Y dijo á sus discípulos: Por tanto os digo: No estéis afanosos de vuestra vida, qué comeréis; ni del cuerpo, qué vestiréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 23, 'La vida más es que la comida, y el cuerpo que el vestido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 24, 'Considerad los cuervos, que ni siembran, ni siegan; que ni tienen cillero, ni alfolí; y Dios los alimenta. ¿Cuánto de más estima sois vosotros que las aves?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 25, '¿Y quién de vosotros podrá con afán añadir á su estatura un codo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 26, 'Pues si no podéis aun lo que es menos, ¿para qué estaréis afanosos de lo demás?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 27, 'Considerad los lirios, cómo crecen: no labran, ni hilan; y os digo, que ni Salomón con toda su gloria se vistió como uno de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 28, 'Y si así viste Dios á la hierba, que hoy está en el campo, y mañana es echada en el horno; ¿cuánto más á vosotros, hombres de poca fe?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 29, 'Vosotros, pues, no procuréis qué hayáis de comer, ó qué hayáis de beber: ni estéis en ansiosa perplejidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 30, 'Porque todas estas cosas buscan las gentes del mundo; que vuestro Padre sabe que necesitáis estas cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 31, 'Mas procurad el reino de Dios, y todas estas cosas os serán añadidas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 32, 'No temáis, manada pequeña; porque al Padre ha placido daros el reino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 33, 'Vended lo que poseéis, y dad limosna; haceos bolsas que no se envejecen, tesoro en los cielos que nunca falta; donde ladrón no llega, ni polilla corrompe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 34, 'Porque donde está vuestro tesoro, allí también estará vuestro corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 35, 'Estén ceñidos vuestros lomos, y vuestras antorchas encendidas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 36, 'Y vosotros semejantes á hombres que esperan cuando su señor ha de volver de las bodas; para que cuando viniere, y llamare, luego le abran.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 37, 'Bienaventurados aquellos siervos, á los cuales cuando el Señor viniere, hallare velando: de cierto os digo, que se ceñirá, y hará que se sienten á la mesa, y pasando les servirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 38, 'Y aunque venga á la segunda vigilia, y aunque venga á la tercera vigilia, y los hallare así, bienaventurados son los tales siervos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 39, 'Esto empero sabed, que si supiese el padre de familia á qué hora había de venir el ladrón, velaría ciertamente, y no dejaría minar su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 40, 'Vosotros pues también, estad apercibidos; porque á la hora que no pensáis, el Hijo del hombre vendrá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 41, 'Entonces Pedro le dijo: Señor, ¿dices esta parábola á nosotros, ó también á todos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 42, 'Y dijo el Señor: ¿Quién es el mayordomo fiel y prudente, al cual el señor pondrá sobre su familia, para que á tiempo les dé su ración?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 43, 'Bienaventurado aquel siervo, al cual, cuando el señor viniere, hallare haciendo así.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 44, 'En verdad os digo, que él le pondrá sobre todos sus bienes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 45, 'Mas si el tal siervo dijere en su corazón: Mi señor tarda en venir: y comenzare á herir á los siervos y á las criadas, y á comer y á beber y á embriagarse;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 46, 'Vendrá el señor de aquel siervo el día que no espera, y á la hora que no sabe, y le apartará, y pondrá su parte con los infieles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 47, 'Porque el siervo que entendió la voluntad de su señor, y no se apercibió, ni hizo conforme á su voluntad, será azotado mucho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 48, 'Mas el que no entendió, é hizo cosas dignas de azotes, será azotado poco: porque á cualquiera que fué dado mucho, mucho será vuelto á demandar de él; y al que encomendaron mucho, más le será pedido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 49, 'Fuego vine á meter en la tierra: ¿y qué quiero, si ya está encendido?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 50, 'Empero de bautismo me es necesario ser bautizado: y ¡cómo me angustio hasta que sea cumplido!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 51, '¿Pensáis que he venido á la tierra á dar paz? No, os digo; mas disensión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 52, 'Porque estarán de aquí adelante cinco en una casa divididos; tres contra dos, y dos contra tres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 53, 'El padre estará dividido contra el hijo, y el hijo contra el padre; la madre contra la hija, y la hija contra la madre; la suegra contra su nuera, y la nuera contra su suegra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 54, 'Y decía también á las gentes: Cuando veis la nube que sale del poniente, luego decís: Agua viene; y es así.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 55, 'Y cuando sopla el austro, decís: Habrá calor; y lo hay.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 56, '¡Hipócritas! Sabéis examinar la faz del cielo y de la tierra; ¿y cómo no reconocéis este tiempo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 57, '¿Y por qué aun de vosotros mismos no juzgáis lo que es justo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 58, 'Pues cuando vas al magistrado con tu adversario, procura en el camino librarte de él; porque no te arrastre al juez, y el juez te entregue al alguacil, y el alguacil te meta en la cárcel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 12, 59, 'Te digo que no saldrás de allá, hasta que hayas pagado hasta el último maravedí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 1, 'Y EN este mismo tiempo estaban allí unos que le contaban acerca de los Galileos, cuya sangre Pilato había mezclado con sus sacrificios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 2, 'Y respondiendo Jesús, les dijo: ¿Pensáis que estos Galileos, porque han padecido tales cosas, hayan sido más pecadores que todos los Galileos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 3, 'No, os digo; antes si no os arrepintiereis, todos pereceréis igualmente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 4, 'O aquellos dieciocho, sobre los cuales cayó la torre en Siloé, y los mató, ¿pensáis que ellos fueron más deudores que todos los hombres que habitan en Jerusalem?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 5, 'No, os digo; antes si no os arrepintiereis, todos pereceréis asimismo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 6, 'Y dijo esta parábola: Tenía uno una higuera plantada en su viña, y vino á buscar fruto en ella, y no lo halló.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 7, 'Y dijo al viñero: He aquí tres años ha que vengo á buscar fruto en esta higuera, y no lo hallo; córtala, ¿por qué ocupará aún la tierra?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 8, 'El entonces respondiendo, le dijo: Señor, déjala aún este año, hasta que la excave, y estercole.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 9, 'Y si hiciere fruto, bien; y si no, la cortarás después.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 10, 'Y enseñaba en una sinagoga en sábado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 11, 'Y he aquí una mujer que tenía espíritu de enfermedad dieciocho años, y andaba agobiada, que en ninguna manera se podía enhestar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 12, 'Y como Jesús la vió, llamóla, y díjole: Mujer, libre eres de tu enfermedad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 13, 'Y puso las manos sobre ella; y luego se enderezó, y glorificaba á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 14, 'Y respondiendo el príncipe de la sinagoga, enojado de que Jesús hubiese curado en sábado, dijo á la compañía: Seis días hay en que es necesario obrar: en estos, pues, venid y sed curados, y no en días de sábado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 15, 'Entonces el Señor le respondió, y dijo: Hipócrita, cada uno de vosotros ¿no desata en sábado su buey ó su asno del pesebre, y lo lleva á beber?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 16, 'Y á esta hija de Abraham, que he aquí Satanás la había ligado dieciocho años, ¿no convino desatar la de esta ligadura en día de sábado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 17, 'Y diciendo estas cosas, se avergonzaban todos sus adversarios: mas todo el pueblo se gozaba de todas las cosas gloriosas que eran por él hechas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 18, 'Y dijo: ¿A qué es semejante el reino de Dios, y á qué le compararé?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 19, 'Semejante es al grano de la mostaza, que tomándo lo un hombre lo metió en su huerto; y creció, y fué hecho árbol grande, y las aves del cielo hicieron nidos en sus ramas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 20, 'Y otra vez dijo: ¿A qué compararé el reino de Dios?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 21, 'Semejante es á la levadura, que tomó una mujer, y la escondió en tres medidas de harina, hasta que todo hubo fermentado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 22, 'Y pasaba por todas las ciudades y aldeas, enseñando, y caminando á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 23, 'Y díjole uno: Señor, ¿son pocos los que se salvan? Y él les dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 24, 'Porfiad á entrar por la puerta angosta; porque os digo que muchos procurarán entrar, y no podrán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 25, 'Después que el padre de familia se levantare, y cerrare la puerta, y comenzareis á estar fuera, y llamar á la puerta, diciendo: Señor, Señor, ábrenos; y respondiendo os dirá: No os conozco de dónde seáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 26, 'Entonces comenzaréis á decir: Delante de ti hemos comido y bebido, y en nuestras plazas enseñaste;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 27, 'Y os dirá: Dígoos que no os conozco de dónde seáis; apartaos de mí todos los obreros de iniquidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 28, 'Allí será el llanto y el crujir de dientes, cuando viereis á Abraham, y á Isaac, y á Jacob, y á todos los profetas en el reino de Dios, y vosotros excluídos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 29, 'Y vendrán del Oriente y del Occidente, del Norte y del Mediodía, y se sentarán á la mesa en el reino de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 30, 'Y he aquí, son postreros los que eran los primeros; y son primeros los que eran los postreros');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 31, 'Aquel mismo día llegaron unos de los Fariseos, diciéndole: Sal, y vete de aquí, porque Herodes te quiere matar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 32, 'Y les dijo: Id, y decid á aquella zorra: He aquí, echo fuera demonios y acabo sanidades hoy y mañana, y al tercer día soy consumado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 33, 'Empero es menester que hoy, y mañana, y pasado mañana camine; porque no es posible que profeta muera fuera de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 34, '¡Jerusalem, Jerusalem! que matas á los profetas, y apedreas á los que son enviados á ti: ¡cuántas veces quise juntar tus hijos, como la gallina sus pollos debajo de sus alas, y no quisiste!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 13, 35, 'He aquí, os es dejada vuestra casa desierta: y os digo que no me veréis hasta que venga tiempo cuando digáis: Bendito el que viene en nombre del Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 1, 'Y ACONTECIO que entrando en casa de un príncipe de los Fariseos un sábado á comer pan, ellos le acechaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 2, 'Y he aquí un hombre hidrópico estaba delante de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 3, 'Y respondiendo Jesús, habló á los doctores de la ley y á los Fariseos, diciendo: ¿Es lícito sanar en sábado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 4, 'Y ellos callaron. Entonces él tomándole, le sanó, y despidióle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 5, 'Y respondiendo á ellos dijo: ¿El asno ó el buey de cuál de vosotros caerá en algún pozo, y no lo sacará luego en día de sábado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 6, 'Y no le podían replicar á estas cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 7, 'Y observando cómo escogían los primeros asientos á la mesa, propuso una parábola á los convidados, diciéndoles:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 8, 'Cuando fueres convidado de alguno á bodas, no te sientes en el primer lugar, no sea que otro más honrado que tú esté por él convidado,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 9, 'Y viniendo el que te llamó á ti y á él, te diga: Da lugar á éste: y entonces comiences con vergüenza á tener el lugar último.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 10, 'Mas cuando fueres convidado, ve, y siéntate en el postrer lugar; porque cuando viniere el que te llamó, te diga: Amigo, sube arriba: entonces tendrás gloria delante de los que juntamente se asientan á la mesa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 11, 'Porque cualquiera que se ensalza, será humillado; y el que se humilla, será ensalzado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 12, 'Y dijo también al que le había convidado: Cuando haces comida ó cena, no llames á tus amigos, ni á tus hermanos, ni á tus parientes, ni á vecinos ricos; porque también ellos no te vuelvan á convidar, y te sea hecha compensación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 13, 'Mas cuando haces banquete, llama á los pobres, los mancos, los cojos, los ciegos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 14, 'Y serás bienaventurado; porque no te pueden retribuir; mas te será recompensado en la resurrección de los justos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 15, 'Y oyendo esto uno de los que juntamente estaban sentados á la mesa, le dijo: Bienaventurado el que comerá pan en el reino de los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 16, 'El entonces le dijo: Un hombre hizo una grande cena, y convido á muchos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 17, 'Y á la hora de la cena envió á su siervo á decir á los convidados: Venid, que ya está todo aparejado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 18, 'Y comenzaron todos á una á excusarse. El primero le dijo: He comprado una hacienda, y necesito salir y verla; te ruego que me des por excusado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 19, 'Y el otro dijo: He comprado cinco yuntas de bueyes, y voy á probarlos; ruégote que me des por excusado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 20, 'Y el otro dijo: Acabo de casarme, y por tanto no puedo ir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 21, 'Y vuelto el siervo, hizo saber estas cosas á su señor. Entonces enojado el padre de la familia, dijo á su siervo: Ve presto por las plazas y por las calles de la ciudad, y mete acá los pobres, los mancos, y cojos, y ciegos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 22, 'Y dijo el siervo: Señor, hecho es como mandaste, y aun hay lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 23, 'Y dijo el señor al siervo: Ve por los caminos y por los vallados, y fuérza los á entrar, para que se llene mi casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 24, 'Porque os digo que ninguno de aquellos hombres que fueron llamados, gustará mi cena.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 25, 'Y muchas gentes iban con él; y volviéndose les dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 26, 'Si alguno viene á mí, y no aborrece á su padre, y madre, y mujer, é hijos, y hermanos, y hermanas, y aun también su vida, no puede ser mi discípulo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 27, 'Y cualquiera que no trae su cruz, y viene en pos de mí, no puede ser mi discípulo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 28, 'Porque ¿cuál de vosotros, queriendo edificar una torre, no cuenta primero sentado los gastos, si tiene lo que necesita para acabarla?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 29, 'Porque después que haya puesto el fundamento, y no pueda acabarla, todos los que lo vieren, no comiencen á hacer burla de él,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 30, 'Diciendo: Este hombre comenzó á edificar, y no pudo acabar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 31, '¿O cuál rey, habiendo de ir á hacer guerra contra otro rey, sentándose primero no consulta si puede salir al encuentro con diez mil al que viene contra él con veinte mil?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 32, 'De otra manera, cuando aun el otro está lejos, le ruega por la paz, enviándo le embajada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 33, 'Así pues, cualquiera de vosotros que no renuncia á todas las cosas que posee, no puede ser mi discípulo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 34, 'Buena es la sal; mas si aun la sal fuere desvanecida, ¿con qué se adobará?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 14, 35, 'Ni para la tierra, ni para el muladar es buena; fuera la arrojan. Quien tiene oídos para oir, oiga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 1, 'Y SE llegaban á él todos los publicanos y pecadores á oirle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 2, 'Y murmuraban los Fariseos y los escribas, diciendo: Este á los pecadores recibe, y con ellos come.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 3, 'Y él les propuso esta parábola, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 4, '¿Qué hombre de vosotros, teniendo cien ovejas, si perdiere una de ellas, no deja las noventa y nueve en el desierto, y va á la que se perdió, hasta que la halle?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 5, 'Y hallada, la pone sobre sus hombros gozoso;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 6, 'Y viniendo á casa, junta á los amigos y á los vecinos, diciéndoles: Dadme el parabién, porque he hallado mi oveja que se había perdido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 7, 'Os digo, que así habrá más gozo en el cielo de un pecador que se arrepiente, que de noventa y nueve justos, que no necesitan arrepentimiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 8, '¿O qué mujer que tiene diez dracmas, si perdiere una dracma, no enciende el candil, y barre la casa, y busca con diligencia hasta hallarla?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 9, 'Y cuando la hubiere hallado, junta las amigas y las vecinas, diciendo: Dadme el parabién, porque he hallado la dracma que había perdido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 10, 'Así os digo que hay gozo delante de los ángeles de Dios por un pecador que se arrepiente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 11, 'Y dijo: Un hombre tenía dos hijos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 12, 'Y el menor de ellos dijo á su padre: Padre, dame la parte de la hacienda que me pertenece: y les repartió la hacienda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 13, 'Y no muchos días después, juntándolo todo el hijo menor, partió lejos á una provincia apartada; y allí desperdició su hacienda viviendo perdidamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 14, 'Y cuando todo lo hubo malgastado, vino una grande hambre en aquella provincia, y comenzóle á faltar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 15, 'Y fué y se llegó á uno de los ciudadanos de aquella tierra, el cual le envió á su hacienda para que apacentase los puercos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 16, 'Y deseaba henchir su vientre de las algarrobas que comían los puercos; mas nadie se las daba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 17, 'Y volviendo en sí, dijo: ¡Cuántos jornaleros en casa de mi padre tienen abundancia de pan, y yo aquí perezco de hambre!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 18, 'Me levantaré, é iré á mi padre, y le diré: Padre, he pecado contra el cielo y contra ti;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 19, 'Ya no soy digno de ser llamado tu hijo; hazme como á uno de tus jornaleros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 20, 'Y levantándose, vino á su padre. Y como aun estuviese lejos, viólo su padre, y fué movido á misericordia, y corrió, y echóse sobre su cuello, y besóle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 21, 'Y el hijo le dijo: Padre, he pecado contra el cielo, y contra ti, y ya no soy digno de ser llamado tu hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 22, 'Mas el padre dijo á sus siervos: Sacad el principal vestido, y vestidle; y poned un anillo en su mano, y zapatos en sus pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 23, 'Y traed el becerro grueso, y matadlo, y comamos, y hagamos fiesta:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 24, 'Porque este mi hijo muerto era, y ha revivido; habíase perdido, y es hallado. Y comenzaron á regocijarse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 25, 'Y su hijo el mayor estaba en el campo; el cual como vino, y llegó cerca de casa, oyó la sinfonía y las danzas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 26, 'Y llamando á uno de los criados, preguntóle qué era aquello.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 27, 'Y él le dijo: Tu hermano ha venido; y tu padre ha muerto el becerro grueso, por haberle recibido salvo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 28, 'Entonces se enojó, y no quería entrar. Salió por tanto su padre, y le rogaba que entrase.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 29, 'Mas él respondiendo, dijo al padre: He aquí tantos años te sirvo, no habiendo traspasado jamás tu mandamiento, y nunca me has dado un cabrito para gozarme con mis amigos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 30, 'Mas cuando vino éste tu hijo, que ha consumido tu hacienda con rameras, has matado para él el becerro grueso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 31, 'El entonces le dijo: Hijo, tú siempre estás conmigo, y todas mis cosas son tuyas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 15, 32, 'Mas era menester hacer fiesta y holgar nos, porque este tu hermano muerto era, y ha revivido; habíase perdido, y es hallado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 1, 'Y DIJO también á sus discípulos: Había un hombre rico, el cual tenía un mayordomo, y éste fué acusado delante de él como disipador de sus bienes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 2, 'Y le llamó, y le dijo: ¿Qué es esto que oigo de ti? Da cuenta de tu mayordomía, porque ya no podrás más ser mayordomo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 3, 'Entonces el mayordomo dijo dentro de sí: ¿Qué haré? que mi señor me quita la mayordomía. Cavar, no puedo; mendigar, tengo vergüenza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 4, 'Yo sé lo que haré para que cuando fuere quitado de la mayordomía, me reciban en sus casas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 5, 'Y llamando á cada uno de los deudores de su señor, dijo al primero: ¿Cuánto debes á mi señor?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 6, 'Y él dijo: Cien barriles de aceite. Y le dijo: Toma tu obligación, y siéntate presto, y escribe cincuenta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 7, 'Después dijo á otro: ¿Y tú, cuánto debes? Y él dijo: Cien coros de trigo. Y él le dijo: Toma tu obligación, y escribe ochenta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 8, 'Y alabó el señor al mayordomo malo por haber hecho discretamente; porque los hijos de este siglo son en su generación más sagaces que los hijos de luz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 9, 'Y yo os digo: Haceos amigos de las riquezas de maldad, para que cuando faltareis, os reciban en las moradas eternas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 10, 'El que es fiel en lo muy poco, también en lo más es fiel: y el que en lo muy poco es injusto, también en lo más es injusto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 11, 'Pues si en las malas riquezas no fuísteis fieles. ¿quién os confiará lo verdadero?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 12, 'Y si en lo ajeno no fuisteis fieles, ¿quién os dará lo que es vuestro?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 13, 'Ningún siervo puede servir á dos señores; porque ó aborrecerá al uno y amará al otro, ó se allegará al uno y menospreciará al otro. No podéis servir á Dios y á las riquezas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 14, 'Y oían también todas estas cosas los Fariseos, los cuales eran avaros, y se burlaban de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 15, 'Y díjoles: Vosotros sois los que os justificáis á vosotros mismos delante de los hombres; mas Dios conoce vuestros corazones; porque lo que los hombres tienen por sublime, delante de Dios es abominación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 16, 'La ley y los profetas hasta Juan: desde entonces el reino de Dios es anunciado, y quienquiera se esfuerza á entrar en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 17, 'Empero más fácil cosa es pasar el cielo y la tierra, que frustrarse un tilde de la ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 18, 'Cualquiera que repudia á su mujer, y se casa con otra, adultera: y el que se casa con la repudiada del marido, adultera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 19, 'Había un hombre rico, que se vestía de púrpura y de lino fino, y hacía cada día banquete con esplendidez.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 20, 'Había también un mendigo llamado Lázaro, el cual estaba echado á la puerta de él, lleno de llagas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 21, 'Y deseando hartarse de las migajas que caían de la mesa del rico; y aun los perros venían y le lamían las llagas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 22, 'Y aconteció que murió el mendigo, y fué llevado por los ángeles al seno de Abraham: y murió también el rico, y fué sepultado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 23, 'Y en el infierno alzó sus ojos, estando en los tormentos, y vió á Abraham de lejos, y á Lázaro en su seno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 24, 'Entonces él, dando voces, dijo: Padre Abraham, ten misericordia de mí, y envía á Lázaro que moje la punta de su dedo en agua, y refresque mi lengua; porque soy atormentado en esta llama.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 25, 'Y díjole Abraham: Hijo, acuérdate que recibiste tus bienes en tu vida, y Lázaro también males; mas ahora éste es consolado aquí, y tú atormentado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 26, 'Y además de todo esto, una grande sima está constituída entre nosotros y vosotros, que los que quisieren pasar de aquí á vosotros, no pueden, ni de allá pasar acá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 27, 'Y dijo: Ruégote pues, padre, que le envíes á la casa de mi padre;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 28, 'Porque tengo cinco hermanos; para que les testifique, porque no vengan ellos también á este lugar de tormento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 29, 'Y Abraham le dice: A Moisés y á los profetas tienen: óiganlos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 30, 'El entonces dijo: No, padre Abraham: mas si alguno fuere á ellos de los muertos, se arrepentirán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 16, 31, 'Mas Abraham le dijo: Si no oyen á Moisés y á los profetas, tampoco se persuadirán, si alguno se levantare de los muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 1, 'Y A SUS discípulos dice: Imposible es que no vengan escándalos; mas ¡ay de aquél por quien vienen!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 2, 'Mejor le fuera, si le pusiesen al cuello una piedra de molino, y le lanzasen en el mar, que escandalizar á uno de estos pequeñitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 3, 'Mirad por vosotros: si pecare contra ti tu hermano, repréndele; y si se arrepintiere, perdónale.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 4, 'Y si siete veces al día pecare contra ti, y siete veces al día se volviere á ti, diciendo, pésame, perdónale.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 5, 'Y dijeron los apóstoles al Señor: Auméntanos la fe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 6, 'Entonces el Señor dijo: Si tuvieseis fe como un grano de mostaza, diréis á este sicómoro: Desarráigate, y plántate en el mar; y os obedecerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 7, '¿Y quién de vosotros tiene un siervo que ara ó apacienta, que vuelto del campo le diga luego: Pasa, siéntate á la mesa?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 8, '¿No le dice antes: Adereza qué cene, y arremángate, y sírveme hasta que haya comido y bebido; y después de esto, come tú y bebe?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 9, '¿Da gracias al siervo porque hizo lo que le había sido mandado? Pienso que no.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 10, 'Así también vosotros, cuando hubiereis hecho todo lo que os es mandado, decid: Siervos inútiles somos, porque lo que debíamos hacer, hicimos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 11, 'Y aconteció que yendo él á Jerusalem, pasaba por medio de Samaria y de Galilea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 12, 'Y entrando en una aldea, viniéronle al encuentro diez hombres leprosos, los cuales se pararon de lejos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 13, 'Y alzaron la voz, diciendo: Jesús, Maestro, ten misericordia de nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 14, 'Y como él los vió, les dijo: Id, mostraos á los sacerdotes. Y aconteció, que yendo ellos, fueron limpios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 15, 'Entonces uno de ellos, como se vió que estaba limpio, volvió, glorificando á Dios á gran voz;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 16, 'Y derribóse sobre el rostro á sus pies, dándole gracias: y éste era Samaritano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 17, 'Y respondiendo Jesús, dijo: ¿No son diez los que fueron limpios? ¿Y los nueve dónde están?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 18, '¿No hubo quien volviese y diese gloria á Dios sino este extranjero?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 19, 'Y díjole: Levántate, vete; tu fe te ha salvado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 20, 'Y preguntado por los Fariseos, cuándo había de venir el reino de Dios, les respondió y dijo: El reino de Dios no vendrá con advertencia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 21, 'Ni dirán: Helo aquí, ó helo allí: porque he aquí el reino de Dios entre vosotros está.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 22, 'Y dijo á sus discípulos: Tiempo vendrá, cuando desearéis ver uno de los días del Hijo del hombre, y no lo veréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 23, 'Y os dirán: Helo aquí, ó helo allí. No vayáis, ni sigáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 24, 'Porque como el relámpago, relampagueando desde una parte de debajo del cielo, resplandece hasta la otra debajo del cielo, así también será el Hijo del hombre en su día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 25, 'Mas primero es necesario que padezca mucho, y sea reprobado de esta generación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 26, 'Y como fué en los días de Noé, así también será en los días del Hijo del hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 27, 'Comían, bebían, los hombres tomaban mujeres, y las mujeres maridos, hasta el día que entró Noé en el arca; y vino el diluvio, y destruyó á todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 28, 'Asimismo también como fué en los días de Lot; comían, bebían, compraban, vendían, plantaban, edificaban;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 29, 'Mas el día que Lot salió de Sodoma, llovió del cielo fuego y azufre, y destruyó á todos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 30, 'Como esto será el día en que el Hijo del hombre se manifestará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 31, 'En aquel día, el que estuviere en el terrado, y sus alhajas en casa, no descienda á tomarlas: y el que en el campo, asimismo no vuelva atrás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 32, 'Acordaos de la mujer de Lot.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 33, 'Cualquiera que procurare salvar su vida, la perderá; y cualquiera que la perdiere, la salvará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 34, 'Os digo que en aquella noche estarán dos en una cama; el uno será tomado, y el otro será dejado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 35, 'Dos mujeres estarán moliendo juntas: la una será tomada, y la otra dejada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 36, 'Dos estarán en el campo; el uno será tomado, y el otro dejado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 17, 37, 'Y respondiendo, le dicen: ¿Dónde, Señor? Y él les dijo: Donde estuviere el cuerpo, allá se juntarán también las águilas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 1, 'Y PROPUSOLES también una parábola sobre que es necesario orar siempre, y no desmayar,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 2, 'Diciendo: Había un juez en una ciudad, el cual ni temía á Dios, ni respetaba á hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 3, 'Había también en aquella ciudad una viuda, la cual venía á él diciendo: Hazme justicia de mi adversario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 4, 'Pero él no quiso por algún tiempo; mas después de esto dijo dentro de sí: Aunque ni temo á Dios, ni tengo respeto á hombre,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 5, 'Todavía, porque esta viuda me es molesta, le haré justicia, porque al fin no venga y me muela.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 6, 'Y dijo el Señor: Oid lo que dice el juez injusto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 7, '¿Y Dios no hará justicia á sus escogidos, que claman á él día y noche, aunque sea longánime acerca de ellos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 8, 'Os digo que los defenderá presto. Empero cuando el Hijo del hombre viniere, ¿hallará fe en la tierra?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 9, 'Y dijo también á unos que confiaban de sí como justos, y menospreciaban á los otros, esta parábola:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 10, 'Dos hombres subieron al templo á orar: el uno Fariseo, el otro publicano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 11, 'El Fariseo, en pie, oraba consigo de esta manera: Dios, te doy gracias, que no soy como los otros hombres, ladrones, injustos, adúlteros, ni aun como este publicano;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 12, 'Ayuno dos veces á la semana, doy diezmos de todo lo que poseo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 13, 'Mas el publicano estando lejos no quería ni aun alzar los ojos al cielo, sino que hería su pecho, diciendo: Dios, sé propició á mí pecador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 14, 'Os digo que éste descendió á su casa justificado antes que el otro; porque cualquiera que se ensalza, será humillado; y el que se humilla, será ensalzado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 15, 'Y traían á él los niños para que los tocase; lo cual viendo los discípulos les reñían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 16, 'Mas Jesús llamándolos, dijo: Dejad los niños venir á mí, y no los impidáis; porque de tales es el reino de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 17, 'De cierto os digo, que cualquiera que no recibiere el reino de Dios como un niño, no entrará en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 18, 'Y preguntóle un príncipe, diciendo: Maestro bueno, ¿qué haré para poseer la vida eterna?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 19, 'Y Jesús le dijo: ¿Por qué me llamas bueno? ninguno hay bueno sino sólo Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 20, 'Los mandamientos sabes: No matarás: No adulterarás: No hurtarás: No dirás falso testimonio: Honra á tu padre y á tu madre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 21, 'Y él dijo: Todas estas cosas he guardado desde mi juventud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 22, 'Y Jesús, oído esto, le dijo: Aun te falta una cosa: vende todo lo que tienes, y da á los pobres, y tendrás tesoro en el cielo; y ven, sígueme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 23, 'Entonces él, oídas estas cosas, se puso muy triste, porque era muy rico.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 24, 'Y viendo Jesús que se había entristecido mucho, dijo: ¡Cuán dificultosamente entrarán en el reino de Dios los que tienen riquezas!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 25, 'Porque más fácil cosa es entrar un camello por el ojo de una aguja, que un rico entrar en el reino de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 26, 'Y los que lo oían, dijeron: ¿Y quién podrá ser salvo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 27, 'Y él les dijo: Lo que es imposible para con los hombres, posible es para Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 28, 'Entonces Pedro dijo: He aquí, nosotros hemos dejado las posesiones nuestras, y te hemos seguido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 29, 'Y él les dijo: De cierto os digo, que nadie hay que haya dejado casa, padres, ó hermanos, ó mujer, ó hijos, por el reino de Dios,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 30, 'Que no haya de recibir mucho más en este tiempo, y en el siglo venidero la vida eterna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 31, 'Y Jesús, tomando á los doce, les dijo: He aquí subimos á Jerusalem, y serán cumplidas todas las cosas que fueron escritas por los profetas, del Hijo del hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 32, 'Porque será entregado á las gentes, y será escarnecido, é injuriado, y escupido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 33, 'Y después que le hubieren azotado, le matarán: mas al tercer día resucitará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 34, 'Pero ellos nada de estas cosas entendían, y esta palabra les era encubierta, y no entendían lo que se decía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 35, 'Y aconteció que acercándose él á Jericó, un ciego estaba sentado junto al camino mendigando;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 36, 'El cual como oyó la gente que pasaba, preguntó qué era aquello.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 37, 'Y dijéronle que pasaba Jesús Nazareno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 38, 'Entonces dió voces, diciendo: Jesús, Hijo de David, ten misericordia de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 39, 'Y los que iban delante, le reñían que callase; mas él clamaba mucho más: Hijo de David, ten misericordia de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 40, 'Jesús entonces parándose, mandó traerle á sí: y como él llegó, le preguntó,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 41, 'Diciendo: ¿Qué quieres que te haga? Y él dijo: Señor, que vea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 42, 'Y Jesús le dijo: Ve, tu fe te ha hecho salvo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 18, 43, 'Y luego vió, y le seguía, glorificando á Dios: y todo el pueblo como lo vió, dió á Dios alabanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 1, 'Y HABIENDO entrado Jesús, iba pasando por Jericó;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 2, 'Y he aquí un varón llamado Zaqueo, el cual era el principal de los publicanos, y era rico;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 3, 'Y procuraba ver á Jesús quién fuese; mas no podía á causa de la multitud, porque era pequeño de estatura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 4, 'Y corriendo delante, subióse á un árbol sicómoro para verle; porque había de pasar por allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 5, 'Y como vino á aquel lugar Jesús, mirando, le vió, y díjole: Zaqueo, date priesa, desciende, porque hoy es necesario que pose en tu casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 6, 'Entonces él descendió apriesa, y le recibió gozoso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 7, 'Y viendo esto, todos murmuraban, diciendo que había entrado á posar con un hombre pecador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 8, 'Entonces Zaqueo, puesto en pie, dijo al Señor: He aquí, Señor, la mitad de mis bienes doy á los pobres; y si en algo he defraudado á alguno, lo vuelvo con el cuatro tanto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 9, 'Y Jesús le dijo: Hoy ha venido la salvación á esta casa; por cuanto él también es hijo de Abraham.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 10, 'Porque el Hijo del hombre vino á buscar y á salvar lo que se había perdido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 11, 'Y oyendo ellos estas cosas, prosiguió Jesús y dijo una parábola, por cuanto estaba cerca de Jerusalem, y porque pensaban que luego había de ser manifestado el reino de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 12, 'Dijo pues: Un hombre noble partió á una provincia lejos, para tomar para sí un reino, y volver.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 13, 'Mas llamados diez siervos suyos, les dió diez minas, y díjoles: Negociad entre tanto que vengo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 14, 'Empero sus ciudadanos le aborrecían, y enviaron tras de él una embajada, diciendo: No queremos que éste reine sobre nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 15, 'Y aconteció, que vuelto él, habiendo tomado el reino, mandó llamar á sí á aquellos siervos á los cuales había dado el dinero, para saber lo que había negociado cada uno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 16, 'Y vino el primero, diciendo: Señor, tu mina ha ganado diez minas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 17, 'Y él le dice: Está bien, buen siervo; pues que en lo poco has sido fiel, tendrás potestad sobre diez ciudades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 18, 'Y vino otro, diciendo: Señor, tu mina ha hecho cinco minas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 19, 'Y también á éste dijo: Tú también sé sobre cinco ciudades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 20, 'Y vino otro, diciendo: Señor, he aquí tu mina, la cual he tenido guardada en un pañizuelo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 21, 'Porque tuve miedo de ti, que eres hombre recio; tomas lo que no pusiste, y siegas lo que no sembraste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 22, 'Entonces él le dijo: Mal siervo, de tu boca te juzgo. Sabías que yo era hombre recio, que tomo lo que no puse, y que siego lo que no sembré;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 23, '¿Por qué, no diste mi dinero al banco, y yo viniendo lo demandara con el logro?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 24, 'Y dijo á los que estaban presentes: Quitadle la mina, y dadla al que tiene las diez minas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 25, 'Y ellos le dijeron: Señor, tiene diez minas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 26, 'Pues yo os digo que á cualquiera que tuviere, le será dado; mas al que no tuviere, aun lo que tiene le será quitado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 27, 'Y también á aquellos mis enemigos que no querían que yo reinase sobre ellos, traedlos acá, y degolladlos delante de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 28, 'Y dicho esto, iba delante subiendo á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 29, 'Y aconteció, que llegando cerca de Bethfagé, y de Bethania, al monte que se llama de las Olivas, envió dos de sus discípulos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 30, 'Diciendo: Id á la aldea de enfrente; en la cual como entrareis, hallaréis un pollino atado, en el que ningún hombre se ha sentado jamás; desatadlo, y traedlo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 31, 'Y si alguien os preguntare, ¿por qué lo desatáis? le responderéis así: Porque el Señor lo ha menester.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 32, 'Y fueron los que habían sido enviados, y hallaron como les dijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 33, 'Y desatando ellos el pollino, sus dueños les dijeron: ¿Por qué desatáis el pollino?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 34, 'Y ellos dijeron: Porque el Señor lo ha menester.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 35, 'Y trajéronlo á Jesús; y habiéndo echado sus vestidos sobre el pollino, pusieron á Jesús encima.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 36, 'Y yendo él tendían sus capas por el camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 37, 'Y como llegasen ya cerca de la bajada del monte de las Olivas, toda la multitud de los discípulos, gozándose, comenzaron á alabar á Dios á gran voz por todas las maravillas que habían visto,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 38, 'Diciendo: ¡Bendito el rey que viene en el nombre del Señor: paz en el cielo, y gloria en lo altísimo!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 39, 'Entonces algunos de los Fariseos de la compañía, le dijeron: Maestro, reprende á tus discípulos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 40, 'Y él respondiendo, les dijo: Os digo que si éstos callaren, las piedras clamarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 41, 'Y como llegó cerca viendo la ciudad, lloró sobre ella,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 42, 'Diciendo: ¡Oh si también tú conocieses, á lo menos en este tu día, lo que toca á tu paz! mas ahora está encubierto de tus ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 43, 'Porque vendrán días sobre ti, que tus enemigos te cercarán con baluarte, y te pondrán cerco, y de todas partes te pondrán en estrecho,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 44, 'Y te derribarán á tierra, y á tus hijos dentro de ti; y no dejarán sobre ti piedra sobre piedra; por cuanto no conociste el tiempo de tu visitación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 45, 'Y entrando en el templo, comenzó á echar fuera á todos los que vendían y compraban en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 46, 'Diciéndoles: Escrito está: Mi casa, casa de oración es; mas vosotros la habéis hecho cueva de ladrones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 47, 'Y enseñaba cada día en el templo; mas los príncipes de los sacerdotes, y los escribas, y los principales del pueblo procuraban matarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 19, 48, 'Y no hallaban qué hacerle, porque todo el pueblo estaba suspenso oyéndole.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 1, 'Y ACONTECIO un día, que enseñando él al pueblo en el templo, y anunciando el evangelio, llegáronse los príncipes de los sacerdotes y los escribas, con los ancianos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 2, 'Y le hablaron, diciendo: Dinos: ¿con qué potestad haces estas cosas? ¿ó quién es el que te ha dado esta potestad?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 3, 'Respondiendo entonces Jesús, les dijo: Os preguntaré yo también una palabra; respondedme:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 4, 'El bautismo de Juan, ¿era del cielo, ó de los hombres?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 5, 'Mas ellos pensaban dentro de sí, diciendo: Si dijéremos, del cielo, dirá: ¿Por qué, pues, no le creísteis?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 6, 'Y si dijéremos, de los hombres, todo el pueblo nos apedreará: porque están ciertos que Juan era profeta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 7, 'Y respondieron que no sabían de dónde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 8, 'Entonces Jesús les dijo: Ni yo os digo con qué potestad hago estas cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 9, 'Y comenzó á decir al pueblo esta parábola: Un hombre plantó una viña, y arrendóla á labradores, y se ausentó por mucho tiempo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 10, 'Y al tiempo, envió un siervo á los labradores, para que le diesen del fruto de la viña; mas los labradores le hirieron, y enviaron vacío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 11, 'Y volvió á enviar otro siervo; mas ellos á éste también, herido y afrentado, le enviaron vacío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 12, 'Y volvió á enviar al tercer siervo; mas ellos también á éste echaron herido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 13, 'Entonces el señor de la viña dijo: ¿Qué haré? Enviaré mi hijo amado: quizás cuando á éste vieren, tendrán respeto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 14, 'Mas los labradores, viéndole, pensaron entre sí, diciendo: Este es el heredero; venid, matémosle para que la heredad sea nuestra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 15, 'Y echáronle fuera de la viña, y le mataron. ¿Qué pues, les hará el señor de la viña?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 16, 'Vendrá, y destruirá á estos labradores, y dará su viña á otros. Y como ellos lo oyeron, dijeron: ¡Dios nos libre!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 17, 'Mas él mirándolos, dice: ¿Qué pues es lo que está escrito: La piedra que condenaron los edificadores, Esta fué por cabeza de esquina?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 18, 'Cualquiera que cayere sobre aquella piedra, será quebrantado; mas sobre el que la piedra cayere, le desmenuzará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 19, 'Y procuraban los príncipes de los sacerdotes y los escribas echarle mano en aquella hora, porque entendieron que contra ellos había dicho esta parábola: mas temieron al pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 20, 'Y acechándole enviaron espías que se simulasen justos, para sorprenderle en palabras, para que le entregasen al principado y á la potestad del presidente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 21, 'Los cuales le preguntaron, diciendo: Maestro, sabemos que dices y enseñas bien, y que no tienes respeto á persona; antes enseñas el camino de Dios con verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 22, '¿Nos es lícito dar tributo á César, ó no?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 23, 'Mas él, entendiendo la astucia de ellos, les dijo: ¿Por qué me tentáis?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 24, 'Mostradme la moneda. ¿De quién tiene la imagen y la inscripción? Y respondiendo dijeron: De César.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 25, 'Entonces les dijo: Pues dad á César lo que es de César; y lo que es de Dios, á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 26, 'Y no pudieron reprender sus palabras delante del pueblo: antes maravillados de su respuesta, callaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 27, 'Y llegándose unos de los Saduceos, los cuales niegan haber resurrección, le preguntaron,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 28, 'Diciendo: Maestro, Moisés nos escribió: Si el hermano de alguno muriere teniendo mujer, y muriere sin hijos, que su hermano tome la mujer, y levante simiente á su hermano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 29, 'Fueron, pues, siete hermanos: y el primero tomó mujer, y murió sin hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 30, 'Y la tomó el segundo, el cual también murió sin hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 31, 'Y la tomó el tercero: asimismo también todos siete: y muerieron sin dejar prole.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 32, 'Y á la postre de todos murió también la mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 33, 'En la resurrección, pues, ¿mujer de cuál de ellos será? porque los siete la tuvieron por mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 34, 'Entonces respondiendo Jesús, les dijo: Los hijos de este siglo se casan, y son dados en casamiento:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 35, 'Mas los que fueren tenidos por dignos de aquel siglo y de la resurrección de los muertos, ni se casan, ni son dados en casamiento:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 36, 'Porque no pueden ya más morir: porque son iguales á los ángeles, y son hijos de Dios, cuando son hijos de la resurrección.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 37, 'Y que los muertos hayan de resucitar, aun Moisés lo enseñó en el pasaje de la zarza, cuando llama al Señor: Dios de Abraham, y Dios de Isaac, y Dios de Jacob.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 38, 'Porque Dios no es Dios de muertos, mas de vivos: porque todos viven á él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 39, 'Y respondiéndole unos de los escribas, dijeron: Maestro, bien has dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 40, 'Y no osaron más preguntarle algo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 41, 'Y él les dijo: ¿Cómo dicen que el Cristo es hijo de David?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 42, 'Y el mismo David dice en el libro de los Salmos: Dijo el Señor á mi Señor: Siéntate á mi diestra,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 43, 'Entre tanto que pongo tus enemigos por estrado de tus pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 44, 'Así que David le llama Señor: ¿cómo pues es su hijo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 45, 'Y oyéndole todo el pueblo, dijo á sus discípulos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 46, 'Guardaos de los escribas, que quieren andar con ropas largas, y aman las salutaciones en las plazas, y las primeras sillas en las sinagogas, y los primeros asientos en las cenas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 20, 47, 'Que devoran las casas de las viudas, poniendo por pretexto la larga oración: éstos recibirán mayor condenación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 1, 'Y MIRANDO, vió á los ricos que echaban sus ofrendas en el gazofilacio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 2, 'Y vió también una viuda pobrecilla, que echaba allí dos blancas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 3, 'Y dijo: De verdad os digo, que esta pobre viuda echó más que todos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 4, 'Porque todos estos, de lo que les sobra echaron para las ofrendas de Dios; mas ésta de su pobreza echó todo el sustento que tenía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 5, 'Y á unos que decían del templo, que estaba adornado de hermosas piedras y dones, dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 6, 'Estas cosas que veis, días vendrán que no quedará piedra sobre piedra que no sea destruída.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 7, 'Y le preguntaron, diciendo: Maestro, ¿cuándo será esto? ¿y qué señal habrá cuando estas cosas hayan de comenzar á ser hechas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 8, 'El entonces dijo: Mirad, no seáis engañados; porque vendrán muchos en mi nombre, diciendo: Yo soy; y, el tiempo está cerca: por tanto, no vayáis en pos de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 9, 'Empero cuando oyereis guerras y sediciones, no os espantéis; porque es necesario que estas cosas acontezcan primero: mas no luego será el fin.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 10, 'Entonces les dijo: Se levantará gente contra gente, y reino contra reino;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 11, 'Y habrá grandes terremotos, y en varios lugares hambres y pestilencias: y habrá espantos y grandes señales del cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 12, 'Mas antes de todas estas cosas os echarán mano, y perseguirán, entregándoos á las sinagogas y á las cárceles, siendo llevados á los reyes y á los gobernadores por causa de mi nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 13, 'Y os será para testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 14, 'Poned pues en vuestros corazones no pensar antes cómo habéis de responder:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 15, 'Porque yo os daré boca y sabiduría, á la cual no podrán resistir ni contradecir todos los que se os opondrán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 16, 'Mas seréis entregados aun de vuestros padres, y hermanos, y parientes, y amigos; y matarán á algunos de vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 17, 'Y seréis aborrecidos de todos por causa de mi nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 18, 'Mas un pelo de vuestra cabeza no perecerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 19, 'En vuestra paciencia poseeréis vuestras almas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 20, 'Y cuando viereis á Jerusalem cercada de ejércitos, sabed entonces que su destrucción ha llegado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 21, 'Entonces los que estuvieren en Judea, huyan á los montes; y los que en medio de ella, váyanse; y los que estén en los campos, no entren en ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 22, 'Porque estos son días de venganza: para que se cumplan todas las cosas que están escritas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 23, 'Mas ¡ay de las preñadas, y de las que crían en aquellos días! porque habrá apuro grande sobre la tierra é ira en este pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 24, 'Y caerán á filo de espada, y serán llevados cautivos á todas las naciones: y Jerusalem será hollada de las gentes, hasta que los tiempos de las gentes sean cumplidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 25, 'Entonces habrá señales en el sol, y en la luna, y en las estrellas; y en la tierra angustia de gentes por la confusión del sonido de la mar y de las ondas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 26, 'Secándose los hombres á causa del temor y expectación de las cosas que sobrevendrán á la redondez de la tierra: porque las virtudes de los cielos serán conmovidas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 27, 'Y entonces verán al Hijo del hombre, que vendrá en una nube con potestad y majestad grande.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 28, 'Y cuando estas cosas comenzaren á hacerse, mirad, y levantad vuestras cabezas, porque vuestra redención está cerca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 29, 'Y díjoles una parábola: Mirad la higuera y todos los árboles:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 30, 'Cuando ya brotan, viéndolo, de vosotros mismos entendéis que el verano está ya cerca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 31, 'Así también vosotros, cuando viereis hacerse estas cosas, entended que está cerca el reino de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 32, 'De cierto os digo, que no pasará esta generación hasta que todo sea hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 33, 'El cielo y la tierra pasarán; mas mis palabras no pasarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 34, 'Y mirad por vosotros, que vuestros corazones no sean cargados de glotonería y embriaguez, y de los cuidados de esta vida, y venga de repente sobre vosotros aquel día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 35, 'Porque como un lazo vendrá sobre todos los que habitan sobre la faz de toda la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 36, 'Velad pues, orando en todo tiempo, que seáis tenidos por dignos de evitar todas estas cosas que han de venir, y de estar en pie delante del Hijo del hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 37, 'Y enseñaba de día en el templo; y de noche saliendo, estábase en el monte que se llama de las Olivas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 21, 38, 'Y todo el pueblo venía á él por la mañana, para oirle en el templo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 1, 'Y ESTABA cerca el día de la fiesta de los ázimos, que se llama la Pascua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 2, 'Y los príncipes de los sacerdotes y los escribas buscaban cómo le matarían; mas tenían miedo del pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 3, 'Y entró Satanás en Judas, por sobrenombre Iscariote, el cual era uno del número de los doce;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 4, 'Y fué, y habló con los príncipes de los sacerdotes, y con los magistrados, de cómo se lo entregaría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 5, 'Los cuales se holgaron, y concertaron de darle dinero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 6, 'Y prometió, y buscaba oportunidad para entregarle á ellos sin bulla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 7, 'Y vino el día de los ázimos, en el cual era necesario matar la pascua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 8, 'Y envió á Pedro y á Juan, diciendo: Id, aparejadnos la pascua para que comamos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 9, 'Y ellos le dijeron: ¿Dónde quieres que aparejemos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 10, 'Y él les dijo: He aquí cuando entrareis en la ciudad, os encontrará un hombre que lleva un cántaro de agua: seguidle hasta la casa donde entrare,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 11, 'Y decid al padre de la familia de la casa: El Maestro te dice: ¿Dónde está el aposento donde tengo de comer la pascua con mis discípulos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 12, 'Entonces él os mostrará un gran cenáculo aderezado; aparejad allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 13, 'Fueron pues, y hallaron como les había dicho; y aparejaron la pascua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 14, 'Y como fué hora, sentóse á la mesa, y con él los apóstoles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 15, 'Y les dijo: En gran manera he deseado comer con vosotros esta pascua antes que padezca;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 16, 'Porque os digo que no comeré más de ella, hasta que se cumpla en el reino de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 17, 'Y tomando el vaso, habiendo dado gracias, dijo: Tomad esto, y partidlo entre vosotros;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 18, 'Porque os digo, que no beberé más del fruto de la vid, hasta que el reino de Dios venga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 19, 'Y tomando el pan, habiendo dado gracias, partió, y les dió, diciendo: Esto es mi cuerpo, que por vosotros es dado: haced esto en memoria de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 20, 'Asimismo también el vaso, después que hubo cenado, diciendo: Este vaso es el nuevo pacto en mi sangre, que por vosotros se derrama.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 21, 'Con todo eso, he aquí la mano del que me entrega, conmigo en la mesa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 22, 'Y á la verdad el Hijo del hombre va, según lo que está determinado; empero ¡ay de aquél hombre por el cual es entregado!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 23, 'Ellos entonces comenzaron á preguntar entre sí, cuál de ellos sería el que había de hacer esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 24, 'Y hubo entre ellos una contienda, quién de ellos parecía ser el mayor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 25, 'Entonces él les dijo: Los reyes de las gentes se enseñorean de ellas; y los que sobre ellas tienen potestad, son llamados bienhechores:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 26, 'Mas vosotros, no así: antes el que es mayor entre vosotros, sea como el más mozo; y el que es príncipe, como el que sirve.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 27, 'Porque, ¿cuál es mayor, el que se sienta á la mesa, ó el que sirve? ¿No es el que se sienta á la mesa? Y yo soy entre vosotros como el que sirve.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 28, 'Empero vosotros sois los que habéis permanecido conmigo en mis tentaciones:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 29, 'Yo pues os ordeno un reino, como mi Padre me lo ordenó á mí,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 30, 'Para que comáis y bebáis en mi mesa en mi reino, y os sentéis sobre tronos juzgando á las doce tribus de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 31, 'Dijo también el Señor: Simón, Simón, he aquí Satanás os ha pedido para zarandaros como á trigo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 32, 'Mas yo he rogado por ti que tu fe no falte: y tú, una vez vuelto, confirma á tus hermanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 33, 'Y él le dijo: Señor, pronto estoy á ir contigo aun á cárcel y á muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 34, 'Y él dijo: Pedro, te digo que el gallo no cantará hoy antes que tú niegues tres veces que me conoces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 35, 'Y á ellos dijo: Cuando os envié sin bolsa, y sin alforja, y sin zapatos, ¿os faltó algo? Y ellos dijeron: Nada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 36, 'Y les dijo: Pues ahora, el que tiene bolsa, tómela, y también la alforja, y el que no tiene, venda su capa y compre espada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 37, 'Porque os digo, que es necesario que se cumpla todavía en mí aquello que está escrito: Y con los malos fué contado: porque lo que está escrito de mí, cumplimiento tiene.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 38, 'Entonces ellos dijeron: Señor, he aquí dos espadas. Y él les dijo: Basta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 39, 'Y saliendo, se fué, como solía, al monte de las Olivas; y sus discípulos también le siguieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 40, 'Y como llegó á aquel lugar, les dijo: Orad que no entréis en tentación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 41, 'Y él se apartó de ellos como un tiro de piedra; y puesto de rodillas oró,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 42, 'Diciendo: Padre, si quieres, pasa este vaso de mí; empero no se haga mi voluntad, sino la tuya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 43, 'Y le apareció un ángel del cielo confortándole.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 44, 'Y estando en agonía, oraba más intensamente: y fué su sudor como grandes gotas de sangre que caían hasta la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 45, 'Y como se levantó de la oración, y vino á sus discípulos, hallólos durmiendo de tristeza;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 46, 'Y les dijo: ¿Por qué dormís? Levantaos, y orad que no entréis en tentación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 47, 'Estando él aún hablando, he aquí una turba; y el que se llamaba Judas, uno de los doce, iba delante de ellos; y llegóse á Jesús para besarlo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 48, 'Entonces Jesús le dijo: Judas, ¿con beso entregas al Hijo del hombre?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 49, 'Y viendo los que estaban con él lo que había de ser, le dijeron: Señor, ¿heriremos á cuchillo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 50, 'Y uno de ellos hirió á un siervo del príncipe de los sacerdotes, y le quitó la oreja derecha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 51, 'Entonces respondiendo Jesús, dijo: Dejad hasta aquí. Y tocando su oreja, le sanó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 52, 'Y Jesús dijo á los que habían venido á él, los príncipes de los sacerdotes, y los magistrados del templo, y los ancianos: ¿Como á ladrón habéis salido con espadas y con palos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 53, 'Habiendo estado con vosotros cada día en el templo, no extendisteis las manos contra mí; mas ésta es vuestra hora, y la potestad de las tinieblas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 54, 'Y prendiéndole trajéronle, y metiéronle en casa del príncipe de los sacerdotes. Y Pedro le seguía de lejos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 55, 'Y habiendo encendido fuego en medio de la sala, y sentándose todos alrededor, se sentó también Pedro entre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 56, 'Y como una criada le vió que estaba sentado al fuego, fijóse en él, y dijo: Y éste con él estaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 57, 'Entonces él lo negó, diciendo: Mujer, no le conozco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 58, 'Y un poco después, viéndole otro, dijo: Y tú de ellos eras. Y Pedro dijo: Hombre, no soy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 59, 'Y como una hora pasada otro afirmaba, diciendo: Verdaderamente también éste estaba con él, porque es Galileo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 60, 'Y Pedro dijo: Hombre, no sé qué dices. Y luego, estando él aún hablando, el gallo cantó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 61, 'Entonces, vuelto el Señor, miró á Pedro: y Pedro se acordó de la palabra del Señor como le había dicho: Antes que el gallo cante, me negarás tres veces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 62, 'Y saliendo fuera Pedro, lloró amargamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 63, 'Y los hombres que tenían á Jesús, se burlaban de él hiriéndole;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 64, 'Y cubriéndole, herían su rostro, y preguntábanle, diciendo: Profetiza quién es el que te hirió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 65, 'Y decían otras muchas cosas injuriándole.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 66, 'Y cuando fué de día, se juntaron los ancianos del pueblo, y los príncipes de los sacerdotes, y los escribas, y le trajeron á su concilio,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 67, 'Diciendo: ¿Eres tú el Cristo? dínos lo. Y les dijo: Si os lo dijere, no creeréis;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 68, 'Y también si os preguntare, no me responderéis, ni me soltaréis:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 69, 'Mas después de ahora el Hijo del hombre se asentará á la diestra de la potencia de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 70, 'Y dijeron todos: ¿Luego tú eres Hijo de Dios? Y él les dijo: Vosotros decís que yo soy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 22, 71, 'Entonces ellos dijeron: ¿Qué más testimonio deseamos? porque nosotros lo hemos oído de su boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 1, 'LEVANTANDOSE entonces toda la multitud de ellos, lleváronle á Pilato.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 2, 'Y comenzaron á acusarle, diciendo: A éste hemos hallado que pervierte la nación, y que veda dar tributo á César, diciendo que él es el Cristo, el rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 3, 'Entonces Pilato le preguntó, diciendo: ¿Eres tú el Rey de los Judíos? Y respondiéndo él, dijo: Tú lo dices.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 4, 'Y Pilato dijo á los príncipes de los sacerdotes, y á las gentes: Ninguna culpa hallo en este hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 5, 'Mas ellos porfiaban, diciendo: Alborota al pueblo, enseñando por toda Judea, comenzando desde Galilea hasta aquí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 6, 'Entonces Pilato, oyendo de Galilea, preguntó si el hombre era Galileo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 7, 'Y como entendió que era de la jurisdicción de Herodes, le remitió á Herodes, el cual también estaba en Jerusalem en aquellos días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 8, 'Y Herodes, viendo á Jesús, holgóse mucho, porque hacía mucho que deseaba verle; porque había oído de él muchas cosas, y tenía esperanza que le vería hacer alguna señal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 9, 'Y le preguntaba con muchas palabras; mas él nada le respondió:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 10, 'Y estaban los príncipes de los sacerdotes y los escribas acusándole con gran porfía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 11, 'Mas Herodes con su corte le menospreció, y escarneció, vistiéndole de una ropa rica; y volvióle á enviar á Pilato.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 12, 'Y fueron hechos amigos entre sí Pilato y Herodes en el mismo día; porque antes eran enemigos entre sí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 13, 'Entonces Pilato, convocando los príncipes de los sacerdotes, y los magistrados, y el pueblo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 14, 'Les dijo: Me habéis presentado á éste por hombre que desvía al pueblo: y he aquí, preguntando yo delante de vosotros, no he hallado culpa alguna en este hombre de aquéllas de que le acusáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 15, 'Y ni aun Herodes; porque os remití á él, y he aquí, ninguna cosa digna de muerte ha hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 16, 'Le soltaré, pues, castigado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 17, 'Y tenía necesidad de soltarles uno en cada fiesta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 18, 'Mas toda la multitud dió voces á una, diciendo: Quita á éste, y suéltanos á Barrabás:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 19, '(El cual había sido echado en la cárcel por una sedición hecha en la ciudad, y una muerte.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 20, 'Y hablóles otra vez Pilato, queriendo soltar á Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 21, 'Pero ellos volvieron á dar voces, diciendo: Crucifícale, crucifícale.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 22, 'Y él les dijo la tercera vez: ¿Pues qué mal ha hecho éste? Ninguna culpa de muerte he hallado en él: le castigaré, pues, y le soltaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 23, 'Mas ellos instaban á grandes voces, pidiendo que fuese crucificado. Y las voces de ellos y de los príncipes de los sacerdotes crecían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 24, 'Entonces Pilato juzgó que se hiciese lo que ellos pedían;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 25, 'Y les soltó á aquél que había sido echado en la cárcel por sedición y una muerte, al cual habían pedido; y entregó á Jesús á la voluntad de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 26, 'Y llevándole, tomaron á un Simón Cireneo, que venía del campo, y le pusieron encima la cruz para que la llevase tras Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 27, 'Y le seguía una grande multitud de pueblo, y de mujeres, las cuales le lloraban y lamentaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 28, 'Mas Jesús, vuelto á ellas, les dice: Hijas de Jerusalem, no me lloréis á mí, mas llorad por vosotras mismas, y por vuestros hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 29, 'Porque he aquí vendrán días en que dirán: Bienaventuradas las estériles, y los vientres que no engendraron, y los pechos que no criaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 30, 'Entonces comenzarán á decir á los montes: Caed sobre nosotros: y á los collados: Cubridnos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 31, 'Porque si en el árbol verde hacen estas cosas, ¿en el seco, qué se hará?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 32, 'Y llevaban también con él otros dos, malhechores, á ser muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 33, 'Y como vinieron al lugar que se llama de la Calavera, le crucificaron allí, y á los malhechores, uno á la derecha, y otro á la izquierda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 34, 'Y Jesús decía: Padre, perdónalos, porque no saben lo que hacen. Y partiendo sus vestidos, echaron suertes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 35, 'Y el pueblo estaba mirando; y se burlaban de él los príncipes con ellos, diciendo: A otros hizo salvos: sálvese á sí, si éste es el Mesías, el escogido de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 36, 'Escarnecían de él también los soldados, llegándose y presentándole vinagre,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 37, 'Y diciendo: Si tú eres el Rey de los Judíos, sálvate á ti mismo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 38, 'Y había también sobre él un título escrito con letras griegas, y latinas, y hebraicas: ESTE ES EL REY DE LOS JUDIOS.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 39, 'Y uno de los malhechores que estaban colgados, le injuriaba, diciendo: Si tú eres el Cristo, sálvate á ti mismo y á nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 40, 'Y respondiendo el otro, reprendióle, diciendo: ¿Ni aun tú temes á Dios, estando en la misma condenación?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 41, 'Y nosotros, á la verdad, justamente padecemos; porque recibimos lo que merecieron nuestros hechos: mas éste ningún mal hizo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 42, 'Y dijo á Jesús: Acuérdate de mí cuando vinieres á tu reino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 43, 'Entonces Jesús le dijo: De cierto te digo, que hoy estarás conmigo en el paraíso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 44, 'Y cuando era como la hora de sexta, fueron hechas tinieblas sobre toda la tierra hasta la hora de nona.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 45, 'Y el sol se obscureció: y el velo del templo se rompió por medio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 46, 'Entonces Jesús, clamando á gran voz, dijo: Padre, en tus manos encomiendo mi espíritu. Y habiendo dicho esto, espiró.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 47, 'Y como el centurión vió lo que había acontecido, dió gloria á Dios, diciendo: Verdaderamente este hombre era justo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 48, 'Y toda la multitud de los que estaban presentes á este espectáculo, viendo lo que había acontecido, se volvían hiriendo sus pechos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 49, 'Mas todos sus conocidos, y las mujeres que le habían seguido desde Galilea, estaban lejos mirando estas cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 50, 'Y he aquí un varón llamado José, el cual era senador, varón bueno y justo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 51, '(El cual no había consentido en el consejo ni en los hechos de ellos), de Arimatea, ciudad de la Judea, el cual también esperaba el reino de Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 52, 'Este llegó á Pilato, y pidió el cuerpo de Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 53, 'Y quitado, lo envolvió en una sábana, y le puso en un sepulcro abierto en una peña, en el cual ninguno había aún sido puesto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 54, 'Y era día de la víspera de la Pascua; y estaba para rayar el sábado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 55, 'Y las mujeres que con él habían venido de Galilea, siguieron también y vieron el sepulcro, y cómo fué puesto su cuerpo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 23, 56, 'Y vueltas, aparejaron drogas aromáticas y ungüentos; y reposaron el sábado, conforme al mandamiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 1, 'Y EL primer día de la semana, muy de mañana, vinieron al sepulcro, trayendo las drogas aromáticas que habían aparejado, y algunas otras mujeres con ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 2, 'Y hallaron la piedra revuelta del sepulcro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 3, 'Y entrando, no hallaron el cuerpo del Señor Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 4, 'Y aconteció, que estando ellas espantadas de esto, he aquí se pararon junto á ellas dos varones con vestiduras resplandecientes;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 5, 'Y como tuviesen ellas temor, y bajasen el rostro á tierra, les dijeron: ¿Por qué buscáis entre los muertos al que vive?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 6, 'No está aquí, mas ha resucitado: acordaos de lo que os habló, cuando aun estaba en Galilea,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 7, 'Diciendo: Es menester que el Hijo del hombre sea entregado en manos de hombres pecadores, y que sea crucificado, y resucite al tercer día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 8, 'Entonces ellas se acordaron de sus palabras,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 9, 'Y volviendo del sepulcro, dieron nuevas de todas estas cosas á los once, y á todos los demás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 10, 'Y eran María Magdalena, y Juana, y María madre de Jacobo, y las demás con ellas, las que dijeron estas cosas á los apóstoles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 11, 'Mas á ellos les parecían como locura las palabras de ellas, y no las creyeron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 12, 'Pero levantándose Pedro, corrió al sepulcro: y como miró dentro, vió solos los lienzos echados; y se fué maravillándose de lo que había sucedido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 13, 'Y he aquí, dos de ellos iban el mismo día á una aldea que estaba de Jerusalem sesenta estadios, llamada Emmaús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 14, 'E iban hablando entre sí de todas aquellas cosas que habían acaecido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 15, 'Y aconteció que yendo hablando entre sí, y preguntándose el uno al otro, el mismo Jesús se llegó, é iba con ellos juntamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 16, 'Mas los ojos de ellos estaban embargados, para que no le conociesen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 17, 'Y díjoles: ¿Qué pláticas son estas que tratáis entre vosotros andando, y estáis tristes?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 18, 'Y respondiendo el uno, que se llamaba Cleofas, le dijo: ¿Tú sólo peregrino eres en Jerusalem, y no has sabido las cosas que en ella han acontecido estos días?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 19, 'Entonces él les dijo: ¿Qué cosas? Y ellos le dijeron: De Jesús Nazareno, el cual fué varón profeta, poderoso en obra y en palabra delante de Dios y de todo el pueblo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 20, 'Y cómo le entregaron los príncipes de los sacerdotes y nuestros príncipes á condenación de muerte, y le crucificaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 21, 'Mas nosotros esperábamos que él era el que había de redimir á Israel: y ahora sobre todo esto, hoy es el tercer día que esto ha acontecido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 22, 'Aunque también unas mujeres de los nuestros nos han espantado, las cuales antes del día fueron al sepulcro:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 23, 'Y no hallando su cuerpo, vinieron diciendo que también habían visto visión de ángeles, los cuales dijeron que él vive.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 24, 'Y fueron algunos de los nuestros al sepulcro, y hallaron así como las mujeres habían dicho; más á él no le vieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 25, 'Entonces él les dijo: ¡Oh insensatos, y tardos de corazón para creer todo lo que los profetas han dicho!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 26, '¿No era necesario que el Cristo padeciera estas cosas, y que entrara en su gloria?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 27, 'Y comenzando desde Moisés, y de todos los profetas, declarábales en todas las Escrituras lo que de él decían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 28, 'Y llegaron á la aldea á donde iban: y él hizo como que iba más lejos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 29, 'Mas ellos le detuvieron por fuerza, diciendo: Quédate con nosotros, porque se hace tarde, y el día ya ha declinado. Entró pues á estarse con ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 30, 'Y aconteció, que estando sentado con ellos á la mesa, tomando el pan, bendijo, y partió, y dióles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 31, 'Entonces fueron abiertos los ojos de ellos, y le conocieron; mas él se desapareció de los ojos de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 32, 'Y decían el uno al otro: ¿No ardía nuestro corazón en nosotros, mientras nos hablaba en el camino, y cuando nos abría las Escrituras?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 33, 'Y levantándose en la misma hora, tornáronse á Jerusalem, y hallaron á los once reunidos, y á los que estaban con ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 34, 'Que decían: Ha resucitado el Señor verdaderamente, y ha aparecido á Simón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 35, 'Entonces ellos contaban las cosas que les habían acontecido en el camino, y cómo había sido conocido de ellos al partir el pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 36, 'Y entre tanto que ellos hablaban estas cosas, él se puso en medio de ellos, y les dijo: Paz á vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 37, 'Entonces ellos espantados y asombrados, pensaban que veían espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 38, 'Mas él les dice: ¿Por qué estáis turbados, y suben pensamientos á vuestros corazones?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 39, 'Mirad mis manos y mis pies, que yo mismo soy: palpad, y ved; que el espíritu ni tiene carne ni huesos, como veis que yo tengo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 40, 'Y en diciendo esto, les mostró las manos y los pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 41, 'Y no creyéndolo aún ellos de gozo, y maravillados, díjoles: ¿Tenéis aquí algo de comer?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 42, 'Entonces ellos le presentaron parte de un pez asado, y un panal de miel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 43, 'Y él tomó, y comió delante de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 44, 'Y él les dijo: Estas son las palabras que os hablé, estando aún con vosotros: que era necesario que se cumpliesen todas las cosas que están escritas de mí en la ley de Moisés, y en los profetas, y en los salmos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 45, 'Entonces les abrió el sentido, para que entendiesen las Escrituras;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 46, 'Y díjoles: Así está escrito, y así fué necesario que el Cristo padeciese, y resucitase de los muertos al tercer día;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 47, 'Y que se predicase en su nombre el arrepentimiento y la remisión de pecados en todas las naciones, comenzando de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 48, 'Y vosotros sois testigos de estas cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 49, 'Y he aquí, yo enviaré la promesa de mi Padre sobre vosotros: mas vosotros asentad en la ciudad de Jerusalem, hasta que seáis investidos de potencia de lo alto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 50, 'Y sacólos fuera hasta Bethania, y alzando sus manos, los bendijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 51, 'Y aconteció que bendiciéndolos, se fué de ellos; y era llevado arriba al cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 52, 'Y ellos, después de haberle adorado, se volvieron á Jerusalem con gran gozo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LUK', 'Lucas', 24, 53, 'Y estaban siempre en el templo, alabando y bendiciendo á Dios. Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 1, 1, 'EN el primer tratado, oh Teófilo, he hablado de todas las cosas que Jesús comenzó á hacer y á enseñar,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 1, 2, 'Hasta el día en que, habiendo dado mandamientos por el Espíritu Santo á los apóstoles que escogió, fué recibido arriba;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 1, 3, 'A los cuales, después de haber padecido, se presentó vivo con muchas pruebas indubitables, apareciéndoles por cuarenta días, y hablándo les del reino de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 1, 4, 'Y estando juntos, les mandó que no se fuesen de Jerusalem, sino que esperasen la promesa del Padre, que oísteis, dijo, de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 1, 5, 'Porque Juan á la verdad bautizó con agua, mas vosotros seréis bautizados con el Espíritu Santo no muchos días después de estos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 1, 6, 'Entonces los que se habían juntado le preguntaron, diciendo: Señor, ¿restituirás el reino á Israel en este tiempo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 1, 7, 'Y les dijo: No toca á vosotros saber los tiempos ó las sazones que el Padre puso en su sola potestad;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 1, 8, 'Mas recibiréis la virtud del Espíritu Santo que vendrá sobre vosotros; y me sereís testigos en Jerusalem, en toda Judea, y Samaria, y hasta lo último de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 1, 9, 'Y habiendo dicho estas cosas, viéndo lo ellos, fué alzado; y una nube le recibió y le quitó de sus ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 1, 10, 'Y estando con los ojos puestos en el cielo, entre tanto que él iba, he aquí dos varones se pusieron junto á ellos en vestidos blancos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 1, 11, 'Los cuales también les dijeron: Varones Galileos, ¿qué estáis mirando al cielo? este mismo Jesús que ha sido tomado desde vosotros arriba en el cielo, así vendrá como le habéis visto ir al cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 1, 12, 'Entonces se volvieron á Jerusalem del monte que se llama del Olivar, el cual está cerca de Jerusalem camino de un sábado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 1, 13, 'Y entrados, subieron al aposento alto, donde moraban Pedro y Jacobo, y Juan y Andrés, Felipe y Tomás, Bartolomé y Mateo, Jacobo hijo de Alfeo, y Simón Zelotes, y Judas hermano de Jacobo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 1, 14, 'Todos éstos perseveraban unánimes en oración y ruego, con las mujeres, y con María la madre de Jesús, y con sus hermanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 1, 15, 'Y en aquellos días, Pedro, levantándose en medio de los hermanos, dijo (y era la compañía junta como de ciento y veinte en número):');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 1, 16, 'Varones hermanos, convino que se cumpliese la Escritura, la cual dijo antes el Espíritu Santo por la boca de David, de Judas, que fué guía de los que prendieron á Jesús;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 1, 17, 'El cuál era contado con nosotros, y tenía suerte en este ministerio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 1, 18, 'Este, pues, adquirió un campo del salario de su iniquidad, y colgándose, reventó por medio, y todas sus entrañas se derramaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 1, 19, 'Y fué notorio á todos los moradores de Jerusalem; de tal manera que aquel campo es llamado en su propia lengua, Acéldama, que es, Campo de sangre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 1, 20, 'Porque está escrito en el libro de los salmos: Sea hecha desierta su habitación, Y no haya quien more en ella; y: Tome otro su obispado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 1, 21, 'Conviene, pues, que de estos hombres que han estado juntos con nosotros todo el tiempo que el Señor Jesús entró y salió entre nosotros,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 1, 22, 'Comenzando desde el bautismo de Juan, hasta el día que fué recibido arriba de entre nosotros, uno sea hecho testigo con nosotros de su resurrección.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 1, 23, 'Y señalaron á dos: á José, llamado Barsabas, que tenía por sobrenombre Justo, y á Matías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 1, 24, 'Y orando, dijeron: Tú, Señor, que conoces los corazones de todos, muestra cuál escoges de estos dos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 1, 25, 'Para que tome el oficio de este ministerio y apostolado, del cual cayó Judas por transgresión, para irse á su lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 1, 26, 'Y les echaron suertes, y cayó la suerte sobre Matías; y fué contado con los once apóstoles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 1, 'Y COMO se cumplieron los días de Pentecostés, estaban todos unánimes juntos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 2, 'Y de repente vino un estruendo del cielo como de un viento recio que corría, el cual hinchió toda la casa donde estaban sentados;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 3, 'Y se les aparecieron lenguas repartidas, como de fuego, que se asentó sobre cada uno de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 4, 'Y fueron todos llenos del Espíritu Santo, y comenzaron á hablar en otras lenguas, como el Espíritu les daba que hablasen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 5, 'Moraban entonces en Jerusalem Judíos, varones religiosos, de todas las naciones debajo del cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 6, 'Y hecho este estruendo, juntóse la multitud; y estaban confusos, porque cada uno les oía hablar su propia lengua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 7, 'Y estaban atónitos y maravillados, diciendo: He aquí ¿no son "Galileos todos estos que hablan?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 8, '¿Cómo, pues, les oímos nosotros hablar cada uno en nuestra lengua en que somos nacidos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 9, 'Partos y Medos, y Elamitas, y los que habitamos en Mesopotamia, en Judea y en Capadocia, en el Ponto y en Asia,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 10, 'En Phrygia y Pamphylia, en Egipto y en las partes de Africa que está de la otra parte de Cirene, y Romanos extranjeros, tanto Judíos como convertidos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 11, 'Cretenses y Arabes, les oímos hablar en nuestras lenguas las maravillas de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 12, 'Y estaban todos atónitos y perplejos, diciendo los unos á los otros: ¿Qué quiere ser esto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 13, 'Mas otros burlándose, decían: Que están llenos de mosto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 14, 'Entonces Pedro, poniéndose en pie con los once, alzó su voz, y hablóles diciendo: Varones Judíos, y todos los que habitáis en Jerusalem, esto os sea notorio, y oid mis palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 15, 'Porque éstos no están borrachos, como vosotros pensáis, siendo la hora tercia del día;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 16, 'Mas esto es lo que fué dicho por el profeta Joel:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 17, 'Y será en los postreros días, dice Dios, Derramaré de mi Espíritu sobre toda carne, Y vuestros hijos y vuestras hijas profetizarán; Y vuestros mancebos verán visiones, Y vuestros viejos soñarán sueños:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 18, 'Y de cierto sobre mis siervos y sobre mis siervas en aquellos días Derramaré de mi Espíritu, y profetizarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 19, 'Y daré prodigios arriba en el cielo, Y señales abajo en la tierra, Sangre y fuego y vapor de humo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 20, 'El sol se volverá en tinieblas, Y la luna en sangre, Antes que venga el día del Señor, Grande y manifiesto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 21, 'Y será que todo aquel que invocare el nombre del Señor, será salvo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 22, 'Varones Israelitas, oid estas palabras: Jesús Nazareno, varón aprobado de Dios entre vosotros en maravillas y prodigios y señales, que Dios hizo por él en medio de vosotros, como también vosotros sabéis;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 23, 'A éste, entregado por determinado consejo y providencia de Dios, prendisteis y matasteis por manos de los inicuos, crucificándole;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 24, 'Al cual Dios levantó, sueltos los dolores de la muerte, por cuanto era imposible ser detenido de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 25, 'Porque David dice de él: Veía al Señor siempre delante de mí: Porque está á mi diestra, no seré conmovido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 26, 'Por lo cual mi corazón se alegró, y gozóse mi lengua; Y aun mi carne descansará en esperanza;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 27, 'Que no dejarás mi alma en el infierno, Ni darás á tu Santo que vea corrupción.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 28, 'Hicísteme notorios los caminos de la vida; Me henchirás de gozo con tu presencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 29, 'Varones hermanos, se os puede libremente decir del patriarca David, que murió, y fué sepultado, y su sepulcro está con nosotros hasta del día de hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 30, 'Empero siendo profeta, y sabiendo que con juramento le había Dios jurado que del fruto de su lomo, cuanto á la carne, levantaría al Cristo que se sentaría sobre su trono;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 31, 'Viéndolo antes, habló de la resurrección de Cristo, que su alma no fué dejada en el infierno, ni su carne vió corrupción.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 32, 'A este Jesús resucitó Dios, de lo cual todos nosotros somos testigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 33, 'Así que, levantado por la diestra de Dios, y recibiendo del Padre la promesa del Espíritu Santo, ha derramado esto que vosotros veis y oís.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 34, 'Porque David no subió á los cielos; empero él dice: Dijo el Señor á mi Señor: Siéntate á mi diestra,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 35, 'Hasta que ponga á tus enemigos por estrado de tus pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 36, 'Sepa pues ciertísimamente toda la casa de Israel, que á éste Jesús que vosotros crucificasteis, Dios ha hecho Señor y Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 37, 'Entonces oído esto, fueron compungidos de corazón, y dijeron á Pedro y á los otros apóstoles: Varones hermanos, ¿qué haremos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 38, 'Y Pedro les dice: Arrepentíos, y bautícese cada uno de vosotros en el nombre de Jesucristo para perdón de los pecados; y recibiréis el don del Espíritu Santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 39, 'Porque para vosotros es la promesa, y para vuestros hijos, y para todos los que están lejos; para cuantos el Señor nuestro Dios llamare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 40, 'Y con otras muchas palabras testificaba y exhortaba, diciendo: Sed salvos de esta perversa generación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 41, 'Así que, los que recibieron su palabra, fueron bautizados: y fueron añadidas á ellos aquel día como tres mil personas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 42, 'Y perseveraban en la doctrina de los apóstoles, y en la comunión, y en el partimiento del pan, y en las oraciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 43, 'Y toda persona tenía temor: y muchas maravillas y señales eran hechas por los apóstoles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 44, 'Y todos los que creían estaban juntos; y tenían todas las cosas comunes;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 45, 'Y vendían las posesiones, y las haciendas, y repartíanlas á todos, como cada uno había menester.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 46, 'Y perseverando unánimes cada día en el templo, y partiendo el pan en las casas, comían juntos con alegría y con sencillez de corazón,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 2, 47, 'Alabando á Dios, y teniendo gracia con todo el pueblo. Y el Señor añadía cada día á la iglesia los que habían de ser salvos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 3, 1, 'PEDRO y Juan subían juntos al templo á la hora de oración, la de nona.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 3, 2, 'Y un hombre que era cojo desde el vientre de su madre, era traído; al cual ponían cada día á la puerta del templo que se llama la Hermosa, para que pidiese limosna de los que entraban en el templo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 3, 3, 'Este, como vió á Pedro y á Juan que iban á entrar en el templo, rogaba que le diesen limosna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 3, 4, 'Y Pedro, con Juan, fijando los ojos en él, dijo: Mira á nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 3, 5, 'Entonces él estuvo atento á ellos, esperando recibir de ellos algo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 3, 6, 'Y Pedro dijo: Ni tengo plata ni oro; mas lo que tengo te doy: en el nombre de Jesucristo de Nazaret, levántate y anda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 3, 7, 'Y tomándole por la mano derecha le levantó: y luego fueron afirmados sus pies y tobillos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 3, 8, 'Y saltando, se puso en pie, y anduvo; y entró con ellos en el templo, andando, y saltando, y alabando á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 3, 9, 'Y todo el pueblo le vió andar y alabar á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 3, 10, 'Y conocían que él era el que se sentaba á la limosna á la puerta del templo, la Hermosa: y fueron llenos de asombro y de espanto por lo que le había acontecido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 3, 11, 'Y teniendo á Pedro y á Juan el cojo que había sido sanado, todo el pueblo concurrió á ellos al pórtico que se llama de Salomón, atónitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 3, 12, 'Y viendo esto Pedro, respondió al pueblo: Varones Israelitas, ¿por qué os maravilláis de esto? ó ¿por qué ponéis los ojos en nosotros, como si con nuestra virtud ó piedad hubiésemos hecho andar á éste?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 3, 13, 'El Dios de Abraham, y de Isaac, y de Jacob, el Dios de nuestros padres ha glorificado á su Hijo Jesús, al cual vosotros entregasteis, y negasteis delante de Pilato, juzgando él que había de ser suelto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 3, 14, 'Mas vosotros al Santo y al Justo negasteis, y pedisteis que se os diese un homicida;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 3, 15, 'Y matasteis al Autor de la vida, al cual Dios ha resucitado de los muertos; de lo que nosotros somos testigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 3, 16, 'Y en la fe de su nombre, á éste que vosotros veis y conocéis, ha confirmado su nombre: y la fe que por él es, ha dado á este esta completa sanidad en presencia de todos vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 3, 17, 'Mas ahora, hermanos, sé que por ignorancia lo habéis hecho, como también vuestros príncipes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 3, 18, 'Empero, Dios ha cumplido así lo que había antes anunciado por boca de todos sus profetas, que su Cristo había de padecer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 3, 19, 'Así que, arrepentíos y convertíos, para que sean borrados vuestros pecados; pues que vendrán los tiempos del refrigerio de la presencia del Señor,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 3, 20, 'Y enviará á Jesucristo, que os fué antes anunciado:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 3, 21, 'Al cual de cierto es menester que el cielo tenga hasta los tiempos de la restauración de todas las cosas, que habló Dios por boca de sus santos profetas que han sido desde el siglo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 3, 22, 'Porque Moisés dijo á los padres: El Señor vuestro Dios os levantará profeta de vuestros hermanos, como yo; á él oiréis en todas las cosas que os hablare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 3, 23, 'Y será, que cualquiera alma que no oyere á aquel profeta, será desarraigada del pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 3, 24, 'Y todos los profetas desde Samuel y en adelante, todos los que han hablado, han anunciado estos días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 3, 25, 'Vosotros sois los hijos de los profetas, y del pacto que Dios concertó con nuestros padres, diciendo á Abraham: Y en tu simiente serán benditas todas las familias de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 3, 26, 'A vosotros primeramente, Dios, habiendo levantado á su Hijo, le envió para que os bendijese, á fin de que cada uno se convierta de su maldad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 1, 'Y HABLANDO ellos al pueblo, sobrevinieron los sacerdotes, y el magistrado del templo, y los Saduceos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 2, 'Resentidos de que enseñasen al pueblo, y anunciasen en Jesús la resurrección de los muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 3, 'Y les echaron mano, y los pusieron en la cárcel hasta el día siguiente; porque era ya tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 4, 'Mas muchos de los que habían oído la palabra, creyeron; y fué el número de los varones como cinco mil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 5, 'Y aconteció al día siguiente, que se juntaron en Jerusalem los príncipes de ellos, y los ancianos, y los escribas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 6, 'Y Anás, príncipe de los sacerdotes, y Caifás, y Juan y Alejandro, y todos los que eran del linaje sacerdotal;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 7, 'Y haciéndolos presentar en medio, les preguntaron: ¿Con qué potestad, ó en qué nombre, habéis hecho vosotros esto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 8, 'Entonce Pedro, lleno del Espíritu Santo, les dijo: Príncipes del pueblo, y ancianos de Israel:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 9, 'Pues que somos hoy demandados acerca del beneficio hecho á un hombre enfermo, de qué manera éste haya sido sanado,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 10, 'Sea notorio á todos vosotros, y á todo el pueblo de Israel, que en el nombre de Jesucristo de Nazaret, al que vosotros crucificasteis y Dios le resucitó de los muertos, por él este hombre está en vuestra presencia sano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 11, 'Este es la piedra reprobada de vosotros los edificadores, la cual es puesta por cabeza del ángulo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 12, 'Y en ningún otro hay salud; porque no hay otro nombre debajo del cielo, dado á los hombres, en que podamos ser salvos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 13, 'Entonces viendo la constancia de Pedro y de Juan, sabido que eran hombres sin letras é ignorantes, se maravillaban; y les conocían que habían estado con Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 14, 'Y viendo al hombre que había sido sanado, que estaba con ellos, no podían decir nada en contra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 15, 'Mas les mandaron que se saliesen fuera del concilio; y conferían entre sí,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 16, 'Diciendo: ¿Qué hemos de hacer á estos hombres? porque de cierto, señal manifiesta ha sido hecha por ellos, notoria á todos los que moran en Jerusalem, y no lo podemos negar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 17, 'Todavía, porque no se divulgue más por el pueblo, amenacémoslos, que no hablen de aquí adelante á hombre alguno en este nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 18, 'Y llamándolos, les intimaron que en ninguna manera hablasen ni enseñasen en el nombre de Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 19, 'Entonces Pedro y Juan, respondiendo, les dijeron: Juzgad si es justo delante de Dios obedecer antes á vosotros que á Dios:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 20, 'Porque no podemos dejar de decir lo que hemos visto y oído.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 21, 'Ellos entonces los despacharon amenazándolos, no hallando ningún modo de castigarlos, por causa del pueblo; porque todos glorificaban á Dios de lo que había sido hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 22, 'Porque el hombre en quien había sido hecho este milagro de sanidad, era de más de cuarenta años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 23, 'Y sueltos, vinieron á los suyos, y contaron todo lo que los príncipes de los sacerdotes y los ancianos les habían dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 24, 'Y ellos, habiéndolo oído, alzaron unánimes la voz á Dios, y dijeron: Señor, tú eres el Dios que hiciste el cielo y la tierra, la mar, y todo lo que en ellos hay;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 25, 'Que por boca de David, tu siervo, dijiste: ¿Por qué han bramado las gentes, Y los pueblos han pensado cosas vanas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 26, 'Asistieron los reyes de la tierra, Y los príncipes se juntaron en uno Contra el Señor, y contra su Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 27, 'Porque verdaderamente se juntaron en esta ciudad contra tu santo Hijo Jesús, al cual ungiste, Herodes y Poncio Pilato, con los Gentiles y los pueblos de Israel,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 28, 'Para hacer lo que tu mano y tu consejo habían antes determinado que había de ser hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 29, 'Y ahora, Señor, mira sus amenazas, y da á tus siervos que con toda confianza hablen tu palabra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 30, 'Que extiendas tu mano á que sanidades, y milagros, y prodigios sean hechos por el nombre de tu santo Hijo Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 31, 'Y como hubieron orado, el lugar en que estaban congregados tembló; y todos fueron llenos del Espíritu Santo, y hablaron la palabra de Dios con confianza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 32, 'Y la multitud de los que habían creído era de un corazón y un alma: y ninguno decía ser suyo algo de lo que poseía; mas todas las cosas les eran comunes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 33, 'Y los apóstoles daban testimonio de la resurrección del Señor Jesús con gran esfuerzo; y gran gracia era en todos ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 34, 'Que ningún necesitado había entre ellos: porque todos los que poseían heredades ó casas, vendiéndolas, traían el precio de lo vendido,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 35, 'Y lo ponían á los pies de los apóstoles; y era repartido á cada uno según que había menester.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 36, 'Entonces José, que fué llamado de los apóstoles por sobrenombre, Bernabé, (que es interpretado, Hijo de consolación) Levita, natural de Cipro,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 4, 37, 'Como tuviese una heredad, la vendió, y trajo el precio, y púsolo á los pies de los apóstoles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 1, 'MAS un varón llamado Ananías, con Safira su mujer, vendió una posesión,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 2, 'Y defraudó del precio, sabiéndolo también su mujer; y trayendo una parte, púsola á los pies de los apóstoles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 3, 'Y dijo Pedro: Ananías, ¿por qué ha llenado Satanás tu corazón á que mintieses al Espíritu Santo, y defraudases del precio de la heredad?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 4, 'Reteniéndola, ¿no se te quedaba á ti? y vendida, ¿no estaba en tu potestad? ¿Por qué pusiste esto en tu corazón? No has mentido á los hombres, sino á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 5, 'Entonces Ananías, oyendo estas palabras, cayó y espiró. Y vino un gran temor sobre todos los que lo oyeron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 6, 'Y levantándose los mancebos, le tomaron, y sacándolo, sepultáronlo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 7, 'Y pasado espacio como de tres horas, sucedió que entró su mujer, no sabiendo lo que había acontecido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 8, 'Entonces Pedro le dijo: Dime: ¿vendisteis en tanto la heredad? Y ella dijo: Sí, en tanto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 9, 'Y Pedro le dijo: ¿Por qué os concertasteis para tentar al Espíritu del Señor? He aquí á la puerta los pies de los que han sepultado á tu marido, y te sacarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 10, 'Y luego cayó á los pies de él, y espiró: y entrados los mancebos, la hallaron muerta; y la sacaron, y la sepultaron junto á su marido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 11, 'Y vino un gran temor en toda la iglesia, y en todos los que oyeron estas cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 12, 'Y por las manos de los apóstoles eran hechos muchos milagros y prodigios en el pueblo; y estaban todos unánimes en el pórtico de Salomón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 13, 'Y de los otros, ninguno osaba juntarse con ellos; mas el pueblo los alababa grandemente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 14, 'Y los que creían en el Señor se aumentaban más, gran número así de hombres como de mujeres;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 15, 'Tanto que echaban los enfermos por las calles, y los ponían en camas y en lechos, para que viniendo Pedro, á lo menos su sombra tocase á alguno de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 16, 'Y aun de las ciudades vecinas concurría multitud á Jerusalem, trayendo enfermos y atormentados de espíritus inmundos; los cuales todos eran curados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 17, 'Entonces levantándose el príncipe de los sacerdotes, y todos los que estaban con él, que es la secta de los Saduceos, se llenaron de celo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 18, 'Y echaron mano á los apóstoles, y pusiéronlos en la cárcel pública.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 19, 'Mas el ángel del Señor, abriendo de noche las puertas de la cárcel, y sacándolos, dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 20, 'Id, y estando en el templo, hablad al pueblo todas las palabras de esta vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 21, 'Y oído que hubieron esto, entraron de mañana en el templo, y enseñaban. Entre tanto, viniendo el príncipe de los sacerdotes, y los que eran con él, convocaron el concilio, y á todos los ancianos de los hijos de Israel, y enviaron á la cárcel para que fuesen traídos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 22, 'Mas como llegaron los ministros, y no los hallaron en la cárcel, volvieron, y dieron aviso,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 23, 'Diciendo: Por cierto, la cárcel hemos hallado cerrada con toda seguridad, y los guardas que estaban delante de las puertas; mas cuando abrimos, á nadie hallamos dentro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 24, 'Y cuando oyeron estas palabras el pontífice y el magistrado del templo y los príncipes de los sacerdotes, dudaban en qué vendría á parar aquello.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 25, 'Pero viniendo uno, dióles esta noticia: He aquí, los varones que echasteis en la cárcel, están en el templo, y enseñan al pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 26, 'Entonces fué el magistrado con los ministros, y trájolos sin violencia; porque temían del pueblo ser apedreados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 27, 'Y como los trajeron, los presentaron en el concilio: y el príncipe de los sacerdotes les preguntó,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 28, 'Diciendo: ¿No os denunciamos estrechamente, que no enseñaseis en este nombre? y he aquí, habéis llenado á Jerusalem de vuestra doctrina, y queréis echar sobre nosotros la sangre de este hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 29, 'Y respondiendo Pedro y los apóstoles, dijeron: Es menester obedecer á Dios antes que á los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 30, 'El Dios de nuestros padres levantó á Jesús, al cual vosotros matasteis colgándole de un madero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 31, 'A éste ha Dios ensalzado con su diestra por Príncipe y Salvador, para dar á Israel arrepentimiento y remisión de pecados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 32, 'Y nosotros somos testigos suyos de estas cosas, y también el Espíritu Santo, el cual ha dado Dios á los que le obedecen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 33, 'Ellos, oyendo esto, regañaban, y consultaban matarlos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 34, 'Entonces levantándose en el concilio un Fariseo llamado Gamaliel, doctor de la ley, venerable á todo el pueblo, mandó que sacasen fuera un poco á los apóstoles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 35, 'Y les dijo: Varones Israelitas, mirad por vosotros acerca de estos hombres en lo que habéis de hacer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 36, 'Porque antes de estos días se levantó Teudas, diciendo que era alguien; al que se agregó un número de hombres como cuatrocientos: el cual fué matado; y todos los que le creyeron fueron dispersos, y reducidos á nada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 37, 'Después de éste, se levantó Judas el Galileo en los días del empadronamiento, y llevó mucho pueblo tras sí. Pereció también aquél; y todos los que consintieron con él, fueron derramados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 38, 'Y ahora os digo: Dejaos de estos hombres, y dejadlos; porque si este consejo ó esta obra es de los hombres, se desvanecerá:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 39, 'Mas si es de Dios, no la podréis deshacer; no seáis tal vez hallados resistiendo á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 40, 'Y convinieron con él: y llamando á los apóstoles, después de azotados, les intimaron que no hablasen en el nombre de Jesús, y soltáronlos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 41, 'Y ellos partieron de delante del concilio, gozosos de que fuesen tenidos por dignos de padecer afrenta por el Nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 5, 42, 'Y todos los días, en el templo y por las casas, no cesaban de enseñar y predicar á Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 6, 1, 'EN aquellos días, creciendo el número de los discípulos, hubo murmuración de los Griegos contra los Hebreos, de que sus viudas eran menospreciadas en el ministerio cotidiano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 6, 2, 'Así que, los doce convocaron la multitud de los discípulos, y dijeron: No es justo que nosotros dejemos la palabra de Dios, y sirvamos á las mesas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 6, 3, 'Buscad pues, hermanos, siete varones de vosotros de buen testimonio, llenos de Espíritu Santo y de sabiduría, los cuales pongamos en esta obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 6, 4, 'Y nosotros persistiremos en la oración, y en el ministerio de la palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 6, 5, 'Y plugo el parecer á toda la multitud; y eligieron á Esteban, varón lleno de fe y de Espíritu Santo, y á Felipe, y á Prócoro, y á Nicanor, y á Timón, y á Parmenas, y á Nicolás, prosélito de Antioquía:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 6, 6, 'A estos presentaron delante de los apóstoles, los cuales orando les pusieron las manos encima.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 6, 7, 'Y crecía la palabra del Señor, y el número de los discípulos se multiplicaba mucho en Jerusalem: también una gran multitud de los sacerdotes obedecía á la fe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 6, 8, 'Empero Esteban, lleno de gracia y de potencia, hacía prodigios y milagros grandes en el pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 6, 9, 'Levantáronse entonces unos de la sinagoga que se llama de los Libertinos, y Cireneos, y Alejandrinos, y de los de Cilicia, y de Asia, disputando con Esteban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 6, 10, 'Mas no podían resistir á la sabiduría y al Espíritu con que hablaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 6, 11, 'Entonces sobornaron á unos que dijesen que le habían oído hablar palabras blasfemas contra Moisés y Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 6, 12, 'Y conmovieron al pueblo, y á los ancianos, y á los escribas; y arremetiendo le arrebataron, y le trajeron al concilio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 6, 13, 'Y pusieron testigos falsos, que dijesen: Este hombre no cesa de hablar palabras blasfemas contra este lugar santo y la ley:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 6, 14, 'Porque le hemos oído decir, que Jesús de Nazaret destruirá este lugar, y mudará las ordenanzas que nos dió Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 6, 15, 'Entonces todos los que estaban sentados en el concilio, puestos los ojos en él, vieron su rostro como el rostro de un ángel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 1, 'EL príncipe de los sacerdotes dijo entonces: ¿Es esto así?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 2, 'Y él dijo: Varones hermanos y padres, oid: El Dios de la gloria apareció á nuestro padre Abraham, estando en Mesopotamia, antes que morase en Chârán,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 3, 'Y le dijo: Sal de tu tierra y de tu parentela, y ven á la tierra que te mostraré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 4, 'Entonces salió de la tierra de los Caldeos, y habitó en Chârán: y de allí, muerto su padre, le traspasó á esta tierra, en la cual vosotros habitáis ahora;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 5, 'Y no le dió herencia en ella, ni aun para asentar un pie: mas le prometió que se la daría en posesión, y á su simiente después de él, no teniendo hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 6, 'Y hablóle Dios así: Que su simiente sería extranjera en tierra ajena, y que los reducirían á servidumbre y maltratarían, por cuatrocientos años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 7, 'Mas yo juzgaré, dijo Dios, la nación á la cual serán siervos: y después de esto saldrán y me servirán en este lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 8, 'Y dióle el pacto de la circuncisión: y así Abraham engendró á Isaac, y le circuncidó al octavo día; é Isaac á Jacob, y Jacob á los doce patriarcas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 9, 'Y los patriarcas, movidos de envidia, vendieron á José para Egipto; mas Dios era con él,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 10, 'Y le libró de todas sus tribulaciones, y le dió gracia y sabiduría en la presencia de Faraón, rey de Egipto, el cual le puso por gobernador sobre Egipto, y sobre toda su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 11, 'Vino entonces hambre en toda la tierra de Egipto y de Canaán, y grande tribulación; y nuestros padres no hallaban alimentos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 12, 'Y como oyese Jacob que había trigo en Egipto, envió á nuestros padres la primera vez.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 13, 'Y en la segunda, José fué conocido de sus hermanos, y fué sabido de Faraón el linaje de José.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 14, 'Y enviando José, hizo venir á su padre Jacob, y á toda su parentela, en número de setenta y cinco personas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 15, 'Así descendió Jacob á Egipto, donde murió él y nuestros padres;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 16, 'Los cuales fueron trasladados á Sichêm, y puestos en el sepulcro que compró Abraham á precio de dinero de los hijos de Hemor de Sichêm.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 17, 'Mas como se acercaba el tiempo de la promesa, la cual Dios había jurado á Abraham, el pueblo creció y multiplicóse en Egipto,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 18, 'Hasta que se levantó otro rey en Egipto que no conocía á José.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 19, 'Este, usando de astucia con nuestro linaje, maltrató á nuestros padres, á fin de que pusiesen á peligro de muerte sus niños, para que cesase la generación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 20, 'En aquel mismo tiempo nació Moisés, y fué agradable á Dios: y fué criado tres meses en casa de su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 21, 'Mas siendo puesto al peligro, la hija de Faraón le tomó, y le crió como á hijo suyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 22, 'Y fué enseñado Moisés en toda la sabiduría de los egipcios; y era poderoso en sus dichos y hechos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 23, 'Y cuando hubo cumplido la edad de cuarenta años, le vino voluntad de visitar á sus hermanos los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 24, 'Y como vió á uno que era injuriado, defendióle, é hiriendo al Egipcio, vengó al injuriado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 25, 'Pero él pensaba que sus hermanos entendían que Dios les había de dar salud por su mano; mas ellos no lo habían entendido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 26, 'Y al día siguiente, riñendo ellos, se les mostró, y los ponía en paz, diciendo: Varones, hermanos sois, ¿por que os injuriáis los unos á los otros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 27, 'Entonces el que injuriaba á su prójimo, le rempujó, diciendo: ¿Quién te ha puesto por príncipe y juez sobre nosotros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 28, '¿Quieres tú matarme, como mataste ayer al Egipcio?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 29, 'A esta palabra Moisés huyó, y se hizo extranjero en tierra de Madián, donde engendró dos hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 30, 'Y cumplidos cuarenta años, un ángel le apareció en el desierto del monte Sina, en fuego de llama de una zarza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 31, 'Entonces Moisés mirando, se maravilló de la visión: y llegándose para considerar, fué hecha á él voz del Señor:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 32, 'Yo soy el Dios de tus padres, y el Dios de Abraham, el Dios de Isaac, y el Dios de Jacob. Mas Moisés, temeroso, no osaba mirar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 33, 'Y le dijo el Señor: Quita los zapatos de tus pies, porque el lugar en que estás es tierra santa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 34, 'He visto, he visto la aflicción de mi pueblo que está en Egipto, y he oído el gemido de ellos, y he descendido para librarlos. Ahora pues, ven, te enviaré á Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 35, 'A este Moisés, al cual habían rehusado, diciendo: ¿Quién te ha puesto por príncipe y juez? á éste envió Dios por príncipe y redentor con la mano del ángel que le apareció en la zarza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 36, 'Este los sacó, habiendo hecho prodigios y milagros en la tierra de Egipto, y en el mar Bermejo, y en el desierto por cuarenta años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 37, 'Este es el Moisés, el cual dijo á los hijos de Israel: Profeta os levantará el Señor Dios vuestro de vuestros hermanos, como yo; á él oiréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 38, 'Este es aquél que estuvo en la congregación en el desierto con el ángel que le hablaba en el monte Sina, y con nuestros padres; y recibió las palabras de vida para darnos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 39, 'Al cual nuestros padres no quisieron obedecer; antes le desecharon, y se apartaron de corazón á Egipto,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 40, 'Diciendo á Aarón: Haznos dioses que vayan delante de nosotros; porque á este Moisés, que nos sacó de tierra de Egipto, no sabemos qué le ha acontecido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 41, 'Y entonces hicieron un becerro, y ofrecieron sacrificio al ídolo, y en las obras de sus manos se holgaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 42, 'Y Dios se apartó, y los entregó que sirviesen al ejército del cielo; como está escrito en el libro de los profetas: ¿Me ofrecisteis víctimas y sacrificios En el desierto por cuarenta años, casa de Israel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 43, 'Antes, trajisteis el tabernáculo de Moloch, Y la estrella de vuestro dios Remphan: Figuras que os hicisteis para adorarlas: Os transportaré pues, más allá de Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 44, 'Tuvieron nuestros padres el tabernáculo del testimonio en el desierto, como había ordenado Dios, hablando á Moisés que lo hiciese según la forma que había visto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 45, 'El cual recibido, metieron también nuestros padres con Josué en la posesión de los Gentiles, que Dios echó de la presencia de nuestros padres, hasta los días de David;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 46, 'El cual halló gracia delante de Dios, y pidió hallar tabernáculo para el Dios de Jacob.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 47, 'Mas Salomón le edificó casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 48, 'Si bien el Altísimo no habita en templos hechos de mano; como el profeta dice:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 49, 'El cielo es mi trono, Y la tierra es el estrado de mis pies. ¿Qué casa me edificaréis? dice el Señor; ¿O cuál es el lugar de mi reposo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 50, '¿No hizo mi mano todas estas cosas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 51, 'Duros de cerviz, é incircuncisos de corazón y de oídos, vosotros resistís siempre al Espíritu Santo: como vuestros padres, así también vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 52, '¿A cuál de los profetas no persiguieron vuestros padres? y mataron á los que antes anunciaron la venida del Justo, del cual vosotros ahora habéis sido entregadores y matadores;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 53, 'Que recibisteis la ley por disposición de ángeles, y no la guardasteis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 54, 'Y oyendo estas cosas, regañaban de sus corazones, y crujían los dientes contra él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 55, 'Más él, estando lleno de Espíritu Santo, puestos los ojos en el cielo, vió la gloria de Dios, y á Jesús que estaba á la diestra de Dios,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 56, 'Y dijo: He aquí, veo los cielos abiertos, y al Hijo del hombre que está á la diestra de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 57, 'Entonces dando grandes voces, se taparon sus oídos, y arremetieron unánimes contra él;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 58, 'Y echándolo fuera de la ciudad, le apedreaban: y los testigos pusieron sus vestidos á los pies de un mancebo que se llamaba Saulo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 59, 'Y apedrearon á Esteban, invocando él y diciendo: Señor Jesús, recibe mi espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 7, 60, 'Y puesto de rodillas, clamó á gran voz: Señor, no les imputes este pecado. Y habiendo dicho esto, durmió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 1, 'Y SAULO consentía en su muerte. Y en aquel día se hizo una grande persecución en la iglesia que estaba en Jerusalem; y todos fueron esparcidos por las tierras de Judea y de Samaria, salvo los apóstoles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 2, 'Y llevaron á enterrar á Esteban varones piadosos, é hicieron gran llanto sobre él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 3, 'Entonces Saulo asolaba la iglesia, entrando por las casas: y trayendo hombres y mujeres, los entregaba en la cárcel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 4, 'Mas los que fueron esparcidos, iban por todas partes anunciando la palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 5, 'Entonces Felipe, descendiendo á la ciudad de Samaria, les predicaba á Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 6, 'Y las gentes escuchaban atentamente unánimes las cosas que decía Felipe, oyendo y viendo las señales que hacía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 7, 'Porque de muchos que tenían espíritus inmundos, salían éstos dando grandes voces; y muchos paralíticos y cojos eran sanados:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 8, 'Así que había gran gozo en aquella ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 9, 'Y había un hombre llamado Simón, el cual había sido antes mágico en aquella ciudad, y había engañado la gente de Samaria, diciéndose ser algún grande:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 10, 'Al cual oían todos atentamente desde al más pequeño hasta el más grande, diciendo: Este es la gran virtud de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 11, 'Y le estaban atentos, porque con sus artes mágicas los había embelesado mucho tiempo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 12, 'Mas cuando creyeron á Felipe, que anunciaba el evangelio del reino de Dios y el nombre de Jesucristo, se bautizaban hombres y mujeres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 13, 'El mismo Simón creyó también entonces, y bautizándose, se llegó á Felipe: y viendo los milagros y grandes maravillas que se hacían, estaba atónito.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 14, 'Y los apóstoles que estaban en Jerusalem, habiendo oído que Samaria había recibido la palabra de Dios, les enviaron á Pedro y á Juan:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 15, 'Los cuales venidos, oraron por ellos, para que recibiesen el Espíritu Santo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 16, '(Porque aun no había descendido sobre ninguno de ellos, mas solamente eran bautizados en el nombre de Jesús.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 17, 'Entonces les impusieron las manos, y recibieron el Espíritu Santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 18, 'Y como vió Simón que por la imposición de las manos de los apóstoles se daba el Espíritu Santo, les ofreció dinero,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 19, 'Diciendo: Dadme también á mí esta potestad, que á cualquiera que pusiere las manos encima, reciba el Espíritu Santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 20, 'Entonces Pedro le dijo: Tu dinero perezca contigo, que piensas que el don de Dios se gane por dinero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 21, 'No tienes tú parte ni suerte en este negocio; porque tu corazón no es recto delante de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 22, 'Arrepiéntete pues de esta tu maldad, y ruega á Dios, si quizás te será perdonado el pensamiento de tu corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 23, 'Porque en hiel de amargura y en prisión de maldad veo que estás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 24, 'Respondiendo entonces Simón, dijo: Rogad vosotros por mí al Señor, que ninguna cosa de estas que habéis dicho, venga sobre mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 25, 'Y ellos, habiendo testificado y hablado la palabra de Dios, se volvieron á Jerusalem, y en muchas tierras de los Samaritanos anunciaron el evangelio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 26, 'Empero el ángel de Señor habló á Felipe, diciendo: Levántate y ve hacia el mediodía, al camino que desciende de Jerusalem á Gaza, el cual es desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 27, 'Entonces él se levantó, y fué: y he aquí un Etiope, eunuco, gobernador de Candace, reina de los Etiopes, el cual era puesto sobre todos sus tesoros, y había venido á adorar á Jerusalem,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 28, 'Se volvía sentado en su carro, y leyendo el profeta Isaías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 29, 'Y el Espíritu dijo á Felipe: Llégate, y júntate á este carro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 30, 'Y acudiendo Felipe, le oyó que leía el profeta Isaías, y dijo: Mas ¿entiendes lo que lees?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 31, 'Y dijo: ¿Y cómo podré, si alguno no me enseñare? Y rogó á Felipe que subiese, y se sentase con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 32, 'Y el lugar de la Escritura que leía, era éste: Como oveja á la muerte fué llevado; Y como cordero mudo delante del que le trasquila, Así no abrió su boca:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 33, 'En su humillación su juicio fué quitado: Mas su generación, ¿quién la contará? Porque es quitada de la tierra su vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 34, 'Y respondiendo el eunuco á Felipe, dijo: Ruégote ¿de quién el profeta dice esto? ¿de sí, ó de otro alguno?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 35, 'Entonces Felipe, abriendo su boca, y comenzando desde esta escritura, le anunció el evangelio de Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 36, 'Y yendo por el camino, llegaron á cierta agua; y dijo el eunuco: He aquí agua; ¿qué impide que yo sea bautizado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 37, 'Y Felipe dijo: Si crees de todo corazón, bien puedes. Y respondiendo, dijo: Creo que Jesucristo es el Hijo de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 38, 'Y mandó parar el carro: y descendieron ambos al agua, Felipe y el eunuco; y bautizóle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 39, 'Y como subieron del agua, el Espíritu del Señor arrebató á Felipe; y no le vió más el eunuco, y se fué por su camino gozoso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 8, 40, 'Felipe empero se halló en Azoto: y pasando, anunciaba el evangelio en todas las ciudades, hasta que llegó á Cesarea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 1, 'Y SAULO, respirando aún amenazas y muerte contra los discípulos del Señor, vino al príncipe de los sacerdotes,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 2, 'Y demandó de él letras para Damasco á las sinagogas, para que si hallase algunos hombres ó mujeres de esta secta, los trajese presos á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 3, 'Y yendo por el camino, aconteció que llegando cerca de Damasco, súbitamente le cercó un resplandor de luz del cielo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 4, 'Y cayendo en tierra, oyó una voz que le decía: Saulo, Saulo, ¿por qué me persigues?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 5, 'Y él dijo: ¿Quién eres, Señor? Y él dijo: Yo soy Jesús á quien tú persigues: dura cosa te es dar coses contra el aguijón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 6, 'El, temblando y temeroso, dijo: ¿Señor, qué quieres que haga? Y el Señor le dice: Levántate y entra en la ciudad, y se te dirá lo que te conviene hacer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 7, 'Y los hombres que iban con Saul, se pararon atónitos, oyendo á la verdad la voz, mas no viendo á nadie.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 8, 'Entonces Saulo se levantó de tierra, y abriendo los ojos, no veía á nadie: así que, llevándole por la mano, metiéronle en Damasco;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 9, 'Donde estuvo tres días sin ver, y no comió, ni bebió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 10, 'Había entonces un discípulo en Damasco llamado Ananías, al cual el Señor dijo en visión: Ananías. Y él respondió: Heme aquí, Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 11, 'Y el Señor le dijo: Levántate, y ve á la calle que se llama la Derecha, y busca en casa de Judas á uno llamado Saulo, de Tarso: porque he aquí, él ora;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 12, 'Y ha visto en visión un varón llamado Ananías, que entra y le pone la mano encima, para que reciba la vista.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 13, 'Entonces Ananías respondió: Señor, he oído á muchos acerca de este hombre, cuántos males ha hecho á tus santos en Jerusalem:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 14, 'Y aun aquí tiene facultad de los príncipes de los sacerdotes de prender á todos los que invocan tu nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 15, 'Y le dijo el Señor: Ve: porque instrumento escogido me es éste, para que lleve mi nombre en presencia de los Gentiles, y de reyes, y de los hijos de Israel:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 16, 'Porque yo le mostraré cuánto le sea menester que padezca por mi nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 17, 'Ananías entonces fué, y entró en la casa, y poniéndole las manos encima, dijo: Saulo hermano, el Señor Jesús, que te apareció en el camino por donde venías, me ha enviado para que recibas la vista y seas lleno de Espíritu Santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 18, 'Y luego le cayeron de los ojos como escamas, y recibió al punto la vista: y levantándose, fué bautizado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 19, 'Y como comió, fué confortado. Y estuvo Saulo por algunos días con los discípulos que estaban en Damasco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 20, 'Y luego en las sinagogas predicaba á Cristo, diciendo que éste era el Hijo de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 21, 'Y todos los que le oían estaban atónitos, y decían: ¿No es éste el que asolaba en Jerusalem á los que invocaban este nombre, y á eso vino acá, para llevarlos presos á los príncipes de los sacerdotes?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 22, 'Empero Saulo mucho más se esforzaba, y confundía á los Judíos que moraban en Damasco, afirmando que éste es el Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 23, 'Y como pasaron muchos días, los Judíos hicieron entre sí consejo de matarle;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 24, 'Mas las asechanzas de ellos fueron entendidas de Saulo. Y ellos guardaban las puertas de día y de noche para matarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 25, 'Entonces los discípulos, tomándole de noche, le bajaron por el muro en una espuerta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 26, 'Y como vino á Jerusalem, tentaba de juntarse con los discípulos; mas todos tenían miedo de él, no creyendo que era discípulo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 27, 'Entonces Bernabé, tomándole, lo trajo á los apóstoles, y contóles cómo había visto al Señor en el camino, y que le había hablado, y cómo en Damasco había hablado confiadamente en el nombre de Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 28, 'Y entraba y salía con ellos en Jerusalem;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 29, 'Y hablaba confiadamente en el nombre del Señor: y disputaba con los Griegos; mas ellos procuraban matarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 30, 'Lo cual, como los hermanos entendieron, le acompañaron hasta Cesarea, y le enviaron á Tarso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 31, 'Las iglesias entonces tenían paz por toda Judea y Galilea y Samaria, y eran edificadas, andando en el temor del Señor; y con consuelo del Espíritu Santo eran multiplicadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 32, 'Y aconteció que Pedro, andándolos á todos, vino también á los santos que habitaban en Lydda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 33, 'Y halló allí á uno que se llamaba Eneas, que hacía ocho años que estaba en cama, que era paralítico.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 34, 'Y le dijo Pedro: Eneas, Jesucristo te sana; levántate, y hazte tu cama. Y luego se levantó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 35, 'Y viéronle todos los que habitaban en Lydda y en Sarona, los cuales se convirtieron al Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 36, 'Entonces en Joppe había una discípula llamada Tabita, que si lo declaras, quiere decir Dorcas. Esta era llena de buenas obras y de limosnas que hacía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 37, 'Y aconteció en aquellos días que enfermando, murió; á la cual, después de lavada, pusieron en una sala.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 38, 'Y como Lydda estaba cerca de Joppe, los discípulos, oyendo que Pedro estaba allí, le enviaron dos hombres, rogándole: No te detengas en venir hasta nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 39, 'Pedro entonces levantándose, fué con ellos: y llegado que hubo, le llevaron á la sala, donde le rodearon todas las viudas, llorando y mostrando las túnicas y los vestidos que Dorcas hacía cuando estaba con ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 40, 'Entonces echados fuera todos, Pedro puesto de rodillas, oró; y vuelto al cuerpo, dijo: Tabita, levántate. Y ella abrió los ojos, y viendo á Pedro, incorporóse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 41, 'Y él le dió la mano, y levantóla: entonces llamando á los santos y las viudas, la presentó viva.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 42, 'Esto fué notorio por toda Joppe; y creyeron muchos en el Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 9, 43, 'Y aconteció que se quedó muchos días en Joppe en casa de un cierto Simón, curtidor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 1, 'Y HABIA un varón en Cesarea llamado Cornelio, centurión de la compañía que se llamaba la Italiana,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 2, 'Pío y temeroso de Dios con toda su casa, y que hacía muchas limosnas al pueblo, y oraba á Dios siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 3, 'Este vió en visión manifiestamente, como á la hora nona del día, que un ángel de Dios entraba á él, y le decía: Cornelio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 4, 'Y él, puestos en él los ojos, espantado, dijo: ¿Qué es, Señor? Y díjole: Tus oraciones y tus limosnas han subido en memoria á la presencia de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 5, 'Envía pues ahora hombres á Joppe, y haz venir á un Simón, que tiene por sobrenombre Pedro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 6, 'Este posa en casa de un Simón, curtidor, que tiene su casa junto á la mar: él te dirá lo que te conviene hacer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 7, 'E ido el ángel que hablaba con Cornelio, llamó dos de sus criados, y un devoto soldado de los que le asistían;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 8, 'A los cuales, después de habérselo contado todo, los envió á Joppe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 9, 'Y al día siguiente, yendo ellos su camino, y llegando cerca de la ciudad, Pedro subió á la azotea á orar, cerca de la hora de sexta;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 10, 'Y aconteció que le vino una grande hambre, y quiso comer; pero mientras disponían, sobrevínole un éxtasis;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 11, 'Y vió el cielo abierto, y que descendía un vaso, como un gran lienzo, que atado de los cuatro cabos era bajado á la tierra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 12, 'En el cual había de todos los animales cuadrúpedos de la tierra, y reptiles, y aves del cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 13, 'Y le vino una voz: Levántate, Pedro, mata y come.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 14, 'Entonces Pedro dijo: Señor, no; porque ninguna cosa común é inmunda he comido jamás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 15, 'Y volvió la voz hacia él la segunda vez: Lo que Dios limpió, no lo llames tú común.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 16, 'Y esto fué hecho por tres veces; y el vaso volvió á ser recogido en el cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 17, 'Y estando Pedro dudando dentro de sí qué sería la visión que había visto, he aquí, los hombres que habían sido enviados por Cornelio, que, preguntando por la casa de Simón, llegaron á la puerta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 18, 'Y llamando, preguntaron si un Simón que tenía por sobrenombre Pedro, posaba allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 19, 'Y estando Pedro pensando en la visión, le dijo el Espíritu: He aquí, tres hombres te buscan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 20, 'Levántate, pues, y desciende, y no dudes ir con ellos; porque yo los he enviado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 21, 'Entonces Pedro, descendiendo á los hombres que eran enviados por Cornelio, dijo: He aquí, yo soy el que buscáis: ¿cuál es la causa por la que habéis venido?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 22, 'Y ellos dijeron: Cornelio, el centurión, varón justo y temeroso de Dios, y que tiene testimonio de toda la nación de los Judíos, ha recibido respuesta por un santo ángel, de hacerte venir á su casa, y oir de ti palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 23, 'Entonces metiéndolos dentro, los hospedó. Y al día siguiente, levantándose, se fué con ellos; y le acompañaron algunos de los hermanos de Joppe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 24, 'Y al otro día entraron en Cesarea. Y Cornelio los estaba esperando, habiendo llamado á sus parientes y los amigos más familiares.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 25, 'Y como Pedro entró, salió Cornelio á recibirle; y derribándose á sus pies, adoró.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 26, 'Mas Pedro le levantó, diciendo: Levántate; yo mismo también soy hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 27, 'Y hablando con él, entró, y halló á muchos que se habían juntado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 28, 'Y les dijo: Vosotros sabéis que es abominable á un varón Judío juntarse ó llegarse á extranjero; mas me ha mostrado Dios que á ningún hombre llame común ó inmundo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 29, 'Por lo cual, llamado, he venido sin dudar. Así que pregunto: ¿por qué causa me habéis hecho venir?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 30, 'Entonces Cornelio dijo: Cuatro días ha que á esta hora yo estaba ayuno; y á la hora de nona estando orando en mi casa, he aquí un varón se puso delante de mí en vestido resplandeciente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 31, 'Y dijo: Cornelio, tu oración es oída, y tus limosnas han venido en memoria en la presencia de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 32, 'Envía pues á Joppe, y haz venir á un Simón, que tiene por sobrenombre Pedro; éste posa en casa de Simón, curtidor, junto á la mar; el cual venido, te hablará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 33, 'Así que, luego envié á ti; y tú has hecho bien en venir. Ahora pues, todos nosotros estamos aquí en la presencia de Dios, para oir todo lo que Dios te ha mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 34, 'Entonces Pedro, abriendo su boca, dijo: Por verdad hallo que Dios no hace acepción de personas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 35, 'Sino que de cualquiera nación que le teme y obra justicia, se agrada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 36, 'Envió palabra Dios á los hijos de Israel, anunciando la paz por Jesucristo; éste es el Señor de todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 37, 'Vosotros sabéis lo que fué divulgado por toda Judea; comenzando desde Galilea después del bautismo que Juan predicó,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 38, 'Cuanto á Jesús de Nazaret; cómo le ungió Dios de Espíritu Santo y de potencia; el cual anduvo haciendo bienes, y sanando á todos los oprimidos del diablo; porque Dios era con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 39, 'Y nosotros somos testigos de todas las cosas que hizo en la tierra de Judea, y en Jerusalem; al cual mataron colgándole en un madero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 40, 'A éste levantó Dios al tercer día, é hizo que apareciese manifiesto,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 41, 'No á todo el pueblo, sino á los testigos que Dios antes había ordenado, es á saber, á nosotros que comimos y bebimos con él, después que resucitó de los muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 42, 'Y nos mandó que predicásemos al pueblo, y testificásemos que él es el que Dios ha puesto por Juez de vivos y muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 43, 'A éste dan testimonio todos los profetas, de que todos los que en él creyeren, recibirán perdón de pecados por su nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 44, 'Estando aún hablando Pedro estas palabras, el Espíritu Santo cayó sobre todos los que oían el sermón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 45, 'Y se espantaron los fieles que eran de la circuncisión, que habían venido con Pedro, de que también sobre los Gentiles se derramase el don del Espíritu Santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 46, 'Porque los oían que hablaban en lenguas, y que magnificaban á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 47, 'Entonces respondió Pedro: ¿Puede alguno impedir el agua, para que no sean bautizados éstos que han recibido el Espíritu Santo también como nosotros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 10, 48, 'Y les mandó bautizar en el nombre del Señor Jesús. Entonces le rogaron que se quedase por algunos días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 11, 1, 'Y OYERON los apóstoles y los hermanos que estaban en Judea, que también los Gentiles habían recibido la palabra de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 11, 2, 'Y como Pedro subió á Jerusalem, contendían contra él los que eran de la circuncisión,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 11, 3, 'Diciendo: ¿Por qué has entrado á hombres incircuncisos, y has comido con ellos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 11, 4, 'Entonces comenzando Pedro, les declaró por orden lo pasado, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 11, 5, 'Estaba yo en la ciudad de Joppe orando, y vi en rapto de entendimiento una visión: un vaso, como un gran lienzo, que descendía, que por los cuatro cabos era abajado del cielo, y venía hasta mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 11, 6, 'En el cual como puse los ojos, consideré y vi animales terrestres de cuatro pies, y fieras, y reptiles, y aves del cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 11, 7, 'Y oí una voz que me decía: Levántate, Pedro, mata y come.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 11, 8, 'Y dije: Señor, no; porque ninguna cosa común ó inmunda entró jamás en mi boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 11, 9, 'Entonces la voz me respondió del cielo segunda vez: Lo que Dios limpió, no lo llames tú común.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 11, 10, 'Y esto fué hecho por tres veces: y volvió todo á ser tomado arriba en el cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 11, 11, 'Y he aquí, luego sobrevinieron tres hombres á la casa donde yo estaba, enviados á mí de Cesarea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 11, 12, 'Y el Espíritu me dijo que fuese con ellos sin dudar. Y vinieron también conmigo estos seis hermanos, y entramos en casa de un varón,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 11, 13, 'El cual nos contó cómo había visto un ángel en su casa, que se paró, y le dijo: Envía á Joppe, y haz venir á un Simón que tiene por sobrenombre Pedro;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 11, 14, 'El cual te hablará palabras por las cuales serás salvo tu, y toda tu casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 11, 15, 'Y como comencé á hablar, cayó el Espíritu Santo sobre ellos también, como sobre nosotros al principio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 11, 16, 'Entonces me acordé del dicho del Señor, como dijo: Juan ciertamente bautizó en agua; mas vosotros seréis bautizados en Espíritu Santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 11, 17, 'Así que, si Dios les dió el mismo don también como á nosotros que hemos creído en el Señor Jesucristo, ¿quién era yo que pudiese estorbar á Dios?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 11, 18, 'Entonces, oídas estas cosas, callaron, y glorificaron á Dios, diciendo: De manera que también á los Gentiles ha dado Dios arrepentimiento para vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 11, 19, 'Y los que habían sido esparcidos por causa de la tribulación que sobrevino en tiempo de Esteban, anduvieron hasta Fenicia, y Cipro, y Antioquía, no hablando á nadie la palabra, sino sólo á los Judíos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 11, 20, 'Y de ellos había unos varones Ciprios y Cirenences, los cuales como entraron en Antioquía, hablaron á los Griegos, anunciando el evangelio del Señor Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 11, 21, 'Y la mano del Señor era con ellos: y creyendo, gran número se convirtió al Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 11, 22, 'Y llegó la fama de estas cosas á oídos de la iglesia que estaba en Jerusalem: y enviaron á Bernabé que fuese hasta Antioquía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 11, 23, 'El cual, como llegó, y vió la gracia de Dios, regocijóse; y exhortó á todos á que permaneciesen en el propósito del corazón en el Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 11, 24, 'Porque era varón bueno, y lleno de Espíritu Santo y de fe: y mucha compañía fué agregada al Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 11, 25, 'Después partió Bernabé á Tarso á buscar á Saulo; y hallado, le trajo á Antioquía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 11, 26, 'Y conversaron todo un año allí con la iglesia, y enseñaron á mucha gente; y los discípulos fueron llamados Cristianos primeramente en Antioquía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 11, 27, 'Y en aquellos días descendieron de Jerusalem profetas á Antioquía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 11, 28, 'Y levantándose uno de ellos, llamado Agabo, daba á entender por Espíritu, que había de haber una grande hambre en toda la tierra habitada: la cual hubo en tiempo de Claudio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 11, 29, 'Entonces los discípulos, cada uno conforme á lo que tenía, determinaron enviar subsidio á los hermanos que habitaban en Judea:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 11, 30, 'Lo cual asimismo hicieron, enviándolo á los ancianos por mano de Bernabé y de Saulo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 12, 1, 'Y EN el mismo tiempo el rey Herodes echó mano á maltratar algunos de la iglesia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 12, 2, 'Y mató á cuchillo á Jacobo, hermano de Juan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 12, 3, 'Y viendo que había agradado á los Judíos, pasó adelante para prender también á Pedro. Eran entonces los días de los ázimos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 12, 4, 'Y habiéndole preso, púsole en la cárcel, entregándole á cuatro cuaterniones de soldados que le guardasen; queriendo sacarle al pueblo después de la Pascua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 12, 5, 'Así que, Pedro era guardado en la cárcel; y la iglesia hacía sin cesar oración á Dios por él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 12, 6, 'Y cuando Herodes le había de sacar, aquella misma noche estaba Pedro durmiendo entre dos soldados, preso con dos cadenas, y los guardas delante de la puerta, que guardaban la cárcel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 12, 7, 'Y he aquí, el ángel del Señor sobrevino, y una luz resplandeció en la cárcel; é hiriendo á Pedro en el lado, le despertó, diciendo: Levántate prestamente. Y las cadenas se le cayeron de las manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 12, 8, 'Y le dijo el ángel: Cíñete, y átate tus sandalias. Y lo hizo así. Y le dijo: Rodéate tu ropa, y sígueme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 12, 9, 'Y saliendo, le seguía; y no sabía que era verdad lo que hacía el ángel, mas pensaba que veía visión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 12, 10, 'Y como pasaron la primera y la segunda guardia, vinieron á la puerta de hierro que va á la ciudad, la cual se les abrió de suyo: y salidos, pasaron una calle; y luego el ángel se apartó de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 12, 11, 'Entonces Pedro, volviendo en sí, dijo: Ahora entiendo verdaderamente que el Señor ha enviado su ángel, y me ha librado de la mano de Herodes, y de todo el pueblo de los Judíos que me esperaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 12, 12, 'Y habiendo considerado esto, llegó á casa de María la madre de Juan, el que tenía por sobrenombre Marcos, donde muchos estaban juntos orando.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 12, 13, 'Y tocando Pedro á la puerta del patio, salió una muchacha, para escuchar, llamada Rhode:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 12, 14, 'La cual como conoció la voz de Pedro, de gozo no abrió el postigo, sino corriendo adentro, dió nueva de que Pedro estaba al postigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 12, 15, 'Y ellos le dijeron: Estás loca. Mas ella afirmaba que así era. Entonces ellos decían: Su ángel es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 12, 16, 'Mas Pedro perseveraba en llamar: y cuando abrieron, viéronle, y se espantaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 12, 17, 'Mas él haciéndoles con la mano señal de que callasen, les contó cómo el Señor le había sacado de la cárcel. Y dijo: Haced saber esto á Jacobo y á los hermanos. Y salió, y partió á otro lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 12, 18, 'Luego que fué de día, hubo no poco alboroto entre los soldados sobre qué se había hecho de Pedro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 12, 19, 'Mas Herodes, como le buscó y no le halló, hecha inquisición de los guardas, los mandó llevar. Después descendiendo de Judea á Cesarea, se quedó allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 12, 20, 'Y Herodes estaba enojado contra los de Tiro y los de Sidón: mas ellos vinieron concordes á él, y sobornado Blasto, que era el camarero del rey, pedían paz; porque las tierras de ellos eran abastecidas por las del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 12, 21, 'Y un día señalado, Herodes vestido de ropa real, se sentó en el tribunal, y arengóles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 12, 22, 'Y el pueblo aclamaba: Voz de Dios, y no de hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 12, 23, 'Y luego el ángel del Señor le hirió, por cuanto no dió la gloria á Dios; y espiró comido de gusanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 12, 24, 'Mas la palabra del Señor crecía y era multiplicada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 12, 25, 'Y Bernabé y Saulo volvieron de Jerusalem cumplido su servicio, tomando también consigo á Juan, el que tenía por sobrenombre Marcos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 1, 'HABIA entonces en la iglesia que estaba en Antioquía, profetas y doctores: Bernabé, y Simón el que se llamaba Niger, y Lucio Cireneo, y Manahén, que había sido criado con Herodes el tetrarca, y Saulo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 2, 'Ministrando pues éstos al Señor, y ayunando, dijo el Espíritu Santo: Apartadme á Bernabé y á Saulo para la obra para la cual los he llamado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 3, 'Entonces habiendo ayunado y orado, y puesto las manos encima de ellos, despidiéronlos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 4, 'Y ellos, enviados así por el Espíritu Santo, descendieron á Seleucia: y de allí navegaron á Cipro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 5, 'Y llegados á Salamina, anunciaban la palabra de Dios en las sinagogas de los Judíos: y tenían también á Juan en el ministerio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 6, 'Y habiendo atravesado toda la isla hasta Papho, hallaron un hombre mago, falso profeta, Judío, llamado Bar jesús;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 7, 'El cual estaba con el procónsul Sergio Paulo, varón prudente. Este, llamando á Bernabé y á Saulo, deseaba oír la palabra de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 8, 'Mas les resistía Elimas el encantador (que así se interpreta su nombre), procurando apartar de la fe al procónsul.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 9, 'Entonces Saulo, que también es Pablo, lleno del Espíritu Santo, poniendo en él los ojos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 10, 'Dijo: Oh, lleno de todo engaño y de toda maldad, hijo del diablo, enemigo de toda justicia, ¿no cesarás de trastornar los caminos rectos del Señor?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 11, 'Ahora pues, he aquí la mano del Señor es contra ti, y serás ciego, que no veas el sol por tiempo. Y luego cayeron en él obscuridad y tinieblas; y andando alrededor, buscaba quién le condujese por la mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 12, 'Entonces el procónsul, viendo lo que había sido hecho, creyó, maravillado de la doctrina del Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 13, 'Y partidos de Papho, Pablo y sus compañeros arribaron á Perge de Pamphylia: entonces Juan, apartándose de ellos, se volvió á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 14, 'Y ellos pasando de Perge, llegaron á Antioquía de Pisidia, y entrando en la sinagoga un día de sábado, sentáronse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 15, 'Y después de la lectura de la ley y de los profetas, los príncipes de la sinagoga enviaron á ellos, diciendo: Varones hermanos, si tenéis alguna palabra de exhortación para el pueblo, hablad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 16, 'Entonces Pablo, levantándose, hecha señal de silencio con la mano, dice: Varones Israelitas, y los que teméis á Dios, oid:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 17, 'El Dios del pueblo de Israel escogió á nuestros padres, y ensalzó al pueblo, siendo ellos extranjeros en la tierra de Egipto, y con brazo levantado los sacó de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 18, 'Y por tiempo como de cuarenta años soportó sus costumbres en el desierto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 19, 'Y destruyendo siete naciones en la tierra de Canaán, les repartió por suerte la tierra de ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 20, 'Y después, como por cuatrocientos y cincuenta años, dió les jueces hasta el profeta Samuel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 21, 'Y entonces demandaron rey; y les dió Dios á Saúl, hijo de Cis, varón de la tribu de Benjamín, por cuarenta años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 22, 'Y quitado aquél, levantóles por rey á David, el que dió también testimonio, diciendo: He hallado á David, hijo de Jessé, varón conforme á mi corazón, el cual hará todo lo que yo quiero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 23, 'De la simiente de éste, Dios, conforme á la promesa, levantó á Jesús por Salvador á Israel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 24, 'Predicando Juan delante de la faz de su venida el bautismo de arrepentimiento á todo el pueblo de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 25, 'Mas como Juan cumpliese su carrera, dijo: ¿Quién pensáis que soy? No soy yo él; mas he aquí, viene tras mí uno, cuyo calzado de los pies no soy digno de desatar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 26, 'Varones hermanos, hijos del linaje de Abraham, y los que entre vosotros temen á Dios, á vosotros es enviada la palabra de esta salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 27, 'Porque los que habitaban en Jerusalem, y sus príncipes, no conociendo á éste, y las voces de los profetas que se leen todos los sábados, condenándo les, las cumplieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 28, 'Y sin hallar en él causa de muerte, pidieron á Pilato que le matasen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 29, 'Y habiendo cumplido todas las cosas que de él estaban escritas, quitándolo del madero, lo pusieron en el sepulcro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 30, 'Mas Dios le levantó de los muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 31, 'Y él fué visto por muchos días de los que habían subido juntamente con él de Galilea á Jerusalem, los cuales son sus testigos al pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 32, 'Y nosotros también os anunciamos el evangelio de aquella promesa que fué hecha á los padres,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 33, 'La cual Dios ha cumplido á los hijos de ellos, á nosotros, resucitando á Jesús: como también en el salmo segundo está escrito: Mi hijo eres tú, yo te he engendrado hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 34, 'Y que le levantó de los muertos para nunca más volver á corrupción, así lo dijo: Os daré las misericordias fieles de David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 35, 'Por eso dice también en otro lugar: No permitirás que tu Santo vea corrupción.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 36, 'Porque á la verdad David, habiendo servido en su edad á la voluntad de Dios, durmió, y fué juntado con sus padres, y vió corrupción.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 37, 'Mas aquel que Dios levantó, no vió corrupción.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 38, 'Séaos pues notorio, varones hermanos, que por éste os es anunciada remisión de pecados,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 39, 'Y de todo lo que por la ley de Moisés no pudisteis ser justificados, en éste es justificado todo aquel que creyere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 40, 'Mirad, pues, que no venga sobre vosotros lo que está dicho en los profetas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 41, 'Mirad, oh menospreciadores, y entonteceos, y desvaneceos; Porque yo obro una obra en vuestros días, Obra que no creeréis, si alguien os la contare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 42, 'Y saliendo ellos de la sinagoga de los Judíos, los Gentiles les rogaron que el sábado siguiente les hablasen estas palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 43, 'Y despedida la congregación, muchos de los Judíos y de los religiosos prosélitos siguieron á Pablo y á Bernabé; los cuales hablándoles, les persuadían que permaneciesen en la gracia de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 44, 'Y el sábado siguiente se juntó casi toda la ciudad á oir la palabra de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 45, 'Mas los Judíos, visto el gentío, llenáronse de celo, y se oponían á lo que Pablo decía, contradiciendo y blasfemando.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 46, 'Entonces Pablo y Bernabé, usando de libertad, dijeron: A vosotros á la verdad era menester que se os hablase la palabra de Dios; mas pues que la desecháis, y os juzgáis indignos de la vida eterna, he aquí, nos volvemos á los Gentiles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 47, 'Porque así nos ha mandado el Señor, diciendo: Te he puesto para luz de los Gentiles, Para que seas salud hasta lo postrero de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 48, 'Y los Gentiles oyendo esto, fueron gozosos, y glorificaban la palabra del Señor: y creyeron todos los que estaban ordenados para vida eterna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 49, 'Y la palabra del Señor era sembrada por toda aquella provincia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 50, 'Mas los Judíos concitaron mujeres pías y honestas, y á los principales de la ciudad, y levantaron persecución contra Pablo y Bernabé, y los echaron de sus términos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 51, 'Ellos entonces sacudiendo en ellos el polvo de sus pies, vinieron á Iconio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 13, 52, 'Y los discípulos estaban llenos de gozo, y del Espíritu Santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 14, 1, 'Y ACONTECIO en Iconio, que entrados juntamente en la sinagoga de los Judíos, hablaron de tal manera, que creyó una grande multitud de Judíos, y asimismo de Griegos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 14, 2, 'Mas los Judíos que fueron incrédulos, incitaron y corrompieron los ánimos de los Gentiles contra los hermanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 14, 3, 'Con todo eso se detuvieron allí mucho tiempo, confiados en el Señor, el cual daba testimonio á la palabra de su gracia, dando que señales y milagros fuesen hechos por las manos de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 14, 4, 'Mas el vulgo de la ciudad estaba dividido; y unos eran con los Judíos, y otros con los apóstoles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 14, 5, 'Y haciendo ímpetu los Judíos y los Gentiles juntamente con sus príncipes, para afrentarlos y apedrearlos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 14, 6, 'Habiéndolo entendido, huyeron á Listra y Derbe, ciudades de Licaonia, y por toda la tierra alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 14, 7, 'Y allí predicaban el evangelio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 14, 8, 'Y un hombre de Listra, impotente de los pies, estaba sentado, cojo desde el vientre de su madre, que jamás había andado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 14, 9, 'Este oyó hablar á Pablo; el cual, como puso los ojos en él, y vió que tenía fe para ser sano,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 14, 10, 'Dijo á gran voz: Levántate derecho sobre tus pies. Y saltó, y anduvo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 14, 11, 'Entonces las gentes, visto lo que Pablo había hecho, alzaron la voz, diciendo en lengua licaónica: Dioses semejantes á hombres han descendido á nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 14, 12, 'Y á Bernabé llamaban Júpiter, y á Pablo, Mercurio, porque era el que llevaba la palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 14, 13, 'Y el sacerdote de Júpiter, que estaba delante de la ciudad de ellos, trayendo toros y guirnaldas delante de las puertas, quería con el pueblo sacrificar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 14, 14, 'Y como lo oyeron los apóstoles Bernabé y Pablo, rotas sus ropas, se lanzaron al gentío, dando voces,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 14, 15, 'Y diciendo: Varones, ¿por qué hacéis esto? Nosotros también somos hombres semejantes á vosotros, que os anunciamos que de estas vanidades os convirtáis al Dios vivo, que hizo el cielo y la tierra, y la mar, y todo lo que está en ellos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 14, 16, 'El cual en las edades pasadas ha dejado á todas las gentes andar en sus caminos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 14, 17, 'Si bien no se dejó á sí mismo sin testimonio, haciendo bien, dándonos lluvias del cielo y tiempos fructíferos, hinchiendo de mantenimiento y de alegría nuestros corazones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 14, 18, 'Y diciendo estas cosas, apenas apaciguaron el pueblo, para que no les ofreciesen sacrificio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 14, 19, 'Entonces sobrevinieron unos Judíos de Antioquía y de Iconio, que persuadieron á la multitud, y habiendo apedreado á Pablo, le sacaron fuera de la ciudad, pensando que estaba muerto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 14, 20, 'Mas rodeándole los discípulos, se levantó y entró en la ciudad y un día después, partió con Bernabé á Derbe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 14, 21, 'Y como hubieron anunciado el evangelio á aquella ciudad, y enseñado á muchos, volvieron á Listra, y á Iconio, y á Antioquía,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 14, 22, 'Confirmando los ánimos de los discípulos, exhortándoles á que permaneciesen en la fe, y que es menester que por muchas tribulaciones entremos en el reino de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 14, 23, 'Y habiéndoles constituído ancianos en cada una de las iglesias, y habiendo orado con ayunos, los encomendaron al Señor en el cual habían creído.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 14, 24, 'Y pasando por Pisidia vinieron á Pamphylia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 14, 25, 'Y habiendo predicado la palabra en Perge, descendieron á Atalia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 14, 26, 'Y de allí navegaron á Antioquía, donde habían sido encomendados á la gracia de Dios para la obra que habían acabado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 14, 27, 'Y habiendo llegado, y reunido la iglesia, relataron cuán grandes cosas había Dios hecho con ellos, y cómo había abierto á los Gentiles la puerta de la fe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 14, 28, 'Y se quedaron allí mucho tiempo con los discípulos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 1, 'ENTONCES algunos que venían de Judea enseñaban á los hermanos: Que si no os circuncidáis conforme al rito de Moisés, no podéis ser salvos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 2, 'Así que, suscitada una disensión y contienda no pequeña á Pablo y á Bernabé contra ellos, determinaron que subiesen Pablo y Bernabé á Jerusalem, y algunos otros de ellos, á los apóstoles y á los ancianos, sobre esta cuestión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 3, 'Ellos, pues, habiendo sido acompañados de la iglesia, pasaron por la Fenicia y Samaria, contando la conversión de los Gentiles; y daban gran gozo á todos los hermanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 4, 'Y llegados á Jerusalem, fueron recibidos de la iglesia y de los apóstoles y de los ancianos: y refirieron todas las cosas que Dios había hecho con ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 5, 'Mas algunos de la secta de los Fariseos, que habían creído, se levantaron, diciendo: Que es menester circuncidarlos, y mandarles que guarden la ley de Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 6, 'Y se juntaron los apóstoles y los ancianos para conocer de este negocio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 7, 'Y habiendo habido grande contienda, levantándose Pedro, les dijo: Varones hermanos, vosotros sabéis cómo ya hace algún tiempo que Dios escogió que los Gentiles oyesen por mi boca la palabra del evangelio, y creyesen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 8, 'Y Dios, que conoce los corazones, les dió testimonio, dándoles el Espíritu Santo también como á nosotros;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 9, 'Y ninguna diferencia hizo entre nosotros y ellos, purificando con la fe sus corazones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 10, 'Ahora pues, ¿por qué tentáis á Dios, poniendo sobre la cerviz de los discípulos yugo, que ni nuestros padres ni nosotros hemos podido llevar?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 11, 'Antes por la gracia del Señor Jesús creemos que seremos salvos, como también ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 12, 'Entonces toda la multitud calló, y oyeron á Bernabé y á Pablo, que contaban cuán grandes maravillas y señales Dios había hecho por ellos entre los Gentiles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 13, 'Y después que hubieron callado, Jacobo respondió, diciendo: Varones hermanos, oidme:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 14, 'Simón ha contado cómo Dios primero visitó á los Gentiles, para tomar de ellos pueblo para su nombre;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 15, 'Y con esto concuerdan las palabras de los profetas, como está escrito:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 16, 'Después de esto volveré Y restauraré la habitación de David, que estaba caída; Y repararé sus ruinas, Y la volveré á levantar;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 17, 'Para que el resto de los hombres busque al Señor, Y todos los Gentiles, sobre los cuales es llamado mi nombre, Dice el Señor, que hace todas estas cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 18, 'Conocidas son á Dios desde el siglo todas sus obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 19, 'Por lo cual yo juzgo, que los que de los Gentiles se convierten á Dios, no han de ser inquietados;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 20, 'Sino escribirles que se aparten de las contaminaciones de los ídolos, y de fornicación, y de ahogado, y de sangre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 21, 'Porque Moisés desde los tiempos antiguos tiene en cada ciudad quien le predique en las sinagogas, donde es leído cada sábado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 22, 'Entonces pareció bien á los apóstoles y á los ancianos, con toda la iglesia, elegir varones de ellos, y enviarlos á Antioquía con Pablo y Bernabé: á Judas que tenía por sobrenombre Barsabas, y á Silas, varones principales entre los hermanos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 23, 'Y escribir por mano de ellos: Los apóstoles y los ancianos y los hermanos, á los hermanos de los Gentiles que están en Antioquía, y en Siria, y en Cilicia, salud:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 24, 'Por cuanto hemos oído que algunos que han salido de nosotros, os han inquietado con palabras, trastornando vuestras almas, mandando circuncidaros y guardar la ley, á los cuales no mandamos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 25, 'Nos ha parecido, congregados en uno, elegir varones, y enviarlos á vosotros con nuestros amados Bernabé y Pablo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 26, 'Hombres que han expuesto sus vidas por el nombre de nuestro Señor Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 27, 'Así que, enviamos á Judas y á Silas, los cuales también por palabra os harán saber lo mismo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 28, 'Que ha parecido bien al Espíritu Santo, y á nosotros, no imponeros ninguna carga más que estas cosas necesarias:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 29, 'Que os abstengáis de cosas sacrificadas á ídolos, y de sangre, y de ahogado, y de fornicación; de las cuales cosas si os guardareis, bien haréis. Pasadlo bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 30, 'Ellos entonces enviados, descendieron á Antioquía; y juntando la multitud, dieron la carta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 31, 'La cual, como leyeron, fueron gozosos de la consolación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 32, 'Judas también y Silas, como ellos también eran profetas, consolaron y confirmaron á los hermanos con abundancia de palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 33, 'Y pasando allí algún tiempo, fueron enviados de los hermanos á los apóstoles en paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 34, 'Mas á Silas pareció bien el quedarse allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 35, 'Y Pablo y Bernabé se estaban en Antioquía, enseñando la palabra del Señor y anunciando el evangelio con otros muchos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 36, 'Y después de algunos días, Pablo dijo á Bernabé: Volvamos á visitar á los hermanos por todas las ciudades en las cuales hemos anunciado la palabra del Señor, cómo están.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 37, 'Y Bernabé quería que tomasen consigo á Juan, el que tenía por sobrenombre Marcos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 38, 'Mas á Pablo no le parecía bien llevar consigo al que se había apartado de ellos desde Pamphylia, y no había ido con ellos á la obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 39, 'Y hubo tal contención entre ellos, que se apartaron el uno del otro; y Bernabé tomando á Marcos, navegó á Cipro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 40, 'Y Pablo escogiendo á Silas, partió encomendado de los hermanos á la gracia del Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 15, 41, 'Y anduvo la Siria y la Cilicia, confirmando á las iglesias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 1, 'DESPUÉS llegó á Derbe, y á Listra: y he aquí, estaba allí un discípulo llamado Timoteo, hijo de una mujer Judía fiel, mas de padre Griego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 2, 'De éste daban buen testimonio los hermanos que estaban en Listra y en Iconio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 3, 'Este quiso Pablo que fuese con él; y tomándole, le circuncidó por causa de los Judíos que estaban en aquellos lugares; porque todos sabían que su padre era Griego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 4, 'Y como pasaban por las ciudades, les daban que guardasen los decretos que habían sido determinados por los apóstoles y los ancianos que estaban en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 5, 'Así que, las iglesias eran confirmadas en fe, y eran aumentadas en número cada día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 6, 'Y pasando á Phrygia y la provincia de Galacia, les fué prohibido por el Espíritu Santo hablar la palabra en Asia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 7, 'Y como vinieron á Misia, tentaron de ir á Bithynia; mas el Espíritu no les dejó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 8, 'Y pasando á Misia, descendieron á Troas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 9, 'Y fué mostrada á Pablo de noche una visión: Un varón Macedonio se puso delante, rogándole, y diciendo: Pasa á Macedonia, y ayúdanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 10, 'Y como vió la visión, luego procuramos partir á Macedonia, dando por cierto que Dios nos llamaba para que les anunciásemos el evangelio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 11, 'Partidos pues de Troas, vinimos camino derecho á Samotracia, y el día siguiente á Neápolis;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 12, 'Y de allí á Filipos, que es la primera ciudad de la parte de Macedonia, y una colonia; y estuvimos en aquella ciudad algunos días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 13, 'Y un día de sábado salimos de la puerta junto al río, donde solía ser la oración; y sentándonos, hablamos á las mujeres que se habían juntado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 14, 'Entonces una mujer llamada Lidia, que vendía púrpura en la ciudad de Tiatira, temerosa de Dios, estaba oyendo; el corazón de la cual abrió el Señor para que estuviese atenta á lo que Pablo decía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 15, 'Y cuando fué bautizada, y su familia, nos rogó, diciendo: Si habéis juzgado que yo sea fiel al Señor, entrad en mi casa, y posad: y constriñónos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 16, 'Y aconteció, que yendo nosotros á la oración, una muchacha que tenía espíritu pitónico, nos salió al encuentro, la cual daba grande ganancia á sus amos adivinando.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 17, 'Esta, siguiendo á Pablo y á nosotros, daba voces, diciendo: Estos hombres son siervos del Dios Alto, los cuales os anuncian el camino de salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 18, 'Y esto hacía por muchos días; mas desagradando á Pablo, se volvió y dijo al espíritu: Te mando en el nombre de Jesucristo, que salgas de ella. Y salió en la misma hora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 19, 'Y viendo sus amos que había salido la esperanza de su ganancia, prendieron á Pablo y á Silas, y los trajeron al foro, al magistrado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 20, 'Y presentándolos á los magistrados, dijeron: Estos hombres, siendo Judíos, alborotan nuestra ciudad,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 21, 'Y predican ritos, los cuales no nos es lícito recibir ni hacer, pues somos Romanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 22, 'Y agolpóse el pueblo contra ellos: y los magistrados rompiéndoles sus ropas, les mandaron azotar con varas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 23, 'Y después que los hubieron herido de muchos azotes, los echaron en la cárcel, mandando al carcelero que los guardase con diligencia:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 24, 'El cual, recibido este mandamiento, los metió en la cárcel de más adentro; y les apretó los pies en el cepo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 25, 'Mas á media noche, orando Pablo y Silas, cantaban himnos á Dios: y los que estaban presos los oían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 26, 'Entonces fué hecho de repente un gran terremoto, de tal manera que los cimientos de la cárcel se movían; y luego todas las puertas se abrieron, y las prisiones de todos soltaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 27, 'Y despertado el carcelero, como vió abiertas las puertas de la cárcel, sacando la espada se quería matar, pensando que los presos se habían huído.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 28, 'Mas Pablo clamó á gran voz, diciendo: No te hagas ningún mal; que todos estamos aquí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 29, 'El entonces pidiendo luz, entró dentro, y temblando, derribóse á los pies de Pablo y de Silas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 30, 'Y sacándolos fuera, le dice: Señores, ¿qué es menester que yo haga para ser salvo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 31, 'Y ellos dijeron: Cree en el Señor Jesucristo, y serás salvo tú, y tu casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 32, 'Y le hablaron la palabra del Señor, y á todos los que estan en su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 33, 'Y tomándolos en aquella misma hora de la noche, les lavó los azotes; y se bautizó luego él, y todos los suyos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 34, 'Y llevándolos á su casa, les puso la mesa: y se gozó de que con toda su casa había creído á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 35, 'Y como fué, día, los magistrados enviaron los alguaciles, diciendo: Deja ir á aquellos hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 36, 'Y el carcelero hizo saber estas palabras á Pablo: Los magistrados han enviado á decir que seás sueltos: así que ahora salid, é id en paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 37, 'Entonces Pablo les dijo: Azotados públicamente sin ser condenados, siendo hombres Romanos, nos echaron en la cárcel; y ¿ahora nos echan encubiertamente? No, de cierto, sino vengan ellos y sáquennos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 38, 'Y los alguaciles volvieron á decir á los magistrados estas palabras: y tuvieron miedo, oído que eran Romanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 39, 'Y viniendo, les rogaron; y sacándolos, les pidieron que se saliesen de la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 16, 40, 'Entonces salidos de la cárcel, entraron en casa de Lidia; y habiendo visto á los hermanos, los consolaron, y se salieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 1, 'Y PASANDO por Amphípolis y Apolonia, llegaron á Tesalónica, donde estaba la sinagoga de los Judíos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 2, 'Y Pablo, como acostumbraba, entró á ellos, y por tres sábados disputó con ellos de las Escrituras,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 3, 'Declarando y proponiendo, que convenía que el Cristo padeciese, y resucitase de los muertos; y que Jesús, el cual yo os anuncio, decía él, éste era el Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 4, 'Y algunos de ellos creyeron, y se juntaron con Pablo y con Silas; y de los Griegos religiosos grande multitud, y mujeres nobles no pocas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 5, 'Entonces los Judíos que eran incrédulos, teniendo celos, tomaron consigo á algunos ociosos, malos hombres, y juntando compañía, alborotaron la ciudad; y acometiendo á la casa de Jasón, procuraban sacarlos al pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 6, 'Mas no hallándolos, trajeron á Jasón y á algunos hermanos á los gobernadores de la ciudad, dando voces: Estos que alborotan el mundo, también han venido acá;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 7, 'A los cuales Jasón ha recibido; y todos estos hacen contra los decretos de César, diciendo que hay otro rey, Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 8, 'Y alborotaron al pueblo y á los gobernadores de la ciudad, oyendo estas cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 9, 'Mas recibida satisfacción de Jasón y de los demás, los soltaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 10, 'Entonces los hermanos, luego de noche, enviaron á Pablo y á Silas á Berea; los cuales habiendo llegado, entraron en la sinagoga de los Judíos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 11, 'Y fueron estós más nobles que los que estaban en Tesalónica, pues recibieron la palabra con toda solicitud, escudriñando cada día las Escrituras, si estas cosas eran así.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 12, 'Así que creyeron muchos de ellos; y mujeres Griegas de distinción, y no pocos hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 13, 'Mas como entendieron los Judíos de Tesalónica que también en Berea era anunciada la palabra de Dios por Pablo, fueron, y también allí tumultuaron al pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 14, 'Empero luego los hermanos enviaron á Pablo que fuese como á la mar; y Silas y Timoteo se quedaron allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 15, 'Y los que habían tomado á cargo á Pablo, le llevaron hasta Atenas; y tomando encargo para Silas y Timoteo, que viniesen á él lo más presto que pudiesen, partieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 16, 'Y esperándolos Pablo en Atenas, su espíritu se deshacía en él viendo la ciudad dada á idolatría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 17, 'Así que, disputaba en la sinagoga con los Judíos y religiosos; y en la plaza cada día con los que le ocurrían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 18, 'Y algunos filósofos de los Epicúreos y de los Estóicos, disputaban con él; y unos decían: ¿Qué quiere decir este palabrero? Y otros: Parece que es predicador de nuevos dioses: porque les predicaba á Jesús y la resurrección.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 19, 'Y tomándole, le trajeron al Areópago, diciendo: ¿Podremos saber qué sea esta nueva doctrina que dices?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 20, 'Porque pones en nuestros oídos unas nuevas cosas: queremos pues saber qué quiere ser esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 21, '(Entonces todos los Atenienses y los huéspedes extranjeros, en ningun otra cosa entendían, sino ó en decir ó en oir alguna cosa nueva.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 22, 'Estando pues Pablo en medio del Areópago, dijo: Varones Atenienses, en todo os veo como más superticiosos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 23, 'Porque pasando y mirando vuestros santuarios, hallé también un altar en el cual estaba esta inscripción: AL DIOS NO CONOCIDO. Aquél pues, que vosotros honráis sin conocerle, á éste os anuncio yo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 24, 'El Dios que hizo el mundo y todas las cosas que en él hay, éste, como sea Señor del cielo y de la tierra, no habita en templos hechos de manos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 25, 'Ni es honrado con manos de hombres, necesitado de algo; pues él da á todos vida, y respiración, y todas las cosas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 26, 'Y de una sangre ha hecho todo el linaje de los hombres, para que habitasen sobre toda la faz de la tierra; y les ha prefijado el orden de los tiempos, y los términos de los habitación de ellos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 27, 'Para que buscasen á Dios, si en alguna manera, palpando, le hallen; aunque cierto no está lejos de cada uno de nosotros:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 28, 'Porque en él vivimos, y nos movemos, y somos; como también algunos de vuestros poetas dijeron: Porque linaje de éste somos también.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 29, 'Siendo pues linaje de Dios, no hemos de estimar la Divinidad ser semejante á oro, ó á plata, ó á piedra, escultura de artificio ó de imaginación de hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 30, 'Empero Dios, habiendo disimulado los tiempos de esta ignorancia, ahora denuncia á todos los hombres en todos los lugares que se arrepientan:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 31, 'Por cuanto ha establecido un día, en el cual ha de juzgar al mundo con justicia, por aquel varón al cual determinó; dando fe á todos con haberle levantado de los muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 32, 'Y así como oyeron de la resurrección de los muertos, unos se burlaban, y otros decían: Te oiremos acerca de esto otra vez.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 33, 'Y así Pablo se salió de en medio de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 17, 34, 'Mas algunos creyeron, juntándose con él; entre los cuales también fué Dionisio el del Areópago, y una mujer llamada Dámaris, y otros con ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 18, 1, 'PASADAS estas cosas, Pablo partió de Atenas, y vino á Corinto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 18, 2, 'Y hallando á un Judío llamado Aquila, natural del Ponto, que hacía poco que había venido de Italia, y á Priscila su mujer, (porque Claudio había mandado que todos los Judíos saliesen de Roma) se vino á ellos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 18, 3, 'Y porque era de su oficio, posó con ellos, y trabajaba; porque el oficio de ellos era hacer tiendas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 18, 4, 'Y disputaba en la sinagoga todos los sábados, y persuadía á Judíos y á Griegos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 18, 5, 'Y cuando Silas y Timoteo vinieron de Macedonia, Pablo estaba constreñido por la palabra, testificando á los Judíos que Jesús era el Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 18, 6, 'Mas contradiciendo y blasfemando ellos, les dijo: sacudiendo sus vestidos: Vuestra sangre sea sobre vuestra cabeza; yo, limpio; desde ahora me iré á los Gentiles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 18, 7, 'Y partiendo de allí, entró en casa de uno llamado Justo, temeroso de Dios, la casa del cual estaba junto á la sinagoga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 18, 8, 'Y Crispo, él prepósito de la sinagoga, creyó al Señor con toda su casa: y muchos de los Corintios oyendo creían, y eran bautizados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 18, 9, 'Entonces él Señor dijo de noche en visión á Pablo: No temas, sino habla, y no calles:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 18, 10, 'Porque yo estoy contigo, y ninguno te podrá hacer mal; porque yo tengo mucho pueblo en esta ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 18, 11, 'Y se detuvo allí un año y seis meses, enseñándoles la palabra de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 18, 12, 'Y siendo Galión procónsul de Acaya, los Judíos se levantaron de común acuerdo contra Pablo, y le llevaron al tribunal,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 18, 13, 'Diciendo: Que éste persuade á los hombres á honrar á Dios contra la ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 18, 14, 'Y comenzando Pablo á abrir la boca, Galión dijo á los Judíos: Si fuera algún agravio ó algún crimen enorme, oh Judíos, conforme á derecho yo os tolerara:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 18, 15, 'Mas si son cuestiones de palabras, y de nombres, y de vuestra ley, vedlo vosotros; porque yo no quiero ser juez de estas cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 18, 16, 'Y los echó del tribunal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 18, 17, 'Entonces todos los Griegos tomando á Sóstenes, prepósito de la sinagoga, le herían delante del tribunal: y á Galión nada se le daba de ello.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 18, 18, 'Mas Pablo habiéndose detenido aún allí muchos días, después se despidió de los hermanos, y navegó á Siria, y con él Priscila y Aquila, habiéndose trasquilado la cabeza en Cencreas, porque tenía voto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 18, 19, 'Y llegó á Efeso, y los dejó allí: y él entrando en la sinagoga, disputó con los Judíos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 18, 20, 'Los cuales le rogaban que se quedase con ellos por más tiempo; mas no accedió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 18, 21, 'Sino que se despidió de ellos, diciendo: Es menester que en todo caso tenga la fiesta que viene, en Jerusalem; mas otra vez volveré á vosotros, queriendo Dios. Y partió de Efeso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 18, 22, 'Y habiendo arribado á Cesarea subió á Jerusalem; y después de saludar á la iglesia, descendió á Antioquía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 18, 23, 'Y habiendo estado allí algún tiempo, partió, andando por orden la provincia de Galacia, y la Phrygia, confirmando á todos los discípulos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 18, 24, 'Llegó entonces á Efeso un Judío, llamado Apolos, natural de Alejandría, varón elocuente, poderoso en las Escrituras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 18, 25, 'Este era instruído en el camino del Señor; y ferviente de espíritu, hablaba y enseñaba diligentemente las cosas que son del Señor, enseñando solamente en el bautismo de Juan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 18, 26, 'Y comenzó á hablar confiadamente en la sinagoga: al cual como oyeron Priscila y Aquila, le tomaron, y le declararon más particularmente el camino de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 18, 27, 'Y queriendo él pasar á Acaya, los hermanos exhortados, escribieron á los discípulos que le recibiesen; y venido él, aprovechó mucho por la gracia á los que habían creído:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 18, 28, 'Porque con gran vehemencia convencía públicamente á los Judíos, mostrando por las Escrituras que Jesús era el Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 1, 'Y ACONTECIO que entre tanto que Apolos estaba en Corinto, Pablo, andadas las regiones superiores, vino á Efeso, y hallando ciertos discípulos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 2, 'Díjoles: ¿Habéis recibido el Espíritu Santo después que creísteis? Y ellos le dijeron: Antes ni aun hemos oído si hay Espíritu Santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 3, 'Entonces dijo: ¿En qué pues sois bautizados? Y ellos dijeron: En el bautismo de Juan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 4, 'Y dijo Pablo: Juan bautizó con bautismo de arrepentimiento, diciendo al pueblo que creyesen en el que había de venir después de él, es á saber, en Jesús el Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 5, 'Oído que hubieron esto, fueron bautizados en el nombre del Señor Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 6, 'Y habiéndoles impuesto Pablo las manos, vino sobre ellos el Espíritu Santo; y hablaban en lenguas, y profetizaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 7, 'Y eran en todos como unos doce hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 8, 'Y entrando él dentro de la sinagoga, hablaba libremente por espacio de tres meses, disputando y persuadiendo del reino de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 9, 'Mas endureciéndose algunos y no creyendo, maldiciendo el Camino delante de la multitud, apartándose Pablo de ellos separó á los discípulos, disputando cada día en la escuela de un cierto Tyranno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 10, 'Y esto fué por espacio de dos años; de manera que todos los que habitaban en Asia, Judíos y Griegos, oyeron la palabra del Señor Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 11, 'Y hacía Dios singulares maravillas por manos de Pablo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 12, 'De tal manera que aun se llevaban sobre los enfermos los sudarios y los pañuelos de su cuerpo, y las enfermedades se iban de ellos, y los malos espíritus salían de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 13, 'Y algunos de los Judíos, exorcistas vagabundos, tentaron á invocar el nombre del Señor Jesús sobre los que tenían espíritus malos, diciendo: Os conjuro por Jesús, el que Pablo predica.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 14, 'Y había siete hijos de un tal Sceva, Judío, príncipe de los sacerdotes, que hacían esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 15, 'Y respondiendo el espíritu malo, dijo: A Jesús conozco y sé quién es Pablo: mas vosotros ¿quiénes sois?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 16, 'Y el hombre en quien estaba el espíritu malo, saltando en ellos, y enseñoreándose de ellos, pudo más que ellos, de tal manera que huyeron de aquella casa desnudos y heridos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 17, 'Y esto fué notorio á todos, así Judíos como Griegos, los que habitaban en Efeso: y cayó temor sobre todos ellos, y era ensalzado el nombre del Señor Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 18, 'Y muchos de los que habían creído, venían, confesando y dando cuenta de sus hechos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 19, 'Asimismo muchos de los que habían practicado vanas artes, trajeron los libros, y los quemaron delante de todos; y echada la cuenta del precio de ellos, hallaron ser cincuenta mil denarios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 20, 'Así crecía poderosamente la palabra del Señor, y prevalecía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 21, 'Y acabadas estas cosas, se propuso Pablo en espíritu partir á Jerusalem, después de andada Macedonia y Acaya, diciendo: Después que hubiere estado allá me será menester ver también á Roma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 22, 'Y enviando á Macedonia á dos de los que le ayudaban, Timoteo y Erasto, él se estuvo por algún tiempo en Asia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 23, 'Entonces hubo un alboroto no pequeño acerca del Camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 24, 'Porque un platero llamado Demetrio, el cual hacía de plata templecillos de Diana, daba á los artífices no poca ganancia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 25, 'A los cuales, reunidos con los oficiales de semejante oficio, dijo: Varones, sabéis que de este oficio tenemos ganancia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 26, 'Y veis y oís que este Pablo, no solamente en Efeso, sino á muchas gentes de casi toda el Asia, ha apartado con persuasión, diciendo, que no son dioses los que se hacen con las manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 27, 'Y no solamente hay peligro de que este negocio se nos vuelva en reproche, sino también que el templo de la gran diosa Diana sea estimado en nada, y comience á ser destruída su majestad, la cual honra toda el Asia y el mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 28, 'Oídas estas cosas, llenáronse de ira, y dieron alarido diciendo: ¡Grande es Diana de los Efesios!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 29, 'Y la ciudad se llenó de confusión; y unánimes se arrojaron al teatro, arrebatando á Gayo y á Aristarco, Macedonios, compañeros de Pablo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 30, 'Y queriendo Pablo salir al pueblo, los discípulos no le dejaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 31, 'También algunos de los principales de Asia, que eran sus amigos, enviaron á él rogando que no se presentase en el teatro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 32, 'Y otros gritaban otra cosa; porque la concurrencia estaba confusa, y los más no sabían por qué se habían juntado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 33, 'Y sacaron de entre la multitud á Alejandro, empujándole los Judíos. Entonces Alejandro, pedido silencio con la mano, quería dar razón al pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 34, 'Mas como conocieron que era Judío, fué hecha un voz de todos, que gritaron casi por dos horas: ¡Grande es Diana de los Efesios!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 35, 'Entonces el escribano, apaciguado que hubo la gente, dijo: Varones Efesios ¿y quién hay de los hombres que no sepa que la ciudad de los Efesios es honradora de la gran diosa Diana, y de la imagen venida de Júpiter?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 36, 'Así que, pues esto no puede ser contradicho, conviene que os apacigüéis, y que nada hagáis temerariamente;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 37, 'Pues habéis traído á estos hombres, sin ser sacrílegos ni blasfemadores de vuestra diosa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 38, 'Que si Demetrio y los oficiales que están con él tienen negocio con alguno, audiencias se hacen, y procónsules hay; acúsense los unos á los otros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 39, 'Y si demandáis alguna otra cosa, en legítima asamblea se pueda decidir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 40, 'Porque peligro hay de que seamos argüidos de sedición por hoy, no habiendo ninguna causa por la cual podamos dar razón de este concurso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 19, 41, '(19-40) Y habiendo dicho esto, despidió la concurrencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 1, 'Y DESPUÉS que cesó el alboroto, llamando Pablo á los discípulos habiéndoles exhortado y abrazado, se despidió, y partió para ir á Macedonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 2, 'Y andado que hubo aquellas partes, y exhortádoles con abundancia de palabra, vino á Grecia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 3, 'Y después de haber estado allí tres meses, y habiendo de navegar á Siria, le fueron puestas asechanzas por los Judíos; y así tomó consejo de volverse por Macedonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 4, 'Y le acompañaron hasta Asia Sopater Bereense, y los Tesalonicenses, Aristarco y Segundo; y Gayo de Derbe, y Timoteo; y de Asia, Tychîco y Trófimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 5, 'Estos yendo delante, nos esperaron en Troas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 6, 'Y nosotros, pasados los días de los panes sin levadura, navegamos de Filipos y vinimos á ellos á Troas en cinco días, donde estuvimos siete días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 7, 'Y el día primero de la semana, juntos los discípulos á partir el pan, Pablo les enseñaba, habiendo de partir al día siguiente: y alargó el discurso hasta la media noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 8, 'Y había muchas lámparas en el aposento alto donde estaban juntos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 9, 'Y un mancebo llamado Eutichô que estaba sentado en la ventana, tomado de un sueño profundo, como Pablo disputaba largamente, postrado del sueño cayó del tercer piso abajo, y fué alzado muerto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 10, 'Entonces descendió Pablo, y derribóse sobre él, y abrazándole, dijo: No os alborotéis, que su alma está en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 11, 'Después subiendo, y partiendo el pan, y gustando, habló largamente hasta el alba, y así partió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 12, 'Y llevaron al mozo vivo, y fueron consolados no poco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 13, 'Y nosotros subiendo en el navío, navegamos á Assón, para recibir de allí á Pablo; pues así había determinado que debía él ir por tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 14, 'Y como se juntó con nosotros en Assón, tomándole vinimos á Mitilene.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 15, 'Y navegamos de allí, al día siguiente llegamos delante de Chîo, y al otro día tomamos puerto en Samo: y habiendo reposado en Trogilio, al día siguiente llegamos á Mileto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 16, 'Porque Pablo se había propuesto pasar adelante de Efeso, por no deternerse en Asia: porque se apresuraba por hacer el día de Pentecostés, si le fuese posible, en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 17, 'Y enviando desde Mileto á Efeso, hizo llamar á los ancianos de la iglesia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 18, 'Y cuando vinieron á él, les dijo: Vosotros sabéis cómo, desde el primer día que entré en Asia, he estado con vosotros por todo el tiempo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 19, 'Sirviendo al Señor con toda humildad, y con muchas lágrimas, y tentaciones que me han venido por las asechanzas de los Judíos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 20, 'Cómo nada que fuese útil he rehuído de anunciaros y enseñaros, públicamente y por las casas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 21, 'Testificando á los Judíos y á los Gentiles arrepentimiento para con Dios, y la fe en nuestro Señor Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 22, 'Y ahora, he aquí, ligado yo en espíritu, voy á Jerusalem, sin saber lo que allá me ha de acontecer:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 23, 'Mas que el Espíritu Santo por todas las ciudades me da testimonio, diciendo que prisiones y tribulaciones me esperan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 24, 'Mas de ninguna cosa hago caso, ni estimo mi vida preciosa para mí mismo; solamente que acabe mi carrera con gozo, y el ministerio que recibí del Señor Jesús, para dar testimonio del evangelio de la gracia de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 25, 'Y ahora, he aquí, yo sé que ninguno de todos vosotros, por quien he pasado predicando el reino de Dios, verá más mi rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 26, 'Por tanto, yo os protesto el día de hoy, que yo soy limpio de la sangre de todos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 27, 'Porque no he rehuído de anunciaros todo el consejo de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 28, 'Por tanto mirad por vosotros y por todo el rebaño en que el Espíritu Santo os ha puesto por obispos, para apacentar la iglesia del Señor, la cual ganó por su sangre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 29, 'Porque yo sé que después de mi partida entrarán en medio de vosotros lobos rapaces, que no perdonarán al ganado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 30, 'Y de vosotros mismos se levantarán hombres que hablen cosas perversas, para llevar discípulos tras sí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 31, 'Por tanto, velad, acordándoos que por tres años de noche y de día, no he cesado de amonestar con lágrimas á cada uno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 32, 'Y ahora, hermanos, os encomiendo á Dios, y á la palabra de su gracia: el cual es poderoso para sobreedificar, y daros heredad con todos los santificados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 33, 'La plata, ó el oro, ó el vestido de nadie he codiciado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 34, 'Antes vosotros sabéis que para lo que me ha sido necesario, y á los que están conmigo, estas manos me han servido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 35, 'En todo os he enseñado que, trabajando así, es necesario sobrellevar á los enfermos, y tener presente las palabras del Señor Jesús, el cual dijo: Más bienaventurada cosa es dar que recibir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 36, 'Y como hubo dicho estas cosas, se puso de rodillas, y oró con todos ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 37, 'Entonces hubo un gran lloro de todos: y echándose en el cuello de Pablo, le besaban,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 20, 38, 'Doliéndose en gran manera por la palabra que dijo, que no habían de ver más su rostro. Y le acompañaron al navío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 1, 'Y HABIENDO partido de ellos, navegamos y vinimos camino derecho á Coos, y al día siguiente á Rhodas, y de allí á Pátara.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 2, 'Y hallando un barco que pasaba á Fenicia, nos embarcamos, y partimos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 3, 'Y como avistamos á Cipro, dejándola á mano izquierda, navegamos á Siria, y vinimos á Tiro: porque el barco había de descargar allí su carga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 4, 'Y nos quedamos allí siete días, hallados los discípulos, los cuales decían á Pablo por Espíritu, que no subiese á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 5, 'Y cumplidos aquellos días, salimos acompañándonos todos, con sus mujeres é hijos, hasta fuera de la ciudad; y puestos de rodillas en la ribera, oramos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 6, 'Y abrazándonos los unos á los otros, subimos al barco, y ellos se volvieron á sus casas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 7, 'Y nosotros, cumplida la navegación, vinimos de Tiro á Tolemaida; y habiendo saludado á los hermanos, nos quedamos con ellos un día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 8, 'Y otro día, partidos Pablo y los que con él estábamos, vinimos á Cesarea: y entrando en casa de Felipe el evangelista, él cual era uno de los siete, posamos con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 9, 'Y éste tenía cuatro hijas, doncellas, que profetizaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 10, 'Y parando nosotros allí por muchos días, descendió de Judea un profeta, llamado Agabo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 11, 'Y venido á nosotros, tomó el cinto de Pablo, y atándose los pies y las manos, dijo: Esto dice el Espíritu Santo: Así atarán los Judíos en Jerusalem al varón cuyo es este cinto, y le entregarán en manos de los Gentiles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 12, 'Lo cual como oímos, le rogamos nosotros y los de aquel lugar, que no subiese á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 13, 'Entonces Pablo respondió: ¿Qué hacéis llorando y afligiéndome el corazón? porque yo no sólo estoy presto á ser atado, mas aun á morir en Jerusalem por el nombre del Señor Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 14, 'Y como no le pudimos persuadir, desistimos, diciendo: Hágase la voluntad del Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 15, 'Y después de estos días, apercibidos, subimos á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 16, 'Y vinieron también con nosotros de Cesarea algunos de los discípulos, trayendo consigo á un Mnasón, Cyprio, discípulo antiguo, con el cual posásemos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 17, 'Y cuando llegamos á Jerusalem, los hermanos nos recibieron de buena voluntad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 18, 'Y al día siguiente Pablo entró con nosotros á Jacobo, y todos los ancianos se juntaron;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 19, 'A los cuales, como los hubo saludado, contó por menudo lo que Dios había hecho entre los Gentiles por su ministerio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 20, 'Y ellos como lo oyeron, glorificaron á Dios, y le dijeron: Ya ves, hermano, cuántos millares de Judíos hay que han creído; y todos son celadores de la ley:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 21, 'Mas fueron informados acerca de ti, que enseñas á apartarse de Moisés á todos los Judíos que están entre los Gentiles, diciéndoles que no han de circuncidar á los hijos, ni andar según la costumbre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 22, '¿Qué hay pues? La multitud se reunirá de cierto: porque oirán que has venido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 23, 'Haz pues esto que te decimos: Hay entre nosotros cuatro hombres que tienen voto sobre sí:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 24, 'Tomando á éstos contigo, purifícate con ellos, y gasta con ellos, para que rasuren sus cabezas, y todos entiendan que no hay nada de lo que fueron informados acerca de ti; sino que tú también andas guardando la ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 25, 'Empero cuanto á los que de los Gentiles han creído, nosotros hemos escrito haberse acordado que no guarden nada de esto; solamente que se abstengan de lo que fue sacrificado á los ídolos, y de sangre, y de ahogado, y de fornicación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 26, 'Entonces Pablo tomó consigo aquellos hombres, y al día siguiente, habiéndose purificado con ellos, entró en el templo, para anunciar el cumplimiento de los días de la purificación, hasta ser ofrecida ofrenda por cada uno de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 27, 'Y cuando estaban para acabarse los siete días, unos Judíos de Asia, como le vieron en el templo, alborotaron todo el pueblo y le echaron mano,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 28, 'Dando voces: Varones Israelitas, ayudad: Este es el hombre que por todas partes enseña á todos contra el pueblo, y la ley, y este lugar; y además de esto ha metido Gentiles en el templo, y ha contaminado este lugar Santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 29, 'Porque antes habían visto con él en la ciudad á Trófimo, Efesio, al cual pensaban que Pablo había metido en el templo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 30, 'Así que, toda la ciudad se alborotó, y agolpóse el pueblo; y tomando á Pablo, hiciéronle salir fuera del templo, y luego las puertas fueron cerradas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 31, 'Y procurando ellos matarle, fué dado aviso al tribuno de la compañía, que toda la ciudad de Jerusalem estaba alborotada;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 32, 'El cual tomando luego soldados y centuriones, corrió á ellos. Y ellos como vieron al tribuno y á los soldados, cesaron de herir á Pablo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 33, 'Entonces llegando el tribuno, le prendió, y le mandó atar con dos cadenas; y preguntó quién era, y qué había hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 34, 'Y entre la multitud, unos gritaban una cosa, y otros otra: y como no podía entender nada de cierto á causa del alboroto, le mandó llevar á la fortaleza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 35, 'Y como llegó á las gradas, aconteció que fué llevado de los soldados á causa de la violencia del pueblo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 36, 'Porque multitud de pueblo venía detrás, gritando: Mátale.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 37, 'Y como comenzaron á meter á Pablo en la fortaleza, dice al tribuno: ¿Me será lícito hablarte algo? Y él dijo: ¿Sabes griego?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 38, '¿No eres tú aquel Egipcio que levantaste una sedición antes de estos días, y sacaste al desierto cuatro mil hombres salteadores?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 39, 'Entonces dijo Pablo: Yo de cierto soy hombre Judío, ciudadano de Tarso, ciudad no obscura de Cilicia: empero ruégote que me permitas que hable al pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 21, 40, 'Y como él se lo permitió, Pablo, estando en pie en las gradas, hizo señal con la mano al pueblo. Y hecho grande silencio, habló en lengua hebrea, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 22, 1, 'VARONES hermanos y padres, oid la razón que ahora os doy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 22, 2, '(Y como oyeron que les hablaba en lengua hebrea, guardaron más silencio.) Y dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 22, 3, 'Yo de cierto soy Judío, nacido en Tarso de Cilicia, mas criado en esta ciudad á los pies de Gamaliel, enseñado conforme á la verdad de la ley de la patria, celoso de Dios, como todos vosotros sois hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 22, 4, 'Que he perseguido este camino hasta la muerte, prendiendo y entregando en cárceles hombres y mujeres:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 22, 5, 'Como también el príncipe de los sacerdotes me es testigo, y todos los ancianos; de los cuales también tomando letras á los hermanos, iba á Damasco para traer presos á Jerusalem aun á los que estuviesen allí, para que fuesen castigados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 22, 6, 'Mas aconteció que yendo yo, y llegando cerca de Damasco, como á medio día, de repente me rodeó mucha luz del cielo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 22, 7, 'Y caí en el suelo, y oí una voz que me decía: Saulo, Saulo, ¿por qué me persigues?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 22, 8, 'Yo entonces respondí: ¿Quién eres, Señor? Y me dijo: Yo soy Jesús de Nazaret, á quién tú persigues.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 22, 9, 'Y los que estaban conmigo vieron á la verdad la luz, y se espantaron; mas no oyeron la voz del que hablaba conmigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 22, 10, 'Y dije: ¿Qué haré, Señor? Y el Señor me dijo: Levántate, y ve á Damasco, y allí te será dicho todo lo que te está señalado hacer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 22, 11, 'Y como yo no viese por causa de la claridad de la luz, llevado de la mano por los que estaban conmigo, vine á Damasco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 22, 12, 'Entonces un Ananías, varón pío conforme á la ley, que tenía buen testimonio de todos los Judíos que allí moraban,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 22, 13, 'Viniendo á mí, y acercándose, me dijo: Hermano Saulo, recibe la vista. Y yo en aquella hora le miré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 22, 14, 'Y él dijo: El Dios de nuestros padres te ha predestinado para que conocieses su voluntad, y vieses á aquel Justo, y oyeses la voz de su boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 22, 15, 'Porque has de ser testigo suyo á todos los hombres, de lo que has visto y oído.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 22, 16, 'Ahora pues, ¿por qué te detienes? Levántate, y bautízate, y lava tus pecados, invocando su nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 22, 17, 'Y me aconteció, vuelto á Jerusalem, que orando en el templo, fuí arrebatado fuera de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 22, 18, 'Y le vi que me decía: Date prisa, y sal prestamente fuera de Jerusalem; porque no recibirán tu testimonio de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 22, 19, 'Y yo dije: Señor, ellos saben que yo encerraba en cárcel, y hería por las sinagogas á los que creían en ti;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 22, 20, 'Y cuando se derramaba la sangre de Esteban tu testigo, yo también estaba presente, y consentía á su muerte, y guardaba las ropas de los que le mataban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 22, 21, 'Y me dijo: Ve, porque yo te tengo que enviar lejos á los Gentiles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 22, 22, 'Y le oyeron hasta esta palabra: entonces alzaron la voz, diciendo: Quita de la tierra á un tal hombre, porque no conviene que viva.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 22, 23, 'Y dando ellos voces, y arrojando sus ropas y echando polvo al aire,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 22, 24, 'Mandó el tribuno que le llevasen á la fortaleza, y ordenó que fuese examinado con azotes, para saber por qué causa clamaban así contra él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 22, 25, 'Y como le ataron con correas, Pablo dijo al centurión que estaba presente: ¿Os es lícito azotar á un hombre Romano sin ser condenado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 22, 26, 'Y como el centurión oyó esto, fué y dió aviso al tribuno, diciendo ¿Qué vas á hacer? porque este hombre es Romano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 22, 27, 'Y viniendo el tribuno, le dijo: Dime, ¿eres tú Romano? Y él dijo: Sí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 22, 28, 'Y respondió el tribuno: Yo con grande suma alcancé esta ciudadanía. Entonces Pablo dijo: Pero yo lo soy de nacimiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 22, 29, 'Así que, luego se apartaron de él los que le habían de atormentar: y aun el tribuno también tuvo temor, entendido que era Romano, por haberle atado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 22, 30, 'Y al día siguiente, queriendo saber de cierto la causa por qué era acusado de los Judíos, le soltó de las prisiones, y mandó venir á los príncipes de los sacerdotes, y á todo su concilio: y sacando á Pablo, le presentó delante de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 1, 'ENTONCES Pablo, poniendo los ojos en el concilio, dice: Varones hermanos, yo con toda buena conciencia he conversado delante de Dios hasta el día de hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 2, 'El príncipe de los sacerdotes, Ananías, mandó entonces á los que estaban delante de él, que le hiriesen en la boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 3, 'Entonces Pablo le dijo: Herirte ha Dios, pared blanqueada: ¿y estás tú sentado para juzgarme conforme á la ley, y contra la ley me mandas herir?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 4, 'Y los que estaban presentes dijeron: ¿Al sumo sacerdote de Dios maldices?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 5, 'Y Pablo dijo: No sabía, hermanos, que era el sumo sacerdote; pues escrito está: Al príncipe de tu pueblo no maldecirás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 6, 'Entonces Pablo, sabiendo que la una parte era de Saduceos, y la otra de Fariseos, clamó en el concilio: Varones hermanos, yo soy Fariseo, hijo de Fariseo: de la esperanza y de la resurrección de los muertos soy yo juzgado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 7, 'Y como hubo dicho esto, fué hecha disensión entre los Fariseos y los Saduceos; y la multitud fué dividida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 8, 'Porque los Saduceos dicen que no hay resurrección, ni ángel, ni espíritu; mas los Fariseos confiesan ambas cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 9, 'Y levantóse un gran clamor: y levantándose los escribas de la parte de los Fariseos, contendían diciendo: Ningún mal hallamos en este hombre; que si espíritu le ha hablado, ó ángel, no resistamos á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 10, 'Y habiendo grande disensión, el tribuno, teniendo temor de que Pablo fuese despedazado de ellos, mandó venir soldados, y arrebatarle de en medio de ellos, y llevarle á la fortaleza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 11, 'Y la noche siguiente, presentándosele el Señor, le dijo: Confía, Pablo; que como has testificado de mí en Jerusalem, así es menester testifiques también en Roma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 12, 'Y venido el día, algunos de los Judíos se juntaron, é hicieron voto bajo de maldición, diciendo que ni comerían ni beberían hasta que hubiesen muerto á Pablo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 13, 'Y eran más de cuarenta los que habían hecho esta conjuración;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 14, 'Los cuales se fueron á los príncipes de los sacerdotes y á los ancianos, y dijeron: Nosotros hemos hecho voto debajo de maldición, que no hemos de gustar nada hasta que hayamos muerto á Pablo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 15, 'Ahora pues, vosotros, con el concilio, requerid al tribuno que le saque mañana á vosotros como que queréis entender de él alguna cosa más cierta; y nosotros, antes que él llegue, estaremos aparejados para matarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 16, 'Entonces un hijo de la hermana de Pablo, oyendo las asechanzas, fué, y entró en la fortaleza, y dió aviso á Pablo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 17, 'Y Pablo, llamando á uno de los centuriones, dice: Lleva á este mancebo al tribuno, porque tiene cierto aviso que darle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 18, 'El entonces tomándole, le llevó al tribuno, y dijo: El preso Pablo, llamándome, me rogó que trajese á ti este mancebo, que tiene algo que hablarte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 19, 'Y el tribuno, tomándole de la mano y retirándose aparte, le preguntó: ¿Qué es lo que tienes que decirme?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 20, 'Y él dijo: Los Judíos han concertado rogarte que mañana saques á Pablo al concilio, como que han de inquirir de él alguna cosa más cierta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 21, 'Mas tú no los creas; porque más de cuarenta hombres de ellos le acechan, los cuales han hecho voto debajo de maldición, de no comer ni beber hasta que le hayan muerto; y ahora están apercibidos esperando tu promesa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 22, 'Entonces el tribuno despidió al mancebo, mandándole que á nadie dijese que le había dado aviso de esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 23, 'Y llamados dos centuriones, mandó que apercibiesen para la hora tercia de la noche doscientos soldados, que fuesen hasta Cesarea, y setenta de á caballo, y doscientos lanceros;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 24, 'Y que aparejasen cabalgaduras en que poniendo á Pablo, le llevasen en salvo á Félix el Presidente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 25, 'Y escribió una carta en estos términos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 26, 'Claudio Lisias al excelentísimo gobernador Félix: Salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 27, 'A este hombre, aprehendido de los Judíos, y que iban ellos á matar, libré yo acudiendo con la tropa, habiendo entendido que era Romano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 28, 'Y queriendo saber la causa por qué le acusaban, le llevé al concilio de ellos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 29, 'Y hallé que le acusaban de cuestiones de la ley de ellos, y que ningún crimen tenía digno de muerte ó de prisión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 30, 'Mas siéndome dado aviso de asechanzas que le habían aparejado los Judíos, luego al punto le he enviado á ti, intimando también á los acusadores que traten delante de ti lo que tienen contra él. Pásalo bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 31, 'Y los soldados, tomando á Pablo como les era mandado, lleváronle de noche á Antipatris.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 32, 'Y al día siguiente, dejando á los de á caballo que fuesen con él, se volvieron á la fortaleza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 33, 'y como llegaron á Cesarea, y dieron la carta al gobernador, presentaron también á Pablo delante de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 34, 'Y el gobernador, leída la carta, preguntó de qué provincia era; y entendiendo que de Cilicia,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 23, 35, 'Te oiré, dijo, cuando vinieren tus acusadores. Y mandó que le guardasen en el pretorio de Herodes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 24, 1, 'Y CINCO días después descendió el sumo sacerdote Ananías, con algunos de los ancianos, y un cierto Tértulo, orador; y parecieron delante del gobernador contra Pablo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 24, 2, 'Y citado que fué, Tértulo comenzó á acusar, diciendo: Como por causa tuya vivamos en grande paz, y muchas cosas sean bien gobernadas en el pueblo por tu prudencia,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 24, 3, 'Siempre y en todo lugar lo recibimos con todo hacimiento de gracias, oh excelentísimo Félix.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 24, 4, 'Empero por no molestarte más largamente, ruégote que nos oigas brevemente conforme á tu equidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 24, 5, 'Porque hemos hallado que este hombre es pestilencial, y levantador de sediciones entre todos los Judíos por todo el mundo, y príncipe de la secta de los Nazarenos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 24, 6, 'El cual también tentó á violar el templo; y prendiéndole, le quisimos juzgar conforme á nuestra ley:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 24, 7, 'Mas interviniendo el tribuno Lisias, con grande violencia le quitó de nuestras manos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 24, 8, 'Mandando á sus acusadores que viniesen á ti; del cual tú mismo juzgando, podrás entender todas estas cosas de que le acusamos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 24, 9, 'Y contendían también los Judíos, diciendo ser así estas cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 24, 10, 'Entonces Pablo, haciéndole el gobernador señal que hablase, respondió: Porque sé que muchos años ha eres gobernador de esta nación, con buen ánimo satisfaré por mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 24, 11, 'Porque tú puedes entender que no hace más de doce días que subí á adorar á Jerusalem;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 24, 12, 'Y ni me hallaron en el templo disputando con ninguno, ni haciendo concurso de multitud, ni en sinagogas, ni en la ciudad;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 24, 13, 'Ni te pueden probar las cosas de que ahora me acusan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 24, 14, 'Esto empero te confieso, que conforme á aquel Camino que llaman herejía, así sirvo al Dios de mis padres, creyendo todas las cosas que en la ley y en los profetas están escritas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 24, 15, 'Teniendo esperanza en Dios que ha de haber resurrección de los muertos, así de justos como de injustos, la cual también ellos esperan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 24, 16, 'Y por esto, procuro yo tener siempre conciencia sin remordimiento acerca de Dios y acerca de los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 24, 17, 'Mas pasados muchos años, vine á hacer limosnas á mi nación, y ofrendas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 24, 18, 'Cuando me hallaron purificado en el templo (no con multitud ni con alboroto) unos Judíos de Asia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 24, 19, 'Los cuales debieron comparecer delante de ti, y acusarme, si contra mí tenían algo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 24, 20, 'O digan estos mismos si hallaron en mí alguna cosa mal hecha, cuando yo estuve en el concilio,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 24, 21, 'Si no sea que, estando entre ellos prorrumpí en alta voz: Acerca de la resurrección de los muertos soy hoy juzgado de vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 24, 22, 'Entonces Félix, oídas estas cosas, estando bien informado de esta secta, les puso dilación, diciendo: Cuando descendiere el tribuno Lisias acabaré de conocer de vuestro negocio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 24, 23, 'Y mandó al centurión que Pablo fuese guardado, y aliviado de las prisiones; y que no vedase á ninguno de sus familiares servirle, ó venir á él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 24, 24, 'Y algunos días después, viniendo Félix con Drusila, su mujer, la cual era Judía, llamó á Pablo, y oyó de él la fe que es en Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 24, 25, 'Y disertando él de la justicia, y de la continencia, y del juicio venidero, espantado Félix, respondió: Ahora vete, mas en teniendo oportunidad te llmaré:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 24, 26, 'Esperando también con esto, que de parte de Pablo le serían dados dineros, porque le soltase; por lo cual, haciéndole venir muchas veces, hablaba con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 24, 27, 'Mas al cabo de dos años recibió Félix por sucesor á Porcio Festo: y queriendo Félix ganar la gracia de los Judíos, dejó preso á Pablo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 25, 1, 'FESTO pues, entrado en la provincia, tres días después subió de Cesarea á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 25, 2, 'Y vinieron á él los príncipes de los sacerdotes y los principales de los Judíos contra Pablo; y le rogaron,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 25, 3, 'Pidiendo gracia contra él, que le hiciese traer á Jerusalem, poniendo ellos asechanzas para matarle en el camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 25, 4, 'Mas Festo respondió, que Pablo estaba guardado en Cesarea, y que él mismo partiría presto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 25, 5, 'Los que de vosotros pueden, dijo desciendan juntamente; y si hay algún crimen en este varón, acúsenle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 25, 6, 'Y deteniéndose entre ellos no más de ocho ó diez días, venido á Cesarea, el siguiente día se sentó en el tribunal, y mandó que Pablo fuese traído.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 25, 7, 'El cual venido, le rodearon los Judíos que habían venido de Jerusalem, poniendo contra Pablo muchas y graves acusaciones, las cuales no podían probar;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 25, 8, 'Alegando él por su parte: Ni contra la ley de los Judíos, ni contra el templo, ni contra César he pecado en nada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 25, 9, 'Mas Festo, queriendo congraciarse con los Judíos, respondiendo á Pablo, dijo: ¿Quieres subir á Jerusalem, y allá ser juzgado de estas cosas delante de mí?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 25, 10, 'Y Pablo dijo: Ante el tribunal de César estoy, donde conviene que sea juzgado. A los Judíos no he hecho injuria alguna, como tú sabes muy bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 25, 11, 'Porque si alguna injuria, ó cosa alguna digna de muerte he hecho, no rehuso morir; mas si nada hay de las cosas de que éstos me acusan, nadie puede darme á ellos. A César apelo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 25, 12, 'Entonces Festo, habiendo hablado con el consejo, respondió: ¿A César has apelado? á César irás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 25, 13, 'Y pasados algunos días, el rey Agripa y Bernice vinieron á Cesarea á saludar á Festo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 25, 14, 'Y como estuvieron allí muchos días, Festo declaró la causa de Pablo al rey, diciendo: Un hombre ha sido dejado preso por Félix,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 25, 15, 'Sobre el cual, cuando fuí á Jerusalem, vinieron á mí los príncipes de los sacerdotes y los ancianos de los Judíos, pidiendo condenación contra él:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 25, 16, 'A los cuales respondí: no ser costumbre de los Romanos dar alguno á la muerte antes que el que es acusado tenga presentes sus acusadores, y haya lugar de defenderse de la acusación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 25, 17, 'Así que, habiendo venido ellos juntos acá, sin ninguna dilación, al día siguiente, sentado en el tribunal, mandé traer al hombre;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 25, 18, 'Y estando presentes los acusadores, ningún cargo produjeron de los que yo sospechaba:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 25, 19, 'Solamente tenían contra él ciertas cuestiones acerca de su superstición, y de un cierto Jesús, difunto, el cual Pablo afirmaba que estaba vivo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 25, 20, 'Y yo, dudando en cuestión semejante, dije, si quería ir á Jerusalem, y allá ser juzgado de estas cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 25, 21, 'Mas apelando Pablo á ser guardado al conocimiento de Augusto, mandé que le guardasen hasta que le enviara á César.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 25, 22, 'Entonces Agripa dijo á Festo: Yo también quisiera oir á ese hombre. Y él dijo: Mañana le oirás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 25, 23, 'Y al otro día, viniendo Agripa y Bernice con mucho aparato, y entrando en la audiencia con los tribunos y principales hombres de la ciudad, por mandato de Festo, fué traído Pablo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 25, 24, 'Entonces Festo dijo: Rey Agripa, y todos los varones que estáis aquí juntos con nosotros: veis á éste, por el cual toda la multitud de los Judíos me ha demandado en Jerusalem y aquí, dando voces que no conviene que viva más;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 25, 25, 'Mas yo, hallando que ninguna cosa digna de muerte ha hecho, y él mismo apelando á Augusto, he determinado enviarle:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 25, 26, 'Del cual no tengo cosa cierta que escriba al señor; por lo que le he sacado á vosotros, y mayormente á tí, oh rey Agripa, para que hecha información, tenga yo qué escribir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 25, 27, 'Porque fuera de razón me parece enviar un preso, y no informar de las causas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 1, 'ENTONCES Agripa dijo á Pablo: Se te permite hablar por ti mismo. Pablo entonces, extendiendo la mano, comenzó á responder por sí, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 2, 'Acerca de todas las cosas de que soy acusado por los Judíos, oh rey Agripa, me tengo por dichoso de que haya hoy de defenderme delante de ti;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 3, 'Mayormente sabiendo tú todas las costumbres y cuestiones que hay entre los Judíos: por lo cual te ruego que me oigas con paciencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 4, 'Mi vida pues desde la mocedad, la cual desde el principio fué en mi nación, en Jerusalem, todos los Judíos la saben:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 5, 'Los cuales tienen ya conocido que yo desde el principio, si quieren testificarlo, conforme á la más rigurosa secta de nuestra religión he vivido Fariseo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 6, 'Y ahora, por la esperanza de la promesa que hizo Dios á nuestros padres, soy llamado en juicio;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 7, 'A la cual promesa nuestras doce tribus, sirviendo constantemente de día y de noche, esperan que han de llegar. Por la cual esperanza, oh rey Agripa, soy acusado de los Judíos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 8, '¡Qué! ¿Júzgase cosa increíble entre vosotros que Dios resucite los muertos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 9, 'Yo ciertamente había pensando deber hacer muchas cosas contra el nombre de Jesús de Nazaret:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 10, 'Lo cual también hice en Jerusalem, y yo encerré en cárcel es á muchos de los santos, recibida potestad de los príncipes de los sacerdotes; y cuando eran matados, yo dí mi voto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 11, 'Y muchas veces, castigándolos por todas las sinagogas, los forcé á blasfemar; y enfurecido sobremanera contra ellos, los perseguí hasta en las ciudades extrañas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 12, 'En lo cual ocupado, yendo á Damasco con potestad y comisión de los príncipes de los sacerdotes,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 13, 'En mitad del día, oh rey, vi en el camino una luz del cielo, que sobrepujaba el resplandor del sol, la cual me rodeó y á los que iban conmigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 14, 'Y habiendo caído todos nosotros en tierra, oí una voz que me hablaba, y decía en lengua hebraica: Saulo, Saulo, ¿por qué me persigues? Dura cosa te es dar coces contra los aguijones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 15, 'Yo entonces dije: ¿Quién eres, Señor? Y el Señor dijo: Yo soy Jesús, á quien tú persigues.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 16, 'Mas levántate, y ponte sobre tus pies; porque para esto te he aparecido, para ponerte por ministro y testigo de las cosas que has visto, y de aquellas en que apareceré á ti:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 17, 'Librándote del pueblo y de los Gentiles, á los cuales ahora te envío,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 18, 'Para que abras sus ojos, para que se conviertan de las tinieblas á la luz, y de la potestad de Satanás á Dios; para que reciban, por la fe que es en mí, remisión de pecados y suerte entre los santificados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 19, 'Por lo cual, oh rey Agripa, no fuí rebelde á la visión celestial:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 20, 'Antes anuncié primeramente á los que están en Damasco, y Jerusalem, y por toda la tierra de Judea, y á los gentiles, que se arrepintiesen y se convirtiesen á Dios, haciendo obras dignas de arrepentimiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 21, 'Por causa de esto los Judíos, tomándome en el templo, tentaron matarme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 22, 'Mas ayudado del auxilio de Dios, persevero hasta el día de hoy, dando testimonio á pequeños y á grandes, no diciendo nada fuera de las cosas que los profetas y Moisés dijeron que habían de venir:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 23, 'Que Cristo había de padecer, y ser el primero de la resurrección de los muertos, para anunciar luz al pueblo y á los Gentiles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 24, 'Y diciendo él estas cosas en su defensa, Festo á gran voz dijo: Estás loco, Pablo: las muchas letras te vuelven loco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 25, 'Mas él dijo: No estoy loco, excelentísimo Festo, sino que hablo palabras de verdad y de templanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 26, 'Pues el rey sabe estas cosas, delante del cual también hablo confiadamente. Pues no pienso que ignora nada de esto; pues no ha sido esto hecho en algún rincón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 27, '¿Crees, rey Agripa, á los profetas? Yo sé que crees.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 28, 'Entonces Agripa dijo á Pablo: Por poco me persuades á ser Cristiano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 29, 'Y Pablo dijo: ¡Pluguiese á Dios que por poco ó por mucho, no solamente tú, mas también todos los que hoy me oyen, fueseis hechos tales cual yo soy, excepto estas prisiones!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 30, 'Y como hubo dicho estas cosas, se levantó el rey, y el presidente, y Bernice, y los que se habían sentado con ellos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 31, 'Y como se retiraron aparte, hablaban los unos á los otros, diciendo: Ninguna cosa digna ni de muerte, ni de prisión, hace este hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 26, 32, 'Y Agripa dijo á Festo: Podía este hombre ser suelto, si no hubiera apelado á César.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 1, 'MAS como fué determinado que habíamos de navegar para Italia, entregaron á Pablo y algunos otros presos á un centurión, llamado Julio, de la compañía Augusta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 2, 'Así que, embarcándonos en una nave Adrumentina, partimos, estando con nosotros Aristarco, Macedonio de Tesalónica, para navegar junto á los lugares de Asia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 3, 'Y otro día llegamos á Sidón; y Julio, tratando á Pablo con humanidad, permitióle que fuese á los amigos, para ser de ellos asistido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 4, 'Y haciéndonos á la vela desde allí, navegamos bajo de Cipro, porque los vientos eran contrarios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 5, 'Y habiendo pasado la mar de Cilicia y Pamphylia, arribamos á Mira, ciudad de Licia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 6, 'Y hallando allí el centurión una nave Alejandrina que navegaba á Italia, nos puso en ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 7, 'Y navegando muchos días despacio, y habiendo apenas llegado delante de Gnido, no dejándonos el viento, navegamos bajo de Creta, junto á Salmón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 8, 'Y costeándola difícilmente, llegamos á un lugar que llaman Buenos Puertos, cerca del cual estaba la ciudad de Lasea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 9, 'Y pasado mucho tiempo, y siendo ya peligrosa la navegación, porque ya era pasado el ayuno, Pablo amonestaba,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 10, 'Diciéndoles: Varones, veo que con trabajo y mucho daño, no sólo de la cargazón y de la nave, mas aun de nuestras personas, habrá de ser la navegación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 11, 'Mas el centurión creía más al piloto y al patrón de la nave, que á lo que Pablo decía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 12, 'Y no habiendo puerto cómodo para invernar, muchos acordaron pasar aún de allí, por si pudiesen arribar á Fenice é invernar allí, que es un puerto de Creta que mira al Nordeste y Sudeste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 13, 'Y soplando el austro, pareciéndoles que ya tenían lo que deseaban, alzando velas, iban cerca de la costa de Creta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 14, 'Mas no mucho después dió en ella un viento repentino, que se llama Euroclidón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 15, 'Y siendo arrebatada la nave, y no pudiendo resistir contra el viento, la dejamos, y erámos llevados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 16, 'Y habiendo corrido á sotavento de una pequeña isla que se llama Clauda, apenas pudimos ganar el esquife:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 17, 'El cual tomado, usaban de remedios, ciñendo la nave; y teniendo temor de que diesen en la Sirte, abajadas las velas, eran así llevados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 18, 'Mas siendo atormentados de una vehemente tempestad, al siguiente día alijaron;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 19, 'Y al tercer día nosotros con nuestras manos arrojamos los aparejos de la nave.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 20, 'Y no pareciendo sol ni estrellas por muchos días, y viniendo una tempestad no pequeña, ya era perdida toda la esperanza de nuestra salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 21, 'Entonces Pablo, habiendo ya mucho que no comíamos, puesto en pie en medio de ellos, dijo: Fuera de cierto conveniente, oh varones, haberme oído, y no partir de Creta, y evitar este inconveniente y daño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 22, 'Mas ahora os amonesto que tengáis buen ánimo; porque ninguna pérdida habrá de persona de vosotros, sino solamente de la nave.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 23, 'Porque esta noche ha estado conmigo el ángel del Dios del cual yo soy, y al cual sirvo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 24, 'Diciendo: Pablo, no temas; es menester que seas presentado delante de César; y he aquí, Dios te ha dado todos los que navegan contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 25, 'Por tanto, oh varones, tened buen ánimo; porque yo confío en Dios que será así como me ha dicho;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 26, 'Si bien es menester que demos en una isla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 27, 'Y venida la décimacuarta noche, y siendo llevados por el mar Adriático, los marineros á la media noche sospecharon que estaban cerca de alguna tierra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 28, 'Y echando la sonda, hallaron veinte brazas, y pasando un poco más adelante, volviendo á echar la sonda, hallaron quince brazas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 29, 'Y habiendo temor de dar en lugares escabrosos, echando cuatro anclas de la popa, deseaban que se hiciese de día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 30, 'Entonces procurando los marineros huir de la nave, echado que hubieron el esquife á la mar, aparentando como que querían largar las anclas de proa,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 31, 'Pablo dijo al centurión y á los soldados: Si éstos no quedan en la nave, vosotros no podéis salvaros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 32, 'Entonces los soldados cortaron los cabos del esquife, y dejáronlo perder.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 33, 'Y como comenzó á ser de día, Pablo exhortaba á todos que comiesen, diciendo: Este es el décimocuarto día que esperáis y permanecéis ayunos, no comiendo nada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 34, 'Por tanto, os ruego que comáis por vuestra salud: que ni aun un cabello de la cabeza de ninguno de vosotros perecerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 35, 'Y habiendo dicho esto, tomando el pan, hizo gracias á Dios en presencia de todos, y partiendo, comenzó á comer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 36, 'Entonces todos teniendo ya mejor ánimo, comieron ellos también.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 37, 'Y éramos todas las personas en la nave doscientas setenta y seis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 38, 'Y satisfechos de comida, aliviaban la nave, echando el grano á la mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 39, 'Y como se hizo de día, no conocían la tierra; mas veían un golfo que tenía orilla, al cual acordaron echar, si pudiesen, la nave.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 40, 'Cortando pues las anclas, las dejaron en la mar, largando también las ataduras de los gobernalles; y alzada la vela mayor al viento, íbanse á la orilla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 41, 'Mas dando en un lugar de dos aguas, hicieron encallar la nave; y la proa, hincada, estaba sin moverse, y la popa se abría con la fuerza de la mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 42, 'Entonces el acuerdo de los soldados era que matasen los presos, porque ninguno se fugase nadando.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 43, 'Mas el centurión, queriendo salvar á Pablo, estorbó este acuerdo, y mandó que los que pudiesen nadar, se echasen los primeros, y saliesen á tierra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 27, 44, 'Y los demás, parte en tablas, parte en cosas de la nave. Y así aconteció que todos se salvaron saliendo á tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 1, 'Y CUANDO escapamos, entonces supimos que la isla se llamaba Melita.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 2, 'Y los bárbaros nos mostraron no poca humanidad; porque, encendido un fuego, nos recibieron á todos, á causa de la lluvia que venía, y del frío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 3, 'Entonces habiendo Pablo recogido algunos sarmientos, y puéstolos en el fuego, una víbora, huyendo del calor, le acometió á la mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 4, 'Y como los bárbaros vieron la víbora colgando de su mano, decían los unos á los otros: Ciertamente este hombre es homicida, á quien, escapado de la mar, la justicia no deja vivir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 5, 'Mas él, sacudiendo la víbora en el fuego, ningún mal padeció.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 6, 'Empero ellos estaban esperando cuándo se había de hinchar, ó caer muerto de repente; mas habiendo esperado mucho, y viendo que ningún mal le venía, mudados, decían que era un dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 7, 'En aquellos lugares había heredades del principal de la isla, llamado Publio, el cual nos recibió y hospedó tres días humanamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 8, 'Y aconteció que el padre de Publio estaba en cama, enfermo de fiebres y de disentería: al cual Pablo entró, y después de haber orado, le puso las manos encima, y le sanó:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 9, 'Y esto hecho, también otros que en la isla tenían enfermedades, llegaban, y eran sanados:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 10, 'Los cuales también nos honraron con muchos obsequios; y cuando partimos, nos cargaron de las cosas necesarias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 11, 'Así que, pasados tres meses, navegamos en una nave Alejandrina que había invernado en la isla, la cual tenía por enseña á Cástor y Pólux.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 12, 'Y llegados á Siracusa, estuvimos allí tres días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 13, 'De allí, costeando alrededor, vinimos á Regio; y otro día después, soplando el austro, vinimos al segundo día á Puteolos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 14, 'Donde habiendo hallado hermanos, nos rogaron que quedásemos con ellos siete días; y luego vinimos á Roma;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 15, 'De donde, oyendo de nosotros los hermanos, nos salieron á recibir hasta la plaza de Appio, y Las Tres Tabernas: á los cuales como Pablo vió, dió gracias á Dios, y tomó aliento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 16, 'Y como llegamos á Roma, el centurión entregó los presos al prefecto de los ejércitos, mas á Pablo fué permitido estar por sí, con un soldado que le guardase.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 17, 'Y aconteció que tres días después, Pablo convocó á los principales de los Judíos; á los cuales, luego que estuvieron juntos, les dijo: Yo, varones hermanos, no habiendo hecho nada contra el pueblo, ni contra los ritos de la patria, he sido entregado preso desde Jerusalem en manos de los Romanos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 18, 'Los cuales, habiéndome examinado, me querían soltar; por no haber en mí ninguna causa de muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 19, 'Mas contradiciendo los Judíos, fuí forzado á apelar á César; no que tenga de qué acusar á mi nación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 20, 'Así que, por esta causa, os he llamado para veros y hablaros; porque por la esperanza de Israel estoy rodeado de esta cadena.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 21, 'Entonces ellos le dijeron: Nosotros ni hemos recibido cartas tocante á tí de Judea, ni ha venido alguno de los hermanos que haya denunciado ó hablado algún mal de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 22, 'Mas querríamos oir de ti lo que sientes; porque de esta secta notorio nos es que en todos lugares es contradicha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 23, 'Y habiéndole señalado un día, vinieron á él muchos á la posada, á los cuales declaraba y testificaba el reino de Dios, persuadiéndoles lo concerniente á Jesús, por la ley de Moisés y por los profetas, desde la mañana hasta la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 24, 'Y algunos asentían á lo que se decía, mas algunos no creían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 25, 'Y como fueron entre sí discordes, se fueron, diciendo Pablo esta palabra: Bien ha hablado el Espíritu Santo por el profeta Isaías á nuestros padres,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 26, 'Diciendo: Ve á este pueblo, y di les: De oído oiréis, y no entenderéis; Y viendo veréis, y no percibiréis:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 27, 'Porque el corazón de este pueblo se ha engrosado, Y de los oídos oyeron pesadamente, Y sus ojos taparon; Porque no vean con los ojos, Y oigan con los oídos, Y entiendan de corazón, Y se conviertan, Y yo los sane.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 28, 'Séaos pues notorio que á los Gentiles es enviada esta salud de Dios: y ellos oirán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 29, 'Y habiendo dicho esto, los Judíos salieron, teniendo entre sí gran contienda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 30, 'Pablo empero, quedó dos años enteros en su casa de alquiler, y recibía á todos los que á él venían,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ACT', 'Hechos', 28, 31, 'Predicando el reino de Dios y enseñando lo que es del Señor Jesucristo con toda libertad, sin impedimento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 1, 1, 'PABLO, apóstol de Jesucristo por la voluntad de Dios, á los santos y fieles en Cristo Jesús que están en Efeso:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 1, 2, 'Gracia sea á vosotros, y paz de Dios Padre nuestro, y del Señor Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 1, 3, 'Bendito el Dios y Padre del Señor nuestro Jesucristo, el cual nos bendijo con toda bendición espiritual en lugares celestiales en Cristo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 1, 4, 'Según nos escogió en él antes de la fundación del mundo, para que fuésemos santos y sin mancha delante de él en amor;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 1, 5, 'Habiéndonos predestinado para ser adoptados hijos por Jesucristo á sí mismo, según el puro afecto de su voluntad,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 1, 6, 'Para alabanza de la gloria de su gracia, con la cual nos hizo aceptos en el Amado:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 1, 7, 'En el cual tenemos redención por su sangre, la remisión de pecados por las riquezas de su gracia,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 1, 8, 'Que sobreabundó en nosotros en toda sabiduría é inteligencia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 1, 9, 'Descubriéndonos el misterio de su voluntad, según su beneplácito, que se había propuesto en sí mismo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 1, 10, 'De reunir todas las cosas en Cristo, en la dispensación del cumplimiento de los tiempos, así las que están en los cielos, como las que están en la tierra:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 1, 11, 'En él digo, en quien asimismo tuvimos suerte, habiendo sido predestinados conforme al propósito del que hace todas las cosas según el consejo de su voluntad,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 1, 12, 'Para que seamos para alabanza de su gloria, nosotros que antes esperamos en Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 1, 13, 'En el cual esperasteis también vosotros en oyendo la palabra de verdad, el evangelio de vuestra salud: en el cual también desde que creísteis, fuisteis sellados con el Espíritu Santo de la promesa,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 1, 14, 'Que es las arras de nuestra herencia, para la redención de la posesión adquirida para alabanza de su gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 1, 15, 'Por lo cual también yo, habiendo oído de vuestra fe en el Señor Jesús, y amor para con todos los santos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 1, 16, 'No ceso de dar gracias por vosotros, haciendo memoria de vosotros en mis oraciones;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 1, 17, 'Que el Dios del Señor nuestro Jesucristo, el Padre de gloria, os dé espíritu de sabiduría y de revelación para su conocimiento;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 1, 18, 'Alumbrando los ojos de vuestro entendimiento, para que sepáis cuál sea la esperanza de su vocación, y cuáles las riquezas de la gloria de su herencia en los santos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 1, 19, 'Y cuál aquella supereminente grandeza de su poder para con nosotros los que creemos, por la operación de la potencia de su fortaleza,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 1, 20, 'La cual obró en Cristo, resucitándole de los muertos, y colocándole á su diestra en los cielos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 1, 21, 'Sobre todo principado, y potestad, y potencia, y señorío, y todo nombre que se nombra, no sólo en este siglo, mas aun en el venidero:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 1, 22, 'Y sometió todas las cosas debajo de sus pies, y diólo por cabeza sobre todas las cosas á la iglesia,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 1, 23, 'La cual es su cuerpo, la plenitud de Aquel que hinche todas las cosas en todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 2, 1, 'Y DE ella recibisteis vosotros, que estabais muertos en vuestros delitos y pecados,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 2, 2, 'En que en otro tiempo anduvisteis conforme á la condición de este mundo, conforme al príncipe de la potestad del aire, el espíritu que ahora obra en los hijos de desobediencia:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 2, 3, 'Entre los cuales todos nosotros también vivimos en otro tiempo en los deseos de nuestra carne, haciendo la voluntad de la carne y de los pensamientos; y éramos por naturaleza hijos de ira, también como los demás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 2, 4, 'Empero Dios, que es rico en misericordia, por su mucho amor con que nos amó,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 2, 5, 'Aun estando nosotros muertos en pecados, nos dió vida juntamente con Cristo; por gracia sois salvos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 2, 6, 'Y juntamente nos resucitó, y asimismo nos hizo sentar en los cielos con Cristo Jesús,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 2, 7, 'Para mostrar en los siglos venideros las abundantes riquezas de su gracia en su bondad para con nosotros en Cristo Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 2, 8, 'Porque por gracia sois salvos por la fe; y esto no de vosotros, pues es don de Dios:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 2, 9, 'No por obras, para que nadie se gloríe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 2, 10, 'Porque somos hechura suya, criados en Cristo Jesús para buenas obras, las cuales Dios preparó para que anduviésemos en ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 2, 11, 'Por tanto, acordaos que en otro tiempo vosotros los Gentiles en la carne, que erais llamados incircuncisión por la que se llama circuncisión, hecha con mano en la carne;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 2, 12, 'Que en aquel tiempo estabais sin Cristo, alejados de la república de Israel, y extranjeros á los pactos de la promesa, sin esperanza y sin Dios en el mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 2, 13, 'Mas ahora en Cristo Jesús, vosotros que en otro tiempo estabais lejos, habéis sido hechos cercanos por la sangre de Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 2, 14, 'Porque él es nuestra paz, que de ambos hizo uno, derribando la pared intermedia de separación;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 2, 15, 'Dirimiendo en su carne las enemistades, la ley de los mandamientos en orden á ritos, para edificar en sí mismo los dos en un nuevo hombre, haciendo la paz,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 2, 16, 'Y reconciliar por la cruz con Dios á ambos en un mismo cuerpo, matando en ella las enemistades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 2, 17, 'Y vino, y anunció la paz á vosotros que estabais lejos, y á los que estaban cerca:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 2, 18, 'Que por él los unos y los otros tenemos entrada por un mismo Espíritu al Padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 2, 19, 'Así que ya no sois extranjeros ni advenedizos, sino juntamente ciudadanos con los santos, y domésticos de Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 2, 20, 'Edificados sobre el fundamento de los apóstoles y profetas, siendo la principal piedra del ángulo Jesucristo mismo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 2, 21, 'En el cual, compaginado todo el edificio, va creciendo para ser un templo santo en el Señor:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 2, 22, 'En el cual vosotros también sois juntamente edificados, para morada de Dios en Espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 3, 1, 'POR esta causa yo Pablo, prisionero de Cristo Jesús por vosotros los Gentiles,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 3, 2, 'Si es que habéis oído la dispensación de la gracia de Dios que me ha sido dada para con vosotros,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 3, 3, 'A saber, que por revelación me fué declarado el misterio, como antes he escrito en breve;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 3, 4, 'Leyendo lo cual podéis entender cuál sea mi inteligencia en el misterio de Cristo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 3, 5, 'El cual misterio en los otros siglos no se dió á conocer á los hijos de los hombres como ahora es revelado á sus santos apóstoles y profetas en el Espíritu:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 3, 6, 'Que los Gentiles sean juntamente herederos, é incorporados, y consortes de su promesa en Cristo por el evangelio:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 3, 7, 'Del cual yo soy hecho ministro por el don de la gracia de Dios que me ha sido dado según la operación de su potencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 3, 8, 'A mí, que soy menos que el más pequeño de todos los santos, es dada esta gracia de anunciar entre los Gentiles el evangelio de las inescrutables riquezas de Cristo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 3, 9, 'Y de aclarar á todos cuál sea la dispensación del misterio escondido desde los siglos en Dios, que crió todas las cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 3, 10, 'Para que la multiforme sabiduría de Dios sea ahora notificada por la iglesia á los principados y potestades en los cielos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 3, 11, 'Conforme á la determinación eterna, que hizo en Cristo Jesús nuestro Señor:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 3, 12, 'En el cual tenemos seguridad y entrada con confianza por la fe de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 3, 13, 'Por tanto, pido que no desmayéis á causa de mis tribulaciones por vosotros, las cuales son vuestra gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 3, 14, 'Por esta causa doblo mis rodillas al Padre de nuestro Señor Jesucristo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 3, 15, 'Del cual es nombrada toda la parentela en los cielos y en la tierra,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 3, 16, 'Que os dé, conforme á las riquezas de su gloria, el ser corroborados con potencia en el hombre interior por su Espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 3, 17, 'Que habite Cristo por la fe en vuestros corazones; para que, arraigados y fundados en amor,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 3, 18, 'Podáis bien comprender con todos los santos cuál sea la anchura y la longura y la profundidad y la altura,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 3, 19, 'Y conocer el amor de Cristo, que excede á todo conocimiento, para que seáis llenos de toda la plenitud de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 3, 20, 'Y á Aquel que es poderoso para hacer todas las cosas mucho más abundantemente de lo que pedimos ó entendemos, por la potencia que obra en nosotros,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 3, 21, 'A él sea gloria en la iglesia por Cristo Jesús, por todas edades del siglo de los siglos. Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 1, 'YO pues, preso en el Señor, os ruego que andéis como es digno de la vocación con que sois llamados;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 2, 'Con toda humildad y mansedumbre, con paciencia soportando los unos á los otros en amor;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 3, 'Solícitos á guardar la unidad del Espíritu en el vínculo de la paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 4, 'Un cuerpo, y un Espíritu; como sois también llamados á una misma esperanza de vuestra vocación:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 5, 'Un Señor, una fe, un bautismo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 6, 'Un Dios y Padre de todos, el cual es sobre todas las cosas, y por todas las cosas, y en todos vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 7, 'Empero á cada uno de nosotros es dada la gracia conforme á la medida del don de Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 8, 'Por lo cual dice: Subiendo á lo alto, llevó cautiva la cautividad, Y dió dones á los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 9, '(Y que subió, ¿qué es, sino que también había descendido primero á las partes más bajas de la tierra?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 10, 'El que descendió, él mismo es el que también subió sobre todos los cielos para cumplir todas las cosas.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 11, 'Y él mismo dió unos, ciertamente apóstoles; y otros, profetas; y otros, evangelistas; y otros, pastores y doctores;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 12, 'Para perfección de los santos, para la obra del ministerio, para edificación del cuerpo de Cristo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 13, 'Hasta que todos lleguemos á la unidad de la fe y del conocimiento del Hijo de Dios, á un varón perfecto, á la medida de la edad de la plenitud de Cristo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 14, 'Que ya no seamos niños fluctuantes, y llevados por doquiera de todo viento de doctrina, por estratagema de hombres que, para engañar, emplean con astucia los artificios del error:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 15, 'Antes siguiendo la verdad en amor, crezcamos en todas cosas en aquel que es la cabeza, a saber, Cristo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 16, 'Del cual, todo el cuerpo compuesto y bien ligado entre sí por todas las junturas de su alimento, que recibe según la operación, cada miembro conforme á su medida toma aumento de cuerpo edificándose en amor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 17, 'Esto pues digo, y requiero en el Señor, que no andéis más como los otros Gentiles, que andan en la vanidad de su sentido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 18, 'Teniendo el entendimiento entenebrecido, ajenos de la vida de Dios por la ignorancia que en ellos hay, por la dureza de su corazón:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 19, 'Los cuales después que perdieron el sentido de la conciencia, se entregaron á la desvergüenza para cometer con avidez toda suerte de impureza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 20, 'Mas vosotros no habéis aprendido así á Cristo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 21, 'Si empero lo habéis oído, y habéis sido por él enseñados, como la verdad está en Jesús,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 22, 'A que dejéis, cuanto á la pasada manera de vivir; el viejo hombre que está viciado conforme á los deseos de error;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 23, 'Y á renovarnos en el espíritu de vuestra mente,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 24, 'Y vestir el nuevo hombre que es criado conforme á Dios en justicia y en santidad de verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 25, 'Por lo cual, dejada la mentira, hablad verdad cada uno con su prójimo; porque somos miembros los unos de los otros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 26, 'Airaos, y no pequéis; no se ponga el sol sobre vuestro enojo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 27, 'Ni deis lugar al diablo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 28, 'El que hurtaba, no hurte más; antes trabaje, obrando con sus manos lo que es bueno, para que tenga de qué dar al que padeciere necesidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 29, 'Ninguna palabra torpe salga de vuestra boca, sino la que sea buena para edificación, para que dé gracia á los oyentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 30, 'Y no contristéis al Espíritu Santo de Dios, con el cual estáis sellados para el día de la redención.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 31, 'Toda amargura, y enojó, é ira, y voces, y maledicencia sea quitada de vosotros, y toda malicia:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 4, 32, 'Antes sed los unos con los otros benignos, misericordiosos, perdónandoos los unos á los otros, como también Dios os perdonó en Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 1, 'SED, pues, imitadores de Dios como hijos amados:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 2, 'Y andad en amor, como también Cristo nos amó, y se entregó á sí mismo por nosotros, ofrenda y sacrificio á Dios en olor suave.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 3, 'Pero fornicación y toda inmundicia, ó avaricia, ni aun se nombre entre vosotros, como conviene á santos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 4, 'Ni palabras torpes, ni necedades, ni truhanerías, que no convienen; sino antes bien acciones de gracias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 5, 'Porque sabéis esto, que ningún fornicario, ó inmundo, ó avaro, que es servidor de ídolos, tiene herencia en el reino de Cristo y de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 6, 'Nadie os engañe con palabras vanas; porque por estas cosas viene la ira de Dios sobre los hijos de desobediencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 7, 'No seáis pues aparceros con ellos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 8, 'Porque en otro tiempo erais tinieblas; mas ahora sois luz en el Señor: andad como hijos de luz,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 9, '(Porque el fruto del Espíritu es en toda bondad, y justicia, y verdad;)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 10, 'Aprobando lo que es agradable al Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 11, 'Y no comuniquéis con las obras infructuosas de las tinieblas; sino antes bien redargüidlas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 12, 'Porque torpe cosa es aun hablar de lo que ellos hacen en oculto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 13, 'Mas todas las cosas cuando son redargüidas, son manifestadas por la luz; porque lo que manifiesta todo, la luz es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 14, 'Por lo cual dice: Despiértate, tú que duermes, y levántate de los muertos, y te alumbrará Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 15, 'Mirad, pues, cómo andéis avisadamente; no como necios, mas como sabios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 16, 'Redimiendo el tiempo, porque los días son malos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 17, 'Por tanto, no seáis imprudentes, sino entendidos de cuál sea la voluntad del Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 18, 'Y no os embriaguéis de vino, en lo cual hay disolución; mas sed llenos de Espíritu;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 19, 'Hablando entre vosotros con salmos, y con himnos, y canciones espirituales, cantando y alabando al Señor en vuestros corazones;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 20, 'Dando gracias siempre de todo al Dios y Padre en el nombre de nuestro Señor Jesucristo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 21, 'Sujetados los unos á los otros en el temor de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 22, 'Las casadas estén sujetas á sus propios maridos, como al Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 23, 'Porque el marido es cabeza de la mujer, así como Cristo es cabeza de la iglesia; y él es el que da la salud al cuerpo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 24, 'Así que, como la iglesia está sujeta á Cristo, así también las casadas lo estén á sus maridos en todo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 25, 'Maridos, amad á vuestras mujeres, así como Cristo amó á la iglesia, y se entregó á sí mismo por ella,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 26, 'Para santificarla limpiándola en el lavacro del agua por la palabra,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 27, 'Para presentársela gloriosa para sí, una iglesia que no tuviese mancha ni arruga, ni cosa semejante; sino que fuese santa y sin mancha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 28, 'Así también los maridos deben amar á sus mujeres como á sus mismos cuerpos. El que ama á su mujer, á sí mismo se ama.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 29, 'Porque ninguno aborreció jamás á su propia carne, antes la sustenta y regala, como también Cristo á la iglesia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 30, 'Porque somos miembros de su cuerpo, de su carne y de sus huesos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 31, 'Por esto dejará el hombre á su padre y á su madre, y se allegará á su mujer, y serán dos en una carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 32, 'Este misterio grande es: mas yo digo esto con respecto á Cristo y á la iglesia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 5, 33, 'Cada uno empero de vosotros de por sí, ame también á su mujer como á sí mismo; y la mujer reverencie á su marido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 6, 1, 'HIJOS, obedeced en el Señor á vuestros padres; porque esto es justo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 6, 2, 'Honra á tu padre y á tu madre, que es el primer mandamiento con promesa,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 6, 3, 'Para que te vaya bien, y seas de larga vida sobre la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 6, 4, 'Y vosotros, padres, no provoquéis á ira á vuestros hijos; sino fhhijos; sino fh amonestación del Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 6, 5, 'Siervos, obedeced á vuestros amos según la carne con temor y temblor, con sencillez de vuestro corazón, como á Cristo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 6, 6, 'No sirviendo al ojo, como los que agradan á los hombres; sino como siervos de Cristo, haciendo de ánimo la voluntad de Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 6, 7, 'Sirviendo con buena voluntad, como al Señor, y no á los hombres;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 6, 8, 'Sabiendo que el bien que cada uno hiciere, esto recibirá del Señor, sea siervo ó sea libre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 6, 9, 'Y vosotros, amos, haced á ellos lo mismo, dejando las amenazas: sabiendo que el Señor de ellos y vuestro está en los cielos, y que no hay acepción de personas con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 6, 10, 'Por lo demás, hermanos míos, confortaos en el Señor, y en la potencia de su fortaleza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 6, 11, 'Vestíos de toda la armadura de Dios, para que podáis estar firmes contra las asechanzas del diablo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 6, 12, 'Porque no tenemos lucha contra sangre y carne; sino contra principados, contra potestades, contra señores del mundo, gobernadores de estas tinieblas, contra malicias espirituales en los aires.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 6, 13, 'Por tanto, tomad toda la armadura de Dios, para que podáis resistir en el día malo, y estar firmes, habiendo acabado todo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 6, 14, 'Estad pues firmes, ceñidos vuestros lomos de verdad, y vestidos de la cota de justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 6, 15, 'Y calzados los pies con el apresto del evangelio de paz;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 6, 16, 'Sobre todo, tomando el escudo de la fe, con que podáis apagar todos los dardos de fuego del maligno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 6, 17, 'Y tomad el yelmo de salud, y la espada del Espíritu; que es la palabra de Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 6, 18, 'Orando en todo tiempo con toda deprecación y súplica en el Espíritu, y velando en ello con toda instancia y suplicación por todos los santos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 6, 19, 'Y por mí, para que me sea dada palabra en el abrir de mi boca con confianza, para hacer notorio el misterio del evangelio,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 6, 20, 'Por el cual soy embajador en cadenas; que resueltamente hable de él, como debo hablar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 6, 21, 'Mas para que también vosotros sepáis mis negocios, y cómo lo paso, todo os lo hará saber Tichîco, hermano amado y fiel ministro en el Señor:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 6, 22, 'Al cual os he enviado para esto mismo, para que entendáis lo tocante á nosotros, y que consuele vuestros corazones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 6, 23, 'Paz sea á los hermanos y amor con fe, de Dios Padre y del Señor Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EPH', 'Efesios', 6, 24, 'Gracia sea con todos los que aman á nuestro Señor Jesucristo en sinceridad. Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 1, 1, 'PABLO y Timoteo, siervos de Jesucristo, á todos los santos en Cristo Jesús que están en Filipos, con los obispos y diáconos');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 1, 2, 'Gracia sea á vosotros, y paz de Dios nuestro Padre y del Señor Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 1, 3, 'Doy gracias á mi Dios en toda memoria de vosotros,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 1, 4, 'Siempre en todas mis oraciones haciendo oración por todos vosotros con gozo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 1, 5, 'Por vuestra comunión en el evangelio, desde el primer día hasta ahora:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 1, 6, 'Estando confiado de esto, que el que comenzó en vosotros la buena obra, la perfeccionará hasta el día de Jesucristo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 1, 7, 'Como me es justo sentir esto de todos vosotros, por cuanto os tengo en el corazón; y en mis prisiones, y en la defensa y confirmación del evangelio, sois todos vosotros compañeros de mi gracia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 1, 8, 'Porque Dios me es testigo de cómo os amo á todos vosotros en las entrañas de Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 1, 9, 'Y esto ruego, que vuestro amor abunde aun más y más en ciencia y en todo conocimiento,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 1, 10, 'Para que discernáis lo mejor; que seáis sinceros y sin ofensa para el día de Cristo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 1, 11, 'Llenos de frutos de justicia, que son por Jesucristo, á gloria y loor de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 1, 12, 'Y quiero, hermanos, que sepáis que las cosas que me han sucedido, han redundado más en provecho del evangelio;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 1, 13, 'De manera que mis prisiones han sido célebres en Cristo en todo el pretorio, y á todos los demás;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 1, 14, 'Y muchos de los hermanos en el Señor, tomando ánimo con mis prisiones, se atreven mucho más á hablar la palabra sin temor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 1, 15, 'Y algunos, á la verdad, predican á Cristo por envidia y porfía; mas algunos también por buena voluntad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 1, 16, 'Los unos anuncian á Cristo por contención, no sinceramente, pensando añadir aflicción á mis prisiones;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 1, 17, 'Pero los otros por amor, sabiendo que soy puesto por la defensa del evangelio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 1, 18, '¿Qué pues? Que no obstante, en todas maneras, ó por pretexto ó por verdad, es anunciado Cristo; y en esto me huelgo, y aun me holgaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 1, 19, 'Porque sé que esto se me tornará á salud, por vuestra oración, y por la suministración del Espíritu de Jesucristo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 1, 20, 'Conforme á mi mira y esperanza, que en nada seré confundido; antes bien con toda confianza, como siempre, ahora también será engrandecido Cristo en mi cuerpo, ó por vida, ó por muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 1, 21, 'Porque para mí el vivir es Cristo, y el morir es ganancia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 1, 22, 'Mas si el vivir en la carne, esto me será para fruto de la obra, no sé entonces qué escoger;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 1, 23, 'Porque de ambas cosas estoy puesto en estrecho, teniendo deseo de ser desatado, y estar con Cristo, lo cual es mucho mejor:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 1, 24, 'Empero quedar en la carne es más necesario por causa de vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 1, 25, 'Y confiado en esto, sé que quedaré, que aun permaneceré con todos vosotros, para provecho vuestro y gozo de la fe;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 1, 26, 'Para que crezca vuestra gloria de mí en Cristo Jesús por mi venida otra vez á vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 1, 27, 'Solamente que converséis como es digno del evangelio de Cristo; para que, ó sea que vaya á veros, ó que esté ausente, oiga de vosotros que estáis firmes en un mismo espíritu, unánimes combatiendo juntamente por la fe del evangelio,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 1, 28, 'Y en nada intimidados de los que se oponen: que á ellos ciertamente es indicio de perdición, mas á vosotros de salud; y esto de Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 1, 29, 'Porque á vosotros es concedido por Cristo, no sólo que creáis en él, sino también que padezcáis por él,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 1, 30, 'Teniendo el mismo conflicto que habéis visto en mí, y ahora oís estar en mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 2, 1, 'POR tanto, si hay alguna consolación en Cristo; si algún refrigerio de amor; si alguna comunión del Espíritu; si algunas entrañas y misericordias,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 2, 2, 'Cumplid mi gozo; que sintáis lo mismo, teniendo el mismo amor, unánimes, sintiendo una misma cosa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 2, 3, 'Nada hagáis por contienda ó por vanagloria; antes bien en humildad, estimándoos inferiores los unos á los otros:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 2, 4, 'No mirando cada uno á lo suyo propio, sino cada cual también á lo de los otros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 2, 5, 'Haya, pues, en vosotros este sentir que hubo también en Cristo Jesús:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 2, 6, 'El cual, siendo en forma de Dios, no tuvo por usurpación ser igual á Dios:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 2, 7, 'Sin embargo, se anonadó á sí mismo, tomando forma de siervo, hecho semejante á los hombres;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 2, 8, 'Y hallado en la condición como hombre, se humilló á sí mismo, hecho obediente hasta la muerte, y muerte de cruz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 2, 9, 'Por lo cual Dios también le ensalzó á lo sumo, y dióle un nombre que es sobre todo nombre;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 2, 10, 'Para que en el nombre de Jesús se doble toda rodilla de los que están en los cielos, y de los que en la tierra, y de los que debajo de la tierra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 2, 11, 'Y toda lengua confiese que Jesucristo es el Señor, á la gloria de Dios Padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 2, 12, 'Por tanto, amados míos, como siempre habéis obedecido, no como en mi presencia solamente, sino mucho más ahora en mi ausencia, ocupaos en vuestra salvación con temor y temblor;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 2, 13, 'Porque Dios es el que en vosotros obra así el querer como el hacer, por su buena voluntad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 2, 14, 'Haced todo sin murmuraciones y contiendas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 2, 15, 'Para que seáis irreprensibles y sencillos, hijos de Dios sin culpa en medio de la nación maligna y perversa, entre los cuales resplandecéis como luminares en el mundo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 2, 16, 'Reteniendo la palabra de vida para que yo pueda gloriarme en el día de Cristo, que no he corrido en vano, ni trabajado en vano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 2, 17, 'Y aun si soy derramado en libación sobre el sacrificio y servicio de vuestra fe, me gozo y congratulo por todos vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 2, 18, 'Y asimismo gozaos también vosotros, y regocijaos conmigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 2, 19, 'Mas espero en el Señor Jesús enviaros presto á Timoteo, para que yo también esté de buen ánimo, entendido vuestro estado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 2, 20, 'Porque á ninguno tengo tan unánime, y que con sincera afición esté solícito por vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 2, 21, 'Porque todos buscan lo suyo propio, no lo que es de Cristo Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 2, 22, 'Pero la experiencia de él habéis conocido, que como hijo á padre ha servido conmigo en el evangelio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 2, 23, 'Así que á éste espero enviaros, luego que yo viere cómo van mis negocios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 2, 24, 'Y confío en el Señor que yo también iré presto á vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 2, 25, 'Mas tuve por cosa necesaria enviaros á Epafrodito, mi hermano, y colaborador y compañero de milicia, y vuestro mensajero, y ministrador de mis necesidades;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 2, 26, 'Porque tenía gran deseo de ver á todos vosotros, y gravemente se angustió porque habíais oído que había enfermado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 2, 27, 'Pues en verdad estuvo enfermo á la muerte: mas Dios tuvo misericordia de él; y no solamente de él, sino aun de mí, para que yo no tuviese tristeza sobre tristeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 2, 28, 'Así que le envío más presto, para que viéndole os volváis á gozar, y yo esté con menos tristeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 2, 29, 'Recibidle pues en el Señor con todo gozo; y tened en estima á los tales:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 2, 30, 'Porque por la obra de Cristo estuvo cercano á la muerte, poniendo su vida para suplir vuestra falta en mi servicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 3, 1, 'RESTA, hermanos, que os gocéis en el Señor. A mí, á la verdad, no es molesto el escribiros las mismas cosas, y para vosotros es seguro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 3, 2, 'Guardaos de los perros, guardaos de los malos obreros, guardaos del cortamiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 3, 3, 'Porque nosotros somos la circuncisión, los que servimos en espíritu á Dios, y nos gloriamos en Cristo Jesús, no teniendo confianza en la carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 3, 4, 'Aunque yo tengo también de qué confiar en la carne. Si alguno parece que tiene de qué confiar en la carne, yo más:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 3, 5, 'Circuncidado al octavo día, del linaje de Israel, de la tribu de Benjamín, Hebreo de Hebreos; cuanto á la ley, Fariseo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 3, 6, 'Cuanto al celo, perseguidor de la iglesia; cuanto á la justicia que es en la ley, irreprensible.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 3, 7, 'Pero las cosas que para mí eran ganancias, helas reputado pérdidas por amor de Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 3, 8, 'Y ciertamente, aun reputo todas las cosas pérdida por el eminente conocimiento de Cristo Jesús, mi Señor, por amor del cual lo he perdido todo, y téngolo por estiércol, para ganar á Cristo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 3, 9, 'Y ser hallado en él, no teniendo mi justicia, que es por la ley, sino la que es por la fe de Cristo, la justicia que es de Dios por la fe;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 3, 10, 'A fin de conocerle, y la virtud de su resurrección, y la participación de sus padecimientos, en conformidad á su muerte,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 3, 11, 'Si en alguna manera llegase á la resurrección de los muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 3, 12, 'No que ya haya alcanzado, ni que ya sea perfecto; sino que prosigo, por ver si alcanzo aquello para lo cual fuí también alcanzado de Cristo Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 3, 13, 'Hermanos, yo mismo no hago cuenta de haber lo ya alcanzado; pero una cosa hago: olvidando ciertamente lo que queda atrás, y extendiéndome á lo que está delante,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 3, 14, 'Prosigo al blanco, al premio de la soberana vocación de Dios en Cristo Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 3, 15, 'Así que, todos los que somos perfectos, esto mismo sintamos: y si otra cosa sentís, esto también os revelará Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 3, 16, 'Empero en aquello á que hemos llegado, vamos por la misma regla, sintamos una misma cosa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 3, 17, 'Hermanos, sed imitadores de mí, y mirad los que así anduvieren como nos tenéis por ejemplo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 3, 18, 'Porque muchos andan, de los cuales os dije muchas veces, y aun ahora lo digo llorando, que son enemigos de la cruz de Cristo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 3, 19, 'Cuyo fin será perdición, cuyo dios es el vientre, y su gloria es en confusión; que sienten lo terreno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 3, 20, 'Mas nuestra vivienda es en los cielos; de donde también esperamos al Salvador, al Señor Jesucristo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 3, 21, 'El cual transformará el cuerpo de nuestra bajeza, para ser semejante al cuerpo de su gloria, por la operación con la cual puede también sujetar á sí todas las cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 4, 1, 'ASI que, hermanos míos amados y deseados, gozo y corona mía, estad así firmes en el Señor, amados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 4, 2, 'A Euodias ruego, y á Syntychê exhorto, que sientan lo mismo en el Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 4, 3, 'Asimismo te ruego también á ti, hermano compañero, ayuda á las que trabajaron juntamente conmigo en el evangelio, con Clemente también, y los demás mis colaboradores, cuyos nombres están en el libro de la vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 4, 4, 'Gozaos en el Señor siempre: otra vez digo: Que os gocéis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 4, 5, 'Vuestra modestia sea conocida de todos los hombres. El Señor está cerca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 4, 6, 'Por nada estéis afanosos; sino sean notorias vuestras peticiones delante de Dios en toda oración y ruego, con hacimiento de gracias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 4, 7, 'Y la paz de Dios, que sobrepuja todo entendimiento, guardará vuestros corazones y vuestros entendimientos en Cristo Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 4, 8, 'Por lo demás, hermanos, todo lo que es verdadero, todo lo honesto, todo lo justo, todo lo puro, todo lo amable, todo lo que es de buen nombre; si hay virtud alguna, si alguna alabanza, en esto pensad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 4, 9, 'Lo que aprendisteis y recibisteis y oísteis y visteis en mí, esto haced; y el Dios de paz será con vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 4, 10, 'Mas en gran manera me gocé en el Señor de que ya al fin ha reflorecido vuestro cuidado de mí; de lo cual aun estabais solícitos, pero os faltaba la oportunidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 4, 11, 'No lo digo en razón de indigencia, pues he aprendido á contentarme con lo que tengo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 4, 12, 'Sé estar humillado, y sé tener abundancia: en todo y por todo estoy enseñado, así para hartura como para hambre, así para tener abundancia como para padecer necesidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 4, 13, 'Todo lo puedo en Cristo que me fortalece.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 4, 14, 'Sin embargo, bien hicisteis que comunicasteis juntamente á mi tribulación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 4, 15, 'Y sabéis también vosotros, oh Filipenses, que al principio del evangelio, cuando partí de Macedonia, ninguna iglesia me comunicó en razón de dar y recibir, sino vosotros solos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 4, 16, 'Porque aun á Tesalónica me enviasteis lo necesario una y dos veces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 4, 17, 'No porque busque dádivas; mas busco fruto que abunde en vuestra cuenta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 4, 18, 'Empero todo lo he recibido, y tengo abundancia: estoy lleno, habiendo recibido de Epafrodito lo que enviasteis, olor de suavidad, sacrificio acepto, agradable á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 4, 19, 'Mi Dios, pues, suplirá todo lo que os falta conforme á sus riquezas en gloria en Cristo Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 4, 20, 'Al Dios pues y Padre nuestro sea gloria por los siglos de los siglos. Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 4, 21, 'Saludad á todos los santos en Cristo Jesús. Los hermanos que están conmigo os saludan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 4, 22, 'Todos los santos os saludan, y mayormente los que son de casa de César.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHP', 'Filipenses', 4, 23, 'La gracia de nuestro Señor Jesucristo sea con todos vosotros. Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHM', 'Filemón', 1, 1, 'PABLO, prisionero de Jesucristo, y el hermano Timoteo, á Filemón amado, y coadjutor nuestro;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHM', 'Filemón', 1, 2, 'Y á la amada Apphia, y á Archîpo, compañero de nuestra milicia, y á la iglesia que está en tu casa:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHM', 'Filemón', 1, 3, 'Gracia á vosotros y paz de Dios nuestro Padre, y del Señor Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHM', 'Filemón', 1, 4, 'Doy gracias á mi Dios, haciendo siempre memoria de ti en mis oraciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHM', 'Filemón', 1, 5, 'Oyendo tu caridad, y la fe que tienes en el Señor Jesús, y para con todos los santos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHM', 'Filemón', 1, 6, 'Para que la comunicación de tu fe sea eficaz, en el conocimiento de todo el bien que está en vosotros, por Cristo Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHM', 'Filemón', 1, 7, 'Porque tenemos gran gozo y consolación de tu caridad, de que por ti, oh hermano, han sido recreadas las entrañas de los santos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHM', 'Filemón', 1, 8, 'Por lo cual, aunque tengo mucha resolución en Cristo para mandarte lo que conviene,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHM', 'Filemón', 1, 9, 'Ruégo te más bien por amor, siendo tal cual soy, Pablo viejo, y aun ahora prisionero de Jesucristo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHM', 'Filemón', 1, 10, 'Ruégote por mi hijo Onésimo, que he engendrado en mis prisiones,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHM', 'Filemón', 1, 11, 'El cual en otro tiempo te fué inútil, mas ahora á ti y á mí es útil;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHM', 'Filemón', 1, 12, 'El cual te vuelvo á enviar; tu pues, recíbele como á mis entrañas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHM', 'Filemón', 1, 13, 'Yo quisiera detenerle conmigo, para que en lugar de ti me sirviese en las prisiones del evangelio;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHM', 'Filemón', 1, 14, 'Mas nada quise hacer sin tu consejo, porque tu beneficio no fuese como de necesidad, sino voluntario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHM', 'Filemón', 1, 15, 'Porque acaso por esto se ha apartado de ti por algún tiempo, para que le recibieses para siempre;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHM', 'Filemón', 1, 16, 'No ya como siervo, antes más que siervo, como hermano amado, mayormente de mí, pero cuánto más de ti, en la carne y en el Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHM', 'Filemón', 1, 17, 'Así que, si me tienes por compañero, recíbele como á mi.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHM', 'Filemón', 1, 18, 'Y si en algo te dañó, ó te debe, ponlo á mi cuenta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHM', 'Filemón', 1, 19, 'Yo Pablo lo escribí de mi mano, yo lo pagaré: por no decirte que aun á ti mismo te me debes demás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHM', 'Filemón', 1, 20, 'Sí, hermano, góceme yo de ti en el Señor; recrea mis entrañas en el Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHM', 'Filemón', 1, 21, 'Te he escrito confiando en tu obediencia, sabiendo que aun harás más de lo que digo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHM', 'Filemón', 1, 22, 'Y asimismo prepárame también alojamiento; porque espero que por vuestras oraciones os tengo de ser concedido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHM', 'Filemón', 1, 23, 'Te saludan Epafras, mi compañero en la prisión por Cristo Jesús,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHM', 'Filemón', 1, 24, 'Marcos, Aristarco, Demas y Lucas, mis cooperadores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PHM', 'Filemón', 1, 25, 'La gracia de nuestro Señor Jesucristo sea con vuestro espíritu. Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 1, 1, 'JACOBO, siervo de Dios y del Señor Jesucristo, á las doce tribus que están esparcidas, salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 1, 2, 'Hermanos míos, tened por sumo gozo cuando cayereis en diversas tentaciones;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 1, 3, 'Sabiendo que la prueba de vuestra fe obra paciencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 1, 4, 'Mas tenga la paciencia perfecta su obra, para que seáis perfectos y cabales, sin faltar en alguna cosa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 1, 5, 'Y si alguno de vosotros tiene falta de sabiduría, demándela á Dios, el cual da á todos abundantemente, y no zahiere; y le será dada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 1, 6, 'Pero pida en fe, no dudando nada: porque el que duda es semejante á la onda de la mar, que es movida del viento, y echada de una parte á otra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 1, 7, 'No piense pues el tal hombre que recibirá ninguna cosa del Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 1, 8, 'El hombre de doblado ánimo es inconstante en todos sus caminos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 1, 9, 'El hermano que es de baja suerte, gloríese en su alteza:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 1, 10, 'Mas el que es rico, en su bajeza; porque él se pasará como la flor de la hierba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 1, 11, 'Porque salido el sol con ardor, la hierba se secó, y su flor se cayó, y pereció su hermosa apariencia: así también se marchitará el rico en todos sus caminos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 1, 12, 'Bienaventurado el varón que sufre la tentación; porque cuando fuere probado, recibirá la corona de vida, que Dios ha prometido á los que le aman.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 1, 13, 'Cuando alguno es tentado, no diga que es tentado de Dios: porque Dios no puede ser tentado de los malos, ni él tienta á alguno:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 1, 14, 'Sino que cada uno es tentado, cuando de su propia concupiscencia es atraído, y cebado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 1, 15, 'Y la concupiscencia, después que ha concebido, pare el pecado: y el pecado, siendo cumplido, engendra muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 1, 16, 'Amados hermanos míos, no erréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 1, 17, 'Toda buena dádiva y todo don perfecto es de lo alto, que desciende del Padre de las luces, en el cual no hay mudanza, ni sombra de variación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 1, 18, 'El, de su voluntad nos ha engendrado por la palabra de verdad, para que seamos primicias de sus criaturas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 1, 19, 'Por esto, mis amados hermanos, todo hombre sea pronto para oir, tardío para hablar, tardío para airarse:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 1, 20, 'Porque la ira del hombre no obra la justicia de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 1, 21, 'Por lo cual, dejando toda inmundicia y superfluidad de malicia, recibid con mansedumbre la palabra ingerida, la cual puede hacer salvas vuestras almas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 1, 22, 'Mas sed hacedores de la palabra, y no tan solamente oidores, engañándoos á vosotros mismos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 1, 23, 'Porque si alguno oye la palabra, y no la pone por obra, este tal es semejante al hombre que considera en un espejo su rostro natural.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 1, 24, 'Porque él se consideró á sí mismo, y se fué, y luego se olvidó qué tal era.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 1, 25, 'Mas el que hubiere mirado atentamente en la perfecta ley, que es la de la libertad, y perseverado en ella, no siendo oidor olvidadizo, sino hacedor de la obra, este tal será bienaventurado en su hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 1, 26, 'Si alguno piensa ser religioso entre vosotros, y no refrena su lengua, sino engañando su corazón, la religión del tal es vana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 1, 27, 'La religión pura y sin mácula delante de Dios y Padre es esta: Visitar los huérfanos y las viudas en sus tribulaciones, y guardarse sin mancha de este mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 2, 1, 'HERMANOS míos, no tengáis la fe de nuestro Señor Jesucristo glorioso en acepción de personas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 2, 2, 'Porque si en vuestra congregación entra un hombre con anillo de oro, y de preciosa ropa, y también entra un pobre con vestidura vil,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 2, 3, 'Y tuviereis respeto al que trae la vestidura preciosa, y le dijereis: Siéntate tú aquí en buen lugar: y dijereis al pobre: Estáte tú allí en pie; ó siéntate aquí debajo de mi estrado:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 2, 4, '¿No juzguáis en vosotros mismos, y venís á ser jueces de pensamientos malos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 2, 5, 'Hermanos míos amados, oid: ¿No ha elegido Dios los pobres de este mundo, ricos en fe, y herederos del reino que ha prometido á los que le aman?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 2, 6, 'Mas vosotros habéis afrentado al pobre. ¿No os oprimen los ricos, y no son ellos los mismos que os arrastran á los juzgados?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 2, 7, '¿No blasfeman ellos el buen nombre que fué invocado sobre vosotros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 2, 8, 'Si en verdad cumplís vosotros la ley real, conforme á la Escritura: Amarás á tu prójimo como á ti mismo, bien hacéis:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 2, 9, 'Mas si hacéis acepción de personas, cometéis pecado, y sois reconvenidos de la ley como transgresores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 2, 10, 'Porque cualquiera que hubiere guardado toda la ley, y ofendiere en un punto, es hecho culpado de todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 2, 11, 'Porque el que dijo: No cometerás adulterio, también ha dicho: No matarás. Ahora bien, si no hubieres matado, ya eres hecho transgresor de la ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 2, 12, 'Así hablad, y así obrad, como los que habéis de ser juzgados por la ley de libertad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 2, 13, 'Porque juicio sin misericordia será hecho con aquel que no hiciere misericordia: y la misericordia se gloría contra el juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 2, 14, 'Hermanos míos, ¿qué aprovechará si alguno dice que tiene fe, y no tiene obras? ¿Podrá la fe salvarle?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 2, 15, 'Y si el hermano ó la hermana están desnudos, y tienen necesidad del mantenimiento de cada día,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 2, 16, 'Y alguno de vosotros les dice: Id en paz, calentaos y hartaos; pero no les diereis las cosas que son necesarias para el cuerpo: ¿qué aprovechará?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 2, 17, 'Así también la fe, si no tuviere obras, es muerta en sí misma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 2, 18, 'Pero alguno dirá: Tú tienes fe, y yo tengo obras: muéstrame tu fe sin tus obras, y yo te mostraré mi fe por mis obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 2, 19, 'Tú crees que Dios es uno; bien haces: también los demonios creen, y tiemblan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 2, 20, '¿Mas quieres saber, hombre vano, que la fe sin obras es muerta?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 2, 21, '¿No fué justificado por las obras Abraham nuestro padre, cuando ofreció á su hijo Isaac sobre el altar?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 2, 22, '¿No ves que la fe obró con sus obras, y que la fe fué perfecta por las obras?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 2, 23, 'Y fué cumplida la Escritura que dice: Abraham creyó á Dios, y le fué imputado á justicia, y fué llamado amigo de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 2, 24, 'Vosotros veis, pues, que el hombre es justificado por las obras, y no solamente por la fe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 2, 25, 'Asimismo también Rahab la ramera, ¿no fué justificada por obras, cuando recibió los mensajeros, y los echó fuera por otro camino?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 2, 26, 'Porque como el cuerpo sin espíritu está muerto, así también la fe sin obras es muerta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 3, 1, 'HERMANOS míos, no os hagáis muchos maestros, sabiendo que recibiremos mayor condenación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 3, 2, 'Porque todos ofendemos en muchas cosas. Si alguno no ofende en palabra, éste es varón perfecto, que también puede con freno gobernar todo el cuerpo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 3, 3, 'He aquí nosotros ponemos frenos en las bocas de los caballos para que nos obedezcan, y gobernamos todo su cuerpo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 3, 4, 'Mirad también las naves: aunque tan grandes, y llevadas de impetuosos vientos, son gobernadas con un muy pequeño timón por donde quisiere el que las gobierna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 3, 5, 'Así también, la lengua es un miembro pequeño, y se gloría de grandes cosas. He aquí, un pequeño fuego ¡cuán grande bosque enciende!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 3, 6, 'Y la lengua es un fuego, un mundo de maldad. Así la lengua está puesta entre nuestros miembros, la cual contamina todo el cuerpo, é inflama la rueda de la creación, y es inflamada del infierno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 3, 7, 'Porque toda naturaleza de bestias, y de aves, y de serpientes, y de seres de la mar, se doma y es domada de la naturaleza humana:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 3, 8, 'Pero ningún hombre puede domar la lengua, que es un mal que no puede ser refrenado; llena de veneno mortal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 3, 9, 'Con ella bendecimos al Dios y Padre, y con ella maldecimos á los hombres, los cuales son hechos á la semejanza de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 3, 10, 'De una misma boca proceden bendición y maldición. Hermanos míos, no conviene que estas cosas sean así hechas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 3, 11, '¿Echa alguna fuente por una misma abertura agua dulce y amarga?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 3, 12, 'Hermanos míos, ¿puede la higuera producir aceitunas, ó la vid higos? Así ninguna fuente puede hacer agua salada y dulce.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 3, 13, '¿Quién es sabio y avisado entre vosotros? muestre por buena conversación sus obras en mansedumbre de sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 3, 14, 'Pero si tenéis envidia amarga y contención en vuestros corazones, no os gloriés, ni seáis mentirosos contra la verdad:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 3, 15, 'Que esta sabiduría no es la que desciende de lo alto, sino terrena, animal, diabólica.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 3, 16, 'Porque donde hay envidia y contención, allí hay perturbación y toda obra perversa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 3, 17, 'Mas la sabiduría que es de lo alto, primeramente es pura, después pacífica, modesta, benigna, llena de misericordia y de buenos frutos, no juzgadora, no fingida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 3, 18, 'Y el fruto de justicia se siembra en paz para aquellos que hacen paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 4, 1, '¿DE dónde vienen las guerras y los pleitos entre vosotros? ¿No son de vuestras concupiscencias, las cuales combaten en vuestros miembros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 4, 2, 'Codiciáis, y no tenéis; matáis y ardéis de envidia, y no podéis alcanzar; combatís y gerreáis, y no tenéis lo que deseáis, porque no pedís.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 4, 3, 'Pedís, y no recibís, porque pedís mal, para gastar en vuestros deleites.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 4, 4, 'Adúlteros y adúlteras, ¿no sabéis que la amistad del mundo es enemistad con Dios? Cualquiera pues que quisiere ser amigo del mundo, se constituye enemigo de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 4, 5, '¿Pensáis que la Escritura dice sin causa: Es espíritu que mora en nosotros codicia para envidia?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 4, 6, 'Mas él da mayor gracia. Por esto dice: Dios resiste á los soberbios, y da gracia á los humildes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 4, 7, 'Someteos pues á Dios; resistid al diablo, y de vosotros huirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 4, 8, 'Allegaos á Dios, y él se allegará á vosotros. Pecadores, limpiad las manos; y vosotros de doblado ánimo, purificad los corazones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 4, 9, 'Afligíos, y lamentad, y llorad. Vuestra risa se convierta en lloro, y vuestro gozo en tristeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 4, 10, 'Humillaos delante del Señor, y él os ensalzará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 4, 11, 'Hermanos, no murmuréis los unos de los otros. El que murmura del hermano, y juzga á su hermano, este tal murmura de la ley, y juzga á la ley; pero si tú juzgas á la ley, no eres guardador de la ley, sino juez.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 4, 12, 'Uno es el dador de la ley, que puede salvar y perder: ¿quién eres tú que juzgas á otro?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 4, 13, 'Ea ahora, los que decís: Hoy y mañana iremos á tal ciudad, y estaremos allá un año, y compraremos mercadería, y ganaremos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 4, 14, 'Y no sabéis lo que será mañana. Porque ¿qué es vuestra vida? Ciertamente es un vapor que se aparece por un poco de tiempo, y luego se desvanece.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 4, 15, 'En lugar de lo cual deberíais decir: Si el Señor quisiere, y si viviéremos, haremos esto ó aquello.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 4, 16, 'Mas ahora os jactáis en vuestras soberbias. Toda jactancia semejante es mala.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 4, 17, 'El pecado, pues, está en aquel que sabe hacer lo bueno, y no lo hace.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 5, 1, 'EA ya ahora, oh ricos, llorad aullando por vuestras miserias que os vendrán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 5, 2, 'Vuestras riquezas están podridas: vuestras ropas están comidas de polilla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 5, 3, 'Vuestro oro y plata están corrompidos de orín; y su orín os será testimonio, y comerá del todo vuestras carnes como fuego. Os habéis allegado tesoro para en los postreros días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 5, 4, 'He aquí, el jornal de los obreros que han segado vuestras tierras, el cual por engaño no les ha sido pagado de vosotros, clama; y los clamores de los que habían segado, han entrado en los oídos del Señor de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 5, 5, 'Habéis vivido en deleites sobre la tierra, y sido disolutos; habéis cebado vuestros corazones como en el día de sacrificios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 5, 6, 'Habéis condenado y muerto al justo; y él no os resiste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 5, 7, 'Pues, hermanos, tened paciencia hasta la venida del Señor. Mirad cómo el labrador espera el precioso fruto de la tierra, aguardando con paciencia, hasta que reciba la lluvia temprana y tardía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 5, 8, 'Tened también vosotros paciencia; confirmad vuestros corazones: porque la venida del Señor se acerca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 5, 9, 'Hermanos, no os quejéis unos contra otros, porque no seáis condenados; he aquí, el juez está delante de la puerta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 5, 10, 'Hermanos míos, tomad por ejemplo de aflicción y de paciencia, á los profetas que hablaron en nombre del Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 5, 11, 'He aquí, tenemos por bienaventurados á los que sufren. Habéis oído la paciencia de Job, y habéis visto el fin del Señor, que el Señor es muy misericordioso y piadoso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 5, 12, 'Mas sobre todo, hermanos míos, no juréis, ni por el cielo, ni por la tierra, ni por otro cualquier juramento; sino vuestro sí sea sí, y vuestro no sea no; porque no caigáis en condenación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 5, 13, '¿Está alguno entre vosotros afligido? haga oración. ¿Está alguno alegre? cante salmos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 5, 14, '¿Está alguno enfermo entre vosotros? llame á los ancianos de la iglesia, y oren por él, ungiéndole con aceite en el nombre del Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 5, 15, 'Y la oración de fe salvará al enfermo, y el Señor lo levantará; y si estuviere en pecados, le serán perdonados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 5, 16, 'Confesaos vuestras faltas unos á otros, y rogad los unos por los otros, para que seáis sanos; la oración del justo, obrando eficazmente, puede mucho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 5, 17, 'Elías era hombre sujeto á semejantes pasiones que nosotros, y rogó con oración que no lloviese, y no llovió sobre la tierra en tres años y seis meses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 5, 18, 'Y otra vez oró, y el cielo dió lluvia, y la tierra produjo su fruto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 5, 19, 'Hermanos, si alguno de entre vosotros ha errado de la verdad, y alguno le convirtiere,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JAS', 'Santiago', 5, 20, 'Sepa que el que hubiere hecho convertir al pecador del error de su camino, salvará un alma de muerte, y cubrirá multitud de pecados.');
